def latest_browser_compare(results_dir: Path) -> Path | None:
    paths = sorted(results_dir.glob("browser-compare-*/browser-compare.json"))
    return paths[-1] if paths else None


def validate_payload(payload: dict[str, object]) -> list[str]:
    failures: list[str] = []
    default_result = validate_default_prefs(
        payload.get("browser_default_prefs", {})
    )
    if not default_result.get("ok"):
        for failure in default_result.get("failures", []):
            failures.append(f"default pref: {failure}")

    allow_webdriver_artifact = False
    browser_quality = payload.get("browser_quality", {})
    if isinstance(browser_quality, dict):
        no_marionette = browser_quality.get("no_marionette_fingerprint")
        if isinstance(no_marionette, dict):
            no_marionette_result = validate_browser_fingerprint_snapshot(
                no_marionette
            )
            if no_marionette.get("ok") and no_marionette_result.get("ok"):
                allow_webdriver_artifact = True
            else:
                for failure in no_marionette_result.get("failures", []):
                    failures.append(f"no-Marionette browser fingerprint: {failure}")
                if not no_marionette.get("ok"):
                    failures.append(
                        "no-Marionette browser fingerprint: "
                        f"{no_marionette.get('error', 'proof failed')}"
                    )

    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return failures + ["profiles payload is not a dict"]

    for profile_name, profile in profiles.items():
        if not isinstance(profile, dict):
            failures.append(f"{profile_name}: profile payload is not a dict")
            continue
        if profile.get("skipped"):
            continue
        if profile_name in {"bundled_c_tor_browser", "local_c_tor_browser"}:
            torrc = profile.get("torrc", {})
            if not isinstance(torrc, dict) or not torrc.get("isolate_socks_auth"):
                failures.append(f"{profile_name}: SocksPort lacks IsolateSOCKSAuth")
        warmup = profile.get("warmup_boot")
        if isinstance(warmup, dict) and not warmup.get("ok"):
            failures.append(f"{profile_name}: warmup proxy did not bootstrap")
        if not profile.get("boot", {}).get("ok"):
            failures.append(f"{profile_name}: proxy did not bootstrap")
        benchmarks = profile.get("benchmarks", {})
        if not isinstance(benchmarks, dict) or not benchmarks:
            failures.append(f"{profile_name}: no browser benchmarks")
            continue
        for url, bench in benchmarks.items():
            if not bench.get("summary", {}).get("ok"):
                failures.append(f"{profile_name} {url}: summary not ok")
            for index, run in enumerate(bench.get("runs", []), start=1):
                failures.extend(
                    validate_run(
                        profile_name,
                        str(url),
                        index,
                        run,
                        allow_webdriver_artifact=allow_webdriver_artifact,
                    )
                )
    failures.extend(validate_browser_fingerprint_consistency(payload))
    return failures


def validate_run(
    profile_name: str,
    url: str,
    index: int,
    run: dict[str, object],
    *,
    allow_webdriver_artifact: bool = False,
) -> list[str]:
    failures: list[str] = []
    prefix = f"{profile_name} {url} run {index}"
    if not run.get("ok"):
        failures.append(f"{prefix}: run not ok")
    screenshot = run.get("screenshot", {})
    if (
        not isinstance(screenshot, dict)
        or not screenshot.get("exists")
        or not screenshot.get("bytes")
        or not screenshot.get("width")
        or not screenshot.get("height")
    ):
        failures.append(f"{prefix}: screenshot proof missing")

    effective = run.get("effective_proxy_prefs", {})
    if not isinstance(effective, dict):
        failures.append(f"{prefix}: effective proxy prefs missing")
        return failures

    expected_port = run.get("expected_socks_port")
    if effective.get("network.proxy.socks") != "127.0.0.1":
        failures.append(f"{prefix}: SOCKS host is not 127.0.0.1")
    if expected_port is not None and effective.get("network.proxy.socks_port") != expected_port:
        failures.append(f"{prefix}: SOCKS port mismatch")
    if effective.get("network.proxy.socks_remote_dns") is not True:
        failures.append(f"{prefix}: SOCKS remote DNS is not true")
    if effective.get("network.proxy.type") != 1:
        failures.append(f"{prefix}: proxy type is not SOCKS/manual")

    if "browser_quality_prefs" in run:
        quality_pref_result = validate_browser_quality_prefs(
            run.get("browser_quality_prefs", {})
        )
        if not quality_pref_result.get("ok"):
            for failure in quality_pref_result.get("failures", []):
                failures.append(f"{prefix}: browser quality pref {failure}")

    if "browser_fingerprint_snapshot" in run:
        fingerprint_result = validate_browser_fingerprint_snapshot(
            run.get("browser_fingerprint_snapshot", {}),
            allow_webdriver_artifact=allow_webdriver_artifact,
        )
        if not fingerprint_result.get("ok"):
            for failure in fingerprint_result.get("failures", []):
                failures.append(f"{prefix}: browser fingerprint {failure}")
    return failures


def validate_browser_fingerprint_consistency(
    payload: dict[str, object],
) -> list[str]:
    grouped: dict[tuple[str, int], list[tuple[str, dict[str, object]]]] = {}
    for profile_name, profile, target, _summary, run in iter_runs(payload):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        run_index = numeric(run.get("run_index"))
        if run_index is None:
            continue
        audit = run.get("browser_fingerprint_snapshot", {})
        if not isinstance(audit, dict) or audit.get("ok") is not True:
            continue
        snapshot = audit.get("snapshot", {})
        if not isinstance(snapshot, dict):
            continue
        grouped.setdefault((str(target), int(run_index)), []).append(
            (str(profile_name), snapshot)
        )

    failures: list[str] = []
    for (target, run_index), entries in sorted(grouped.items()):
        if len(entries) < 2:
            continue
        baseline_profile, baseline_snapshot = preferred_fingerprint_baseline(entries)
        for profile_name, snapshot in entries:
            if profile_name == baseline_profile:
                continue
            if snapshot == baseline_snapshot:
                continue
            diff = compact_fingerprint_diff(baseline_snapshot, snapshot)
            failures.append(
                f"{target} run {run_index}: fingerprint snapshot mismatch {profile_name} vs {baseline_profile}: {diff}"
            )
    return failures


def preferred_fingerprint_baseline(
    entries: list[tuple[str, dict[str, object]]],
) -> tuple[str, dict[str, object]]:
    preferred_profiles = (
        "local_c_tor_browser",
        "bundled_c_tor_browser",
        "arti_release_browser",
    )
    for preferred in preferred_profiles:
        for profile_name, snapshot in entries:
            if profile_name == preferred:
                return profile_name, snapshot
    return entries[0]


def compact_fingerprint_diff(
    baseline: dict[str, object], candidate: dict[str, object], limit: int = 5
) -> str:
    keys = sorted(set(baseline) | set(candidate))
    diffs = []
    for key in keys:
        left = baseline.get(key)
        right = candidate.get(key)
        if left == right:
            continue
        diffs.append(f"{key}={left!r}->{right!r}")
        if len(diffs) >= limit:
            break
    if not diffs:
        return "values differ"
    return ", ".join(diffs)


def print_timing_table(payload: dict[str, object]) -> None:
    print("## Timing")
    print()
    print(
        "| profile | target | cache | warmup s | boot s | post wait s | runs | "
        "median elapsed ms | boot+elapsed ms | median load ms | boot+load ms | ok |"
    )
    print("|---|---|---|---:|---:|---:|---:|---:|---:|---:|---:|---|")
    for profile_name, profile, url, summary in iter_summaries(payload):
        cache_mode = profile.get("cache_mode", payload.get("cache_mode", "cold"))
        warmup = profile.get("warmup_boot")
        warmup_seconds = warmup.get("seconds") if isinstance(warmup, dict) else None
        boot = boot_seconds_for_profile(profile)
        post_boot_wait = profile.get(
            "post_boot_wait_seconds", payload.get("post_boot_wait_seconds")
        )
        print(
            "| {profile} | {target} | {cache} | {warmup} | {boot} | "
            "{post_boot_wait} | {runs} | {elapsed} | {boot_elapsed} | "
            "{load} | {boot_load} | {ok} |".format(
                profile=profile_name,
                target=url,
                cache=cache_mode,
                warmup=fmt(warmup_seconds),
                boot=fmt(boot),
                post_boot_wait=fmt(post_boot_wait),
                runs=fmt(summary.get("successes")),
                elapsed=fmt(summary.get("median_elapsed_ms")),
                boot_elapsed=fmt(add_boot_ms(boot, summary.get("median_elapsed_ms"))),
                load=fmt(summary.get("median_load_ms")),
                boot_load=fmt(add_boot_ms(boot, summary.get("median_load_ms"))),
                ok="yes" if summary.get("ok") else "no",
            )
        )


