def torfast_socks_timing_rows_by_timing_id_for_profile(
    profile: dict[str, object],
) -> dict[object, dict[str, object]]:
    lines = proxy_log_lines(profile)
    if not isinstance(lines, list):
        return {}
    rows = group_torfast_socks_timings(
        parse_torfast_socks_timings([str(line) for line in lines])
    ).values()
    return {
        row.get("timing_id"): row
        for row in rows
        if row.get("timing_id") is not None
    }


def torfast_socks_byte_event_tails_by_timing_id_for_profile(
    profile: dict[str, object],
) -> dict[object, dict[str, object]]:
    lines = proxy_log_lines(profile)
    if not isinstance(lines, list):
        return {}
    tails: dict[object, dict[str, object]] = {}
    for event in parse_torfast_socks_byte_events([str(line) for line in lines]):
        timing_id = event.get("timing_id")
        direction = event.get("direction")
        if timing_id is None or direction not in {"tor_to_client", "tor_to_client_write"}:
            continue
        elapsed_ms = numeric(event.get("elapsed_ms"))
        event_epoch_ms = numeric(event.get("event_epoch_ms"))
        cumulative_bytes = numeric(event.get("cumulative_bytes"))
        if elapsed_ms is None and event_epoch_ms is None:
            continue
        row = tails.setdefault(timing_id, {})
        prefix = (
            "last_tor_to_client_write"
            if direction == "tor_to_client_write"
            else "last_tor_to_client"
        )
        current_epoch = numeric(row.get(f"{prefix}_epoch_ms"))
        current_elapsed = numeric(row.get(f"{prefix}_ms"))
        should_replace = False
        if event_epoch_ms is not None:
            should_replace = current_epoch is None or event_epoch_ms > current_epoch
        elif elapsed_ms is not None:
            should_replace = current_elapsed is None or elapsed_ms > current_elapsed
        if not should_replace:
            continue
        if elapsed_ms is not None:
            row[f"{prefix}_ms"] = elapsed_ms
        if event_epoch_ms is not None:
            row[f"{prefix}_epoch_ms"] = event_epoch_ms
        if cumulative_bytes is not None:
            row[f"{prefix}_bytes"] = cumulative_bytes
    return tails


def browser_activity_tagged_stream_resource_rows(
    payload: dict[str, object]
) -> list[dict[str, object]]:
    rows: list[dict[str, object]] = []
    for profile_name, profile, target, _summary, run in iter_runs(payload):
        if not isinstance(profile, dict):
            continue
        timing_rows_by_id = torfast_socks_timing_rows_by_timing_id_for_profile(
            profile
        )
        byte_event_tails_by_id = (
            torfast_socks_byte_event_tails_by_timing_id_for_profile(profile)
        )
        parent_bridges = browser_net_log_parent_bridge_rows_for_run(run)
        if not parent_bridges:
            parent_bridges = browser_activity_probe_parent_bridge_rows_for_run(run)
        bridges = [
            bridge
            for bridge in browser_net_log_socks_stream_bridge_rows_for_run(
                profile, run, parent_bridges
            )
            if bridge.get("stream_bridge_method")
            == "browser_activity_socks_reply_tag"
            and bridge.get("stream_id") is not None
        ]
        if not bridges:
            continue
        resources_by_name: dict[str, list[dict[str, object]]] = {}
        for resource in browser_resource_rows_for_run(run):
            name = resource.get("name")
            if isinstance(name, str):
                resources_by_name.setdefault(name, []).append(resource)
        for bridge in bridges:
            uri = bridge.get("uri")
            if not isinstance(uri, str):
                continue
            timing_row = timing_rows_by_id.get(bridge.get("timing_id"), {})
            byte_tail = byte_event_tails_by_id.get(bridge.get("timing_id"), {})
            conn_started_epoch_ms = numeric(timing_row.get("conn_started_epoch_ms"))
            last_tor_byte_ms = positive_ms(timing_row, "last_tor_to_client_ms")
            if last_tor_byte_ms is None:
                last_tor_byte_ms = positive_ms(byte_tail, "last_tor_to_client_ms")
            last_tor_write_ms = positive_ms(
                timing_row, "last_tor_to_client_write_ms"
            )
            if last_tor_write_ms is None:
                last_tor_write_ms = positive_ms(
                    byte_tail, "last_tor_to_client_write_ms"
                )
            last_tor_byte_epoch_ms = (
                add_numeric(conn_started_epoch_ms, last_tor_byte_ms)
                if last_tor_byte_ms is not None
                else None
            )
            if last_tor_byte_epoch_ms is None:
                last_tor_byte_epoch_ms = numeric(
                    byte_tail.get("last_tor_to_client_epoch_ms")
                )
            last_tor_write_epoch_ms = (
                add_numeric(conn_started_epoch_ms, last_tor_write_ms)
                if last_tor_write_ms is not None
                else None
            )
            if last_tor_write_epoch_ms is None:
                last_tor_write_epoch_ms = numeric(
                    byte_tail.get("last_tor_to_client_write_epoch_ms")
                )
            for resource in resources_by_name.get(uri, []):
                response_end_epoch_ms = add_numeric(
                    browser_time_origin_ms(run), resource.get("responseEnd")
                )
                rows.append(
                    {
                        "profile": profile_name,
                        "target": target,
                        "run_index": run.get("run_index"),
                        "resource": uri,
                        "resource_type": resource.get("initiatorType", ""),
                        "fetch_start_ms": numeric(resource.get("fetchStart")),
                        "request_start_ms": numeric(resource.get("requestStart")),
                        "response_start_ms": numeric(resource.get("responseStart")),
                        "response_end_ms": numeric(resource.get("responseEnd")),
                        "start_time_ms": numeric(resource.get("startTime")),
                        "fetch_to_request_ms": resource_phase_ms(
                            resource, "fetchToRequest"
                        ),
                        "request_wait_ms": resource_phase_ms(
                            resource, "requestWait"
                        ),
                        "response_receive_ms": resource_phase_ms(
                            resource, "responseReceive"
                        ),
                        "duration_ms": numeric(resource.get("duration")),
                        "connection_id": bridge.get("connection_id"),
                        "browser_activity_tag_port": bridge.get(
                            "browser_activity_tag_port"
                        ),
                        "timing_id": bridge.get("timing_id"),
                        "stream_id": bridge.get("stream_id"),
                        "circ_id": bridge.get("circ_id"),
                        "last_tor_to_client_ms": last_tor_byte_ms,
                        "last_tor_to_client_write_ms": last_tor_write_ms,
                        "last_tor_to_client_epoch_ms": last_tor_byte_epoch_ms,
                        "last_tor_to_client_write_epoch_ms": (
                            last_tor_write_epoch_ms
                        ),
                        "last_tor_write_after_last_tor_byte_ms": subtract_numeric(
                            last_tor_write_ms, last_tor_byte_ms
                        ),
                        "response_end_after_last_tor_byte_ms": subtract_numeric(
                            response_end_epoch_ms, last_tor_byte_epoch_ms
                        ),
                        "response_end_after_last_tor_write_ms": subtract_numeric(
                            response_end_epoch_ms, last_tor_write_epoch_ms
                        ),
                        "relay_ms": timing_row.get("relay_ms"),
                        "tor_to_client_bytes": timing_row.get(
                            "tor_to_client_bytes",
                            byte_tail.get("last_tor_to_client_bytes"),
                        ),
                        "tor_to_client_write_bytes": timing_row.get(
                            "tor_to_client_write_bytes",
                            byte_tail.get("last_tor_to_client_write_bytes"),
                        ),
                    }
                )
    return sorted(
        rows,
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0,
            -(numeric(row.get("fetch_to_request_ms")) or 0),
            -(numeric(row.get("duration_ms")) or 0),
        ),
    )


