def browser_activity_tagged_stream_sequence_rows(
    payload: dict[str, object]
) -> list[dict[str, object]]:
    grouped: dict[tuple[object, ...], list[dict[str, object]]] = {}
    for row in browser_activity_tagged_stream_resource_rows(payload):
        key = (
            row.get("profile"),
            row.get("target"),
            row.get("run_index"),
            row.get("connection_id"),
            row.get("browser_activity_tag_port"),
            row.get("timing_id"),
            row.get("stream_id"),
            row.get("circ_id"),
        )
        grouped.setdefault(key, []).append(row)

    rows: list[dict[str, object]] = []
    for key, group_rows in grouped.items():
        sorted_rows = sorted(
            group_rows,
            key=lambda row: (
                numeric(row.get("request_start_ms"))
                if numeric(row.get("request_start_ms")) is not None
                else float("inf"),
                numeric(row.get("fetch_start_ms"))
                if numeric(row.get("fetch_start_ms")) is not None
                else float("inf"),
                str(row.get("resource", "")),
            ),
        )
        previous_resource: dict[str, object] | None = None
        for index, row in enumerate(sorted_rows, start=1):
            request_start = numeric(row.get("request_start_ms"))
            previous_response_end = (
                numeric(previous_resource.get("response_end_ms"))
                if previous_resource is not None
                else None
            )
            output_row = dict(row)
            output_row["sequence_index"] = index
            output_row["previous_resource"] = (
                previous_resource.get("resource", "")
                if previous_resource is not None
                else ""
            )
            output_row["previous_response_end_ms"] = previous_response_end
            output_row["previous_request_start_ms"] = (
                previous_resource.get("request_start_ms")
                if previous_resource is not None
                else None
            )
            output_row["previous_response_start_ms"] = (
                previous_resource.get("response_start_ms")
                if previous_resource is not None
                else None
            )
            output_row["previous_request_wait_ms"] = (
                previous_resource.get("request_wait_ms")
                if previous_resource is not None
                else None
            )
            output_row["previous_response_receive_ms"] = (
                previous_resource.get("response_receive_ms")
                if previous_resource is not None
                else None
            )
            output_row["previous_response_end_after_last_tor_write_ms"] = (
                previous_resource.get("response_end_after_last_tor_write_ms")
                if previous_resource is not None
                else None
            )
            output_row["request_after_previous_response_ms"] = (
                request_start - previous_response_end
                if request_start is not None and previous_response_end is not None
                else None
            )
            rows.append(output_row)
            previous_resource = row

    return sorted(
        rows,
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0,
            -(numeric(row.get("fetch_to_request_ms")) or 0),
            numeric(row.get("sequence_index")) or 0,
        ),
    )


def browser_activity_tagged_stream_queue_cause_hint(row: dict[str, object]) -> str:
    queue_ms = numeric(row.get("fetch_to_request_ms")) or 0.0
    blocked_ms = numeric(row.get("queue_blocked_by_previous_response_ms")) or 0.0
    unexplained_ms = numeric(row.get("queue_unexplained_after_previous_ms")) or 0.0
    if queue_ms <= 0:
        return "no browser queue"
    if not row.get("previous_resource"):
        return "first resource on tagged stream"
    if blocked_ms >= queue_ms * 0.9:
        return "queued behind previous response"
    if unexplained_ms > blocked_ms:
        return "queue mostly after previous response"
    return "mixed previous response and browser delay"


def browser_activity_tagged_stream_queue_cause_rows(
    payload: dict[str, object]
) -> list[dict[str, object]]:
    rows: list[dict[str, object]] = []
    for row in browser_activity_tagged_stream_sequence_rows(payload):
        if not row.get("previous_resource"):
            continue
        queue_ms = numeric(row.get("fetch_to_request_ms"))
        fetch_start = numeric(row.get("fetch_start_ms"))
        request_start = numeric(row.get("request_start_ms"))
        previous_response_end = numeric(row.get("previous_response_end_ms"))
        if (
            queue_ms is None
            or queue_ms <= 0
            or fetch_start is None
            or request_start is None
            or previous_response_end is None
        ):
            continue
        blocked_ms = max(
            0.0,
            min(request_start, previous_response_end) - fetch_start,
        )
        blocked_ms = min(blocked_ms, queue_ms)
        wait_blocked_ms = interval_overlap_ms(
            fetch_start,
            request_start,
            numeric(row.get("previous_request_start_ms")),
            numeric(row.get("previous_response_start_ms")),
        )
        receive_blocked_ms = interval_overlap_ms(
            fetch_start,
            request_start,
            numeric(row.get("previous_response_start_ms")),
            previous_response_end,
        )
        pre_request_blocked_ms = max(
            0.0,
            blocked_ms - (wait_blocked_ms or 0.0) - (receive_blocked_ms or 0.0),
        )
        output_row = dict(row)
        output_row["queue_blocked_by_previous_response_ms"] = blocked_ms
        output_row["queue_blocked_by_previous_pre_request_ms"] = (
            pre_request_blocked_ms
        )
        output_row["queue_blocked_by_previous_wait_ms"] = wait_blocked_ms
        output_row["queue_blocked_by_previous_receive_ms"] = receive_blocked_ms
        output_row["queue_unexplained_after_previous_ms"] = max(
            0.0, queue_ms - blocked_ms
        )
        output_row["queue_cause_hint"] = (
            browser_activity_tagged_stream_queue_cause_hint(output_row)
        )
        rows.append(output_row)

    return sorted(
        rows,
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0,
            -(numeric(row.get("fetch_to_request_ms")) or 0),
            numeric(row.get("sequence_index")) or 0,
        ),
    )


