def browser_activity_tagged_stream_group_rows(
    payload: dict[str, object]
) -> list[dict[str, object]]:
    grouped: dict[tuple[object, ...], list[dict[str, object]]] = {}
    for row in browser_activity_tagged_stream_resource_rows(payload):
        key = (
            row.get("profile"),
            row.get("target"),
            row.get("run_index"),
            row.get("connection_id"),
            row.get("browser_activity_tag_port"),
            row.get("timing_id"),
            row.get("stream_id"),
            row.get("circ_id"),
        )
        grouped.setdefault(key, []).append(row)

    rows: list[dict[str, object]] = []
    for (
        profile,
        target,
        run_index,
        connection_id,
        tag_port,
        timing_id,
        stream_id,
        circ_id,
    ), group_rows in grouped.items():
        queue_values = [
            numeric(row.get("fetch_to_request_ms"))
            for row in group_rows
            if numeric(row.get("fetch_to_request_ms")) is not None
        ]
        wait_values = [
            numeric(row.get("request_wait_ms"))
            for row in group_rows
            if numeric(row.get("request_wait_ms")) is not None
        ]
        receive_values = [
            numeric(row.get("response_receive_ms"))
            for row in group_rows
            if numeric(row.get("response_receive_ms")) is not None
        ]
        duration_values = [
            numeric(row.get("duration_ms"))
            for row in group_rows
            if numeric(row.get("duration_ms")) is not None
        ]
        write_lag_values = [
            numeric(row.get("last_tor_write_after_last_tor_byte_ms"))
            for row in group_rows
            if numeric(row.get("last_tor_write_after_last_tor_byte_ms")) is not None
        ]
        response_after_write_values = [
            numeric(row.get("response_end_after_last_tor_write_ms"))
            for row in group_rows
            if numeric(row.get("response_end_after_last_tor_write_ms")) is not None
        ]
        top_resources = [
            compact_url(str(row.get("resource", "")), max_length=52)
            for row in sorted(
                group_rows,
                key=lambda item: (
                    numeric(item.get("fetch_to_request_ms")) or 0,
                    numeric(item.get("duration_ms")) or 0,
                ),
                reverse=True,
            )[:5]
        ]
        rows.append(
            {
                "profile": profile,
                "target": target,
                "run_index": run_index,
                "connection_id": connection_id,
                "browser_activity_tag_port": tag_port,
                "timing_id": timing_id,
                "stream_id": stream_id,
                "circ_id": circ_id,
                "resources": len(group_rows),
                "queued_1000ms": sum(
                    1 for value in queue_values if value is not None and value >= 1000
                ),
                "median_fetch_to_request_ms": median(queue_values)
                if queue_values
                else None,
                "max_fetch_to_request_ms": max(queue_values) if queue_values else None,
                "max_request_wait_ms": max(wait_values) if wait_values else None,
                "max_response_receive_ms": max(receive_values)
                if receive_values
                else None,
                "max_duration_ms": max(duration_values) if duration_values else None,
                "max_last_tor_write_after_last_tor_byte_ms": (
                    max(write_lag_values) if write_lag_values else None
                ),
                "median_response_end_after_last_tor_write_ms": (
                    median(response_after_write_values)
                    if response_after_write_values
                    else None
                ),
                "top_resources": ", ".join(top_resources),
            }
        )
    return sorted(
        rows,
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0,
            -(numeric(row.get("max_fetch_to_request_ms")) or 0),
            -(numeric(row.get("resources")) or 0),
        ),
    )


