def browser_activity_tagged_connection_sequence_rows(
    payload: dict[str, object]
) -> list[dict[str, object]]:
    grouped: dict[tuple[object, ...], list[dict[str, object]]] = {}
    for row in browser_activity_tagged_connection_resource_rows(payload):
        key = (
            row.get("profile"),
            row.get("target"),
            row.get("run_index"),
            row.get("connection_id"),
            row.get("browser_activity_tag_port"),
            row.get("socks_target_host"),
        )
        grouped.setdefault(key, []).append(row)

    rows: list[dict[str, object]] = []
    for _key, group_rows in grouped.items():
        sorted_rows = sorted(
            group_rows,
            key=lambda row: (
                numeric(row.get("request_start_ms"))
                if numeric(row.get("request_start_ms")) is not None
                else float("inf"),
                numeric(row.get("fetch_start_ms"))
                if numeric(row.get("fetch_start_ms")) is not None
                else float("inf"),
                str(row.get("resource", "")),
            ),
        )
        previous_resource: dict[str, object] | None = None
        for index, row in enumerate(sorted_rows, start=1):
            request_start = numeric(row.get("request_start_ms"))
            previous_response_end = (
                numeric(previous_resource.get("response_end_ms"))
                if previous_resource is not None
                else None
            )
            output_row = dict(row)
            output_row["sequence_index"] = index
            output_row["previous_resource"] = (
                previous_resource.get("resource", "")
                if previous_resource is not None
                else ""
            )
            output_row["previous_response_end_ms"] = previous_response_end
            output_row["previous_response_end_epoch_ms"] = (
                previous_resource.get("response_end_epoch_ms")
                if previous_resource is not None
                else None
            )
            output_row["previous_request_start_ms"] = (
                previous_resource.get("request_start_ms")
                if previous_resource is not None
                else None
            )
            output_row["previous_request_start_epoch_ms"] = (
                previous_resource.get("request_start_epoch_ms")
                if previous_resource is not None
                else None
            )
            output_row["previous_response_start_ms"] = (
                previous_resource.get("response_start_ms")
                if previous_resource is not None
                else None
            )
            output_row["previous_response_start_epoch_ms"] = (
                previous_resource.get("response_start_epoch_ms")
                if previous_resource is not None
                else None
            )
            output_row["previous_request_wait_ms"] = (
                previous_resource.get("request_wait_ms")
                if previous_resource is not None
                else None
            )
            output_row["previous_response_receive_ms"] = (
                previous_resource.get("response_receive_ms")
                if previous_resource is not None
                else None
            )
            output_row["request_after_previous_response_ms"] = (
                request_start - previous_response_end
                if request_start is not None and previous_response_end is not None
                else None
            )
            rows.append(output_row)
            previous_resource = row

    return sorted(
        rows,
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0,
            -(numeric(row.get("fetch_to_request_ms")) or 0),
            numeric(row.get("sequence_index")) or 0,
        ),
    )


def browser_activity_tagged_connection_queue_cause_summary_rows(
    payload: dict[str, object]
) -> list[dict[str, object]]:
    groups: dict[tuple[object, ...], list[dict[str, object]]] = {}
    for row in browser_activity_tagged_connection_queue_cause_rows(payload):
        key = (
            row.get("profile"),
            row.get("target"),
            row.get("run_index"),
        )
        groups.setdefault(key, []).append(row)

    rows: list[dict[str, object]] = []
    for (profile, target, run_index), group_rows in groups.items():
        total_queue = sum(
            numeric(row.get("fetch_to_request_ms")) or 0.0 for row in group_rows
        )
        total_blocked = sum(
            numeric(row.get("queue_blocked_by_previous_response_ms")) or 0.0
            for row in group_rows
        )
        total_unexplained = sum(
            numeric(row.get("queue_unexplained_after_previous_ms")) or 0.0
            for row in group_rows
        )
        total_wait_blocked = sum(
            numeric(row.get("queue_blocked_by_previous_wait_ms")) or 0.0
            for row in group_rows
        )
        total_receive_blocked = sum(
            numeric(row.get("queue_blocked_by_previous_receive_ms")) or 0.0
            for row in group_rows
        )
        total_pre_request_blocked = sum(
            numeric(row.get("queue_blocked_by_previous_pre_request_ms")) or 0.0
            for row in group_rows
        )
        response_after_proxy_data_values = numeric_values(
            group_rows, "previous_response_end_after_last_proxy_data_ms"
        )
        response_proxy_data_rows = [
            row
            for row in group_rows
            if (numeric(row.get("previous_response_proxy_stream_data_events")) or 0)
            > 0
        ]
        browser_after_proxy_data_values = numeric_values(
            group_rows, "previous_receive_browser_after_last_proxy_data_ms"
        )
        proxy_data_rows = [
            row
            for row in group_rows
            if (numeric(row.get("previous_receive_proxy_stream_data_events")) or 0)
            > 0
        ]
        top_row = max(
            group_rows,
            key=lambda row: (
                numeric(row.get("fetch_to_request_ms")) or 0.0,
                numeric(row.get("duration_ms")) or 0.0,
            ),
        )
        rows.append(
            {
                "profile": profile,
                "target": target,
                "run_index": run_index,
                "rows": len(group_rows),
                "queued_1000ms": row_count_at_least(
                    group_rows, "fetch_to_request_ms", 1000
                ),
                "total_fetch_to_request_ms": total_queue,
                "total_queue_blocked_by_previous_response_ms": total_blocked,
                "total_queue_blocked_by_previous_pre_request_ms": (
                    total_pre_request_blocked
                ),
                "total_queue_blocked_by_previous_wait_ms": total_wait_blocked,
                "total_queue_blocked_by_previous_receive_ms": total_receive_blocked,
                "previous_response_rows_with_proxy_data": len(
                    response_proxy_data_rows
                ),
                "total_previous_response_proxy_stream_data_bytes": sum(
                    numeric(row.get("previous_response_proxy_stream_data_bytes"))
                    or 0.0
                    for row in group_rows
                ),
                "median_previous_response_end_after_last_proxy_data_ms": (
                    median(response_after_proxy_data_values)
                    if response_after_proxy_data_values
                    else None
                ),
                "max_previous_response_end_after_last_proxy_data_ms": (
                    max(response_after_proxy_data_values)
                    if response_after_proxy_data_values
                    else None
                ),
                "previous_receive_rows_with_proxy_data": len(proxy_data_rows),
                "total_previous_receive_proxy_stream_data_bytes": sum(
                    numeric(row.get("previous_receive_proxy_stream_data_bytes"))
                    or 0.0
                    for row in group_rows
                ),
                "median_previous_receive_browser_after_last_proxy_data_ms": (
                    median(browser_after_proxy_data_values)
                    if browser_after_proxy_data_values
                    else None
                ),
                "max_previous_receive_browser_after_last_proxy_data_ms": (
                    max(browser_after_proxy_data_values)
                    if browser_after_proxy_data_values
                    else None
                ),
                "blocked_by_previous_response_share_pct": (
                    total_blocked * 100.0 / total_queue if total_queue else None
                ),
                "total_queue_unexplained_after_previous_ms": total_unexplained,
                "max_fetch_to_request_ms": row_max(group_rows, "fetch_to_request_ms"),
                "max_unexplained_after_previous_ms": row_max(
                    group_rows, "queue_unexplained_after_previous_ms"
                ),
                "top_queued_resource": top_row.get("resource", ""),
            }
        )

    return sorted(
        rows,
        key=lambda row: (
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0,
            -(numeric(row.get("max_fetch_to_request_ms")) or 0.0),
            str(row.get("profile", "")),
        ),
    )


def browser_activity_tagged_connection_queue_cause_rows(
    payload: dict[str, object]
) -> list[dict[str, object]]:
    rows: list[dict[str, object]] = []
    profiles = payload.get("profiles", {})
    profile_by_name = profiles if isinstance(profiles, dict) else {}
    byte_tap_events_by_profile: dict[
        object, dict[object, list[dict[str, object]]]
    ] = {}
    for row in browser_activity_tagged_connection_sequence_rows(payload):
        if not row.get("previous_resource"):
            continue
        queue_ms = numeric(row.get("fetch_to_request_ms"))
        fetch_start = numeric(row.get("fetch_start_ms"))
        request_start = numeric(row.get("request_start_ms"))
        previous_response_end = numeric(row.get("previous_response_end_ms"))
        if (
            queue_ms is None
            or queue_ms <= 0
            or fetch_start is None
            or request_start is None
            or previous_response_end is None
        ):
            continue
        blocked_ms = max(
            0.0,
            min(request_start, previous_response_end) - fetch_start,
        )
        blocked_ms = min(blocked_ms, queue_ms)
        wait_blocked_ms = interval_overlap_ms(
            fetch_start,
            request_start,
            numeric(row.get("previous_request_start_ms")),
            numeric(row.get("previous_response_start_ms")),
        )
        receive_blocked_ms = interval_overlap_ms(
            fetch_start,
            request_start,
            numeric(row.get("previous_response_start_ms")),
            previous_response_end,
        )
        previous_receive_start_epoch = numeric(
            row.get("previous_response_start_epoch_ms")
        )
        previous_receive_end_epoch = numeric(row.get("previous_response_end_epoch_ms"))
        previous_request_start_epoch = numeric(
            row.get("previous_request_start_epoch_ms")
        )
        proxy_events_in_previous_response: list[dict[str, object]] = []
        proxy_events_in_previous_receive: list[dict[str, object]] = []
        if previous_receive_end_epoch is not None:
            profile_name = row.get("profile")
            if profile_name not in byte_tap_events_by_profile:
                profile = profile_by_name.get(profile_name)
                byte_tap_events_by_profile[profile_name] = (
                    byte_tap_proxy_stream_data_events_by_connection(profile)
                    if isinstance(profile, dict)
                    else {}
                )
            proxy_events = byte_tap_events_by_profile[profile_name].get(
                row.get("connection_id"), []
            )
            if previous_request_start_epoch is not None:
                proxy_events_in_previous_response = events_in_epoch_window(
                    proxy_events,
                    previous_request_start_epoch,
                    previous_receive_end_epoch,
                )
            if previous_receive_start_epoch is not None:
                proxy_events_in_previous_receive = events_in_epoch_window(
                    proxy_events,
                    previous_receive_start_epoch,
                    previous_receive_end_epoch,
                )
        response_proxy_event_epochs = [
            numeric(event.get("event_epoch_ms"))
            for event in proxy_events_in_previous_response
            if numeric(event.get("event_epoch_ms")) is not None
        ]
        first_response_proxy_epoch = (
            min(response_proxy_event_epochs) if response_proxy_event_epochs else None
        )
        last_response_proxy_epoch = (
            max(response_proxy_event_epochs) if response_proxy_event_epochs else None
        )
        proxy_event_epochs = [
            numeric(event.get("event_epoch_ms"))
            for event in proxy_events_in_previous_receive
            if numeric(event.get("event_epoch_ms")) is not None
        ]
        first_proxy_epoch = min(proxy_event_epochs) if proxy_event_epochs else None
        last_proxy_epoch = max(proxy_event_epochs) if proxy_event_epochs else None
        pre_request_blocked_ms = max(
            0.0,
            blocked_ms - (wait_blocked_ms or 0.0) - (receive_blocked_ms or 0.0),
        )
        output_row = dict(row)
        output_row["queue_blocked_by_previous_response_ms"] = blocked_ms
        output_row["queue_blocked_by_previous_pre_request_ms"] = (
            pre_request_blocked_ms
        )
        output_row["queue_blocked_by_previous_wait_ms"] = wait_blocked_ms
        output_row["queue_blocked_by_previous_receive_ms"] = receive_blocked_ms
        output_row["previous_response_proxy_stream_data_events"] = len(
            proxy_events_in_previous_response
        )
        output_row["previous_response_proxy_stream_data_bytes"] = sum(
            numeric(event.get("stream_data_bytes")) or 0.0
            for event in proxy_events_in_previous_response
        )
        output_row["previous_response_first_proxy_data_after_request_ms"] = (
            first_response_proxy_epoch - previous_request_start_epoch
            if first_response_proxy_epoch is not None
            and previous_request_start_epoch is not None
            else None
        )
        output_row["previous_response_end_after_last_proxy_data_ms"] = (
            previous_receive_end_epoch - last_response_proxy_epoch
            if last_response_proxy_epoch is not None
            and previous_receive_end_epoch is not None
            else None
        )
        output_row["previous_response_proxy_data_span_ms"] = (
            last_response_proxy_epoch - first_response_proxy_epoch
            if first_response_proxy_epoch is not None
            and last_response_proxy_epoch is not None
            and last_response_proxy_epoch >= first_response_proxy_epoch
            else None
        )
        output_row["previous_receive_proxy_stream_data_events"] = len(
            proxy_events_in_previous_receive
        )
        output_row["previous_receive_proxy_stream_data_bytes"] = sum(
            numeric(event.get("stream_data_bytes")) or 0.0
            for event in proxy_events_in_previous_receive
        )
        output_row["previous_receive_first_proxy_data_after_start_ms"] = (
            first_proxy_epoch - previous_receive_start_epoch
            if first_proxy_epoch is not None
            and previous_receive_start_epoch is not None
            else None
        )
        output_row["previous_receive_last_proxy_data_before_end_ms"] = (
            previous_receive_end_epoch - last_proxy_epoch
            if last_proxy_epoch is not None and previous_receive_end_epoch is not None
            else None
        )
        output_row["previous_receive_browser_after_last_proxy_data_ms"] = (
            previous_receive_end_epoch - last_proxy_epoch
            if last_proxy_epoch is not None and previous_receive_end_epoch is not None
            else None
        )
        output_row["previous_receive_proxy_data_span_ms"] = (
            last_proxy_epoch - first_proxy_epoch
            if first_proxy_epoch is not None
            and last_proxy_epoch is not None
            and last_proxy_epoch >= first_proxy_epoch
            else None
        )
        output_row["queue_unexplained_after_previous_ms"] = max(
            0.0, queue_ms - blocked_ms
        )
        output_row["queue_cause_hint"] = (
            browser_activity_tagged_stream_queue_cause_hint(output_row)
        )
        rows.append(output_row)

    return sorted(
        rows,
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0,
            -(numeric(row.get("fetch_to_request_ms")) or 0),
            numeric(row.get("sequence_index")) or 0,
        ),
    )


