def reader_terminal_summary(row: dict[str, object]) -> str:
    kind = row.get("reader_terminal_kind")
    if not kind:
        return ""
    reason = row.get("reader_terminal_end_reason")
    if reason:
        return f"{kind}:{reason}"
    returned_eof = row.get("reader_terminal_returned_eof")
    if returned_eof is not None:
        return f"{kind}:eof={format_bool(returned_eof)}"
    return str(kind)


def last_proxy_output_line(run: dict[str, object]) -> str:
    lines = run.get("proxy_output_tail", [])
    if not isinstance(lines, list):
        return ""
    for line in reversed(lines):
        text = str(line).strip()
        if text:
            return text
    return ""


def print_browser_connection_pref_table(payload: dict[str, object]) -> None:
    print("## Browser Connection Pref Audit")
    print()
    print(
        "| profile | target | run | ok | http3 | h2 pref | max conn | max per server | max per proxy |"
    )
    print("|---|---|---:|---|---:|---:|---:|---:|---:|")
    for profile_name, _profile, target, _summary, run in iter_runs(payload):
        audit = run.get("browser_connection_prefs")
        if not isinstance(audit, dict):
            continue
        prefs = audit.get("prefs", {})
        if not isinstance(prefs, dict):
            prefs = {}
        print(
            "| {profile} | {target} | {run} | {ok} | {http3} | {h2} | {max_conn} | {max_server} | {max_proxy} |".format(
                profile=profile_name,
                target=target,
                run=fmt(run.get("run_index")),
                ok=format_bool(audit.get("ok")),
                http3=fmt(pref_audit_value(prefs, "network.http.http3.enable")),
                h2=fmt(pref_audit_value(prefs, "network.http.spdy.enabled.http2")),
                max_conn=fmt(pref_audit_value(prefs, "network.http.max-connections")),
                max_server=fmt(
                    pref_audit_value(
                        prefs, "network.http.max-persistent-connections-per-server"
                    )
                ),
                max_proxy=fmt(
                    pref_audit_value(
                        prefs, "network.http.max-persistent-connections-per-proxy"
                    )
                ),
            )
        )


def pref_audit_value(prefs: dict[str, object], key: str) -> object:
    entry = prefs.get(key)
    if not isinstance(entry, dict):
        return None
    return entry.get("value")


def print_phase_table(payload: dict[str, object]) -> None:
    print("## Navigation Phases")
    print()
    print(
        "| profile | target | response start ms | response to dom ms | dom to load ms |"
    )
    print("|---|---|---:|---:|---:|")
    for profile_name, profile, url, summary in iter_summaries(payload):
        phases = navigation_phase_summary(profile, str(url), summary)
        print(
            "| {profile} | {target} | {response} | {response_to_dom} | {dom_to_load} |".format(
                profile=profile_name,
                target=url,
                response=fmt(phases.get("median_nav_response_start_ms")),
                response_to_dom=fmt(phases.get("median_nav_response_to_dom_ms")),
                dom_to_load=fmt(phases.get("median_nav_dom_to_load_ms")),
            )
        )


def print_run_phase_table(payload: dict[str, object]) -> None:
    print("## Per-Run Navigation Phases")
    print()
    print(
        "| profile | target | run | ok | load ms | elapsed ms | response start ms | response to dom ms | dom to load ms | slowest resource ms |"
    )
    print("|---|---|---:|---|---:|---:|---:|---:|---:|---:|")
    for profile_name, _profile, url, _summary, run in iter_runs(payload):
        print(
            "| {profile} | {target} | {run} | {ok} | {load} | {elapsed} | {response} | {response_to_dom} | {dom_to_load} | {slowest} |".format(
                profile=profile_name,
                target=url,
                run=fmt(run.get("run_index")),
                ok="yes" if run.get("ok") else "no",
                load=fmt(run.get("load_ms")),
                elapsed=fmt(run.get("elapsed_ms")),
                response=fmt(nav_value(run, "responseStart")),
                response_to_dom=fmt(
                    nav_phase(
                        run,
                        "responseStart",
                        "domContentLoadedEventEnd",
                    )
                ),
                dom_to_load=fmt(
                    nav_phase(
                        run,
                        "domContentLoadedEventEnd",
                        "loadEventEnd",
                    )
                ),
                slowest=fmt(run_slowest_resource_ms(run)),
            )
        )


def print_phase_delta_table(payload: dict[str, object]) -> None:
    print("## Navigation Phase Delta vs Local C Tor")
    print()
    print(
        "| profile | target | response start delta ms | response to dom delta ms | dom to load delta ms |"
    )
    print("|---|---|---:|---:|---:|")
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return
    local_profile = profiles.get("local_c_tor_browser", {})
    if not isinstance(local_profile, dict):
        return
    targets = payload.get("targets", [])
    if not isinstance(targets, list):
        return
    for target in targets:
        local_summary = get_summary(payload, "local_c_tor_browser", str(target))
        local_phases = navigation_phase_summary(
            local_profile, str(target), local_summary
        )
        for profile_name, profile in sorted(profiles.items()):
            if profile_name == "local_c_tor_browser":
                continue
            if not isinstance(profile, dict) or profile.get("skipped"):
                continue
            summary = get_summary(payload, profile_name, str(target))
            phases = navigation_phase_summary(profile, str(target), summary)
            print(
                "| {profile} | {target} | {response} | {response_to_dom} | {dom_to_load} |".format(
                    profile=profile_name,
                    target=target,
                    response=fmt_diff(
                        subtract_numeric(
                            phases.get("median_nav_response_start_ms"),
                            local_phases.get("median_nav_response_start_ms"),
                        )
                    ),
                    response_to_dom=fmt_diff(
                        subtract_numeric(
                            phases.get("median_nav_response_to_dom_ms"),
                            local_phases.get("median_nav_response_to_dom_ms"),
                        )
                    ),
                    dom_to_load=fmt_diff(
                        subtract_numeric(
                            phases.get("median_nav_dom_to_load_ms"),
                            local_phases.get("median_nav_dom_to_load_ms"),
                        )
                    ),
                )
            )


def print_resource_phase_summary(payload: dict[str, object]) -> None:
    print("## Resource Phase Summary")
    print()
    print(
        "| profile | target | sampled resources | median duration ms | median wait ms | median receive ms | median body bytes |"
    )
    print("|---|---|---:|---:|---:|---:|---:|")
    for profile_name, profile, url, _summary in iter_summaries(payload):
        resources = resource_rows_for_profile_target(profile, str(url))
        durations = [
            resource.get("duration")
            for resource in resources
            if isinstance(resource.get("duration"), (int, float))
        ]
        waits = [
            value
            for value in (
                resource_phase_ms(resource, "requestWait") for resource in resources
            )
            if value is not None
        ]
        receives = [
            value
            for value in (
                resource_phase_ms(resource, "responseReceive") for resource in resources
            )
            if value is not None
        ]
        bodies = [
            resource.get("encodedBodySize")
            for resource in resources
            if isinstance(resource.get("encodedBodySize"), (int, float))
        ]
        print(
            "| {profile} | {target} | {count} | {duration} | {wait} | {receive} | {body} |".format(
                profile=profile_name,
                target=url,
                count=len(resources),
                duration=fmt(median(durations) if durations else None),
                wait=fmt(median(waits) if waits else None),
                receive=fmt(median(receives) if receives else None),
                body=fmt(median(bodies) if bodies else None),
            )
        )


