def print_browser_byte_tap_correlation(payload: dict[str, object]) -> None:
    print("## Browser Response vs Neutral Byte Tap")
    print()
    print(
        "| profile | target | run | browser response epoch ms | nearest stream data epoch ms | stream data minus browser ms |"
    )
    print("|---|---|---:|---:|---:|---:|")
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return
    stream_epochs_by_profile = {
        profile_name: byte_tap_stream_data_epochs(profile)
        for profile_name, profile in profiles.items()
        if isinstance(profile, dict)
    }
    for profile_name, _profile, url, _summary, run in iter_runs(payload):
        stream_epochs = stream_epochs_by_profile.get(profile_name, [])
        if not stream_epochs:
            continue
        response_epoch = browser_response_epoch_ms(run)
        if response_epoch is None:
            continue
        nearest = min(stream_epochs, key=lambda epoch: abs(epoch - response_epoch))
        print(
            "| {profile} | {target} | {run} | {response} | {nearest} | {delta} |".format(
                profile=profile_name,
                target=url,
                run=run.get("run_index", ""),
                response=fmt(response_epoch),
                nearest=fmt(nearest),
                delta=fmt(nearest - response_epoch),
            )
        )


