def print_slowest_resources(payload: dict[str, object], limit: int = 5) -> None:
    print("## Slowest Resources")
    print()
    print(
        "| profile | target | run | duration ms | wait ms | receive ms | body bytes | type | resource |"
    )
    print("|---|---|---:|---:|---:|---:|---:|---|---|")
    for profile_name, profile, url, _summary in iter_summaries(payload):
        benchmarks = profile.get("benchmarks", {})
        if not isinstance(benchmarks, dict):
            continue
        bench = benchmarks.get(url, {})
        if not isinstance(bench, dict):
            continue
        runs = bench.get("runs", [])
        if not isinstance(runs, list):
            continue
        for index, run in enumerate(runs, start=1):
            if not isinstance(run, dict):
                continue
            timing = run.get("performance_timing", {})
            if not isinstance(timing, dict):
                continue
            resources = timing.get("slowest_resources", [])
            if not isinstance(resources, list):
                continue
            for resource in resources[:limit]:
                if not isinstance(resource, dict):
                    continue
                wait_ms = resource_phase_ms(resource, "requestWait")
                receive_ms = resource_phase_ms(resource, "responseReceive")
                print(
                    "| {profile} | {target} | {run} | {duration} | {wait} | {receive} | {body} | {rtype} | {resource} |".format(
                        profile=profile_name,
                        target=url,
                        run=index,
                        duration=fmt(resource.get("duration")),
                        wait=fmt(wait_ms),
                        receive=fmt(receive_ms),
                        body=fmt(resource.get("encodedBodySize")),
                        rtype=resource.get("initiatorType", ""),
                        resource=compact_url(str(resource.get("name", ""))),
                    )
                )


def proxy_log_lines(profile: dict[str, object]) -> list[str]:
    lines = []
    seen = set()

    def append_lines(value: object) -> None:
        if not isinstance(value, list):
            return
        source_seen: dict[str, bool] = {}
        for line in value:
            text = str(line)
            allowed = source_seen.get(text)
            if allowed is None:
                allowed = text not in seen
                source_seen[text] = allowed
                if allowed:
                    seen.add(text)
            if not allowed:
                continue
            lines.append(text)

    for key in ("proxy_signal_lines", "proxy_relay_context_lines", "proxy_output_tail"):
        append_lines(profile.get(key, []))
    benchmarks = profile.get("benchmarks", {})
    if isinstance(benchmarks, dict):
        for bench in benchmarks.values():
            if not isinstance(bench, dict):
                continue
            runs = bench.get("runs", [])
            if not isinstance(runs, list):
                continue
            for run in runs:
                if isinstance(run, dict):
                    append_lines(run.get("proxy_signal_lines", []))
                    append_lines(run.get("proxy_relay_context_lines", []))
                    append_lines(run.get("proxy_output_tail", []))
    return lines


def has_proxy_log_tails(payload: dict[str, object]) -> bool:
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return False
    return any(
        isinstance(profile, dict) and bool(proxy_log_lines(profile))
        for profile in profiles.values()
    )


