def print_torfast_relay_receive_timings(payload: dict[str, object]) -> None:
    print("## Torfast Relay Receive Timings")
    print()
    print(
        "| profile | delivered | data delivered | control | queue full | stream gone | incoming request | unknown stream | unique streams | median receive gap ms | max receive gap ms | median queued after bytes | max queued after bytes |"
    )
    print("|---|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|")
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        timings = parse_torfast_relay_receive_timings([str(line) for line in lines])
        if not timings:
            continue
        delivered = [item for item in timings if item.get("event") == "delivered"]
        gaps = event_timestamp_gaps_ms(delivered)
        streams = {
            item.get("stream_id")
            for item in timings
            if item.get("stream_id") is not None
        }
        queued_after_values = [
            item.get("queued_after_bytes")
            for item in delivered
            if isinstance(item.get("queued_after_bytes"), (int, float))
        ]
        print(
            "| {profile} | {delivered} | {data_delivered} | {control} | {queue_full} | {stream_gone} | {incoming_request} | {unknown_stream} | {streams} | {median_gap} | {max_gap} | {median_queue} | {max_queue} |".format(
                profile=profile_name,
                delivered=len(delivered),
                data_delivered=sum(
                    1 for item in delivered if item.get("relay_cmd") == "DATA"
                ),
                control=count_events(timings, "control"),
                queue_full=count_events(timings, "queue_full"),
                stream_gone=count_events(timings, "stream_gone"),
                incoming_request=count_events(timings, "incoming_request"),
                unknown_stream=count_events(timings, "unknown_stream"),
                streams=len(streams),
                median_gap=fmt(median(gaps) if gaps else None),
                max_gap=fmt(max(gaps) if gaps else None),
                median_queue=fmt(median(queued_after_values) if queued_after_values else None),
                max_queue=fmt(max(queued_after_values) if queued_after_values else None),
            )
        )


