def print_torfast_stream_scheduler_timings(payload: dict[str, object]) -> None:
    print("## Torfast Stream Scheduler Timings")
    print()
    print(
        "| profile | picks | data picks | closed | blocked hops | unique streams | median pick gap ms | max pick gap ms |"
    )
    print("|---|---:|---:|---:|---:|---:|---:|---:|")
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        timings = parse_torfast_stream_scheduler_timings([str(line) for line in lines])
        if not timings:
            continue
        picks = [item for item in timings if item.get("event") == "picked"]
        gaps = event_timestamp_gaps_ms(picks)
        streams = {
            item.get("stream_id")
            for item in picks
            if item.get("stream_id") is not None
        }
        print(
            "| {profile} | {picks} | {data_picks} | {closed} | {blocked} | {streams} | {median_gap} | {max_gap} |".format(
                profile=profile_name,
                picks=len(picks),
                data_picks=sum(1 for item in picks if item.get("relay_cmd") == "DATA"),
                closed=count_events(timings, "stream_closed"),
                blocked=count_events(timings, "hop_blocked"),
                streams=len(streams),
                median_gap=fmt(median(gaps) if gaps else None),
                max_gap=fmt(max(gaps) if gaps else None),
            )
        )


