def torfast_stream_lifecycle_summary_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    rows = []
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return rows
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        timings = parse_torfast_stream_lifecycle_timings([str(line) for line in lines])
        if not timings:
            continue
        relay_cmd_counts = value_counts(item.get("relay_cmd") for item in timings)
        delivery_counts = value_counts(item.get("delivery") for item in timings)
        streams = {
            (item.get("circ_id"), item.get("stream_id"))
            for item in timings
            if item.get("stream_id") is not None
        }
        data_lens = [
            numeric(item.get("data_len"))
            for item in timings
            if numeric(item.get("data_len")) is not None
        ]
        rows.append(
            {
                "profile": profile_name,
                "lifecycle_rows": len(timings),
                "sent": delivery_counts.get("sent", 0),
                "channel_queued": delivery_counts.get("channel_queued", 0),
                "delivered": delivery_counts.get("delivered", 0),
                "stream_gone": delivery_counts.get("stream_gone", 0),
                "queue_full": delivery_counts.get("queue_full", 0),
                "connected": relay_cmd_counts.get("CONNECTED", 0),
                "data": relay_cmd_counts.get("DATA", 0),
                "end": relay_cmd_counts.get("END", 0),
                "begin": relay_cmd_counts.get("BEGIN", 0)
                + relay_cmd_counts.get("BEGIN_DIR", 0),
                "unique_streams": len(streams),
                "max_data_len": max(data_lens) if data_lens else None,
            }
        )
    return rows


def print_torfast_stream_lifecycle_timings(payload: dict[str, object]) -> None:
    print("## Torfast Stream Lifecycle")
    print()
    print(
        "| profile | rows | sent | channel queued | delivered | stream gone | queue full | begin | connected | data | end | unique streams | max data len |"
    )
    print("|---|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|")
    for row in torfast_stream_lifecycle_summary_rows(payload):
        print(
            "| {profile} | {rows} | {sent} | {channel_queued} | {delivered} | {stream_gone} | {queue_full} | {begin} | {connected} | {data} | {end} | {streams} | {max_data_len} |".format(
                profile=row["profile"],
                rows=row["lifecycle_rows"],
                sent=row["sent"],
                channel_queued=row["channel_queued"],
                delivered=row["delivered"],
                stream_gone=row["stream_gone"],
                queue_full=row["queue_full"],
                begin=row["begin"],
                connected=row["connected"],
                data=row["data"],
                end=row["end"],
                streams=row["unique_streams"],
                max_data_len=fmt(row["max_data_len"]),
            )
        )


def torfast_stream_lifecycle_response_gap_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    rows = []
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return rows
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        timings = parse_torfast_stream_lifecycle_timings([str(line) for line in lines])
        if not timings:
            continue
        grouped: dict[tuple[object, object], list[dict[str, object]]] = {}
        for item in timings:
            stream_id = item.get("stream_id")
            if stream_id is None:
                continue
            grouped.setdefault((item.get("circ_id", ""), stream_id), []).append(item)
        begin_to_connected_gaps = []
        data_to_data_gaps = []
        begin_with_queue = 0
        data_with_queue = 0
        begin_without_connected = 0
        data_without_response = 0
        for items in grouped.values():
            ordered = sorted(items, key=lambda item: numeric(item.get("timestamp_ms")) or 0)
            begin_ts = first_lifecycle_timestamp(
                ordered,
                relay_cmds={"BEGIN", "BEGIN_DIR"},
                delivery="channel_queued",
            )
            if begin_ts is not None:
                begin_with_queue += 1
                connected_ts = first_lifecycle_timestamp(
                    ordered,
                    relay_cmds={"CONNECTED"},
                    delivery="delivered",
                    not_before=begin_ts,
                )
                if connected_ts is None:
                    begin_without_connected += 1
                else:
                    begin_to_connected_gaps.append(connected_ts - begin_ts)
            data_queued_ts = first_lifecycle_timestamp(
                ordered,
                relay_cmds={"DATA"},
                delivery="channel_queued",
            )
            if data_queued_ts is not None:
                data_with_queue += 1
                data_delivered_ts = first_lifecycle_timestamp(
                    ordered,
                    relay_cmds={"DATA"},
                    delivery="delivered",
                    not_before=data_queued_ts,
                )
                if data_delivered_ts is None:
                    data_without_response += 1
                else:
                    data_to_data_gaps.append(data_delivered_ts - data_queued_ts)
        if not begin_with_queue and not data_with_queue:
            continue
        rows.append(
            {
                "profile": profile_name,
                "streams": len(grouped),
                "begin_queued": begin_with_queue,
                "begin_connected": len(begin_to_connected_gaps),
                "begin_without_connected": begin_without_connected,
                "median_begin_to_connected_ms": median(begin_to_connected_gaps)
                if begin_to_connected_gaps
                else None,
                "max_begin_to_connected_ms": max(begin_to_connected_gaps)
                if begin_to_connected_gaps
                else None,
                "data_queued": data_with_queue,
                "data_response": len(data_to_data_gaps),
                "data_without_response": data_without_response,
                "median_data_to_data_ms": median(data_to_data_gaps)
                if data_to_data_gaps
                else None,
                "max_data_to_data_ms": max(data_to_data_gaps)
                if data_to_data_gaps
                else None,
            }
        )
    return rows


def first_lifecycle_timestamp(
    items: list[dict[str, object]],
    *,
    relay_cmds: set[str],
    delivery: str,
    not_before: float | int | None = None,
) -> float | int | None:
    for item in items:
        if item.get("relay_cmd") not in relay_cmds or item.get("delivery") != delivery:
            continue
        timestamp = numeric(item.get("timestamp_ms"))
        if timestamp is None:
            continue
        if not_before is not None and timestamp < not_before:
            continue
        return timestamp
    return None


def print_torfast_stream_lifecycle_response_gap_timings(
    payload: dict[str, object],
) -> None:
    print("## Torfast Stream Response Gaps")
    print()
    print(
        "| profile | streams | begin queued | connected after begin | begin no connected | median begin to connected ms | max begin to connected ms | data queued | data response | data no response | median data to data ms | max data to data ms |"
    )
    print("|---|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|")
    for row in torfast_stream_lifecycle_response_gap_rows(payload):
        print(
            "| {profile} | {streams} | {begin} | {connected} | {begin_missing} | {begin_median} | {begin_max} | {data} | {data_response} | {data_missing} | {data_median} | {data_max} |".format(
                profile=row["profile"],
                streams=row["streams"],
                begin=row["begin_queued"],
                connected=row["begin_connected"],
                begin_missing=row["begin_without_connected"],
                begin_median=fmt(row["median_begin_to_connected_ms"]),
                begin_max=fmt(row["max_begin_to_connected_ms"]),
                data=row["data_queued"],
                data_response=row["data_response"],
                data_missing=row["data_without_response"],
                data_median=fmt(row["median_data_to_data_ms"]),
                data_max=fmt(row["max_data_to_data_ms"]),
            )
        )


def torfast_channel_flush_summary_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    rows = []
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return rows
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        timings = parse_torfast_channel_flush_timings([str(line) for line in lines])
        if not timings:
            continue
        cmd_counts = value_counts(item.get("channel_cmd") for item in timings)
        queue_after_cells = [
            numeric(item.get("channel_reactor_queue_after_cells"))
            for item in timings
            if item.get("channel_reactor_queue_count_available") is True
            and numeric(item.get("channel_reactor_queue_after_cells")) is not None
        ]
        queue_unknown = sum(
            1
            for item in timings
            if item.get("channel_reactor_queue_count_available") is not True
        )
        channel_circuits = {
            item.get("channel_circ_id")
            for item in timings
            if item.get("channel_circ_id") is not None
            and item.get("channel_circ_id") != 0
        }
        rows.append(
            {
                "profile": profile_name,
                "flush_rows": len(timings),
                "relay": cmd_counts.get("RELAY", 0),
                "relay_early": cmd_counts.get("RELAY_EARLY", 0),
                "destroy": cmd_counts.get("DESTROY", 0),
                "padding": cmd_counts.get("PADDING", 0)
                + cmd_counts.get("VPADDING", 0),
                "unique_channel_circuits": len(channel_circuits),
                "max_channel_reactor_queue_after_cells": max(queue_after_cells)
                if queue_after_cells
                else None,
                "channel_reactor_queue_unknown": queue_unknown,
                "commands": compact_counts(cmd_counts, limit=5),
            }
        )
    return rows


def print_torfast_channel_flush_timings(payload: dict[str, object]) -> None:
    print("## Torfast Channel Flush")
    print()
    print(
        "| profile | rows | relay | relay early | destroy | padding | unique channel circuits | max reactor queue after pop | queue unknown | commands |"
    )
    print("|---|---:|---:|---:|---:|---:|---:|---:|---:|---|")
    for row in torfast_channel_flush_summary_rows(payload):
        print(
            "| {profile} | {rows} | {relay} | {relay_early} | {destroy} | {padding} | {circuits} | {max_queue} | {unknown} | {commands} |".format(
                profile=row["profile"],
                rows=row["flush_rows"],
                relay=row["relay"],
                relay_early=row["relay_early"],
                destroy=row["destroy"],
                padding=row["padding"],
                circuits=row["unique_channel_circuits"],
                max_queue=fmt(row["max_channel_reactor_queue_after_cells"]),
                unknown=row["channel_reactor_queue_unknown"],
                commands=row["commands"],
            )
        )


def torfast_channel_flush_gap_rows(payload: dict[str, object]) -> list[dict[str, object]]:
    rows = []
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return rows
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        text_lines = [str(line) for line in lines]
        lifecycle = parse_torfast_stream_lifecycle_timings(text_lines)
        flushes = parse_torfast_channel_flush_timings(text_lines)
        if not lifecycle or not flushes:
            continue
        flush_by_circ: dict[object, list[float]] = {}
        for item in flushes:
            circ = item.get("channel_circ_id")
            ts = numeric(item.get("timestamp_ms"))
            if circ in (None, 0) or ts is None:
                continue
            flush_by_circ.setdefault(circ, []).append(ts)
        for values in flush_by_circ.values():
            values.sort()
        queue_events = []
        for item in lifecycle:
            if item.get("delivery") != "channel_queued":
                continue
            circ = item.get("channel_circ_id")
            ts = numeric(item.get("timestamp_ms"))
            if circ in (None, 0) or ts is None:
                continue
            queue_events.append((ts, circ))
        if not queue_events:
            continue
        queue_events.sort()
        flush_index: dict[object, int] = {}
        gaps = []
        for ts, circ in queue_events:
            values = flush_by_circ.get(circ, [])
            idx = flush_index.get(circ, 0)
            while idx < len(values) and values[idx] < ts:
                idx += 1
            if idx < len(values):
                gaps.append(values[idx] - ts)
                idx += 1
            flush_index[circ] = idx
        rows.append(
            {
                "profile": profile_name,
                "channel_queued_with_key": len(queue_events),
                "matched_flushes": len(gaps),
                "unmatched_queued": len(queue_events) - len(gaps),
                "median_queue_to_flush_ms": median(gaps) if gaps else None,
                "max_queue_to_flush_ms": max(gaps) if gaps else None,
            }
        )
    return rows


def print_torfast_channel_flush_gap_timings(payload: dict[str, object]) -> None:
    print("## Torfast Channel Queue To Flush")
    print()
    print(
        "| profile | channel queued with key | matched flushes | unmatched queued | median queue to flush ms | max queue to flush ms |"
    )
    print("|---|---:|---:|---:|---:|---:|")
    for row in torfast_channel_flush_gap_rows(payload):
        print(
            "| {profile} | {queued} | {matched} | {unmatched} | {median_gap} | {max_gap} |".format(
                profile=row["profile"],
                queued=row["channel_queued_with_key"],
                matched=row["matched_flushes"],
                unmatched=row["unmatched_queued"],
                median_gap=fmt(row["median_queue_to_flush_ms"]),
                max_gap=fmt(row["max_queue_to_flush_ms"]),
            )
        )


def print_torfast_circuit_congestion_timings(payload: dict[str, object]) -> None:
    print("## Torfast Circuit Congestion")
    print()
    print(
        "| profile | events | sendme sent | sendme received | scheduler blocks | unique circuits | algorithms | can_send false | min cwnd | max cwnd | max inflight | top circuit | top circuit events |"
    )
    print("|---|---:|---:|---:|---:|---:|---|---:|---:|---:|---:|---|---:|")
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        timings = parse_torfast_circuit_congestion_timings([str(line) for line in lines])
        if not timings:
            continue
        circuits = [
            item.get("circ_id") for item in timings if item.get("circ_id") is not None
        ]
        circuit_counts = value_counts(circuits)
        top_circuit = ""
        top_circuit_events = 0
        if circuit_counts:
            top_circuit, top_circuit_events = max(
                circuit_counts.items(), key=lambda item: item[1]
            )
        cwnds = [
            numeric(item.get("cwnd"))
            for item in timings
            if item.get("cwnd_present") is True and numeric(item.get("cwnd")) is not None
        ]
        inflights = [
            numeric(item.get("inflight"))
            for item in timings
            if item.get("inflight_present") is True
            and numeric(item.get("inflight")) is not None
        ]
        algorithms = format_counts(
            value_counts(item.get("algorithm") for item in timings)
        )
        print(
            "| {profile} | {events} | {sent} | {received} | {blocks} | {circuits} | {algorithms} | {blocked} | {min_cwnd} | {max_cwnd} | {max_inflight} | {top_circuit} | {top_events} |".format(
                profile=profile_name,
                events=len(timings),
                sent=count_events(timings, "sendme_sent"),
                received=count_events(timings, "sendme_received"),
                blocks=count_events(timings, "scheduler_hop_blocked"),
                circuits=len(circuit_counts),
                algorithms=algorithms,
                blocked=sum(1 for item in timings if item.get("can_send") is False),
                min_cwnd=fmt(min(cwnds) if cwnds else None),
                max_cwnd=fmt(max(cwnds) if cwnds else None),
                max_inflight=fmt(max(inflights) if inflights else None),
                top_circuit=top_circuit,
                top_events=top_circuit_events,
            )
        )


def has_torfast_stream_receiver_timings(payload: dict[str, object]) -> bool:
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return False
    for profile in profiles.values():
        if not isinstance(profile, dict):
            continue
        lines = proxy_log_lines(profile)
        if isinstance(lines, list) and any(
            "torfast stream receiver" in str(line) for line in lines
        ):
            return True
    return False


def print_torfast_stream_receiver_timings(payload: dict[str, object]) -> None:
    print("## Torfast Stream Receiver Timings")
    print()
    print(
        "| profile | streams | read events | sendmes | sendme ok | data bytes | median recv window after | min recv window after | max read gap ms | max queued after bytes |"
    )
    print("|---|---:|---:|---:|---:|---:|---:|---:|---:|---:|")
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        timings = parse_torfast_stream_receiver_timings([str(line) for line in lines])
        if not timings:
            continue
        rows = torfast_stream_receiver_rows(timings)
        recv_windows = [
            numeric(row.get("min_recv_window_after"))
            for row in rows
            if numeric(row.get("min_recv_window_after")) is not None
        ]
        print(
            "| {profile} | {streams} | {reads} | {sendmes} | {sendme_ok} | {bytes} | {median_window} | {min_window} | {gap} | {queue} |".format(
                profile=profile_name,
                streams=len(rows),
                reads=count_events(timings, "read"),
                sendmes=count_events(timings, "sendme"),
                sendme_ok=sum(
                    1
                    for item in timings
                    if item.get("event") == "sendme" and item.get("sendme_ok") is True
                ),
                bytes=sum(
                    int(numeric(item.get("data_len")) or 0)
                    for item in timings
                    if item.get("event") == "read"
                ),
                median_window=fmt(median(recv_windows) if recv_windows else None),
                min_window=fmt(min(recv_windows) if recv_windows else None),
                gap=fmt(
                    max(
                        (numeric(row.get("max_read_gap_ms")) or 0) for row in rows
                    )
                    if rows
                    else 0
                ),
                queue=fmt(
                    max(
                        (numeric(row.get("max_queued_after_bytes")) or 0) for row in rows
                    )
                    if rows
                    else 0
                ),
            )
        )


