def print_torfast_circuit_selection_timings(payload: dict[str, object]) -> None:
    print("## Torfast Circuit Selection")
    print()
    print(
        "| profile | open picks | candidates>1 open picks | exit candidates>1 open picks | parallelism>1 open picks | exit parallelism>1 open picks | load-aware open picks | exit load-aware picks | health-aware open picks | avoid bad-health open picks | unknown fallback open picks | health-aware changed assignment | health-aware kept assignment | selected nonfirst load-aware picks | max load-aware min spread | load-aware guardrail kept first | same isolation topups | same isolation topup failures | max topup assigned streams | min topup floor | topup selected bad-health | topup requires bad-health | topup active-cap saturated | topup first-stream prewarm | topup other-isolation pressure | topup max other isolation | topup min other-isolation floor | topup max selected active streams | topup max active cap | topup max health gap ms | topup min health score | topup max health age ms | max selected assigned streams | max candidate assigned streams | max candidate assigned spread | active cap picks | active cap moves | active cap saturated | max selected active streams | max candidate active streams | max candidate active age ms | candidate health rows | max candidate health bytes | max candidate health gap ms | max candidate health score | max candidate health span ms | max candidate health age ms | max open total | max rejected open | max isolation rejects | max port rejects | max unusable | pending waits | pending hedge timers | build hedge timers | build hedges | pending hedges | builds | build complete | build failed | build canceled | usage kinds | median open candidates | max open candidates | median select parallelism | parallelism>1 unique circuits | unique selected circuits |"
    )
    print("|---|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---|---:|---:|---:|---:|---:|")
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        timings = parse_torfast_circuit_selection_timings(
            [str(line) for line in lines]
        )
        if not timings:
            continue
        open_items = [item for item in timings if item.get("event") == "open"]
        open_candidates = [
            item.get("open_candidates")
            for item in open_items
            if isinstance(item.get("open_candidates"), (int, float))
        ]
        select_parallelism = [
            item.get("select_parallelism")
            for item in open_items
            if isinstance(item.get("select_parallelism"), (int, float))
        ]
        selected = {
            item.get("tunnel_unique_id")
            for item in open_items
            if item.get("tunnel_unique_id") is not None
        }
        spread_items = [
            item
            for item in open_items
            if isinstance(item.get("select_parallelism"), (int, float))
            and item["select_parallelism"] > 1
        ]
        exit_spread_items = [
            item for item in spread_items if item.get("usage_kind") == "exit"
        ]
        multi_candidate_items = [
            item
            for item in open_items
            if isinstance(item.get("open_candidates"), (int, float))
            and item["open_candidates"] > 1
        ]
        exit_multi_candidate_items = [
            item
            for item in multi_candidate_items
            if item.get("usage_kind") == "exit"
        ]
        load_aware_items = [
            item for item in open_items if item.get("select_load_aware") is True
        ]
        exit_load_aware_items = [
            item for item in load_aware_items if item.get("usage_kind") == "exit"
        ]
        health_aware_items = [
            item for item in load_aware_items if item.get("select_health_aware") is True
        ]
        avoid_bad_health_items = [
            item
            for item in load_aware_items
            if item.get("select_avoid_bad_health") is True
        ]
        avoid_bad_health_unknown_fallback_items = [
            item
            for item in load_aware_items
            if item.get("select_avoid_bad_health_unknown_fallback") is True
        ]
        health_aware_changed_items = [
            item for item in health_aware_items if health_aware_changed_assignment(item)
        ]
        health_aware_kept_items = [
            item for item in health_aware_items if health_aware_guard_kept_assignment(item)
        ]
        selected_assigned_streams = [
            item.get("selected_assigned_streams")
            for item in open_items
            if isinstance(item.get("selected_assigned_streams"), (int, float))
        ]
        selected_nonfirst_load_aware_items = [
            item
            for item in load_aware_items
            if isinstance(item.get("selected_candidate_index"), (int, float))
            and item["selected_candidate_index"] > 0
        ]
        load_aware_min_spreads = [
            numeric(item.get("load_aware_min_assignment_spread"))
            for item in load_aware_items
            if numeric(item.get("load_aware_min_assignment_spread")) is not None
        ]
        load_aware_guardrail_items = [
            item for item in load_aware_items if load_aware_guardrail_kept_first(item)
        ]
        candidate_context_items = open_items
        candidate_assigned_values = [
            row["assigned_streams"]
            for item in candidate_context_items
            for row in parse_torfast_candidate_assignment_summary(
                item.get("candidate_assignment_summary")
            )
        ]
        candidate_assigned_spreads = [
            max(values) - min(values)
            for values in (
                [
                    row["assigned_streams"]
                    for row in parse_torfast_candidate_assignment_summary(
                        item.get("candidate_assignment_summary")
                    )
                ]
                for item in candidate_context_items
            )
            if values
        ]
        candidate_health_rows = [
            row
            for item in candidate_context_items
            for row in parse_torfast_candidate_health_summary(
                item.get("candidate_health_summary")
            )
        ]
        active_cap_items = [
            item
            for item in open_items
            if (numeric(item.get("select_max_active_streams")) or 0) > 0
        ]
        active_cap_move_items = [
            item for item in active_cap_items if item.get("active_stream_cap_moved") is True
        ]
        active_cap_saturated_items = [
            item for item in active_cap_items if item.get("active_stream_cap_saturated") is True
        ]
        selected_active_values = [
            numeric(item.get("selected_active_streams"))
            for item in active_cap_items
            if numeric(item.get("selected_active_streams")) is not None
        ]
        candidate_active_values = [
            numeric(row.get("active_streams"))
            for row in candidate_health_rows
            if numeric(row.get("active_streams")) is not None
        ]
        candidate_active_age_values = [
            numeric(row.get("active_stream_age_ms"))
            for row in candidate_health_rows
            if numeric(row.get("active_stream_age_ms")) is not None
        ]
        support_summaries = [
            row
            for item in candidate_context_items
            if (
                row := parse_torfast_open_support_summary(
                    item.get("open_support_summary")
                )
            )
        ]
        rejected_open_counts = [
            row.get("total", 0) - row.get("supported", 0)
            for row in support_summaries
        ]
        spread_selected = {
            item.get("tunnel_unique_id")
            for item in spread_items
            if item.get("tunnel_unique_id") is not None
        }
        usage_kinds = value_counts(
            item.get("usage_kind") for item in timings if item.get("usage_kind")
        )
        topup_items = [
            item
            for item in timings
            if item.get("event")
            in ("same_isolation_topup", "same_isolation_topup_failed")
        ]
        topup_selected_assigned = [
            numeric(item.get("selected_assigned_streams"))
            for item in topup_items
            if numeric(item.get("selected_assigned_streams")) is not None
        ]
        topup_min_assigned = [
            numeric(item.get("min_assigned_streams"))
            for item in topup_items
            if numeric(item.get("min_assigned_streams")) is not None
        ]
        topup_selected_bad_health = [
            item for item in topup_items if item.get("selected_has_bad_health") is True
        ]
        topup_requires_bad_health = [
            item for item in topup_items if item.get("require_bad_health") is True
        ]
        topup_active_cap_saturated = [
            item
            for item in topup_items
            if item.get("active_stream_cap_saturated") is True
        ]
        topup_first_stream_prewarm = [
            item
            for item in topup_items
            if item.get("prewarm_first_stream") is True
            and numeric(item.get("selected_assigned_streams")) == 0
        ]
        topup_other_isolation_pressure = [
            item for item in topup_items if item.get("other_isolation_pressure") is True
        ]
        topup_other_isolation_counts = [
            numeric(item.get("exit_incompatible_isolated"))
            for item in topup_items
            if numeric(item.get("exit_incompatible_isolated")) is not None
        ]
        topup_other_isolation_mins = [
            numeric(item.get("other_isolation_min"))
            for item in topup_items
            if numeric(item.get("other_isolation_min")) is not None
        ]
        topup_selected_active = [
            numeric(item.get("selected_active_streams"))
            for item in topup_items
            if numeric(item.get("selected_active_streams")) is not None
        ]
        topup_active_caps = [
            numeric(item.get("select_max_active_streams"))
            for item in topup_items
            if numeric(item.get("select_max_active_streams")) is not None
        ]
        topup_health_gaps = [
            numeric(item.get("selected_health_max_gap_ms"))
            for item in topup_items
            if numeric(item.get("selected_health_max_gap_ms")) is not None
        ]
        topup_health_scores = [
            numeric(item.get("selected_health_score_bps"))
            for item in topup_items
            if numeric(item.get("selected_health_score_bps")) is not None
        ]
        topup_health_ages = [
            numeric(item.get("selected_health_age_ms"))
            for item in topup_items
            if numeric(item.get("selected_health_age_ms")) is not None
        ]
        print(
            "| {profile} | {open} | {multi_candidate_open} | {exit_multi_candidate_open} | {spread_open} | {exit_spread_open} | {load_aware_open} | {exit_load_aware_open} | {health_aware_open} | {avoid_bad_health_open} | {unknown_fallback_open} | {health_aware_changed} | {health_aware_kept} | {selected_nonfirst} | {max_min_spread} | {guardrail_first} | {same_isolation_topups} | {same_isolation_topup_failures} | {max_topup_assigned_streams} | {min_topup_floor} | {topup_bad_health} | {topup_require_bad_health} | {topup_active_cap_saturated} | {topup_first_stream_prewarm} | {topup_other_isolation_pressure} | {topup_max_other_isolation} | {topup_min_other_isolation_floor} | {topup_max_selected_active_streams} | {topup_max_active_cap} | {topup_max_health_gap} | {topup_min_health_score} | {topup_max_health_age} | {max_assigned_streams} | {max_candidate_assigned_streams} | {max_candidate_assigned_spread} | {active_cap_picks} | {active_cap_moves} | {active_cap_saturated} | {max_selected_active_streams} | {max_candidate_active_streams} | {max_candidate_active_age} | {candidate_health} | {max_candidate_health_bytes} | {max_candidate_health_gap} | {max_candidate_health_score} | {max_candidate_health_span} | {max_candidate_health_age} | {max_open_total} | {max_rejected_open} | {max_isolation_rejects} | {max_port_rejects} | {max_unusable} | {pending} | {pending_hedge_timers} | {build_hedge_timers} | {build_hedges} | {pending_hedges} | {builds} | {build_complete} | {build_failed} | {build_canceled} | {usage_kinds} | {median_open} | {max_open} | {median_parallelism} | {spread_selected} | {selected} |".format(
                profile=profile_name,
                open=len(open_items),
                multi_candidate_open=len(multi_candidate_items),
                exit_multi_candidate_open=len(exit_multi_candidate_items),
                spread_open=len(spread_items),
                exit_spread_open=len(exit_spread_items),
                load_aware_open=len(load_aware_items),
                exit_load_aware_open=len(exit_load_aware_items),
                health_aware_open=len(health_aware_items),
                avoid_bad_health_open=len(avoid_bad_health_items),
                unknown_fallback_open=len(avoid_bad_health_unknown_fallback_items),
                health_aware_changed=len(health_aware_changed_items),
                health_aware_kept=len(health_aware_kept_items),
                selected_nonfirst=len(selected_nonfirst_load_aware_items),
                max_min_spread=fmt(
                    max(load_aware_min_spreads) if load_aware_min_spreads else None
                ),
                guardrail_first=len(load_aware_guardrail_items),
                same_isolation_topups=count_events(timings, "same_isolation_topup"),
                same_isolation_topup_failures=count_events(
                    timings, "same_isolation_topup_failed"
                ),
                max_topup_assigned_streams=fmt(
                    max(topup_selected_assigned)
                    if topup_selected_assigned
                    else None
                ),
                min_topup_floor=fmt(
                    min(topup_min_assigned) if topup_min_assigned else None
                ),
                topup_bad_health=len(topup_selected_bad_health),
                topup_require_bad_health=len(topup_requires_bad_health),
                topup_active_cap_saturated=len(topup_active_cap_saturated),
                topup_first_stream_prewarm=len(topup_first_stream_prewarm),
                topup_other_isolation_pressure=len(topup_other_isolation_pressure),
                topup_max_other_isolation=fmt(
                    max(topup_other_isolation_counts)
                    if topup_other_isolation_counts
                    else None
                ),
                topup_min_other_isolation_floor=fmt(
                    min(topup_other_isolation_mins)
                    if topup_other_isolation_mins
                    else None
                ),
                topup_max_selected_active_streams=fmt(
                    max(topup_selected_active) if topup_selected_active else None
                ),
                topup_max_active_cap=fmt(
                    max(topup_active_caps) if topup_active_caps else None
                ),
                topup_max_health_gap=fmt(
                    max(topup_health_gaps) if topup_health_gaps else None
                ),
                topup_min_health_score=fmt(
                    min(topup_health_scores) if topup_health_scores else None
                ),
                topup_max_health_age=fmt(
                    max(topup_health_ages) if topup_health_ages else None
                ),
                max_assigned_streams=fmt(
                    max(selected_assigned_streams)
                    if selected_assigned_streams
                    else None
                ),
                max_candidate_assigned_streams=fmt(
                    max(candidate_assigned_values) if candidate_assigned_values else None
                ),
                max_candidate_assigned_spread=fmt(
                    max(candidate_assigned_spreads) if candidate_assigned_spreads else None
                ),
                active_cap_picks=len(active_cap_items),
                active_cap_moves=len(active_cap_move_items),
                active_cap_saturated=len(active_cap_saturated_items),
                max_selected_active_streams=fmt(
                    max(selected_active_values) if selected_active_values else None
                ),
                max_candidate_active_streams=fmt(
                    max(candidate_active_values) if candidate_active_values else None
                ),
                max_candidate_active_age=fmt(
                    max(candidate_active_age_values)
                    if candidate_active_age_values
                    else None
                ),
                candidate_health=len(candidate_health_rows),
                max_candidate_health_bytes=fmt(
                    row_max(candidate_health_rows, "relay_data_bytes")
                ),
                max_candidate_health_gap=fmt(
                    row_max(candidate_health_rows, "max_relay_data_gap_ms")
                ),
                max_candidate_health_score=fmt(
                    row_max(candidate_health_rows, "health_score_bps")
                ),
                max_candidate_health_span=fmt(
                    row_max(candidate_health_rows, "health_span_ms")
                ),
                max_candidate_health_age=fmt(
                    row_max(candidate_health_rows, "health_age_ms")
                ),
                max_open_total=fmt(
                    max((row.get("total", 0) for row in support_summaries), default=None)
                ),
                max_rejected_open=fmt(
                    max(rejected_open_counts) if rejected_open_counts else None
                ),
                max_isolation_rejects=fmt(
                    max((row.get("isolation", 0) for row in support_summaries), default=None)
                ),
                max_port_rejects=fmt(
                    max((row.get("port", 0) for row in support_summaries), default=None)
                ),
                max_unusable=fmt(
                    max((row.get("unusable", 0) for row in support_summaries), default=None)
                ),
                pending=count_pending_wait_events(timings),
                pending_hedge_timers=count_events(timings, "pending_hedge_timer"),
                build_hedge_timers=count_events(timings, "build_hedge_timer"),
                build_hedges=count_events(timings, "build_hedge"),
                pending_hedges=count_events(timings, "pending_hedge"),
                builds=count_events(timings, "build"),
                build_complete=count_events(timings, "build_complete"),
                build_failed=count_events(timings, "build_failed"),
                build_canceled=count_events(timings, "build_canceled"),
                usage_kinds=format_counts(usage_kinds),
                median_open=fmt(median(open_candidates) if open_candidates else None),
                max_open=fmt(max(open_candidates) if open_candidates else None),
                median_parallelism=fmt(
                    median(select_parallelism) if select_parallelism else None
                ),
                spread_selected=len(spread_selected),
                selected=len(selected),
            )
        )


def print_torfast_circuit_selection_per_run(payload: dict[str, object]) -> None:
    print("## Torfast Circuit Selection Per Run")
    print()
    print(
        "| profile | target | run | load ms | open picks | exit open picks | exit candidates>1 | exit load-aware picks | health-aware open picks | avoid bad-health open picks | unknown fallback open picks | health-aware changed assignment | health-aware kept assignment | selected nonfirst load-aware picks | max load-aware min spread | load-aware guardrail kept first | same isolation topups | same isolation topup failures | max topup assigned streams | min topup floor | topup selected bad-health | topup requires bad-health | topup active-cap saturated | topup max selected active streams | topup max active cap | topup max health gap ms | topup min health score | topup max health age ms | median exit candidates | max exit candidates | max selected assigned streams | max candidate assigned streams | max candidate assigned spread | active cap picks | active cap moves | active cap saturated | max selected active streams | max candidate active streams | max candidate active age ms | candidate health rows | max candidate health bytes | max candidate health gap ms | max candidate health score | max candidate health span ms | max candidate health age ms | max open total | max rejected open | max isolation rejects | max port rejects | max unusable | pending waits | builds | build complete | build failed | build canceled |"
    )
    print("|---|---|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|")
    for profile_name, _profile, target, _summary, run in iter_runs(payload):
        lines = run.get("proxy_signal_lines", [])
        if not isinstance(lines, list):
            continue
        timings = parse_torfast_circuit_selection_timings([str(line) for line in lines])
        if not timings:
            continue
        open_items = [item for item in timings if item.get("event") == "open"]
        exit_open_items = [
            item for item in open_items if item.get("usage_kind") == "exit"
        ]
        exit_candidates = [
            item.get("open_candidates")
            for item in exit_open_items
            if isinstance(item.get("open_candidates"), (int, float))
        ]
        assigned_streams = [
            item.get("selected_assigned_streams")
            for item in exit_open_items
            if isinstance(item.get("selected_assigned_streams"), (int, float))
        ]
        exit_load_aware_items = [
            item for item in exit_open_items if item.get("select_load_aware") is True
        ]
        active_cap_items = [
            item
            for item in exit_open_items
            if (numeric(item.get("select_max_active_streams")) or 0) > 0
        ]
        active_cap_move_items = [
            item for item in active_cap_items if item.get("active_stream_cap_moved") is True
        ]
        active_cap_saturated_items = [
            item for item in active_cap_items if item.get("active_stream_cap_saturated") is True
        ]
        candidate_context_items = (
            exit_open_items if active_cap_items else exit_load_aware_items
        )
        health_aware_items = [
            item for item in exit_load_aware_items if item.get("select_health_aware") is True
        ]
        avoid_bad_health_items = [
            item
            for item in exit_load_aware_items
            if item.get("select_avoid_bad_health") is True
        ]
        avoid_bad_health_unknown_fallback_items = [
            item
            for item in exit_load_aware_items
            if item.get("select_avoid_bad_health_unknown_fallback") is True
        ]
        health_aware_changed_items = [
            item for item in health_aware_items if health_aware_changed_assignment(item)
        ]
        health_aware_kept_items = [
            item for item in health_aware_items if health_aware_guard_kept_assignment(item)
        ]
        load_aware_min_spreads = [
            numeric(item.get("load_aware_min_assignment_spread"))
            for item in exit_load_aware_items
            if numeric(item.get("load_aware_min_assignment_spread")) is not None
        ]
        load_aware_guardrail_items = [
            item for item in exit_load_aware_items if load_aware_guardrail_kept_first(item)
        ]
        candidate_assigned_values = [
            row["assigned_streams"]
            for item in candidate_context_items
            for row in parse_torfast_candidate_assignment_summary(
                item.get("candidate_assignment_summary")
            )
        ]
        candidate_assigned_spreads = [
            max(values) - min(values)
            for values in (
                [
                    row["assigned_streams"]
                    for row in parse_torfast_candidate_assignment_summary(
                        item.get("candidate_assignment_summary")
                    )
                ]
                for item in candidate_context_items
            )
            if values
        ]
        candidate_health_rows = [
            row
            for item in candidate_context_items
            for row in parse_torfast_candidate_health_summary(
                item.get("candidate_health_summary")
            )
        ]
        selected_active_values = [
            numeric(item.get("selected_active_streams"))
            for item in active_cap_items
            if numeric(item.get("selected_active_streams")) is not None
        ]
        candidate_active_values = [
            numeric(row.get("active_streams"))
            for row in candidate_health_rows
            if numeric(row.get("active_streams")) is not None
        ]
        candidate_active_age_values = [
            numeric(row.get("active_stream_age_ms"))
            for row in candidate_health_rows
            if numeric(row.get("active_stream_age_ms")) is not None
        ]
        support_summaries = [
            row
            for item in candidate_context_items
            if (
                row := parse_torfast_open_support_summary(
                    item.get("open_support_summary")
                )
            )
        ]
        rejected_open_counts = [
            row.get("total", 0) - row.get("supported", 0)
            for row in support_summaries
        ]
        topup_items = [
            item
            for item in timings
            if item.get("event")
            in ("same_isolation_topup", "same_isolation_topup_failed")
        ]
        topup_selected_assigned = [
            numeric(item.get("selected_assigned_streams"))
            for item in topup_items
            if numeric(item.get("selected_assigned_streams")) is not None
        ]
        topup_min_assigned = [
            numeric(item.get("min_assigned_streams"))
            for item in topup_items
            if numeric(item.get("min_assigned_streams")) is not None
        ]
        topup_selected_bad_health = [
            item for item in topup_items if item.get("selected_has_bad_health") is True
        ]
        topup_requires_bad_health = [
            item for item in topup_items if item.get("require_bad_health") is True
        ]
        topup_active_cap_saturated = [
            item
            for item in topup_items
            if item.get("active_stream_cap_saturated") is True
        ]
        topup_selected_active = [
            numeric(item.get("selected_active_streams"))
            for item in topup_items
            if numeric(item.get("selected_active_streams")) is not None
        ]
        topup_active_caps = [
            numeric(item.get("select_max_active_streams"))
            for item in topup_items
            if numeric(item.get("select_max_active_streams")) is not None
        ]
        topup_health_gaps = [
            numeric(item.get("selected_health_max_gap_ms"))
            for item in topup_items
            if numeric(item.get("selected_health_max_gap_ms")) is not None
        ]
        topup_health_scores = [
            numeric(item.get("selected_health_score_bps"))
            for item in topup_items
            if numeric(item.get("selected_health_score_bps")) is not None
        ]
        topup_health_ages = [
            numeric(item.get("selected_health_age_ms"))
            for item in topup_items
            if numeric(item.get("selected_health_age_ms")) is not None
        ]
        print(
            "| {profile} | {target} | {run} | {load} | {open_picks} | {exit_open} | {exit_multi} | {exit_load_aware} | {health_aware_open} | {avoid_bad_health_open} | {unknown_fallback_open} | {health_aware_changed} | {health_aware_kept} | {selected_nonfirst} | {max_min_spread} | {guardrail_first} | {same_isolation_topups} | {same_isolation_topup_failures} | {max_topup_assigned_streams} | {min_topup_floor} | {topup_bad_health} | {topup_require_bad_health} | {topup_active_cap_saturated} | {topup_max_selected_active_streams} | {topup_max_active_cap} | {topup_max_health_gap} | {topup_min_health_score} | {topup_max_health_age} | {median_exit} | {max_exit} | {max_assigned} | {max_candidate_assigned} | {max_candidate_spread} | {active_cap_picks} | {active_cap_moves} | {active_cap_saturated} | {max_selected_active_streams} | {max_candidate_active_streams} | {max_candidate_active_age} | {candidate_health} | {max_candidate_health_bytes} | {max_candidate_health_gap} | {max_candidate_health_score} | {max_candidate_health_span} | {max_candidate_health_age} | {max_open_total} | {max_rejected_open} | {max_isolation_rejects} | {max_port_rejects} | {max_unusable} | {pending} | {builds} | {build_complete} | {build_failed} | {build_canceled} |".format(
                profile=profile_name,
                target=target,
                run=fmt(run.get("run_index")),
                load=fmt(run.get("load_ms")),
                open_picks=len(open_items),
                exit_open=len(exit_open_items),
                exit_multi=sum(1 for value in exit_candidates if value > 1),
                exit_load_aware=len(exit_load_aware_items),
                health_aware_open=len(health_aware_items),
                avoid_bad_health_open=len(avoid_bad_health_items),
                unknown_fallback_open=len(avoid_bad_health_unknown_fallback_items),
                health_aware_changed=len(health_aware_changed_items),
                health_aware_kept=len(health_aware_kept_items),
                selected_nonfirst=sum(
                    1
                    for item in exit_load_aware_items
                    if isinstance(item.get("selected_candidate_index"), (int, float))
                    and item["selected_candidate_index"] > 0
                ),
                max_min_spread=fmt(
                    max(load_aware_min_spreads) if load_aware_min_spreads else None
                ),
                guardrail_first=len(load_aware_guardrail_items),
                same_isolation_topups=count_events(timings, "same_isolation_topup"),
                same_isolation_topup_failures=count_events(
                    timings, "same_isolation_topup_failed"
                ),
                max_topup_assigned_streams=fmt(
                    max(topup_selected_assigned)
                    if topup_selected_assigned
                    else None
                ),
                min_topup_floor=fmt(
                    min(topup_min_assigned) if topup_min_assigned else None
                ),
                topup_bad_health=len(topup_selected_bad_health),
                topup_require_bad_health=len(topup_requires_bad_health),
                topup_active_cap_saturated=len(topup_active_cap_saturated),
                topup_max_selected_active_streams=fmt(
                    max(topup_selected_active) if topup_selected_active else None
                ),
                topup_max_active_cap=fmt(
                    max(topup_active_caps) if topup_active_caps else None
                ),
                topup_max_health_gap=fmt(
                    max(topup_health_gaps) if topup_health_gaps else None
                ),
                topup_min_health_score=fmt(
                    min(topup_health_scores) if topup_health_scores else None
                ),
                topup_max_health_age=fmt(
                    max(topup_health_ages) if topup_health_ages else None
                ),
                median_exit=fmt(median(exit_candidates) if exit_candidates else None),
                max_exit=fmt(max(exit_candidates) if exit_candidates else None),
                max_assigned=fmt(max(assigned_streams) if assigned_streams else None),
                max_candidate_assigned=fmt(
                    max(candidate_assigned_values) if candidate_assigned_values else None
                ),
                max_candidate_spread=fmt(
                    max(candidate_assigned_spreads) if candidate_assigned_spreads else None
                ),
                active_cap_picks=len(active_cap_items),
                active_cap_moves=len(active_cap_move_items),
                active_cap_saturated=len(active_cap_saturated_items),
                max_selected_active_streams=fmt(
                    max(selected_active_values) if selected_active_values else None
                ),
                max_candidate_active_streams=fmt(
                    max(candidate_active_values) if candidate_active_values else None
                ),
                max_candidate_active_age=fmt(
                    max(candidate_active_age_values)
                    if candidate_active_age_values
                    else None
                ),
                candidate_health=len(candidate_health_rows),
                max_candidate_health_bytes=fmt(
                    row_max(candidate_health_rows, "relay_data_bytes")
                ),
                max_candidate_health_gap=fmt(
                    row_max(candidate_health_rows, "max_relay_data_gap_ms")
                ),
                max_candidate_health_score=fmt(
                    row_max(candidate_health_rows, "health_score_bps")
                ),
                max_candidate_health_span=fmt(
                    row_max(candidate_health_rows, "health_span_ms")
                ),
                max_candidate_health_age=fmt(
                    row_max(candidate_health_rows, "health_age_ms")
                ),
                max_open_total=fmt(
                    max((row.get("total", 0) for row in support_summaries), default=None)
                ),
                max_rejected_open=fmt(
                    max(rejected_open_counts) if rejected_open_counts else None
                ),
                max_isolation_rejects=fmt(
                    max((row.get("isolation", 0) for row in support_summaries), default=None)
                ),
                max_port_rejects=fmt(
                    max((row.get("port", 0) for row in support_summaries), default=None)
                ),
                max_unusable=fmt(
                    max((row.get("unusable", 0) for row in support_summaries), default=None)
                ),
                pending=count_pending_wait_events(timings),
                builds=count_events(timings, "build"),
                build_complete=count_events(timings, "build_complete"),
                build_failed=count_events(timings, "build_failed"),
                build_canceled=count_events(timings, "build_canceled"),
            )
        )


