def has_torfast_hspool_timings(payload: dict[str, object]) -> bool:
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return False
    for profile in profiles.values():
        if not isinstance(profile, dict):
            continue
        lines = proxy_log_lines(profile)
        if isinstance(lines, list) and any("torfast hspool" in str(line) for line in lines):
            return True
    return False


def has_torfast_circuit_assignments(payload: dict[str, object]) -> bool:
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return False
    for profile in profiles.values():
        if not isinstance(profile, dict):
            continue
        lines = proxy_log_lines(profile)
        if isinstance(lines, list) and any("Got a circuit for" in str(line) for line in lines):
            return True
    return False


