def has_torfast_hs_descriptor_fetch_timings(payload: dict[str, object]) -> bool:
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return False
    descriptor_markers = (
        "descriptor dir circuit ready",
        "descriptor dir stream ready",
        "descriptor response ready",
        "descriptor parsed",
    )
    for profile in profiles.values():
        if not isinstance(profile, dict):
            continue
        lines = proxy_log_lines(profile)
        if isinstance(lines, list) and any(
            "torfast hs timing" in str(line)
            and any(marker in str(line) for marker in descriptor_markers)
            for line in lines
        ):
            return True
