def print_torfast_circuit_assignments(payload: dict[str, object]) -> None:
    print("## Torfast Circuit Assignments")
    print()
    print("| profile | assignments | unique circuits | top circuit | top count |")
    print("|---|---:|---:|---|---:|")
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        assignments = parse_torfast_circuit_assignments([str(line) for line in lines])
        if not assignments:
            continue
        counts: dict[str, int] = {}
        for assignment in assignments:
            tunnel_id = assignment.get("tunnel_id")
            if isinstance(tunnel_id, str):
                counts[tunnel_id] = counts.get(tunnel_id, 0) + 1
        top_circuit = ""
        top_count = 0
        if counts:
            top_circuit, top_count = sorted(
                counts.items(), key=lambda item: (-item[1], item[0])
            )[0]
        print(
            "| {profile} | {assignments} | {unique} | {top} | {top_count} |".format(
                profile=profile_name,
                assignments=len(assignments),
                unique=len(counts),
                top=top_circuit,
                top_count=top_count,
            )
        )


