def print_torfast_hs_attempt_timings(payload: dict[str, object]) -> None:
    print("## Torfast HS Attempt Timings")
    print()
    print(
        "| profile | hs connect id | rows | shared hits | shared stores | dir circuits | responses | descriptor connect ms | response connect ms | parsed connect ms | rend established connect ms | intro circuit connect ms | intro ack connect ms | rend2 connect ms | established connect ms | post descriptor connect ms | ack to rend2 connect ms |"
    )
    print("|---|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|")
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        timings = parse_torfast_hs_timings([str(line) for line in lines])
        by_connect: dict[int, list[dict[str, object]]] = {}
        for timing in timings:
            connect_id = numeric(timing.get("hs_connect_id"))
            if connect_id is None:
                continue
            by_connect.setdefault(int(connect_id), []).append(timing)
        for connect_id, rows in sorted(by_connect.items()):
            def connect_elapsed(event: str) -> float | None:
                values = [
                    numeric(row.get("connect_elapsed_ms"))
                    for row in rows
                    if row.get("event") == event
                    and numeric(row.get("connect_elapsed_ms")) is not None
                ]
                if not values:
                    return None
                return max(values)

            descriptor_ms = connect_elapsed("descriptor_ready")
            response_ms = connect_elapsed("descriptor_response_ready")
            parsed_ms = connect_elapsed("descriptor_parsed")
            rend_established_ms = connect_elapsed("rendezvous_established")
            intro_circuit_ms = connect_elapsed("intro_circuit_ready")
            intro_ack_ms = connect_elapsed("introduce_ack_received")
            rend2_ms = connect_elapsed("rendezvous2_received")
            established_ms = connect_elapsed("circuit_established")
            post_descriptor_ms = subtract_numeric(established_ms, descriptor_ms)
            ack_to_rend2_ms = subtract_numeric(rend2_ms, intro_ack_ms)
            print(
                "| {profile} | {connect_id} | {rows} | {shared_hits} | {shared_stores} | {dir_circuits} | {responses} | {descriptor_ms} | {response_ms} | {parsed_ms} | {rend_established_ms} | {intro_circuit_ms} | {intro_ack_ms} | {rend2_ms} | {established_ms} | {post_descriptor_ms} | {ack_to_rend2_ms} |".format(
                    profile=profile_name,
                    connect_id=connect_id,
                    rows=len(rows),
                    shared_hits=count_events(rows, "descriptor_shared_cache_hit"),
                    shared_stores=count_events(rows, "descriptor_shared_cache_store"),
                    dir_circuits=count_events(rows, "descriptor_dir_circuit_ready"),
                    responses=count_events(rows, "descriptor_response_ready"),
                    descriptor_ms=fmt(descriptor_ms),
                    response_ms=fmt(response_ms),
                    parsed_ms=fmt(parsed_ms),
                    rend_established_ms=fmt(rend_established_ms),
                    intro_circuit_ms=fmt(intro_circuit_ms),
                    intro_ack_ms=fmt(intro_ack_ms),
                    rend2_ms=fmt(rend2_ms),
                    established_ms=fmt(established_ms),
                    post_descriptor_ms=fmt(post_descriptor_ms),
                    ack_to_rend2_ms=fmt(ack_to_rend2_ms),
                )
            )


