def torfast_hs_burst_parts(
    rows: list[dict[str, object]],
    *,
    group_field: str,
    elapsed_field: str,
    slow_threshold_ms: float,
) -> tuple[list[str], list[float], float | None, list[object]]:
    grouped: dict[object, list[dict[str, object]]] = {}
    for row in rows:
        group_id = row.get(group_field)
        if group_id in {None, ""}:
            continue
        grouped.setdefault(group_id, []).append(row)

    parts: list[str] = []
    timestamps: list[float] = []
    timing_ids: list[object] = []
    max_elapsed_ms = None
    for group_id, group_rows in sorted(
        grouped.items(),
        key=lambda item: (
            numeric(item[0]) is None,
            numeric(item[0]) or 0,
            str(item[0]),
        ),
    ):
        elapsed_ms = row_max(group_rows, elapsed_field)
        if elapsed_ms is None or elapsed_ms < slow_threshold_ms:
            continue
        parts.append(f"{group_id}:{fmt(elapsed_ms)}")
        if max_elapsed_ms is None or elapsed_ms > max_elapsed_ms:
            max_elapsed_ms = elapsed_ms
        for group_row in group_rows:
            timestamp_ms = numeric(group_row.get("timestamp_ms"))
            if timestamp_ms is not None:
                timestamps.append(timestamp_ms)
            timing_id = group_row.get("timing_id")
            if timing_id is not None:
                timing_ids.append(timing_id)
    return parts, timestamps, max_elapsed_ms, timing_ids


def torfast_hs_burst_run_rows(
    payload: dict[str, object], slow_threshold_ms: float = 10000.0
) -> list[dict[str, object]]:
    rows = []
    for profile_name, _profile, target, _summary, run in iter_runs(payload):
        lines = dedupe_lines(run_torfast_lines(run))
        if not lines:
            continue
        hs_rows = parse_torfast_hs_timings(lines)
        state_rows = parse_torfast_hs_state_timings(lines)
        if not hs_rows and not state_rows:
            continue

        slow_connect_parts, slow_connect_timestamps, max_connect_ms, slow_connect_timing_ids = (
            torfast_hs_burst_parts(
                hs_rows,
                group_field="hs_connect_id",
                elapsed_field="connect_elapsed_ms",
                slow_threshold_ms=slow_threshold_ms,
            )
        )
        slow_state_parts, slow_state_timestamps, max_state_ms, slow_state_timing_ids = torfast_hs_burst_parts(
            state_rows,
            group_field="state_id",
            elapsed_field="elapsed_ms",
            slow_threshold_ms=slow_threshold_ms,
        )
        if not slow_connect_parts and not slow_state_parts:
            continue

        onion_rows = sorted(
            (
                row
                for row in group_torfast_socks_timings(
                    parse_torfast_socks_timings(lines)
                ).values()
                if row.get("target_kind") == "onion"
            ),
            key=lambda row: (
                numeric(row.get("conn_started_epoch_ms"))
                if numeric(row.get("conn_started_epoch_ms")) is not None
                else float("inf"),
                numeric(row.get("timing_id")) or 0,
            ),
        )
        slow_hs_timing_ids = []
        for timing_id in slow_connect_timing_ids + slow_state_timing_ids:
            if timing_id in slow_hs_timing_ids:
                continue
            slow_hs_timing_ids.append(timing_id)
        waiter_timing_ids = []
        for row in state_rows:
            if row.get("event") != "wait_existing_task":
                continue
            owner_timing_id = row.get("owner_timing_id")
            waiter_timing_id = row.get("timing_id")
            if owner_timing_id not in slow_hs_timing_ids:
                continue
            if waiter_timing_id in {None, ""} or waiter_timing_id in waiter_timing_ids:
                continue
            waiter_timing_ids.append(waiter_timing_id)
        matched_onion_rows = onion_rows
        onion_join_mode = "no-onion"
        if slow_hs_timing_ids:
            exact_onion_rows = [
                row for row in onion_rows if row.get("timing_id") in slow_hs_timing_ids
            ]
            if exact_onion_rows:
                matched_onion_rows = exact_onion_rows
                onion_join_mode = "exact"
            else:
                waiter_exact_onion_rows = [
                    row for row in onion_rows if row.get("timing_id") in waiter_timing_ids
                ]
                if waiter_exact_onion_rows:
                    matched_onion_rows = waiter_exact_onion_rows
                    onion_join_mode = "waiter-exact"
                elif onion_rows:
                    onion_join_mode = "run-fallback"
        elif onion_rows:
            onion_join_mode = "run-only"

        hs_log_timestamps = [
            timestamp_ms
            for timestamp_ms in [
                numeric(row.get("timestamp_ms")) for row in hs_rows + state_rows
            ]
            if timestamp_ms is not None
        ]
        hs_anchor_ms = min(hs_log_timestamps) if hs_log_timestamps else None

        burst_timestamps = slow_connect_timestamps + slow_state_timestamps
        hs_log_window_s = ""
        if hs_anchor_ms is not None and burst_timestamps:
            start_ms = min(burst_timestamps)
            end_ms = max(burst_timestamps)
            hs_log_window_s = (
                f"{(start_ms - hs_anchor_ms) / 1000.0:.3f}"
                f"-{(end_ms - hs_anchor_ms) / 1000.0:.3f}"
            )

        first_onion_after_hs_s = None
        onion_start_ms = [
            start_ms
            for start_ms in [
                numeric(row.get("conn_started_epoch_ms")) for row in matched_onion_rows
            ]
            if start_ms is not None
        ]
        if hs_anchor_ms is not None and onion_start_ms:
            first_onion_after_hs_s = (min(onion_start_ms) - hs_anchor_ms) / 1000.0

        rows.append(
            {
                "profile": profile_name,
                "target": target,
                "run_index": run.get("run_index"),
                "ok": run.get("ok"),
                "load_ms": run.get("load_ms"),
                "hs_log_window_s": hs_log_window_s,
                "first_onion_after_hs_s": first_onion_after_hs_s,
                "onion_requests": len(matched_onion_rows),
                "onion_join_mode": onion_join_mode,
                "hs_timing_ids": compact_list(slow_hs_timing_ids, max_items=6),
                "waiter_timing_ids": compact_list(waiter_timing_ids, max_items=6),
                "onion_timing_ids": compact_list(
                    [row.get("timing_id") for row in matched_onion_rows], max_items=6
                ),
                "onion_targets": compact_list(
                    [
                        row.get("target_label")
                        for row in matched_onion_rows
                        if row.get("target_label")
                    ],
                    max_items=4,
                ),
                "slow_hs_connect_ids": compact_list(slow_connect_parts, max_items=6),
                "slow_state_ids": compact_list(slow_state_parts, max_items=6),
                "max_hs_connect_ms": max_connect_ms,
                "max_hs_state_ms": max_state_ms,
            }
        )

    return sorted(
        rows,
        key=lambda row: (
            max(
                numeric(row.get("max_hs_connect_ms")) or 0,
                numeric(row.get("max_hs_state_ms")) or 0,
            ),
            numeric(row.get("load_ms")) or 0,
        ),
        reverse=True,
    )


