def torfast_exit_client_slow_tunnel_rows(
    payload: dict[str, object], threshold_ms: int = 1000
) -> list[dict[str, object]]:
    rows: list[dict[str, object]] = []
    seen: set[tuple[object, object, object, object, object]] = set()

    def append_rows(
        *,
        profile_name: str,
        target: object = "",
        run_index: object = None,
        load_ms: object = None,
        lines: list[str],
    ) -> None:
        timings = parse_torfast_exit_client_timings([str(line) for line in lines])
        if not timings:
            return
        begin_by_tunnel: dict[object, dict[str, object]] = {}
        for item in timings:
            if item.get("event") != "begin_stream_finished":
                continue
            key = item.get("tunnel_unique_id") or item.get("port")
            begin_by_tunnel[key] = item
        for item in timings:
            if item.get("event") != "tunnel_ready":
                continue
            elapsed_ms = numeric(item.get("elapsed_ms"))
            if elapsed_ms is None or elapsed_ms < threshold_ms:
                continue
            key = item.get("tunnel_unique_id") or item.get("port")
            begin = begin_by_tunnel.get(key, {})
            dedupe_key = (
                profile_name,
                target,
                run_index,
                item.get("port"),
                item.get("elapsed_ms"),
            )
            if dedupe_key in seen:
                continue
            seen.add(dedupe_key)
            rows.append(
                {
                    "profile": profile_name,
                    "target": target,
                    "run_index": run_index,
                    "load_ms": load_ms,
                    "port": item.get("port"),
                    "tunnel_unique_id": item.get("tunnel_unique_id", ""),
                    "tunnel_ms": elapsed_ms,
                    "begin_ms": begin.get("elapsed_ms"),
                    "begin_phase_ms": begin.get("begin_phase_ms"),
                    "ok": item.get("ok", begin.get("ok")),
                }
            )

    run_keys: set[str] = set()
    for profile_name, _profile, target, _summary, run in iter_runs(payload):
        lines = run_torfast_lines(run)
        if not lines:
            continue
        append_rows(
            profile_name=profile_name,
            target=target,
            run_index=run.get("run_index"),
            load_ms=run.get("load_ms"),
            lines=lines,
        )
        run_keys.add(profile_name)

    profiles = payload.get("profiles", {})
    if isinstance(profiles, dict):
        for profile_name, profile in sorted(profiles.items()):
            if (
                not isinstance(profile, dict)
                or profile.get("skipped")
                or profile_name in run_keys
            ):
                continue
            append_rows(profile_name=profile_name, lines=proxy_log_lines(profile))
    return sorted(
        rows,
        key=lambda row: numeric(row.get("tunnel_ms")) or 0,
        reverse=True,
    )


def torfast_slow_connect_phase_rows(
    payload: dict[str, object], threshold_ms: int = 1000
) -> list[dict[str, object]]:
    rows: list[dict[str, object]] = []
    seen: set[tuple[object, object, object, object]] = set()
    for profile_name, _profile, target, _summary, run in iter_runs(payload):
        lines = dedupe_lines(run_torfast_lines(run))
        if not lines:
            continue
        socks_rows = torfast_slow_socks_rows(
            parse_torfast_socks_timings(lines),
            connect_threshold_ms=threshold_ms,
            relay_threshold_ms=10**12,
        )
        if not socks_rows:
            continue
        exit_timings = parse_torfast_exit_client_timings(lines)
        hs_timings = parse_torfast_hs_client_timings(lines)
        for socks_row in socks_rows:
            connect_ms = numeric(socks_row.get("connect_ms"))
            if connect_ms is None or connect_ms < threshold_ms:
                continue
            timing_id = socks_row.get("timing_id")
            dedupe_key = (profile_name, target, run.get("run_index"), timing_id)
            if dedupe_key in seen:
                continue
            seen.add(dedupe_key)
            phase = slow_connect_phase_for_socks_row(
                socks_row=socks_row,
                exit_timings=exit_timings,
                hs_timings=hs_timings,
            )
            row = {
                "profile": profile_name,
                "target": target,
                "run_index": run.get("run_index"),
                "timing_id": timing_id,
                "target_kind": socks_row.get("target_kind", ""),
                "connect_ms": connect_ms,
                "phase_source": phase.get("phase_source", ""),
                "tunnel_unique_id": phase.get("tunnel_unique_id", ""),
                "tunnel_ms": phase.get("tunnel_ms"),
                "begin_ms": phase.get("begin_ms"),
                "begin_phase_ms": phase.get("begin_phase_ms"),
                "join_method": phase.get("join_method", ""),
            }
            row["phase_gap_ms"] = subtract_numeric(row.get("connect_ms"), row.get("begin_ms"))
            row["delay_hint"] = slow_connect_phase_delay_hint(row)
            rows.append(row)
    return sorted(
        rows,
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0,
            -(numeric(row.get("connect_ms")) or 0),
        ),
    )


def slow_connect_phase_for_socks_row(
    *,
    socks_row: dict[str, object],
    exit_timings: list[dict[str, object]],
    hs_timings: list[dict[str, object]],
) -> dict[str, object]:
    target_kind = socks_row.get("target_kind")
    connect_ms = numeric(socks_row.get("connect_ms"))
    if connect_ms is None:
        return {}
    if target_kind == "hostname":
        return slow_connect_exit_phase(socks_row, exit_timings, connect_ms)
    if target_kind == "onion":
        return slow_connect_hs_phase(socks_row, hs_timings, connect_ms)
    return {}


def slow_connect_exit_phase(
    socks_row: dict[str, object],
    timings: list[dict[str, object]],
    connect_ms: float,
) -> dict[str, object]:
    begins = [
        item
        for item in timings
        if item.get("event") == "begin_stream_finished"
        and item.get("port") == socks_row.get("port")
    ]
    circ_id = socks_row.get("circ_id")
    exact = [
        item
        for item in begins
        if circ_id and torfast_circ_ids_match(circ_id, item.get("tunnel_unique_id"))
    ]
    if exact:
        return slow_connect_phase_row_from_event(
            exact[0], phase_source="exit", join_method="tunnel id"
        )
    matched = nearest_elapsed_event(begins, connect_ms, tolerance_ms=250)
    if matched is None:
        return {}
    return slow_connect_phase_row_from_event(
        matched, phase_source="exit", join_method="elapsed"
    )


def slow_connect_hs_phase(
    socks_row: dict[str, object],
    timings: list[dict[str, object]],
    connect_ms: float,
) -> dict[str, object]:
    begins = [
        item
        for item in timings
        if item.get("event") == "begin_stream_finished"
        and item.get("port") == socks_row.get("port")
    ]
    matched = nearest_elapsed_event(begins, connect_ms, tolerance_ms=250)
    if matched is None:
        return {}
    return slow_connect_phase_row_from_event(
        matched, phase_source="hs", join_method="elapsed"
    )


def nearest_elapsed_event(
    events: list[dict[str, object]], elapsed_ms: float, tolerance_ms: float
) -> dict[str, object] | None:
    candidates = [
        (abs((numeric(item.get("elapsed_ms")) or 0) - elapsed_ms), item)
        for item in events
        if numeric(item.get("elapsed_ms")) is not None
    ]
    if not candidates:
        return None
    distance, item = min(candidates, key=lambda candidate: candidate[0])
    if distance > tolerance_ms:
        return None
    return item


def slow_connect_phase_row_from_event(
    event: dict[str, object], *, phase_source: str, join_method: str
) -> dict[str, object]:
    return {
        "phase_source": phase_source,
        "join_method": join_method,
        "tunnel_unique_id": event.get("tunnel_unique_id", ""),
        "tunnel_ms": event.get("tunnel_elapsed_ms"),
        "begin_ms": event.get("elapsed_ms"),
        "begin_phase_ms": event.get("begin_phase_ms"),
    }


def slow_connect_phase_delay_hint(row: dict[str, object]) -> str:
    if not row.get("phase_source"):
        return "phase missing"
    tunnel_ms = numeric(row.get("tunnel_ms"))
    begin_phase_ms = numeric(row.get("begin_phase_ms"))
    if tunnel_ms is None or begin_phase_ms is None:
        return "phase incomplete"
    if begin_phase_ms >= 1000 and begin_phase_ms >= tunnel_ms:
        return "begin phase"
    if tunnel_ms >= 1000:
        return "tunnel acquisition"
    if begin_phase_ms >= 1000:
        return "begin phase"
    return "phase not slow"


def print_torfast_socks_timings(payload: dict[str, object]) -> None:
    print("## Torfast SOCKS Timings")
    print()
    print(
        "| profile | requests | stream ready | reply sent | soft timeouts | partial idle timeouts | no-byte timeouts | median connect ms | max connect ms | connects >=1s | median stream elapsed ms | median reply elapsed ms | median first tor byte ms | median first tor byte after reply ms | median last tor byte ms | median idle after last tor byte ms | max idle after last tor byte ms | median client eof ms | median tor writer close ms | median tor read error ms | median relay ms | max relay ms | median client to tor bytes | median tor to client bytes |"
    )
    print(
        "|---|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|"
    )
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        timings = parse_torfast_socks_timings([str(line) for line in lines])
        if not timings:
            continue
        socks_rows = list(group_torfast_socks_timings(timings).values())
        print(
            "| {profile} | {requests} | {stream_ready} | {reply_sent} | {soft_timeouts} | {partial_idle_timeouts} | {no_byte_timeouts} | {connect} | {max_connect} | {slow_connects} | {stream_elapsed} | {reply_elapsed} | {first_tor_byte} | {first_tor_byte_after_reply} | {last_tor_byte} | {idle_after_last} | {max_idle_after_last} | {client_eof} | {tor_writer_close} | {tor_read_error} | {relay} | {max_relay} | {client_to_tor} | {tor_to_client} |".format(
                profile=profile_name,
                requests=count_events(timings, "request_parsed"),
                stream_ready=count_events(timings, "stream_ready"),
                reply_sent=count_events(timings, "socks_reply_sent"),
                soft_timeouts=count_events(timings, "connect_soft_timeout"),
                partial_idle_timeouts=count_events(
                    timings, "partial_relay_idle_timeout"
                ),
                no_byte_timeouts=count_events(timings, "no_tor_byte_relay_timeout"),
                connect=fmt(event_median(timings, "stream_ready", "connect_ms")),
                max_connect=fmt(event_max(timings, "stream_ready", "connect_ms")),
                slow_connects=count_event_at_least(
                    timings, "stream_ready", "connect_ms", 1000
                ),
                stream_elapsed=fmt(event_median(timings, "stream_ready", "elapsed_ms")),
                reply_elapsed=fmt(event_median(timings, "socks_reply_sent", "elapsed_ms")),
                first_tor_byte=fmt(
                    event_positive_median(
                        timings, "relay_finished", "first_tor_to_client_ms"
                    )
                ),
                first_tor_byte_after_reply=fmt(
                    socks_first_byte_after_reply_median(timings)
                ),
                last_tor_byte=fmt(
                    row_positive_median(socks_rows, "last_tor_to_client_ms")
                ),
                idle_after_last=fmt(
                    row_positive_median(
                        socks_rows, "tor_to_client_idle_after_last_ms"
                    )
                ),
                max_idle_after_last=fmt(
                    row_max(socks_rows, "tor_to_client_idle_after_last_ms")
                ),
                client_eof=fmt(row_positive_median(socks_rows, "client_to_tor_eof_ms")),
                tor_writer_close=fmt(
                    row_positive_median(socks_rows, "client_to_tor_write_close_ms")
                ),
                tor_read_error=fmt(
                    row_positive_median(socks_rows, "tor_to_client_error_ms")
                ),
                relay=fmt(event_median(timings, "relay_finished", "relay_ms")),
                max_relay=fmt(event_max(timings, "relay_finished", "relay_ms")),
                client_to_tor=fmt(
                    event_median(timings, "relay_finished", "client_to_tor_bytes")
                ),
                tor_to_client=fmt(
                    event_median(timings, "relay_finished", "tor_to_client_bytes")
                ),
            )
        )


