def print_torfast_socks_connect_hedges(payload: dict[str, object]) -> None:
    print("## Torfast SOCKS Connect Hedges")
    print()
    print(
        "| profile | timing id | target kind | port | hedge after ms | launched | succeeded | skipped inflight | retry | retry succeeded | peer failed | failed | winner attempt | connect ms | hedge wait ms | total elapsed ms | primary error | hedge error | retry error | final error |"
    )
    print(
        "|---|---:|---|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---:|---|---|---|---|"
    )
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        timings = parse_torfast_socks_timings([str(line) for line in lines])
        for row in torfast_socks_connect_hedge_rows(timings):
            print(
                "| {profile} | {timing_id} | {target_kind} | {port} | {hedge_after} | {launched} | {succeeded} | {skipped} | {retry} | {retry_succeeded} | {peer_failed} | {failed} | {winner} | {connect} | {wait} | {elapsed} | {primary_error} | {hedge_error} | {retry_error} | {final_error} |".format(
                    profile=profile_name,
                    timing_id=fmt(row.get("timing_id")),
                    target_kind=row.get("target_kind", ""),
                    port=fmt(row.get("port")),
                    hedge_after=fmt(row.get("hedge_after_ms")),
                    launched=fmt(row.get("connect_hedge_launched")),
                    succeeded=fmt(row.get("connect_hedge_succeeded")),
                    skipped=fmt(row.get("connect_hedge_skipped_inflight")),
                    retry=fmt(row.get("connect_hedge_retries")),
                    retry_succeeded=fmt(row.get("connect_hedge_retry_succeeded")),
                    peer_failed=fmt(row.get("connect_hedge_peer_failed")),
                    failed=fmt(row.get("connect_hedge_failed")),
                    winner=fmt(row.get("winner_attempt")),
                    connect=fmt(row.get("connect_ms")),
                    wait=fmt(row.get("hedge_wait_ms")),
                    elapsed=fmt(row.get("total_elapsed_ms")),
                    primary_error=row.get("primary_error_kind", ""),
                    hedge_error=row.get("hedge_error_kind", ""),
                    retry_error=row.get("retry_error_kind", ""),
                    final_error=row.get("error_kind", ""),
                )
            )


