def count_contains(lines: list[str], pattern: str) -> int:
    return sum(1 for line in lines if pattern in line)


def parse_torfast_circuit_assignments(lines: list[str]) -> list[dict[str, object]]:
    assignments = []
    for line in lines:
        if "Got a circuit for" not in line:
            continue
        match = re.search(r"\btunnel_id=([^ ]+(?: [^ ]+)?)", line)
        if not match:
            continue
        assignments.append({"tunnel_id": match.group(1)})
    return assignments


def parse_torfast_socks_timings(lines: list[str]) -> list[dict[str, object]]:
    timings = []
    for line in lines:
        if "torfast socks timing" not in line:
            continue
        fields = {
            key: parse_log_value(value)
            for key, value in re.findall(r"\b([a-zA-Z_]+)=([^ ]+)", line)
        }
        circ_id = parse_torfast_circ_id(line)
        if circ_id is not None:
            fields["circ_id"] = circ_id
        event = torfast_event_name(line)
        if event is None:
            continue
        fields["event"] = event
        timestamp_ms = parse_log_timestamp_ms(line)
        if timestamp_ms is not None:
            fields["timestamp_ms"] = timestamp_ms
        timings.append(fields)
    return timings


