def parse_torfast_circuit_selection_timings(
    lines: list[str],
) -> list[dict[str, object]]:
    timings = []
    for index, line in enumerate(lines):
        if "torfast circuit selection" not in line:
            continue
        event = torfast_circuit_selection_event_name(line)
        if event is None:
            continue
        fields = {
            key: parse_log_value(value)
            for key, value in re.findall(r"\b([a-zA-Z_]+)=([^ ]+)", line)
        }
        if isinstance(fields.get("selected_tunnel_unique_id"), str):
            fields["selected_tunnel_unique_id"] = str(
                fields["selected_tunnel_unique_id"]
            ).replace("~", " ")
        tunnel_unique_id = parse_torfast_tunnel_unique_id(line)
        if tunnel_unique_id is not None:
            fields["tunnel_unique_id"] = tunnel_unique_id
        fallback_tunnel_unique_id = parse_torfast_named_unique_id(
            line, "fallback_tunnel_unique_id"
        )
        if fallback_tunnel_unique_id is not None:
            fields["fallback_tunnel_unique_id_full"] = fallback_tunnel_unique_id
        fields["event"] = event
        fields["line_index"] = index
        timestamp_ms = parse_log_timestamp_ms(line)
        if timestamp_ms is not None:
            fields["timestamp_ms"] = timestamp_ms
        timings.append(fields)
    return timings


def parse_torfast_candidate_assignment_summary(
    value: object,
) -> list[dict[str, object]]:
    if not isinstance(value, str) or not value:
        return []
    rows = []
    for entry in value.split(","):
        parts = entry.split(":", 2)
        if len(parts) != 3:
            continue
        idx_raw, tunnel_id, assigned_raw = parts
        try:
            idx = int(idx_raw)
            assigned_streams = int(assigned_raw)
        except ValueError:
            continue
        rows.append(
            {
                "index": idx,
                "tunnel_unique_id": tunnel_id.replace("~", " "),
                "assigned_streams": assigned_streams,
            }
        )
    return rows


def parse_torfast_candidate_health_summary(
    value: object,
) -> list[dict[str, object]]:
    if not isinstance(value, str) or not value:
        return []
    rows = []
    for entry in value.split(","):
        parts = entry.split(":")
        if len(parts) not in (5, 8, 10, 11):
            continue
        idx_raw, tunnel_id, cells_raw, bytes_raw, gap_raw = parts[:5]
        try:
            idx = int(idx_raw)
            relay_data_cells = int(cells_raw)
            relay_data_bytes = int(bytes_raw)
            max_relay_data_gap_ms = int(gap_raw)
        except ValueError:
            continue
        rows.append(
            {
                "index": idx,
                "tunnel_unique_id": tunnel_id.replace("~", " "),
                "relay_data_cells": relay_data_cells,
                "relay_data_bytes": relay_data_bytes,
                "max_relay_data_gap_ms": max_relay_data_gap_ms,
            }
        )
        if len(parts) in (8, 10, 11):
            score_raw, span_raw, age_raw = parts[5:8]
            try:
                rows[-1]["health_score_bps"] = int(score_raw)
                rows[-1]["health_span_ms"] = int(span_raw)
                rows[-1]["health_age_ms"] = int(age_raw)
            except ValueError:
                rows.pop()
                continue
        if len(parts) in (10, 11):
            active_raw, max_active_raw = parts[8:10]
            try:
                rows[-1]["active_streams"] = int(active_raw)
                rows[-1]["max_active_streams"] = int(max_active_raw)
            except ValueError:
                rows.pop()
                continue
        if len(parts) == 11:
            active_age_raw = parts[10]
            try:
                rows[-1]["active_stream_age_ms"] = int(active_age_raw)
            except ValueError:
                rows.pop()
    return rows


def torfast_candidate_assignment_for_tunnel(
    item: dict[str, object], tunnel_unique_id: object
) -> dict[str, object]:
    if not isinstance(tunnel_unique_id, str) or not tunnel_unique_id:
        return {}
    for row in parse_torfast_candidate_assignment_summary(
        item.get("candidate_assignment_summary")
    ):
        if row.get("tunnel_unique_id") == tunnel_unique_id:
            return row
    return {}


def torfast_candidate_health_for_tunnel(
    item: dict[str, object], tunnel_unique_id: object
) -> dict[str, object]:
    if not isinstance(tunnel_unique_id, str) or not tunnel_unique_id:
        return {}
    for row in parse_torfast_candidate_health_summary(
        item.get("candidate_health_summary")
    ):
        if row.get("tunnel_unique_id") == tunnel_unique_id:
            return row
    return {}


def torfast_open_item_has_candidate(
    item: dict[str, object], tunnel_unique_id: object
) -> bool:
    return bool(
        torfast_candidate_assignment_for_tunnel(item, tunnel_unique_id)
        or torfast_candidate_health_for_tunnel(item, tunnel_unique_id)
    )


def torfast_inferred_topup_candidate_open(
    open_items: list[dict[str, object]], topup_index: int
) -> tuple[dict[str, object], str | None]:
    before_open_items = [
        item
        for item in open_items
        if item.get("usage_kind") == "exit"
        and (numeric(item.get("line_index")) or -1) < topup_index
    ]
    before_ids: set[str] = set()
    for before_open in before_open_items:
        before_ids.update(
            str(row.get("tunnel_unique_id"))
            for row in parse_torfast_candidate_assignment_summary(
                before_open.get("candidate_assignment_summary")
            )
            if row.get("tunnel_unique_id")
        )

    after_open_items = [
        item
        for item in open_items
        if item.get("usage_kind") == "exit"
        and (numeric(item.get("line_index")) or -1) > topup_index
    ]
    for item in sorted(
        after_open_items, key=lambda item: numeric(item.get("line_index")) or 0
    ):
        for row in parse_torfast_candidate_assignment_summary(
            item.get("candidate_assignment_summary")
        ):
            tunnel = row.get("tunnel_unique_id")
            assigned = numeric(row.get("assigned_streams"))
            if isinstance(tunnel, str) and assigned == 0 and tunnel not in before_ids:
                return item, tunnel
    return {}, None


def load_aware_guardrail_kept_first(item: dict[str, object]) -> bool:
    selected_idx = numeric(item.get("selected_candidate_index"))
    min_spread = numeric(item.get("load_aware_min_assignment_spread")) or 0
    spread = numeric(item.get("load_aware_assignment_spread"))
    rows = parse_torfast_candidate_assignment_summary(
        item.get("candidate_assignment_summary")
    )
    if selected_idx != 0 or min_spread <= 0 or not rows:
        return False
    least_idx = min(rows, key=lambda row: row["assigned_streams"])["index"]
    if least_idx == 0:
        return False
    if spread is None:
        assigned = [row["assigned_streams"] for row in rows]
        spread = max(assigned) - min(assigned)
    return spread < min_spread


def health_aware_changed_assignment(item: dict[str, object]) -> bool:
    if item.get("select_health_aware") is not True:
        return False
    selected_idx = numeric(item.get("selected_candidate_index"))
    assignment_idx = numeric(item.get("load_aware_assignment_candidate_index"))
    return (
        selected_idx is not None
        and assignment_idx is not None
        and selected_idx != assignment_idx
    )


def health_aware_guard_kept_assignment(item: dict[str, object]) -> bool:
    if item.get("select_health_aware") is not True:
        return False
    selected_idx = numeric(item.get("selected_candidate_index"))
    assignment_idx = numeric(item.get("load_aware_assignment_candidate_index"))
    health_idx = numeric(item.get("health_aware_candidate_index"))
    return (
        selected_idx is not None
        and assignment_idx is not None
        and health_idx is not None
        and selected_idx == assignment_idx
        and health_idx != assignment_idx
    )


def parse_torfast_open_support_summary(value: object) -> dict[str, int]:
    if not isinstance(value, str) or not value:
        return {}
    fields: dict[str, int] = {}
    for entry in value.split(","):
        key, sep, raw_value = entry.partition(":")
        if not sep or not key:
            continue
        try:
            fields[key] = int(raw_value)
        except ValueError:
            continue
    return fields


def parse_torfast_hspool_timings(lines: list[str]) -> list[dict[str, object]]:
    timings = []
    for line in lines:
        if "torfast hspool" not in line:
            continue
        event = torfast_hspool_event_name(line)
        if event is None:
            continue
        fields = {
            key: parse_log_value(value)
            for key, value in re.findall(r"\b([a-zA-Z_]+)=([^ ]+)", line)
        }
        fields["event"] = event
        timings.append(fields)
    return timings


