def torfast_hs_client_event_name(line: str) -> str | None:
    if "begin stream finished" in line:
        return "begin_stream_finished"
    if "tunnel ready" in line:
        return "tunnel_ready"
    if "keys ready" in line:
        return "keys_ready"
    if "netdir ready" in line:
        return "netdir_ready"
    if "bootstrap ready" in line:
        return "bootstrap_ready"
    if "torfast hs client timing start" in line:
        return "start"
    return None


def torfast_hs_state_event_name(line: str) -> str | None:
    if "client wrapper start" in line:
        return "client_wrapper_start"
    if "client wrapper finished" in line:
        return "client_wrapper_finished"
    if "cache hit" in line:
        return "cache_hit"
    if "wait existing task" in line:
        return "wait_existing_task"
    if "spawn connect task" in line:
        return "spawn_connect_task"
    if "connect task finished" in line:
        return "connect_task_finished"
    if "existing task finished" in line:
        return "existing_task_finished"
    if "tunnel returned" in line:
        return "tunnel_returned"
    return None


def torfast_exit_client_event_name(line: str) -> str | None:
    if "begin stream finished" in line:
        return "begin_stream_finished"
    if "tunnel ready" in line:
        return "tunnel_ready"
    return None


def torfast_relay_receive_event_name(line: str) -> str | None:
    if "relay receive delivered" in line:
        return "delivered"
    if "relay receive control" in line:
        return "control"
    if "relay receive queue full" in line:
        return "queue_full"
    if "relay receive stream gone" in line:
        return "stream_gone"
    if "relay receive incoming request" in line:
        return "incoming_request"
    if "relay receive unknown stream" in line:
        return "unknown_stream"
    return None


def parse_torfast_circ_id(line: str) -> str | None:
    match = re.search(r"\bcirc_id=(.*?)\s+hop=", line)
    if match:
        return match.group(1)
    return None


def parse_torfast_channel_id(line: str) -> str | None:
    match = re.search(r"\bchannel_id=(Chan \d+)", line)
    if match:
        return match.group(1)
    return None


def torfast_relay_receive_stream_rows(
    timings: list[dict[str, object]],
) -> list[dict[str, object]]:
    grouped: dict[tuple[object, object], list[dict[str, object]]] = {}
    for item in timings:
        if item.get("event") != "delivered" or item.get("stream_id") is None:
            continue
        key = (item.get("circ_id", ""), item.get("stream_id"))
        grouped.setdefault(key, []).append(item)

    rows = []
    for (circ_id, stream_id), items in grouped.items():
        data_items = [item for item in items if item.get("relay_cmd") == "DATA"]
        timestamps = [
            item.get("timestamp_ms")
            for item in items
            if isinstance(item.get("timestamp_ms"), (int, float))
        ]
        queued_after_values = [
            item.get("queued_after_bytes")
            for item in items
            if isinstance(item.get("queued_after_bytes"), (int, float))
        ]
        gaps = event_timestamp_gaps_ms(items)
        rows.append(
            {
                "circ_id": circ_id,
                "stream_id": stream_id,
                "data_cells": len(data_items),
                "data_bytes": sum(
                    int(item.get("data_len") or 0) for item in data_items
                ),
                "span_ms": (
                    max(timestamps) - min(timestamps)
                    if len(timestamps) >= 2
                    else None
                ),
                "first_receive_epoch_ms": min(timestamps) if timestamps else None,
                "last_receive_epoch_ms": max(timestamps) if timestamps else None,
                "max_gap_ms": max(gaps) if gaps else None,
                "max_queued_after_bytes": (
                    max(queued_after_values) if queued_after_values else None
                ),
            }
        )
    return sorted(
        rows,
        key=lambda row: (
            row.get("data_bytes") if isinstance(row.get("data_bytes"), int) else 0,
            row.get("max_queued_after_bytes")
            if isinstance(row.get("max_queued_after_bytes"), int)
            else 0,
        ),
        reverse=True,
    )


def torfast_relay_receive_run_summary_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    rows = []
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return rows
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        timings = parse_torfast_relay_receive_timings([str(line) for line in lines])
        delivered = [item for item in timings if item.get("event") == "delivered"]
        if not delivered:
            continue
        benchmarks = profile.get("benchmarks", {})
        if not isinstance(benchmarks, dict):
            continue
        for target, bench in sorted(benchmarks.items()):
            if not isinstance(bench, dict):
                continue
            runs = [
                run
                for run in bench.get("runs", [])
                if isinstance(run, dict) and browser_time_origin_ms(run) is not None
            ]
            runs.sort(key=lambda run: browser_time_origin_ms(run) or 0)
            bounds = browser_run_epoch_bounds(runs)
            for index, run in enumerate(runs):
                lower, upper = bounds[index]
                time_origin = browser_time_origin_ms(run)
                response_epoch = browser_response_epoch_ms(run)
                load_epoch = browser_load_epoch_ms(run)
                run_items = [
                    item
                    for item in delivered
                    if numeric(item.get("timestamp_ms")) is not None
                    and lower <= (numeric(item.get("timestamp_ms")) or 0) < upper
                ]
                if not run_items:
                    continue
                data_items = [
                    item for item in run_items if item.get("relay_cmd") == "DATA"
                ]
                timestamps = [
                    value
                    for value in (
                        numeric(item.get("timestamp_ms")) for item in run_items
                    )
                    if value is not None
                ]
                queued_after_values = [
                    value
                    for value in (
                        numeric(item.get("queued_after_bytes")) for item in run_items
                    )
                    if value is not None
                ]
                circuits = {
                    item.get("circ_id")
                    for item in run_items
                    if item.get("circ_id") is not None
                }
                streams = {
                    item.get("stream_id")
                    for item in run_items
                    if item.get("stream_id") is not None
                }
                gaps = event_timestamp_gaps_ms(run_items)
                first_receive = min(timestamps) if timestamps else None
                last_receive = max(timestamps) if timestamps else None
                rows.append(
                    {
                        "profile": profile_name,
                        "target": str(target),
                        "run_index": run.get("run_index", index + 1),
                        "load_ms": run.get("load_ms"),
                        "delivered": len(run_items),
                        "data_cells": len(data_items),
                        "data_bytes": sum(
                            int(item.get("data_len") or 0) for item in data_items
                        ),
                        "unique_circuits": len(circuits),
                        "unique_streams": len(streams),
                        "first_receive_after_start_ms": subtract_numeric(
                            first_receive, time_origin
                        ),
                        "first_receive_minus_response_ms": subtract_numeric(
                            first_receive, response_epoch
                        ),
                        "receive_span_ms": (
                            max(timestamps) - min(timestamps)
                            if len(timestamps) >= 2
                            else None
                        ),
                        "last_receive_before_load_ms": subtract_numeric(
                            load_epoch, last_receive
                        ),
                        "max_receive_gap_ms": max(gaps) if gaps else None,
                        "max_queued_after_bytes": (
                            max(queued_after_values) if queued_after_values else None
                        ),
                    }
                )
    return rows


def torfast_relay_receive_gap_detail_rows(
    payload: dict[str, object], limit_per_run: int = 3
) -> list[dict[str, object]]:
    rows: list[dict[str, object]] = []
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return rows
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        timings = parse_torfast_relay_receive_timings([str(line) for line in lines])
        delivered = [item for item in timings if item.get("event") == "delivered"]
        if not delivered:
            continue
        benchmarks = profile.get("benchmarks", {})
        if not isinstance(benchmarks, dict):
            continue
        for target, bench in sorted(benchmarks.items()):
            if not isinstance(bench, dict):
                continue
            runs = [
                run
                for run in bench.get("runs", [])
                if isinstance(run, dict) and browser_time_origin_ms(run) is not None
            ]
            runs.sort(key=lambda run: browser_time_origin_ms(run) or 0)
            bounds = browser_run_epoch_bounds(runs)
            for index, run in enumerate(runs):
                lower, upper = bounds[index]
                run_items = [
                    item
                    for item in delivered
                    if numeric(item.get("timestamp_ms")) is not None
                    and lower <= (numeric(item.get("timestamp_ms")) or 0) < upper
                ]
                run_items.sort(key=lambda item: numeric(item.get("timestamp_ms")) or 0)
                load_epoch = browser_load_epoch_ms(run)
                gap_rows = []
                for previous, current in zip(run_items, run_items[1:]):
                    previous_ts = numeric(previous.get("timestamp_ms"))
                    current_ts = numeric(current.get("timestamp_ms"))
                    if previous_ts is None or current_ts is None or current_ts < previous_ts:
                        continue
                    gap_rows.append(
                        {
                            "profile": profile_name,
                            "target": str(target),
                            "run_index": run.get("run_index", index + 1),
                            "gap_ms": current_ts - previous_ts,
                            "prev_circ_id": previous.get("circ_id"),
                            "prev_stream_id": previous.get("stream_id"),
                            "prev_relay_cmd": previous.get("relay_cmd"),
                            "prev_queued_after_bytes": previous.get(
                                "queued_after_bytes"
                            ),
                            "next_circ_id": current.get("circ_id"),
                            "next_stream_id": current.get("stream_id"),
                            "next_relay_cmd": current.get("relay_cmd"),
                            "next_queued_before_bytes": current.get(
                                "queued_before_bytes"
                            ),
                            "next_queued_after_bytes": current.get(
                                "queued_after_bytes"
                            ),
                            "gap_end_before_load_ms": subtract_numeric(
                                load_epoch, current_ts
                            ),
                        }
                    )
                rows.extend(
                    sorted(
                        gap_rows,
                        key=lambda row: numeric(row.get("gap_ms")) or 0,
                        reverse=True,
                    )[:limit_per_run]
                )
    return sorted(
        rows,
        key=lambda row: numeric(row.get("gap_ms")) or 0,
        reverse=True,
    )


def torfast_relay_receive_circuit_gap_detail_rows(
    payload: dict[str, object], limit_per_run: int = 5
) -> list[dict[str, object]]:
    rows: list[dict[str, object]] = []
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return rows
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        timings = parse_torfast_relay_receive_timings([str(line) for line in lines])
        delivered = [item for item in timings if item.get("event") == "delivered"]
        if not delivered:
            continue
        benchmarks = profile.get("benchmarks", {})
        if not isinstance(benchmarks, dict):
            continue
        for target, bench in sorted(benchmarks.items()):
            if not isinstance(bench, dict):
                continue
            runs = [
                run
                for run in bench.get("runs", [])
                if isinstance(run, dict) and browser_time_origin_ms(run) is not None
            ]
            runs.sort(key=lambda run: browser_time_origin_ms(run) or 0)
            bounds = browser_run_epoch_bounds(runs)
            for index, run in enumerate(runs):
                lower, upper = bounds[index]
                run_items = [
                    item
                    for item in delivered
                    if numeric(item.get("timestamp_ms")) is not None
                    and lower <= (numeric(item.get("timestamp_ms")) or 0) < upper
                    and item.get("circ_id") is not None
                ]
                by_circuit: dict[object, list[dict[str, object]]] = {}
                for item in run_items:
                    by_circuit.setdefault(item.get("circ_id"), []).append(item)
                load_epoch = browser_load_epoch_ms(run)
                gap_rows = []
                for circ_id, items in by_circuit.items():
                    items.sort(key=lambda item: numeric(item.get("timestamp_ms")) or 0)
                    circuit_streams = {
                        item.get("stream_id")
                        for item in items
                        if item.get("stream_id") is not None
                    }
                    for previous, current in zip(items, items[1:]):
                        previous_ts = numeric(previous.get("timestamp_ms"))
                        current_ts = numeric(current.get("timestamp_ms"))
                        if (
                            previous_ts is None
                            or current_ts is None
                            or current_ts < previous_ts
                        ):
                            continue
                        gap_rows.append(
                            {
                                "profile": profile_name,
                                "target": str(target),
                                "run_index": run.get("run_index", index + 1),
                                "gap_ms": current_ts - previous_ts,
                                "circ_id": circ_id,
                                "circuit_streams": len(circuit_streams),
                                "prev_stream_id": previous.get("stream_id"),
                                "prev_relay_cmd": previous.get("relay_cmd"),
                                "prev_queued_after_bytes": previous.get(
                                    "queued_after_bytes"
                                ),
                                "next_stream_id": current.get("stream_id"),
                                "next_relay_cmd": current.get("relay_cmd"),
                                "next_queued_before_bytes": current.get(
                                    "queued_before_bytes"
                                ),
                                "next_queued_after_bytes": current.get(
                                    "queued_after_bytes"
                                ),
                                "gap_end_before_load_ms": subtract_numeric(
                                    load_epoch, current_ts
                                ),
                            }
                        )
                rows.extend(
                    sorted(
                        gap_rows,
                        key=lambda row: numeric(row.get("gap_ms")) or 0,
                        reverse=True,
                    )[:limit_per_run]
                )
    return sorted(
        rows,
        key=lambda row: numeric(row.get("gap_ms")) or 0,
        reverse=True,
    )


def torfast_relay_receive_stream_gap_detail_rows(
    payload: dict[str, object], limit_per_run: int = 5
) -> list[dict[str, object]]:
    rows: list[dict[str, object]] = []
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return rows
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        timings = parse_torfast_relay_receive_timings([str(line) for line in lines])
        delivered = [item for item in timings if item.get("event") == "delivered"]
        if not delivered:
            continue
        benchmarks = profile.get("benchmarks", {})
        if not isinstance(benchmarks, dict):
            continue
        for target, bench in sorted(benchmarks.items()):
            if not isinstance(bench, dict):
                continue
            runs = [
                run
                for run in bench.get("runs", [])
                if isinstance(run, dict) and browser_time_origin_ms(run) is not None
            ]
            runs.sort(key=lambda run: browser_time_origin_ms(run) or 0)
            bounds = browser_run_epoch_bounds(runs)
            for index, run in enumerate(runs):
                lower, upper = bounds[index]
                run_items = [
                    item
                    for item in delivered
                    if numeric(item.get("timestamp_ms")) is not None
                    and lower <= (numeric(item.get("timestamp_ms")) or 0) < upper
                    and item.get("circ_id") is not None
                    and item.get("stream_id") is not None
                ]
                by_stream: dict[tuple[object, object], list[dict[str, object]]] = {}
                for item in run_items:
                    key = (item.get("circ_id"), item.get("stream_id"))
                    by_stream.setdefault(key, []).append(item)
                load_epoch = browser_load_epoch_ms(run)
                gap_rows = []
                for (circ_id, stream_id), items in by_stream.items():
                    items.sort(key=lambda item: numeric(item.get("timestamp_ms")) or 0)
                    for previous, current in zip(items, items[1:]):
                        previous_ts = numeric(previous.get("timestamp_ms"))
                        current_ts = numeric(current.get("timestamp_ms"))
                        if (
                            previous_ts is None
                            or current_ts is None
                            or current_ts < previous_ts
                        ):
                            continue
                        gap_rows.append(
                            {
                                "profile": profile_name,
                                "target": str(target),
                                "run_index": run.get("run_index", index + 1),
                                "gap_ms": current_ts - previous_ts,
                                "circ_id": circ_id,
                                "stream_id": stream_id,
                                "prev_relay_cmd": previous.get("relay_cmd"),
                                "prev_queued_after_bytes": previous.get(
                                    "queued_after_bytes"
                                ),
                                "next_relay_cmd": current.get("relay_cmd"),
                                "next_queued_before_bytes": current.get(
                                    "queued_before_bytes"
                                ),
                                "next_queued_after_bytes": current.get(
                                    "queued_after_bytes"
                                ),
                                "gap_end_before_load_ms": subtract_numeric(
                                    load_epoch, current_ts
                                ),
                            }
                        )
                rows.extend(
                    sorted(
                        gap_rows,
                        key=lambda row: numeric(row.get("gap_ms")) or 0,
                        reverse=True,
                    )[:limit_per_run]
                )
    return sorted(
        rows,
        key=lambda row: numeric(row.get("gap_ms")) or 0,
        reverse=True,
    )


def torfast_relay_receive_circuit_gap_summary_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    rows: list[dict[str, object]] = []
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return rows
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        timings = parse_torfast_relay_receive_timings([str(line) for line in lines])
        delivered_data = [
            item
            for item in timings
            if item.get("event") == "delivered"
            and item.get("relay_cmd") == "DATA"
            and item.get("circ_id") is not None
            and numeric(item.get("timestamp_ms")) is not None
        ]
        if not delivered_data:
            continue
        benchmarks = profile.get("benchmarks", {})
        if not isinstance(benchmarks, dict):
            continue
        for target, bench in sorted(benchmarks.items()):
            if not isinstance(bench, dict):
                continue
            runs = [
                run
                for run in bench.get("runs", [])
                if isinstance(run, dict) and browser_time_origin_ms(run) is not None
            ]
            runs.sort(key=lambda run: browser_time_origin_ms(run) or 0)
            bounds = browser_run_epoch_bounds(runs)
            for index, run in enumerate(runs):
                lower, upper = bounds[index]
                run_items = [
                    item
                    for item in delivered_data
                    if lower <= (numeric(item.get("timestamp_ms")) or 0) < upper
                ]
                by_circuit: dict[object, list[dict[str, object]]] = {}
                for item in run_items:
                    by_circuit.setdefault(item.get("circ_id"), []).append(item)
                load_epoch = browser_load_epoch_ms(run)
                for circ_id, items in by_circuit.items():
                    items.sort(key=lambda item: numeric(item.get("timestamp_ms")) or 0)
                    timestamps = [
                        value
                        for value in (
                            numeric(item.get("timestamp_ms")) for item in items
                        )
                        if value is not None
                    ]
                    if not timestamps:
                        continue
                    gaps = []
                    same_stream_gaps = 0
                    cross_stream_gaps = 0
                    max_gap_row: dict[str, object] = {}
                    for previous, current in zip(items, items[1:]):
                        previous_ts = numeric(previous.get("timestamp_ms"))
                        current_ts = numeric(current.get("timestamp_ms"))
                        if (
                            previous_ts is None
                            or current_ts is None
                            or current_ts < previous_ts
                        ):
                            continue
                        gap = current_ts - previous_ts
                        gaps.append(gap)
                        same_stream = previous.get("stream_id") == current.get(
                            "stream_id"
                        )
                        if same_stream:
                            same_stream_gaps += 1
                        else:
                            cross_stream_gaps += 1
                        if gap >= (numeric(max_gap_row.get("gap_ms")) or -1):
                            max_gap_row = {
                                "gap_ms": gap,
                                "prev_stream_id": previous.get("stream_id"),
                                "next_stream_id": current.get("stream_id"),
                                "same_stream_gap": same_stream,
                                "gap_end_before_load_ms": subtract_numeric(
                                    load_epoch, current_ts
                                ),
                            }
                    streams = {
                        item.get("stream_id")
                        for item in items
                        if item.get("stream_id") is not None
                    }
                    rows.append(
                        {
                            "profile": profile_name,
                            "target": str(target),
                            "run_index": run.get("run_index", index + 1),
                            "circuit": circ_id,
                            "data_cells": len(items),
                            "data_bytes": sum(
                                int(item.get("data_len") or 0) for item in items
                            ),
                            "circuit_streams": len(streams),
                            "first_circuit_data_epoch_ms": min(timestamps),
                            "last_circuit_data_epoch_ms": max(timestamps),
                            "max_circuit_data_gap_ms": max(gaps) if gaps else None,
                            "median_circuit_data_gap_ms": (
                                median(gaps) if gaps else None
                            ),
                            "same_stream_gap_rows": same_stream_gaps,
                            "cross_stream_gap_rows": cross_stream_gaps,
                            "max_gap_prev_stream_id": max_gap_row.get(
                                "prev_stream_id"
                            ),
                            "max_gap_next_stream_id": max_gap_row.get(
                                "next_stream_id"
                            ),
                            "max_gap_same_stream": max_gap_row.get(
                                "same_stream_gap"
                            ),
                            "max_gap_end_before_load_ms": max_gap_row.get(
                                "gap_end_before_load_ms"
                            ),
                        }
                    )
    return sorted(
        rows,
        key=lambda row: numeric(row.get("max_circuit_data_gap_ms")) or 0,
        reverse=True,
    )


