def parse_torfast_tunnel_unique_id(line: str) -> str | None:
    match = re.search(r"\btunnel_unique_id=([^ ]+(?: [^ ]+)?)", line)
    if match:
        return match.group(1)
    return None


def parse_torfast_named_unique_id(line: str, field: str) -> str | None:
    match = re.search(rf"\b{re.escape(field)}=([^ ]+(?: [^ ]+)?)", line)
    if match:
        return match.group(1)
    return None


def torfast_log_line_mentions_circuit(line: str, field: str, circuit: object) -> bool:
    if not isinstance(circuit, str) or not circuit:
        return False
    return (
        re.search(
            rf"\b{re.escape(field)}={re.escape(circuit)}(?=$|[\s)])",
            line,
        )
        is not None
    )


