def parse_log_value(value: str) -> object:
    relay_cmd = re.fullmatch(r"RelayCmd\(([^)]+)\)", value)
    if relay_cmd:
        return relay_cmd.group(1)
    channel_cmd = re.fullmatch(r"ChanCmd\(([^)]+)\)", value)
    if channel_cmd:
        return channel_cmd.group(1)
    if len(value) >= 2 and value.startswith('"') and value.endswith('"'):
        return value[1:-1]
    if value in {"true", "false"}:
        return value == "true"
    try:
        return int(value)
    except ValueError:
        return value


def count_events(timings: list[dict[str, object]], event: str) -> int:
    return sum(1 for item in timings if item.get("event") == event)


def count_pending_wait_events(timings: list[dict[str, object]]) -> int:
    return (
        count_events(timings, "pending")
        + count_events(timings, "same_isolation_pending_wait")
        + count_events(timings, "bad_health_pending_wait")
    )


def value_counts(values: object) -> dict[str, int]:
    counts: dict[str, int] = {}
    for value in values:
        if not isinstance(value, str) or not value:
            continue
        counts[value] = counts.get(value, 0) + 1
    return counts


def format_counts(counts: dict[str, int]) -> str:
    return ", ".join(f"{key}:{value}" for key, value in sorted(counts.items()))


def event_median(
    timings: list[dict[str, object]], event: str, field: str
) -> float | None:
    values = [
        item.get(field)
        for item in timings
        if item.get("event") == event and isinstance(item.get(field), (int, float))
    ]
    return median(values) if values else None


def event_positive_median(
    timings: list[dict[str, object]], event: str, field: str
) -> float | None:
    values = [
        item.get(field)
        for item in timings
        if item.get("event") == event
        and isinstance(item.get(field), (int, float))
        and item.get(field) > 0
    ]
    return median(values) if values else None


def event_max(timings: list[dict[str, object]], event: str, field: str) -> float | None:
    values = [
        item.get(field)
        for item in timings
        if item.get("event") == event and isinstance(item.get(field), (int, float))
    ]
    return float(max(values)) if values else None


def event_timestamp_gaps_ms(timings: list[dict[str, object]]) -> list[float]:
    timestamps = [
        item.get("timestamp_ms")
        for item in timings
        if isinstance(item.get("timestamp_ms"), (int, float))
    ]
    return [
        float(right - left)
        for left, right in zip(timestamps, timestamps[1:])
        if right >= left
    ]


def event_timestamp_gap_bounds_ms(
    timings: list[dict[str, object]],
) -> list[dict[str, object]]:
    timed_items = sorted(
        (
            (float(timestamp), item)
            for item in timings
            if isinstance((timestamp := item.get("timestamp_ms")), (int, float))
        ),
        key=lambda pair: pair[0],
    )
    gaps = []
    for (left_ts, left_item), (right_ts, right_item) in zip(
        timed_items, timed_items[1:]
    ):
        if right_ts < left_ts:
            continue
        gaps.append(
            {
                "gap_ms": right_ts - left_ts,
                "start_timestamp_ms": left_ts,
                "end_timestamp_ms": right_ts,
                "start_item": left_item,
                "end_item": right_item,
            }
        )
    return gaps


def torfast_stream_receiver_rows(
    timings: list[dict[str, object]],
) -> list[dict[str, object]]:
    grouped: dict[object, list[dict[str, object]]] = {}
    for item in timings:
        stream_id = item.get("stream_id")
        if stream_id is None:
            continue
        grouped.setdefault(stream_id, []).append(item)

    rows = []
    for stream_id, items in grouped.items():
        items.sort(key=lambda item: numeric(item.get("timestamp_ms")) or 0)
        reads = [item for item in items if item.get("event") == "read"]
        sendmes = [item for item in items if item.get("event") == "sendme"]
        read_gaps = event_timestamp_gaps_ms(reads)
        recv_windows = [
            numeric(item.get("recv_window_after"))
            for item in reads
            if numeric(item.get("recv_window_after")) is not None
        ]
        queued_after = [
            numeric(item.get("queued_after_bytes"))
            for item in items
            if numeric(item.get("queued_after_bytes")) is not None
        ]
        rows.append(
            {
                "stream_id": stream_id,
                "read_events": len(reads),
                "sendmes": len(sendmes),
                "sendme_ok": sum(1 for item in sendmes if item.get("sendme_ok") is True),
                "data_bytes": sum(
                    int(numeric(item.get("data_len")) or 0) for item in reads
                ),
                "max_read_gap_ms": max(read_gaps) if read_gaps else None,
                "min_recv_window_after": min(recv_windows) if recv_windows else None,
                "max_queued_after_bytes": max(queued_after) if queued_after else None,
            }
        )
    return sorted(
        rows,
        key=lambda row: numeric(row.get("max_read_gap_ms")) or 0,
        reverse=True,
    )


def torfast_stream_receiver_terminal_summary_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    rows = []
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return rows
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        timings = parse_torfast_stream_receiver_timings([str(line) for line in lines])
        terminals = [item for item in timings if item.get("event") == "terminal"]
        if not terminals:
            continue
        transfer_ms = [
            numeric(item.get("transfer_ms"))
            for item in terminals
            if numeric(item.get("transfer_ms")) is not None
        ]
        top = max(
            terminals,
            key=lambda item: numeric(item.get("transfer_ms")) or 0,
            default={},
        )
        rows.append(
            {
                "profile": profile_name,
                "streams": len(
                    {
                        item.get("stream_id")
                        for item in terminals
                        if item.get("stream_id") is not None
                    }
                ),
                "terminal_summaries": len(terminals),
                "non_eof": sum(
                    1 for item in terminals if item.get("returned_eof") is not True
                ),
                "relay_kib": sum(
                    numeric(item.get("relay_data_bytes")) or 0 for item in terminals
                )
                / 1024.0,
                "user_kib": sum(
                    numeric(item.get("user_read_bytes")) or 0 for item in terminals
                )
                / 1024.0,
                "data_cells": sum(
                    numeric(item.get("data_cells")) or 0 for item in terminals
                ),
                "read_events": sum(
                    numeric(item.get("read_events")) or 0 for item in terminals
                ),
                "sendmes": sum(
                    numeric(item.get("sendmes")) or 0 for item in terminals
                ),
                "sendme_ok": sum(
                    numeric(item.get("sendme_ok")) or 0 for item in terminals
                ),
                "min_recv_window_after_take": row_min(
                    terminals, "min_recv_window_after_take"
                ),
                "max_queued_after_bytes": row_max(terminals, "max_queued_after_bytes"),
                "median_transfer_ms": median(transfer_ms) if transfer_ms else None,
                "max_transfer_ms": max(transfer_ms) if transfer_ms else None,
                "max_data_gap_ms": max(
                    (numeric(item.get("max_data_gap_ms")) or 0 for item in terminals),
                    default=0,
                ),
                "max_idle_after_last_data_ms": max(
                    (
                        numeric(item.get("idle_after_last_data_ms")) or 0
                        for item in terminals
                    ),
                    default=0,
                ),
                "max_first_data_after_start_ms": max(
                    (
                        numeric(item.get("first_data_after_start_ms")) or 0
                        for item in terminals
                    ),
                    default=0,
                ),
                "top_stream_id": top.get("stream_id"),
            }
        )
    return sorted(
        rows,
        key=lambda row: numeric(row.get("max_transfer_ms")) or 0,
        reverse=True,
    )


def torfast_stream_receiver_terminal_top_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    rows = []
    seen: set[tuple[object, object, object, object, object]] = set()

    def append_rows(
        *,
        profile_name: str,
        target: object = "",
        run_index: object = None,
        load_ms: object = None,
        lines: list[str],
    ) -> None:
        line_strings = dedupe_lines([str(line) for line in lines])
        socks_rows = list(
            group_torfast_socks_timings(
                parse_torfast_socks_timings(line_strings)
            ).values()
        )
        timings = parse_torfast_stream_receiver_timings(line_strings)
        terminals = [item for item in timings if item.get("event") == "terminal"]
        no_end_closes = [
            item for item in timings if item.get("event") == "no_end_close"
        ]
        close_decisions = [
            item
            for item in parse_torfast_stream_lifecycle_timings(line_strings)
            if item.get("delivery") == "close_decision"
        ]
        for item in terminals:
            socks_row = matching_socks_row_for_terminal(item, socks_rows)
            matching_no_end = matching_stream_receiver_events_for_terminal(
                item, no_end_closes
            )
            matching_close_decisions = matching_stream_receiver_events_for_terminal(
                item, close_decisions
            )
            key = (
                profile_name,
                target,
                run_index,
                item.get("stream_id"),
                item.get("event_epoch_ms") or item.get("timestamp_ms"),
            )
            if key in seen:
                continue
            seen.add(key)
            relay_bytes = numeric(item.get("relay_data_bytes")) or 0
            user_bytes = numeric(item.get("user_read_bytes")) or 0
            transfer_ms = numeric(item.get("transfer_ms")) or 0
            max_gap_ms = numeric(item.get("max_data_gap_ms")) or 0
            idle_ms = numeric(item.get("idle_after_last_data_ms")) or 0
            first_data_ms = numeric(item.get("first_data_after_start_ms")) or 0
            rows.append(
                {
                    "profile": profile_name,
                    "target": target,
                    "run_index": run_index,
                    "load_ms": load_ms,
                    "timing_id": socks_row.get("timing_id"),
                    "target_kind": socks_row.get("target_kind", ""),
                    "socks_relay_ms": socks_row.get("relay_ms"),
                    "socks_ok": socks_row.get("ok"),
                    "copy_error_kind": socks_row.get("copy_error_kind", ""),
                    "stream_id": item.get("stream_id"),
                    "circ_id": item.get("circ_id", ""),
                    "connected": item.get("connected"),
                    "not_connected_source": item.get("not_connected_source", ""),
                    "stream_close_cause": item.get("stream_close_cause", ""),
                    "returned_eof": item.get("returned_eof"),
                    "transfer_ms": transfer_ms,
                    "max_data_gap_ms": max_gap_ms,
                    "idle_after_last_data_ms": idle_ms,
                    "first_data_after_start_ms": first_data_ms,
                    "relay_kib": relay_bytes / 1024.0,
                    "user_kib": user_bytes / 1024.0,
                    "data_cells": numeric(item.get("data_cells")),
                    "read_events": numeric(item.get("read_events")),
                    "sendmes": numeric(item.get("sendmes")),
                    "sendme_ok": numeric(item.get("sendme_ok")),
                    "no_end_close_events": len(matching_no_end),
                    "no_end_close_read_events": row_max(
                        matching_no_end, "read_events"
                    ),
                    "no_end_close_queued_after_bytes": row_max(
                        matching_no_end, "queued_after_bytes"
                    ),
                    "close_decision_events": len(matching_close_decisions),
                    "close_reasons": compact_counts(
                        count_labels(
                            item.get("close_reason")
                            for item in matching_close_decisions
                        )
                    ),
                    "close_should_send_end": compact_counts(
                        count_labels(
                            item.get("should_send_end")
                            for item in matching_close_decisions
                        )
                    ),
                    "close_behaviors": compact_counts(
                        count_labels(
                            item.get("close_behavior")
                            for item in matching_close_decisions
                        )
                    ),
                    "_close_reason_values": [
                        str(item.get("close_reason") or "unknown")
                        for item in matching_close_decisions
                    ],
                    "_close_should_send_end_values": [
                        str(item.get("should_send_end") or "unknown")
                        for item in matching_close_decisions
                    ],
                    "min_recv_window_after_take": numeric(
                        item.get("min_recv_window_after_take")
                    ),
                    "max_queued_after_bytes": numeric(
                        item.get("max_queued_after_bytes")
                    ),
                    "error_kind": item.get("error_kind", ""),
                    "_sort_ms": max(
                        transfer_ms,
                        max_gap_ms,
                        idle_ms,
                        first_data_ms,
                    ),
                }
            )

    run_keys: set[str] = set()
    for profile_name, _profile, target, _summary, run in iter_runs(payload):
        lines = run_torfast_lines(run)
        if not lines:
            continue
        append_rows(
            profile_name=profile_name,
            target=target,
            run_index=run.get("run_index"),
            load_ms=run.get("load_ms"),
            lines=lines,
        )
        run_keys.add(profile_name)

    profiles = payload.get("profiles", {})
    if isinstance(profiles, dict):
        for profile_name, profile in sorted(profiles.items()):
            if (
                not isinstance(profile, dict)
                or profile.get("skipped")
                or profile_name in run_keys
            ):
                continue
            append_rows(profile_name=profile_name, lines=proxy_log_lines(profile))
    return sorted(
        rows,
        key=lambda row: (
            numeric(row.get("_sort_ms")) or 0,
            numeric(row.get("transfer_ms")) or 0,
            numeric(row.get("max_data_gap_ms")) or 0,
            numeric(row.get("idle_after_last_data_ms")) or 0,
        ),
        reverse=True,
    )


def torfast_stream_receiver_not_connected_summary_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    grouped: dict[tuple[str, object, object], list[dict[str, object]]] = {}
    for row in torfast_stream_receiver_terminal_top_rows(payload):
        if not stream_receiver_row_is_not_connected(row):
            continue
        key = (
            str(row.get("profile", "")),
            row.get("target", ""),
            row.get("run_index"),
        )
        grouped.setdefault(key, []).append(row)

    rows: list[dict[str, object]] = []
    for (profile, target, run_index), group_rows in grouped.items():
        target_kind_counts = count_labels(
            str(row.get("target_kind") or "unknown") for row in group_rows
        )
        sorted_rows = sorted(
            group_rows, key=promotion_risk_receiver_sort_key, reverse=True
        )
        rows.append(
            {
                "profile": profile,
                "target": target,
                "run_index": run_index,
                "load_ms": row_max(group_rows, "load_ms"),
                "not_connected_streams": len(group_rows),
                "hostname_streams": target_kind_counts.get("hostname", 0),
                "onion_streams": target_kind_counts.get("onion", 0),
                "max_socks_relay_ms": row_max(group_rows, "socks_relay_ms"),
                "max_idle_after_last_data_ms": row_max(
                    group_rows, "idle_after_last_data_ms"
                ),
                "max_transfer_ms": row_max(group_rows, "transfer_ms"),
                "max_data_gap_ms": row_max(group_rows, "max_data_gap_ms"),
                "max_first_data_after_start_ms": row_max(
                    group_rows, "first_data_after_start_ms"
                ),
                "top_not_connected_sources": compact_counts(
                    count_labels(
                        row.get("not_connected_source")
                        for row in group_rows
                        if row.get("not_connected_source")
                    )
                ),
                "top_stream_close_causes": compact_counts(
                    count_labels(
                        row.get("stream_close_cause")
                        for row in group_rows
                        if row.get("stream_close_cause")
                    )
                ),
                "top_timing_ids": compact_list(
                    [row.get("timing_id") for row in sorted_rows], max_items=4
                ),
                "top_circuits": compact_list(
                    [row.get("circ_id") for row in sorted_rows], max_items=3
                ),
                "top_stream_ids": compact_list(
                    [row.get("stream_id") for row in sorted_rows], max_items=4
                ),
            }
        )

    return sorted(
        rows,
        key=lambda row: (
            numeric(row.get("max_idle_after_last_data_ms")) or 0,
            numeric(row.get("max_socks_relay_ms")) or 0,
            numeric(row.get("not_connected_streams")) or 0,
        ),
        reverse=True,
    )


def stream_receiver_row_is_not_connected(row: dict[str, object]) -> bool:
    return (
        row.get("error_kind") == "not_connected"
        or row.get("copy_error_kind") == "not_connected"
    )


def positive_ms(row: dict[str, object], field: str) -> float | None:
    value = numeric(row.get(field))
    if value is None or value <= 0:
        return None
    return value


def socks_row_has_client_eof_tor_error(row: dict[str, object]) -> bool:
    return (
        positive_ms(row, "client_to_tor_eof_ms") is not None
        and positive_ms(row, "tor_to_client_error_ms") is not None
    )


def socks_row_is_same_close_not_connected(row: dict[str, object]) -> bool:
    if row.get("copy_error_kind") != "not_connected":
        return False
    if row.get("stream_close_cause") == "stream_target_closed":
        return True
    return socks_row_has_client_eof_tor_error(row) and abs(
        numeric(row.get("client_eof_to_tor_error_ms")) or 0
    ) <= 5


def socks_row_is_client_reset_end_close(
    row: dict[str, object],
    lifecycle_rows: list[dict[str, object]],
    *,
    tolerance_ms: float = 5.0,
) -> bool:
    client_error_ms = positive_ms(row, "client_to_tor_error_ms")
    start_epoch_ms = numeric(row.get("conn_started_epoch_ms"))
    if (
        row.get("copy_error_kind") != "connection_reset"
        or client_error_ms is None
        or start_epoch_ms is None
    ):
        return False
    if positive_ms(row, "tor_to_client_error_ms") is not None:
        return False
    if positive_ms(row, "tor_to_client_write_error_ms") is not None:
        return False
    for item in lifecycle_rows_for_socks(row, lifecycle_rows):
        if item.get("relay_cmd") != "END" or item.get("delivery") != "channel_queued":
            continue
        event_epoch_ms = numeric(item.get("event_epoch_ms"))
        if event_epoch_ms is None:
            continue
        if abs((event_epoch_ms - start_epoch_ms) - client_error_ms) <= tolerance_ms:
            return True
    return False


def socks_row_is_remote_end_client_close(
    row: dict[str, object],
    lifecycle_rows: list[dict[str, object]],
    *,
    tolerance_ms: float = 5.0,
) -> bool:
    client_eof_ms = positive_ms(row, "client_to_tor_eof_ms")
    tor_eof_ms = positive_ms(row, "tor_to_client_eof_ms")
    last_tor_ms = positive_ms(row, "last_tor_to_client_ms")
    start_epoch_ms = numeric(row.get("conn_started_epoch_ms"))
    if client_eof_ms is None or start_epoch_ms is None:
        return False
    close_ms = tor_eof_ms if tor_eof_ms is not None else last_tor_ms
    if close_ms is None or abs(client_eof_ms - close_ms) > tolerance_ms:
        return False
    for item in lifecycle_rows_for_socks(row, lifecycle_rows):
        if item.get("relay_cmd") != "END" or item.get("delivery") != "delivered":
            continue
        event_epoch_ms = numeric(item.get("event_epoch_ms"))
        if event_epoch_ms is None:
            continue
        if abs((event_epoch_ms - start_epoch_ms) - close_ms) <= tolerance_ms:
            return True
    return False


def socks_row_is_resolved_client_close(
    row: dict[str, object], lifecycle_rows: list[dict[str, object]]
) -> bool:
    return (
        socks_row_is_same_close_not_connected(row)
        or socks_row_is_client_reset_end_close(row, lifecycle_rows)
        or socks_row_is_remote_end_client_close(row, lifecycle_rows)
    )


def set_positive_delta(
    row: dict[str, object], name: str, start_field: str, end_field: str
) -> None:
    start = positive_ms(row, start_field)
    end = positive_ms(row, end_field)
    if start is not None and end is not None:
        row[name] = end - start


def matching_socks_row_for_terminal(
    terminal: dict[str, object], socks_rows: list[dict[str, object]]
) -> dict[str, object]:
    stream_id = terminal.get("stream_id")
    circ_id = terminal.get("circ_id")
    if stream_id is None:
        return {}
    for row in socks_rows:
        if row.get("stream_id") != stream_id:
            continue
        if circ_id is None or row.get("circ_id") is None:
            return row
        if torfast_circ_ids_match(circ_id, row.get("circ_id")):
            return row
    return {}


def matching_stream_receiver_events_for_terminal(
    terminal: dict[str, object], events: list[dict[str, object]]
) -> list[dict[str, object]]:
    stream_id = terminal.get("stream_id")
    circ_id = terminal.get("circ_id")
    if stream_id is None:
        return []
    rows = []
    for row in events:
        if row.get("stream_id") != stream_id:
            continue
        if circ_id is not None and row.get("circ_id") is not None:
            if not torfast_circ_ids_match(circ_id, row.get("circ_id")):
                continue
        rows.append(row)
    return rows


def count_event_at_least(
    timings: list[dict[str, object]], event: str, field: str, threshold: float
) -> int:
    return sum(
        1
        for item in timings
        if item.get("event") == event
        and isinstance(item.get(field), (int, float))
        and item[field] >= threshold
    )


def connect_attempt_trace_item(item: dict[str, object]) -> str | None:
    attempt = item.get("attempt")
    if attempt is None:
        return None
    event = item.get("event")
    if event == "connect_soft_timeout":
        status = "soft_timeout"
        elapsed = item.get("attempt_ms")
    elif event == "connect_retry":
        status = f"retry_{item.get('error_kind', 'error')}"
        elapsed = item.get("attempt_ms")
    elif event == "connect_retry_succeeded":
        status = "ok"
        elapsed = item.get("attempt_ms")
    elif event == "connect_failed":
        status = f"failed_{item.get('error_kind', 'error')}"
        elapsed = item.get("connect_ms") or item.get("elapsed_ms")
    else:
        return None
    elapsed_text = f"{fmt(elapsed)}ms" if elapsed is not None else ""
    return f"{fmt(attempt)}:{status}:{elapsed_text}"


def group_torfast_socks_timings(
    timings: list[dict[str, object]],
) -> dict[object, dict[str, object]]:
    grouped: dict[object, dict[str, object]] = {}
    for item in timings:
        timing_id = item.get("timing_id")
        if timing_id is None:
            continue
        row = grouped.setdefault(timing_id, {"timing_id": timing_id})
        event = item.get("event")
        if "port" in item:
            row["port"] = item["port"]
        if "target_kind" in item:
            row["target_kind"] = item["target_kind"]
        if "target_label" in item:
            row["target_label"] = item["target_label"]
        copy_if_present(row, item, "conn_started_epoch_ms")
        copy_if_present(row, item, "client_peer_port")
        copy_if_present(row, item, "soft_timeout_attempts")
        attempt_trace = connect_attempt_trace_item(item)
        if attempt_trace is not None:
            row.setdefault("connect_attempt_trace", []).append(attempt_trace)
        if event == "request_parsed":
            if "command" in item:
                row["command"] = item["command"]
            set_max_elapsed(row, item)
        elif event == "connect_hedge_launched":
            row["connect_hedge_launched"] = (
                int(row.get("connect_hedge_launched", 0)) + 1
            )
            copy_if_present(row, item, "hedge_after_ms")
            copy_if_present(row, item, "backup_isolated")
            copy_if_present(row, item, "attempt")
            copy_if_present(row, item, "connect_ms")
            set_max_elapsed(row, item)
        elif event == "connect_hedge_succeeded":
            row["connect_hedge_succeeded"] = (
                int(row.get("connect_hedge_succeeded", 0)) + 1
            )
            copy_if_present(row, item, "winner_attempt")
            copy_if_present(row, item, "hedge_after_ms")
            copy_if_present(row, item, "hedge_wait_ms")
            copy_if_present(row, item, "connect_ms")
            set_max_elapsed(row, item)
        elif event == "connect_hedge_skipped_inflight":
            row["connect_hedge_skipped_inflight"] = (
                int(row.get("connect_hedge_skipped_inflight", 0)) + 1
            )
            copy_if_present(row, item, "hedge_after_ms")
            copy_if_present(row, item, "connect_ms")
            set_max_elapsed(row, item)
        elif event == "connect_hedge_retry":
            row["connect_hedge_retries"] = (
                int(row.get("connect_hedge_retries", 0)) + 1
            )
            copy_if_present(row, item, "primary_error_kind")
            copy_if_present(row, item, "error_kind")
            copy_if_present(row, item, "hedge_after_ms")
            copy_if_present(row, item, "attempt_ms")
            set_max_elapsed(row, item)
        elif event == "connect_hedge_retry_succeeded":
            row["connect_hedge_retry_succeeded"] = (
                int(row.get("connect_hedge_retry_succeeded", 0)) + 1
            )
            copy_if_present(row, item, "attempt")
            copy_if_present(row, item, "hedge_after_ms")
            copy_if_present(row, item, "attempt_ms")
            copy_if_present(row, item, "connect_ms")
            set_max_elapsed(row, item)
        elif event == "connect_hedge_peer_failed":
            row["connect_hedge_peer_failed"] = (
                int(row.get("connect_hedge_peer_failed", 0)) + 1
            )
            copy_if_present(row, item, "attempt")
            copy_if_present(row, item, "error_kind")
            copy_if_present(row, item, "hedge_after_ms")
            copy_if_present(row, item, "hedge_wait_ms")
            set_max_elapsed(row, item)
        elif event == "connect_hedge_failed":
            row["connect_hedge_failed"] = int(row.get("connect_hedge_failed", 0)) + 1
            copy_if_present(row, item, "primary_error_kind")
            copy_if_present(row, item, "hedge_error_kind")
            copy_if_present(row, item, "retry_error_kind")
            copy_if_present(row, item, "error_kind")
            copy_if_present(row, item, "hedge_after_ms")
            copy_if_present(row, item, "connect_ms")
            set_max_elapsed(row, item)
        elif event == "connect_retry":
            row["connect_retries"] = int(row.get("connect_retries", 0)) + 1
            copy_if_present(row, item, "error_kind")
            row["last_retry_elapsed_ms"] = item.get("elapsed_ms")
            set_max_elapsed(row, item)
        elif event == "connect_soft_timeout":
            row["connect_soft_timeouts"] = int(row.get("connect_soft_timeouts", 0)) + 1
            copy_if_present(row, item, "soft_timeout_ms")
            copy_if_present(row, item, "attempt_ms")
            row["last_soft_timeout_elapsed_ms"] = item.get("elapsed_ms")
            set_max_elapsed(row, item)
        elif event == "connect_retry_succeeded":
            row["connect_retry_succeeded"] = True
            copy_if_present(row, item, "attempt")
            copy_if_present(row, item, "attempt_ms")
            copy_if_present(row, item, "connect_ms")
            set_max_elapsed(row, item)
        elif event == "stream_ready":
            copy_if_present(row, item, "connect_ms")
            row["stream_elapsed_ms"] = item.get("elapsed_ms")
            set_max_elapsed(row, item)
        elif event == "stream_linked":
            copy_if_present(row, item, "circ_id")
            copy_if_present(row, item, "hop")
            copy_if_present(row, item, "stream_id")
            row["stream_linked"] = True
            set_max_elapsed(row, item)
        elif event == "socks_reply_sent":
            row["reply_elapsed_ms"] = item.get("elapsed_ms")
            set_max_elapsed(row, item)
        elif event == "relay_finished":
            copy_if_present(row, item, "circ_id")
            copy_if_present(row, item, "hop")
            copy_if_present(row, item, "stream_id")
            copy_if_present(row, item, "relay_ms")
            copy_if_present(row, item, "first_client_to_tor_ms")
            copy_if_present(row, item, "last_client_to_tor_ms")
            copy_if_present(row, item, "client_to_tor_eof_ms")
            copy_if_present(row, item, "client_to_tor_error_ms")
            copy_if_present(row, item, "first_client_to_tor_write_ms")
            copy_if_present(row, item, "first_client_to_tor_write_epoch_ms")
            copy_if_present(row, item, "last_client_to_tor_write_ms")
            copy_if_present(row, item, "client_to_tor_write_error_ms")
            copy_if_present(row, item, "client_to_tor_write_close_ms")
            copy_if_present(row, item, "client_to_tor_write_close_error_ms")
            copy_if_present(row, item, "first_tor_to_client_ms")
            copy_if_present(row, item, "first_tor_to_client_epoch_ms")
            copy_if_present(row, item, "last_tor_to_client_ms")
            copy_if_present(row, item, "tor_to_client_eof_ms")
            copy_if_present(row, item, "tor_to_client_error_ms")
            copy_if_present(row, item, "first_tor_to_client_write_ms")
            copy_if_present(row, item, "first_tor_to_client_write_epoch_ms")
            copy_if_present(row, item, "last_tor_to_client_write_ms")
            copy_if_present(row, item, "tor_to_client_write_error_ms")
            copy_if_present(row, item, "tor_to_client_write_close_ms")
            copy_if_present(row, item, "tor_to_client_write_close_error_ms")
            copy_if_present(row, item, "client_to_tor_bytes")
            copy_if_present(row, item, "client_to_tor_write_bytes")
            copy_if_present(row, item, "tor_to_client_bytes")
            copy_if_present(row, item, "tor_to_client_write_bytes")
            copy_if_present(row, item, "copy_error_kind")
            copy_if_present(row, item, "copy_error")
            copy_if_present(row, item, "ok")
            set_max_elapsed(row, item)
            idle_after_last = tor_to_client_idle_after_last_ms(row)
            if idle_after_last is not None:
                row["tor_to_client_idle_after_last_ms"] = idle_after_last
            set_positive_delta(
                row,
                "client_eof_to_tor_error_ms",
                "client_to_tor_eof_ms",
                "tor_to_client_error_ms",
            )
            set_positive_delta(
                row,
                "client_eof_to_tor_writer_close_ms",
                "client_to_tor_eof_ms",
                "client_to_tor_write_close_ms",
            )
            set_positive_delta(
                row,
                "last_tor_byte_to_client_eof_ms",
                "last_tor_to_client_ms",
                "client_to_tor_eof_ms",
            )
            set_positive_delta(
                row,
                "last_tor_byte_to_tor_error_ms",
                "last_tor_to_client_ms",
                "tor_to_client_error_ms",
            )
        elif event == "connect_failed":
            row["connect_failed"] = True
            copy_if_present(row, item, "error_kind")
            copy_if_present(row, item, "connect_ms")
            copy_if_present(row, item, "soft_timeout_ms")
            copy_if_present(row, item, "attempt")
            set_max_elapsed(row, item)
    return grouped


def torfast_socks_connect_retry_rows(
    timings: list[dict[str, object]],
) -> list[dict[str, object]]:
    rows = []
    for row in group_torfast_socks_timings(timings).values():
        if (
            row.get("connect_soft_timeouts")
            or row.get("connect_retries")
            or row.get("connect_retry_succeeded")
            or row.get("connect_failed")
        ):
            rows.append(row)
    return sorted(rows, key=lambda row: numeric(row.get("timing_id")) or 0)


def torfast_socks_connect_hedge_rows(
    timings: list[dict[str, object]],
) -> list[dict[str, object]]:
    rows = []
    hedge_fields = (
        "connect_hedge_launched",
        "connect_hedge_succeeded",
        "connect_hedge_skipped_inflight",
        "connect_hedge_retries",
        "connect_hedge_retry_succeeded",
        "connect_hedge_peer_failed",
        "connect_hedge_failed",
    )
    for row in group_torfast_socks_timings(timings).values():
        if any(row.get(field) for field in hedge_fields):
            rows.append(row)
    return sorted(rows, key=lambda row: numeric(row.get("timing_id")) or 0)


def torfast_circ_ids_match(left: object, right: object) -> bool:
    if not isinstance(left, str) or not isinstance(right, str):
        return False
    return left == right or left.startswith(right) or right.startswith(left)


SOCKS_STREAM_JOIN_FIELDS = (
    "target_label",
    "port",
    "hop",
    "conn_started_epoch_ms",
    "connect_ms",
    "reply_elapsed_ms",
    "first_client_to_tor_ms",
    "last_client_to_tor_ms",
    "client_to_tor_eof_ms",
    "client_to_tor_error_ms",
    "first_client_to_tor_write_ms",
    "first_client_to_tor_write_epoch_ms",
    "last_client_to_tor_write_ms",
    "client_to_tor_write_error_ms",
    "client_to_tor_write_close_ms",
    "client_to_tor_write_close_error_ms",
    "first_tor_to_client_ms",
    "first_tor_to_client_epoch_ms",
    "last_tor_to_client_ms",
    "tor_to_client_eof_ms",
    "tor_to_client_error_ms",
    "first_tor_to_client_write_ms",
    "first_tor_to_client_write_epoch_ms",
    "last_tor_to_client_write_ms",
    "tor_to_client_write_error_ms",
    "tor_to_client_write_close_ms",
    "tor_to_client_write_close_error_ms",
    "tor_to_client_idle_after_last_ms",
    "total_elapsed_ms",
    "relay_ms",
    "client_to_tor_bytes",
    "client_to_tor_write_bytes",
    "tor_to_client_bytes",
    "tor_to_client_write_bytes",
)


def torfast_socks_stream_rows(lines: list[str]) -> list[dict[str, object]]:
    rows = []
    for socks_row in group_torfast_socks_timings(
        parse_torfast_socks_timings(lines)
    ).values():
        stream_id = socks_row.get("stream_id")
        circ_id = socks_row.get("circ_id")
        if stream_id is None or circ_id is None:
            continue
        row = {
            "timing_id": socks_row.get("timing_id"),
            "target_kind": socks_row.get("target_kind"),
            "circ_id": circ_id,
            "stream_id": stream_id,
            "joined_relay_receive": False,
        }
        for field in SOCKS_STREAM_JOIN_FIELDS:
            if field in socks_row:
                row[field] = socks_row[field]
        rows.append(row)
    return sorted(
        rows,
        key=lambda row: (
            numeric(row.get("relay_ms")) or 0,
            numeric(row.get("tor_to_client_bytes")) or 0,
        ),
        reverse=True,
    )


def torfast_socks_relay_join_rows(lines: list[str]) -> list[dict[str, object]]:
    socks_rows = group_torfast_socks_timings(parse_torfast_socks_timings(lines)).values()
    relay_rows = torfast_relay_receive_stream_rows(
        parse_torfast_relay_receive_timings(lines)
    )

    rows = []
    for socks_row in socks_rows:
        stream_id = socks_row.get("stream_id")
        circ_id = socks_row.get("circ_id")
        if stream_id is None or circ_id is None:
            continue
        matches = [
            relay_row
            for relay_row in relay_rows
            if relay_row.get("stream_id") == stream_id
            and torfast_circ_ids_match(circ_id, relay_row.get("circ_id"))
        ]
        for relay_row in matches:
            row = {
                "timing_id": socks_row.get("timing_id"),
                "target_kind": socks_row.get("target_kind"),
                "circ_id": relay_row.get("circ_id") or circ_id,
                "stream_id": stream_id,
                "joined_relay_receive": True,
            }
            for field in SOCKS_STREAM_JOIN_FIELDS:
                if field in socks_row:
                    row[field] = socks_row[field]
            for field in (
                "relay_ms",
                "client_to_tor_bytes",
                "client_to_tor_write_bytes",
                "tor_to_client_bytes",
                "tor_to_client_write_bytes",
                "data_cells",
                "data_bytes",
                "span_ms",
                "first_receive_epoch_ms",
                "last_receive_epoch_ms",
                "max_gap_ms",
                "max_queued_after_bytes",
            ):
                if field in socks_row:
                    row[field] = socks_row[field]
                if field in relay_row:
                    row[field] = relay_row[field]
            rows.append(row)

    return sorted(
        rows,
        key=lambda row: (
            numeric(row.get("max_gap_ms")) or 0,
            numeric(row.get("span_ms")) or 0,
            numeric(row.get("relay_ms")) or 0,
        ),
        reverse=True,
    )


def torfast_socks_relay_join_epoch_ms(row: dict[str, object]) -> float | None:
    for field in ("conn_started_epoch_ms", "first_tor_to_client_epoch_ms"):
        value = numeric(row.get(field))
        if value is not None:
            return value
    return None


def torfast_socks_row_epoch_ms(row: dict[str, object]) -> float | None:
    for field in ("conn_started_epoch_ms", "first_tor_to_client_epoch_ms"):
        value = numeric(row.get(field))
        if value is not None:
            return value
    return None


def torfast_socks_relay_join_run_summary_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    rows = []
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return rows
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        joined_rows = torfast_socks_relay_join_rows([str(line) for line in lines])
        if not joined_rows:
            continue
        records = profile_browser_run_records(profile)
        if not records:
            continue
        bounds = browser_run_epoch_bounds([run for _target, run, _index in records])
        for record_index, (target, run, original_index) in enumerate(records):
            lower, upper = bounds[record_index]
            time_origin = browser_time_origin_ms(run)
            load_epoch = browser_load_epoch_ms(run)
            run_rows = [
                row
                for row in joined_rows
                if torfast_socks_relay_join_epoch_ms(row) is not None
                and lower <= (torfast_socks_relay_join_epoch_ms(row) or 0) < upper
            ]
            if not run_rows:
                continue

            circuits = {
                row.get("circ_id") for row in run_rows if row.get("circ_id") is not None
            }
            stream_keys = {
                (row.get("circ_id"), row.get("stream_id"))
                for row in run_rows
                if row.get("stream_id") is not None
            }
            start_epochs = [
                value
                for value in (torfast_socks_relay_join_epoch_ms(row) for row in run_rows)
                if value is not None
            ]
            first_receive_epochs = [
                value
                for value in (
                    numeric(row.get("first_receive_epoch_ms")) for row in run_rows
                )
                if value is not None
            ]
            last_receive_epochs = [
                value
                for value in (
                    numeric(row.get("last_receive_epoch_ms")) for row in run_rows
                )
                if value is not None
            ]
            max_gaps = [
                value
                for value in (numeric(row.get("max_gap_ms")) for row in run_rows)
                if value is not None
            ]
            spans = [
                value
                for value in (numeric(row.get("span_ms")) for row in run_rows)
                if value is not None
            ]
            queued = [
                value
                for value in (
                    numeric(row.get("max_queued_after_bytes")) for row in run_rows
                )
                if value is not None
            ]
            top_row = max(
                run_rows,
                key=lambda row: (
                    numeric(row.get("max_gap_ms")) or 0,
                    numeric(row.get("span_ms")) or 0,
                    numeric(row.get("data_bytes")) or 0,
                ),
            )

            rows.append(
                {
                    "profile": profile_name,
                    "target": target,
                    "run_index": run.get("run_index", original_index + 1),
                    "load_ms": run.get("load_ms"),
                    "joined_streams": len(stream_keys),
                    "unique_circuits": len(circuits),
                    "data_cells": sum(
                        int(numeric(row.get("data_cells")) or 0) for row in run_rows
                    ),
                    "data_bytes": sum(
                        int(numeric(row.get("data_bytes")) or 0) for row in run_rows
                    ),
                    "tor_to_client_bytes": sum(
                        int(numeric(row.get("tor_to_client_bytes")) or 0)
                        for row in run_rows
                    ),
                    "first_stream_after_start_ms": subtract_numeric(
                        min(start_epochs) if start_epochs else None,
                        time_origin,
                    ),
                    "first_relay_receive_after_start_ms": subtract_numeric(
                        min(first_receive_epochs) if first_receive_epochs else None,
                        time_origin,
                    ),
                    "last_relay_receive_before_load_ms": subtract_numeric(
                        load_epoch,
                        max(last_receive_epochs) if last_receive_epochs else None,
                    ),
                    "max_receive_gap_ms": max(max_gaps) if max_gaps else None,
                    "max_receive_span_ms": max(spans) if spans else None,
                    "max_queued_after_bytes": max(queued) if queued else None,
                    "top_timing_id": top_row.get("timing_id"),
                    "top_circ_id": top_row.get("circ_id"),
                    "top_stream_id": top_row.get("stream_id"),
                }
            )
    return rows


def torfast_socks_relay_circuit_shape_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    rows = []
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return rows
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        line_strings = [str(line) for line in lines]
        joined_rows = torfast_socks_relay_join_rows(line_strings)
        if not joined_rows:
            joined_rows = torfast_socks_stream_rows(line_strings)
        if not joined_rows:
            continue
        records = profile_browser_run_records(profile)
        if not records:
            continue
        bounds = browser_run_epoch_bounds([run for _target, run, _index in records])
        for record_index, (target, run, original_index) in enumerate(records):
            lower, upper = bounds[record_index]
            run_rows = [
                row
                for row in joined_rows
                if torfast_socks_relay_join_epoch_ms(row) is not None
                and lower <= (torfast_socks_relay_join_epoch_ms(row) or 0) < upper
                and row.get("circ_id") is not None
            ]
            grouped: dict[object, list[dict[str, object]]] = {}
            for row in run_rows:
                grouped.setdefault(row.get("circ_id"), []).append(row)

            for circ_id, circuit_rows in grouped.items():
                stream_keys = {
                    row.get("stream_id")
                    for row in circuit_rows
                    if row.get("stream_id") is not None
                }
                top_row = max(
                    circuit_rows,
                    key=lambda row: (
                        numeric(row.get("span_ms")) or 0,
                        numeric(row.get("max_gap_ms")) or 0,
                        numeric(row.get("data_bytes")) or 0,
                    ),
                )
                rows.append(
                    {
                        "profile": profile_name,
                        "target": target,
                        "run_index": run.get("run_index", original_index + 1),
                        "load_ms": run.get("load_ms"),
                        "circ_id": circ_id,
                        "streams": len(stream_keys),
                        "data_bytes": sum(
                            int(numeric(row.get("data_bytes")) or 0)
                            for row in circuit_rows
                        ),
                        "tor_to_client_bytes": sum(
                            int(numeric(row.get("tor_to_client_bytes")) or 0)
                            for row in circuit_rows
                        ),
                        "max_receive_span_ms": max(
                            (
                                numeric(row.get("span_ms"))
                                for row in circuit_rows
                                if numeric(row.get("span_ms")) is not None
                            ),
                            default=None,
                        ),
                        "max_receive_gap_ms": max(
                            (
                                numeric(row.get("max_gap_ms"))
                                for row in circuit_rows
                                if numeric(row.get("max_gap_ms")) is not None
                            ),
                            default=None,
                        ),
                        "max_queued_after_bytes": max(
                            (
                                numeric(row.get("max_queued_after_bytes"))
                                for row in circuit_rows
                                if numeric(row.get("max_queued_after_bytes"))
                                is not None
                            ),
                            default=None,
                        ),
                        "top_timing_id": top_row.get("timing_id"),
                        "top_stream_id": top_row.get("stream_id"),
                    }
                )
    return sorted(
        rows,
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0,
            -(numeric(row.get("data_bytes")) or 0),
            -(numeric(row.get("max_receive_span_ms")) or 0),
        ),
    )


def torfast_socks_relay_circuit_quality_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    rows = []
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return rows
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        records = profile_browser_run_records(profile)
        if not records:
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        joined_rows = torfast_socks_relay_join_rows([str(line) for line in lines])
        joined_run_keys = set()
        bounds = browser_run_epoch_bounds([run for _target, run, _index in records])
        for record_index, (target, run, original_index) in enumerate(records):
            run_index = run.get("run_index", original_index + 1)
            lower, upper = bounds[record_index]
            run_rows = [
                row
                for row in joined_rows
                if torfast_socks_relay_join_epoch_ms(row) is not None
                and lower <= (torfast_socks_relay_join_epoch_ms(row) or 0) < upper
                and row.get("circ_id") is not None
            ]
            if not run_rows:
                continue
            joined_run_keys.add((target, run_index))
            grouped: dict[object, list[dict[str, object]]] = {}
            for row in run_rows:
                grouped.setdefault(row.get("circ_id"), []).append(row)

            for circ_id, circuit_rows in grouped.items():
                stream_keys = {
                    row.get("stream_id")
                    for row in circuit_rows
                    if row.get("stream_id") is not None
                }
                data_bytes = sum(
                    int(numeric(row.get("data_bytes")) or 0) for row in circuit_rows
                )
                tor_to_client_bytes = sum(
                    int(numeric(row.get("tor_to_client_bytes")) or 0)
                    for row in circuit_rows
                )
                first_bytes = numeric_values(
                    circuit_rows, "first_tor_to_client_ms", positive=True
                )
                relay_ms = numeric_values(circuit_rows, "relay_ms")
                spans = numeric_values(circuit_rows, "span_ms")
                gaps = numeric_values(circuit_rows, "max_gap_ms")
                queued = numeric_values(circuit_rows, "max_queued_after_bytes")
                max_span = max(spans) if spans else None
                top_row = max(
                    circuit_rows,
                    key=lambda row: (
                        numeric(row.get("span_ms")) or 0,
                        numeric(row.get("max_gap_ms")) or 0,
                        numeric(row.get("data_bytes")) or 0,
                    ),
                )
                rows.append(
                    {
                        "profile": profile_name,
                        "target": target,
                        "run_index": run_index,
                        "load_ms": run.get("load_ms"),
                        "circ_id": circ_id,
                        "streams": len(stream_keys),
                        "relay_streams": len(relay_ms),
                        "data_bytes": data_bytes,
                        "tor_to_client_bytes": tor_to_client_bytes,
                        "median_first_tor_to_client_ms": (
                            median(first_bytes) if first_bytes else None
                        ),
                        "median_relay_ms": median(relay_ms) if relay_ms else None,
                        "max_relay_ms": max(relay_ms) if relay_ms else None,
                        "max_receive_span_ms": max_span,
                        "max_receive_gap_ms": max(gaps) if gaps else None,
                        "max_queued_after_bytes": max(queued) if queued else None,
                        "rough_receive_kib_s": rough_kib_per_second(
                            data_bytes, max_span
                        ),
                        "top_timing_id": top_row.get("timing_id"),
                        "top_stream_id": top_row.get("stream_id"),
                    }
                )
        for target, run, original_index in records:
            run_index = run.get("run_index", original_index + 1)
            if (target, run_index) in joined_run_keys:
                continue
            rows.extend(
                torfast_terminal_circuit_quality_rows_for_run(
                    profile_name=profile_name,
                    target=target,
                    run=run,
                    run_index=run_index,
                )
            )
    return sorted(
        rows,
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0,
            -(numeric(row.get("max_relay_ms")) or 0),
            -(numeric(row.get("max_receive_span_ms")) or 0),
        ),
    )


def torfast_terminal_circuit_quality_rows_for_run(
    profile_name: str,
    target: str,
    run: dict[str, object],
    run_index: object,
) -> list[dict[str, object]]:
    lines = run_torfast_lines(run)
    if not lines:
        return []
    socks_rows = list(
        group_torfast_socks_timings(parse_torfast_socks_timings(lines)).values()
    )
    terminal_rows = []
    seen_terminals = set()
    for item in parse_torfast_stream_receiver_timings(lines):
        if item.get("event") != "terminal" or item.get("circ_id") is None:
            continue
        key = (
            item.get("circ_id"),
            item.get("stream_id"),
            item.get("event_epoch_ms"),
            item.get("relay_data_bytes"),
            item.get("transfer_ms"),
        )
        if key in seen_terminals:
            continue
        seen_terminals.add(key)
        terminal_rows.append(item)
    if not terminal_rows:
        return []

    grouped: dict[object, list[tuple[dict[str, object], dict[str, object]]]] = {}
    for terminal in terminal_rows:
        socks_row = matching_socks_row_for_terminal(terminal, socks_rows)
        circ_id = terminal.get("circ_id")
        grouped.setdefault(circ_id, []).append((terminal, socks_row))

    rows = []
    for circ_id, circuit_items in grouped.items():
        stream_keys = {
            terminal.get("stream_id")
            for terminal, _socks in circuit_items
            if terminal.get("stream_id") is not None
        }
        data_bytes = sum(
            int(numeric(terminal.get("relay_data_bytes")) or 0)
            for terminal, _socks in circuit_items
        )
        tor_to_client_bytes = sum(
            int(
                numeric(socks.get("tor_to_client_bytes"))
                or numeric(terminal.get("user_read_bytes"))
                or 0
            )
            for terminal, socks in circuit_items
        )
        first_bytes = [
            value
            for terminal, socks in circuit_items
            for value in [
                numeric(socks.get("first_tor_to_client_ms"))
                or numeric(terminal.get("first_data_after_start_ms"))
            ]
            if value is not None
        ]
        relay_ms = [
            value
            for _terminal, socks in circuit_items
            for value in [numeric(socks.get("relay_ms"))]
            if value is not None
        ]
        spans = [
            value
            for terminal, _socks in circuit_items
            for value in [numeric(terminal.get("transfer_ms"))]
            if value is not None
        ]
        gaps = [
            value
            for terminal, _socks in circuit_items
            for value in [numeric(terminal.get("max_data_gap_ms"))]
            if value is not None
        ]
        queued = [
            value
            for terminal, _socks in circuit_items
            for value in [numeric(terminal.get("max_queued_after_bytes"))]
            if value is not None
        ]
        max_span = max(spans) if spans else None
        top_terminal, top_socks = max(
            circuit_items,
            key=lambda item: (
                numeric(item[0].get("transfer_ms")) or 0,
                numeric(item[0].get("max_data_gap_ms")) or 0,
                numeric(item[0].get("relay_data_bytes")) or 0,
            ),
        )
        rows.append(
            {
                "profile": profile_name,
                "target": target,
                "run_index": run_index,
                "load_ms": run.get("load_ms"),
                "circ_id": circ_id,
                "streams": len(stream_keys),
                "relay_streams": len(relay_ms),
                "data_bytes": data_bytes,
                "tor_to_client_bytes": tor_to_client_bytes,
                "median_first_tor_to_client_ms": (
                    median(first_bytes) if first_bytes else None
                ),
                "median_relay_ms": median(relay_ms) if relay_ms else None,
                "max_relay_ms": max(relay_ms) if relay_ms else None,
                "max_receive_span_ms": max_span,
                "max_receive_gap_ms": max(gaps) if gaps else None,
                "max_queued_after_bytes": max(queued) if queued else None,
                "rough_receive_kib_s": rough_kib_per_second(data_bytes, max_span),
                "top_timing_id": top_socks.get("timing_id"),
                "top_stream_id": top_terminal.get("stream_id"),
            }
        )
    return rows


def torfast_socks_relay_circuit_quality_run_summary_rows(
    payload: dict[str, object],
    low_rate_kib_s: float = 50.0,
    slow_relay_ms: float = 4000.0,
) -> list[dict[str, object]]:
    grouped: dict[tuple[object, object, object], list[dict[str, object]]] = {}
    for row in torfast_socks_relay_circuit_quality_rows(payload):
        key = (row.get("profile"), row.get("target"), row.get("run_index"))
        grouped.setdefault(key, []).append(row)

    rows = []
    for (profile_name, target, run_index), circuit_rows in grouped.items():
        rates = numeric_values(circuit_rows, "rough_receive_kib_s")
        relay_values = numeric_values(circuit_rows, "max_relay_ms")
        low_rate_rows = [
            row
            for row in circuit_rows
            if (numeric(row.get("rough_receive_kib_s")) is not None)
            and (numeric(row.get("rough_receive_kib_s")) or 0) < low_rate_kib_s
        ]
        slow_relay_rows = [
            row
            for row in circuit_rows
            if (numeric(row.get("max_relay_ms")) or 0) >= slow_relay_ms
        ]
        worst_row = min(
            circuit_rows,
            key=lambda row: (
                numeric(row.get("rough_receive_kib_s"))
                if numeric(row.get("rough_receive_kib_s")) is not None
                else float("inf"),
                -(numeric(row.get("max_relay_ms")) or 0),
            ),
        )
        rows.append(
            {
                "profile": profile_name,
                "target": target,
                "run_index": run_index,
                "load_ms": circuit_rows[0].get("load_ms"),
                "circuits": len(circuit_rows),
                "relay_streams": sum(
                    int(numeric(row.get("relay_streams")) or 0)
                    for row in circuit_rows
                ),
                "data_bytes": sum(
                    int(numeric(row.get("data_bytes")) or 0) for row in circuit_rows
                ),
                "min_rough_receive_kib_s": min(rates) if rates else None,
                "median_rough_receive_kib_s": median(rates) if rates else None,
                "low_rate_circuits": len(low_rate_rows),
                "low_rate_streams": sum(
                    int(numeric(row.get("relay_streams")) or 0)
                    for row in low_rate_rows
                ),
                "low_rate_data_bytes": sum(
                    int(numeric(row.get("data_bytes")) or 0)
                    for row in low_rate_rows
                ),
                "slow_relay_circuits": len(slow_relay_rows),
                "max_relay_ms": max(relay_values) if relay_values else None,
                "worst_circ_id": worst_row.get("circ_id"),
            }
        )

    return sorted(
        rows,
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0,
        ),
    )


def torfast_load_aware_selection_health_outcome_rows(
    payload: dict[str, object],
    low_rate_kib_s: float = 50.0,
    slow_relay_ms: float = 4000.0,
) -> list[dict[str, object]]:
    quality_by_run: dict[tuple[str, str, object], list[dict[str, object]]] = {}
    for row in torfast_socks_relay_circuit_quality_rows(payload):
        key = (str(row.get("profile", "")), str(row.get("target", "")), row.get("run_index"))
        quality_by_run.setdefault(key, []).append(row)

    rows = []
    for profile_name, _profile, target, _summary, run in iter_runs(payload):
        lines = run.get("proxy_signal_lines", [])
        if not isinstance(lines, list):
            continue
        timings = parse_torfast_circuit_selection_timings([str(line) for line in lines])
        load_aware_items = [
            item
            for item in timings
            if item.get("event") == "open"
            and item.get("usage_kind") == "exit"
            and item.get("select_load_aware") is True
        ]
        if not load_aware_items:
            continue
        run_index = run.get("run_index")
        quality_rows = quality_by_run.get((str(profile_name), str(target), run_index), [])

        selected_rates = []
        first_rates = []
        selected_scores = []
        first_scores = []
        selected_ages = []
        selected_active_ages = []
        first_active_ages = []
        selected_health_rows = []
        known_selected = 0
        known_first = 0
        selected_nonfirst = 0
        selected_worse = 0
        selected_better = 0
        selected_low_rate = 0
        selected_slow_relay = 0

        for item in load_aware_items:
            candidates = parse_torfast_candidate_assignment_summary(
                item.get("candidate_assignment_summary")
            )
            candidate_health_rows = parse_torfast_candidate_health_summary(
                item.get("candidate_health_summary")
            )
            if not candidates:
                continue
            selected_index = numeric(item.get("selected_candidate_index"))
            if selected_index is not None and selected_index > 0:
                selected_nonfirst += 1
            first_candidate = find_candidate_by_index(candidates, 0)
            selected_candidate = (
                find_candidate_by_index(candidates, int(selected_index))
                if selected_index is not None
                else None
            )
            if selected_candidate is None:
                selected_candidate = find_candidate_by_tunnel_id(
                    candidates, item.get("tunnel_unique_id")
                )
            if first_candidate is None or selected_candidate is None:
                continue
            first_candidate_selection_health = find_candidate_by_index(
                candidate_health_rows, 0
            )
            selected_candidate_selection_health = (
                find_candidate_by_index(candidate_health_rows, int(selected_index))
                if selected_index is not None
                else None
            )
            if selected_candidate_selection_health is None:
                selected_candidate_selection_health = find_candidate_by_tunnel_id(
                    candidate_health_rows, selected_candidate.get("tunnel_unique_id")
                )

            first_health = find_circuit_quality_for_tunnel_id(
                quality_rows, first_candidate.get("tunnel_unique_id")
            )
            selected_health = find_circuit_quality_for_tunnel_id(
                quality_rows, selected_candidate.get("tunnel_unique_id")
            )
            first_rate = numeric((first_health or {}).get("rough_receive_kib_s"))
            selected_rate = numeric((selected_health or {}).get("rough_receive_kib_s"))
            selected_relay = numeric((selected_health or {}).get("max_relay_ms"))

            if first_health is not None:
                known_first += 1
            if selected_health is not None:
                known_selected += 1
                selected_health_rows.append(selected_health)
            if first_rate is not None:
                first_rates.append(first_rate)
            if selected_rate is not None:
                selected_rates.append(selected_rate)
                if selected_rate < low_rate_kib_s:
                    selected_low_rate += 1
            if selected_relay is not None and selected_relay >= slow_relay_ms:
                selected_slow_relay += 1
            selected_candidate_score = numeric(
                (selected_candidate_selection_health or {}).get("health_score_bps")
            )
            first_candidate_score = numeric(
                (first_candidate_selection_health or {}).get("health_score_bps")
            )
            selected_candidate_age = numeric(
                (selected_candidate_selection_health or {}).get("health_age_ms")
            )
            selected_candidate_active_age = numeric(
                (selected_candidate_selection_health or {}).get(
                    "active_stream_age_ms"
                )
            )
            first_candidate_active_age = numeric(
                (first_candidate_selection_health or {}).get("active_stream_age_ms")
            )
            selected_log_active_age = numeric(item.get("selected_active_stream_age_ms"))
            if selected_candidate_score is not None:
                selected_scores.append(selected_candidate_score)
            if first_candidate_score is not None:
                first_scores.append(first_candidate_score)
            if selected_candidate_age is not None:
                selected_ages.append(selected_candidate_age)
            if selected_candidate_active_age is not None:
                selected_active_ages.append(selected_candidate_active_age)
            elif selected_log_active_age is not None:
                selected_active_ages.append(selected_log_active_age)
            if first_candidate_active_age is not None:
                first_active_ages.append(first_candidate_active_age)
            if first_rate is not None and selected_rate is not None:
                if selected_rate < first_rate:
                    selected_worse += 1
                elif selected_rate > first_rate:
                    selected_better += 1

        worst_selected = min(
            selected_health_rows,
            key=lambda row: (
                numeric(row.get("rough_receive_kib_s"))
                if numeric(row.get("rough_receive_kib_s")) is not None
                else float("inf"),
                -(numeric(row.get("max_relay_ms")) or 0),
            ),
            default=None,
        )
        rows.append(
            {
                "profile": profile_name,
                "target": target,
                "run_index": run_index,
                "load_ms": run.get("load_ms"),
                "load_aware_picks": len(load_aware_items),
                "selected_nonfirst": selected_nonfirst,
                "known_selected_health": known_selected,
                "known_first_health": known_first,
                "selected_worse_than_first_rate": selected_worse,
                "selected_better_than_first_rate": selected_better,
                "selected_low_rate": selected_low_rate,
                "selected_slow_relay": selected_slow_relay,
                "median_selected_rough_receive_kib_s": (
                    median(selected_rates) if selected_rates else None
                ),
                "median_first_rough_receive_kib_s": (
                    median(first_rates) if first_rates else None
                ),
                "median_selected_health_score_bps": (
                    median(selected_scores) if selected_scores else None
                ),
                "median_first_health_score_bps": (
                    median(first_scores) if first_scores else None
                ),
                "max_selected_health_age_ms": max(selected_ages) if selected_ages else None,
                "max_selected_active_stream_age_ms": (
                    max(selected_active_ages) if selected_active_ages else None
                ),
                "max_first_active_stream_age_ms": (
                    max(first_active_ages) if first_active_ages else None
                ),
                "worst_selected_circ_id": (worst_selected or {}).get("circ_id"),
            }
        )

    return sorted(
        rows,
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0,
        ),
    )


def find_candidate_by_index(
    candidates: list[dict[str, object]], index: int
) -> dict[str, object] | None:
    for candidate in candidates:
        if candidate.get("index") == index:
            return candidate
    return None


def find_candidate_by_tunnel_id(
    candidates: list[dict[str, object]], tunnel_id: object
) -> dict[str, object] | None:
    for candidate in candidates:
        if torfast_circ_ids_match(candidate.get("tunnel_unique_id"), tunnel_id):
            return candidate
    return None


def find_circuit_quality_for_tunnel_id(
    rows: list[dict[str, object]], tunnel_id: object
) -> dict[str, object] | None:
    matches = [
        row
        for row in rows
        if torfast_circ_ids_match(row.get("circ_id"), tunnel_id)
    ]
    if not matches:
        return None
    return max(
        matches,
        key=lambda row: (
            numeric(row.get("data_bytes")) or 0,
            numeric(row.get("relay_streams")) or 0,
        ),
    )


def torfast_socks_relay_join_gap_detail_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    rows: list[dict[str, object]] = []
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return rows
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        line_strings = [str(line) for line in lines]
        joined_rows = torfast_socks_relay_join_rows(line_strings)
        if not joined_rows:
            continue
        relay_timings = parse_torfast_relay_receive_timings(line_strings)
        delivered = [item for item in relay_timings if item.get("event") == "delivered"]
        records = profile_browser_run_records(profile)
        if not records:
            continue
        bounds = browser_run_epoch_bounds([run for _target, run, _index in records])
        for joined_row in joined_rows:
            joined_epoch = torfast_socks_relay_join_epoch_ms(joined_row)
            if joined_epoch is None:
                continue
            matching_record = None
            for record_index, (target, run, original_index) in enumerate(records):
                lower, upper = bounds[record_index]
                if lower <= joined_epoch < upper:
                    matching_record = (target, run, original_index)
                    break
            if matching_record is None:
                continue
            target, run, original_index = matching_record
            circ_id = joined_row.get("circ_id")
            stream_id = joined_row.get("stream_id")
            stream_items = [
                item
                for item in delivered
                if item.get("stream_id") == stream_id
                and torfast_circ_ids_match(circ_id, item.get("circ_id"))
                and numeric(item.get("timestamp_ms")) is not None
            ]
            stream_items.sort(key=lambda item: numeric(item.get("timestamp_ms")) or 0)
            load_epoch = browser_load_epoch_ms(run)
            best_row = None
            for previous, current in zip(stream_items, stream_items[1:]):
                previous_ts = numeric(previous.get("timestamp_ms"))
                current_ts = numeric(current.get("timestamp_ms"))
                if previous_ts is None or current_ts is None or current_ts < previous_ts:
                    continue
                candidate = {
                    "profile": profile_name,
                    "target": target,
                    "run_index": run.get("run_index", original_index + 1),
                    "timing_id": joined_row.get("timing_id"),
                    "target_kind": joined_row.get("target_kind"),
                    "gap_ms": current_ts - previous_ts,
                    "circ_id": circ_id,
                    "stream_id": stream_id,
                    "prev_relay_cmd": previous.get("relay_cmd"),
                    "prev_event_epoch_ms": previous_ts,
                    "prev_queued_after_bytes": previous.get("queued_after_bytes"),
                    "next_relay_cmd": current.get("relay_cmd"),
                    "next_event_epoch_ms": current_ts,
                    "next_queued_before_bytes": current.get("queued_before_bytes"),
                    "next_queued_after_bytes": current.get("queued_after_bytes"),
                    "gap_end_before_load_ms": subtract_numeric(load_epoch, current_ts),
                }
                if (numeric(candidate.get("gap_ms")) or 0) > (
                    numeric((best_row or {}).get("gap_ms")) or 0
                ):
                    best_row = candidate
            if best_row is not None:
                rows.append(best_row)
    return sorted(
        rows,
        key=lambda row: numeric(row.get("gap_ms")) or 0,
        reverse=True,
    )


def torfast_stream_receiver_gap_context_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    rows: list[dict[str, object]] = []
    gap_rows = torfast_socks_relay_join_gap_detail_rows(payload)
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return rows
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        receiver_timings = parse_torfast_stream_receiver_timings(
            [str(line) for line in lines]
        )
        if not receiver_timings:
            continue
        for gap_row in gap_rows:
            if gap_row.get("profile") != profile_name:
                continue
            stream_id = gap_row.get("stream_id")
            gap_start = numeric(gap_row.get("prev_event_epoch_ms"))
            gap_end = numeric(gap_row.get("next_event_epoch_ms"))
            if stream_id is None or gap_start is None or gap_end is None:
                continue
            in_gap = [
                item
                for item in receiver_timings
                if item.get("stream_id") == stream_id
                and numeric(item.get("timestamp_ms")) is not None
                and gap_start <= (numeric(item.get("timestamp_ms")) or 0) <= gap_end
            ]
            reads = [item for item in in_gap if item.get("event") == "read"]
            sendmes = [item for item in in_gap if item.get("event") == "sendme"]
            read_times = [
                numeric(item.get("timestamp_ms"))
                for item in reads
                if numeric(item.get("timestamp_ms")) is not None
            ]
            recv_windows = [
                numeric(item.get("recv_window_after"))
                for item in reads
                if numeric(item.get("recv_window_after")) is not None
            ]
            queued_after = [
                numeric(item.get("queued_after_bytes"))
                for item in in_gap
                if numeric(item.get("queued_after_bytes")) is not None
            ]
            rows.append(
                {
                    "profile": profile_name,
                    "target": gap_row.get("target"),
                    "run_index": gap_row.get("run_index"),
                    "timing_id": gap_row.get("timing_id"),
                    "stream_id": stream_id,
                    "gap_ms": gap_row.get("gap_ms"),
                    "receiver_reads_in_gap": len(reads),
                    "receiver_sendmes_in_gap": len(sendmes),
                    "receiver_sendme_ok_in_gap": sum(
                        1 for item in sendmes if item.get("sendme_ok") is True
                    ),
                    "first_receiver_read_after_gap_start_ms": subtract_numeric(
                        min(read_times) if read_times else None,
                        gap_start,
                    ),
                    "last_receiver_read_before_gap_end_ms": subtract_numeric(
                        gap_end,
                        max(read_times) if read_times else None,
                    ),
                    "min_recv_window_after": min(recv_windows)
                    if recv_windows
                    else None,
                    "max_receiver_queued_after_bytes": max(queued_after)
                    if queued_after
                    else None,
                }
            )
    return sorted(
        rows,
        key=lambda row: numeric(row.get("gap_ms")) or 0,
        reverse=True,
    )


def browser_resource_socks_relay_join_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    rows = []
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return rows
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        line_strings = [str(line) for line in lines]
        joined_rows = torfast_socks_relay_join_rows(line_strings)
        if not joined_rows:
            joined_rows = torfast_socks_stream_rows(line_strings)
        if not joined_rows:
            continue
        records = profile_browser_run_records(profile)
        if not records:
            continue
        bounds = browser_run_epoch_bounds([run for _target, run, _index in records])
        for record_index, (target, run, original_index) in enumerate(records):
            lower, upper = bounds[record_index]
            run_joined = [
                row
                for row in joined_rows
                if torfast_socks_relay_join_epoch_ms(row) is not None
                and lower <= (torfast_socks_relay_join_epoch_ms(row) or 0) < upper
            ]
            if not run_joined:
                continue
            dom_loaded_ms = nav_value(run, "domContentLoadedEventEnd")
            load_end_ms = nav_value(run, "loadEventEnd")
            for resource in browser_resource_rows_for_run(run):
                resource_epoch, match_field = browser_resource_match_epoch_ms(
                    run, resource
                )
                if resource_epoch is None:
                    continue
                host_lifetime_candidates = resource_host_lifetime_candidate_rows(
                    run, resource, run_joined
                )
                candidate_rows = host_lifetime_candidates or [
                    row
                    for row in run_joined
                    if target_label_matches_hostname(
                        row.get("target_label"),
                        resource_hostname(resource.get("name")),
                    )
                ]
                if not candidate_rows:
                    candidate_rows = run_joined
                nearest = min(
                    candidate_rows,
                    key=lambda row: abs(
                        (torfast_socks_relay_join_epoch_ms(row) or 0)
                        - resource_epoch
                    ),
                )
                joined_epoch = torfast_socks_relay_join_epoch_ms(nearest)
                abs_match_delta_ms = (
                    abs(joined_epoch - resource_epoch)
                    if joined_epoch is not None
                    else None
                )
                timing_confidence = match_confidence(abs_match_delta_ms)
                stream_set_confidence = stream_set_match_confidence(
                    len(host_lifetime_candidates), timing_confidence
                )
                host_lifetime_stream_ids = compact_list(
                    [
                        row.get("stream_id")
                        for row in host_lifetime_candidates
                        if row.get("stream_id") is not None
                    ],
                    max_items=4,
                )
                host_lifetime_circuits = compact_list(
                    [
                        row.get("circ_id")
                        for row in host_lifetime_candidates
                        if row.get("circ_id")
                    ],
                    max_items=3,
                )
                response_end_ms = numeric(resource.get("responseEnd"))
                response_end_epoch_ms = add_numeric(
                    browser_time_origin_ms(run), response_end_ms
                )
                load_end_epoch_ms = add_numeric(browser_time_origin_ms(run), load_end_ms)
                last_tor_byte_epoch_ms = add_numeric(
                    nearest.get("conn_started_epoch_ms"),
                    nearest.get("last_tor_to_client_ms"),
                )
                last_tor_write_epoch_ms = add_numeric(
                    nearest.get("conn_started_epoch_ms"),
                    nearest.get("last_tor_to_client_write_ms"),
                )
                rows.append(
                    {
                        "profile": profile_name,
                        "target": target,
                        "run_index": run.get("run_index", original_index + 1),
                        "time_origin_ms": browser_time_origin_ms(run),
                        "resource": resource.get("name"),
                        "resource_type": resource.get("initiatorType"),
                        "resource_start_ms": resource.get("startTime"),
                        "fetch_start_ms": resource.get("fetchStart"),
                        "request_start_ms": resource.get("requestStart"),
                        "response_start_ms": resource.get("responseStart"),
                        "duration_ms": resource.get("duration"),
                        "fetch_to_request_ms": resource_phase_ms(
                            resource, "fetchToRequest"
                        ),
                        "wait_ms": resource_phase_ms(resource, "requestWait"),
                        "receive_ms": resource_phase_ms(resource, "responseReceive"),
                        "response_end_ms": response_end_ms,
                        "response_end_epoch_ms": response_end_epoch_ms,
                        "tail_after_dom_ms": subtract_numeric(
                            response_end_ms, dom_loaded_ms
                        ),
                        "response_end_before_load_ms": subtract_numeric(
                            load_end_ms, response_end_ms
                        ),
                        "body_bytes": resource.get("encodedBodySize"),
                        "match_field": match_field,
                        "match_delta_ms": subtract_numeric(
                            joined_epoch, resource_epoch
                        ),
                        "abs_match_delta_ms": abs_match_delta_ms,
                        "match_confidence": timing_confidence,
                        "stream_set_match_confidence": stream_set_confidence,
                        "host_lifetime_candidates": len(host_lifetime_candidates),
                        "host_lifetime_candidate_stream_ids": host_lifetime_stream_ids,
                        "host_lifetime_candidate_circuits": host_lifetime_circuits,
                        "resource_stream_lifetime_overlap_ms": (
                            nearest.get("resource_stream_lifetime_overlap_ms")
                        ),
                        "timing_id": nearest.get("timing_id"),
                        "target_label": nearest.get("target_label"),
                        "circ_id": nearest.get("circ_id"),
                        "stream_id": nearest.get("stream_id"),
                        "joined_relay_receive": nearest.get("joined_relay_receive"),
                        "first_client_to_tor_ms": nearest.get(
                            "first_client_to_tor_ms"
                        ),
                        "first_client_to_tor_write_ms": nearest.get(
                            "first_client_to_tor_write_ms"
                        ),
                        "first_client_to_tor_write_epoch_ms": nearest.get(
                            "first_client_to_tor_write_epoch_ms"
                        ),
                        "first_tor_to_client_ms": nearest.get(
                            "first_tor_to_client_ms"
                        ),
                        "first_tor_to_client_epoch_ms": nearest.get(
                            "first_tor_to_client_epoch_ms"
                        ),
                        "first_tor_to_client_write_ms": nearest.get(
                            "first_tor_to_client_write_ms"
                        ),
                        "first_tor_to_client_write_epoch_ms": nearest.get(
                            "first_tor_to_client_write_epoch_ms"
                        ),
                        "last_tor_to_client_ms": nearest.get(
                            "last_tor_to_client_ms"
                        ),
                        "last_tor_to_client_write_ms": nearest.get(
                            "last_tor_to_client_write_ms"
                        ),
                        "last_tor_to_client_epoch_ms": last_tor_byte_epoch_ms,
                        "last_tor_to_client_write_epoch_ms": last_tor_write_epoch_ms,
                        "tor_to_client_idle_after_last_ms": nearest.get(
                            "tor_to_client_idle_after_last_ms"
                        ),
                        "response_end_after_last_tor_byte_ms": subtract_numeric(
                            response_end_epoch_ms, last_tor_byte_epoch_ms
                        ),
                        "response_end_after_last_tor_write_ms": subtract_numeric(
                            response_end_epoch_ms, last_tor_write_epoch_ms
                        ),
                        "last_tor_byte_before_load_ms": subtract_numeric(
                            load_end_epoch_ms, last_tor_byte_epoch_ms
                        ),
                        "relay_ms": nearest.get("relay_ms"),
                        "client_to_tor_bytes": nearest.get("client_to_tor_bytes"),
                        "client_to_tor_write_bytes": nearest.get(
                            "client_to_tor_write_bytes"
                        ),
                        "tor_to_client_bytes": nearest.get("tor_to_client_bytes"),
                        "tor_to_client_write_bytes": nearest.get(
                            "tor_to_client_write_bytes"
                        ),
                        "data_bytes": nearest.get("data_bytes"),
                        "span_ms": nearest.get("span_ms"),
                        "first_receive_epoch_ms": nearest.get(
                            "first_receive_epoch_ms"
                        ),
                        "last_receive_epoch_ms": nearest.get(
                            "last_receive_epoch_ms"
                        ),
                        "max_gap_ms": nearest.get("max_gap_ms"),
                        "max_queued_after_bytes": nearest.get(
                            "max_queued_after_bytes"
                        ),
                    }
                )
    return sorted(
        rows,
        key=lambda row: (
            numeric(row.get("duration_ms")) or 0,
            numeric(row.get("wait_ms")) or 0,
            numeric(row.get("receive_ms")) or 0,
        ),
        reverse=True,
    )


def browser_resource_queue_socks_relay_tail_rows(
    payload: dict[str, object],
    *,
    threshold_ms: float = 100.0,
) -> list[dict[str, object]]:
    rows = [
        row
        for row in browser_resource_socks_relay_join_rows(payload)
        if (numeric(row.get("fetch_to_request_ms")) or 0) >= threshold_ms
    ]
    return sorted(
        rows,
        key=lambda row: (
            numeric(row.get("fetch_to_request_ms")) or 0,
            numeric(row.get("duration_ms")) or 0,
            numeric(row.get("wait_ms")) or 0,
        ),
        reverse=True,
    )


def browser_resource_queue_socks_relay_cluster_rows(
    payload: dict[str, object],
    *,
    threshold_ms: float = 100.0,
) -> list[dict[str, object]]:
    grouped: dict[tuple[str, str, object, object, object, object], list[dict[str, object]]] = {}
    for row in browser_resource_queue_socks_relay_tail_rows(
        payload, threshold_ms=threshold_ms
    ):
        if row.get("match_confidence") != "high":
            continue
        key = (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            row.get("run_index"),
            row.get("timing_id"),
            row.get("circ_id"),
            row.get("stream_id"),
        )
        grouped.setdefault(key, []).append(row)

    rows = []
    for (profile, target, run_index, timing_id, circ_id, stream_id), group_rows in grouped.items():
        rows.append(
            {
                "profile": profile,
                "target": target,
                "run_index": run_index,
                "timing_id": timing_id,
                "circ_id": circ_id,
                "stream_id": stream_id,
                "queued_resources": len(group_rows),
                "queued_500ms": row_count_at_least(
                    group_rows, "fetch_to_request_ms", 500
                ),
                "queued_1000ms": row_count_at_least(
                    group_rows, "fetch_to_request_ms", 1000
                ),
                "median_fetch_to_request_ms": row_median(
                    group_rows, "fetch_to_request_ms"
                ),
                "max_fetch_to_request_ms": row_max(
                    group_rows, "fetch_to_request_ms"
                ),
                "max_duration_ms": row_max(group_rows, "duration_ms"),
                "relay_ms": row_max(group_rows, "relay_ms"),
                "max_receive_gap_ms": row_max(group_rows, "max_gap_ms"),
                "top_resources": compact_list(
                    [
                        compact_url(str(row.get("resource", "")), max_length=42)
                        for row in sorted(
                            group_rows,
                            key=lambda row: numeric(row.get("fetch_to_request_ms"))
                            or 0,
                            reverse=True,
                        )
                    ],
                    max_items=3,
                ),
            }
        )
    return sorted(
        rows,
        key=lambda row: (
            numeric(row.get("queued_1000ms")) or 0,
            numeric(row.get("max_fetch_to_request_ms")) or 0,
            numeric(row.get("queued_resources")) or 0,
        ),
        reverse=True,
    )


def browser_resource_queue_selection_context_rows(
    payload: dict[str, object],
    *,
    threshold_ms: float = 100.0,
) -> list[dict[str, object]]:
    profile_health_min_scores = {
        str(name): (
            numeric(profile.get("arti_exit_select_health_min_move_score_bps"))
            or SELECTOR_HEALTH_MIN_MOVE_SCORE_BPS
        )
        for name, profile in (payload.get("profiles") or {}).items()
        if isinstance(profile, dict)
    }
    selection_by_run: dict[tuple[str, str, object], list[dict[str, object]]] = {}
    for profile_name, _profile, target, _summary, run in iter_runs(payload):
        lines = run.get("proxy_signal_lines", [])
        if not isinstance(lines, list):
            continue
        timings = parse_torfast_circuit_selection_timings([str(line) for line in lines])
        selection_by_run[(str(profile_name), str(target), run.get("run_index"))] = [
            item
            for item in timings
            if item.get("event") == "open" and item.get("usage_kind") == "exit"
        ]

    rows = []
    for cluster in browser_resource_queue_socks_relay_cluster_rows(
        payload, threshold_ms=threshold_ms
    ):
        circ_id = cluster.get("circ_id")
        selection_rows = selection_by_run.get(
            (
                str(cluster.get("profile", "")),
                str(cluster.get("target", "")),
                cluster.get("run_index"),
            ),
            [],
        )
        selected_rows = [
            item
            for item in selection_rows
            if torfast_circ_ids_match(item.get("tunnel_unique_id"), circ_id)
        ]
        if not selected_rows:
            continue

        selected_assignments = []
        selected_scores = []
        selected_gaps = []
        selected_bad_health_rows = 0
        alt_scores = []
        best_alt_scores = []
        best_alt_gaps = []
        lower_assignment_alt_rows = 0
        better_health_alt_rows = 0
        better_health_move_alt_rows = 0
        below_floor_health_alt_rows = 0
        cold_selected_alt_scored_rows = 0
        multi_candidate_rows = 0
        first_context = None
        last_context = None
        health_min_move_score = profile_health_min_scores.get(
            str(cluster.get("profile", "")),
            SELECTOR_HEALTH_MIN_MOVE_SCORE_BPS,
        )

        for item in selected_rows:
            context = selection_candidate_context(
                item,
                min_move_score_bps=health_min_move_score,
            )
            if context is None:
                continue
            first_context = first_context or context
            last_context = context
            if (numeric(item.get("open_candidates")) or 0) > 1:
                multi_candidate_rows += 1
            selected_assignment = numeric(context.get("selected_assigned_streams"))
            selected_score = numeric(context.get("selected_health_score_bps")) or 0
            selected_gap = numeric(context.get("selected_health_max_gap_ms"))
            max_alt_score = numeric(context.get("max_alt_health_score_bps")) or 0
            best_alt_score = numeric(context.get("best_alt_health_score_bps"))
            best_alt_gap = numeric(context.get("best_alt_health_max_gap_ms"))
            if selected_assignment is not None:
                selected_assignments.append(selected_assignment)
            if selected_gap is not None:
                selected_gaps.append(selected_gap)
            if context.get("selected_has_bad_health") is True:
                selected_bad_health_rows += 1
            selected_scores.append(selected_score)
            alt_scores.append(max_alt_score)
            if best_alt_score is not None:
                best_alt_scores.append(best_alt_score)
            if best_alt_gap is not None:
                best_alt_gaps.append(best_alt_gap)
            if context.get("has_lower_assignment_alt") is True:
                lower_assignment_alt_rows += 1
            if context.get("has_better_health_alt") is True:
                better_health_alt_rows += 1
            if context.get("has_better_health_move_alt") is True:
                better_health_move_alt_rows += 1
            if context.get("has_below_floor_health_alt") is True:
                below_floor_health_alt_rows += 1
            if selected_score <= 0 and max_alt_score > 0:
                cold_selected_alt_scored_rows += 1

        rows.append(
            {
                **cluster,
                "selected_open_rows": len(selected_rows),
                "multi_candidate_selected_rows": multi_candidate_rows,
                "lower_assignment_alt_rows": lower_assignment_alt_rows,
                "better_health_alt_rows": better_health_alt_rows,
                "better_health_move_alt_rows": better_health_move_alt_rows,
                "below_floor_health_alt_rows": below_floor_health_alt_rows,
                "cold_selected_alt_scored_rows": cold_selected_alt_scored_rows,
                "health_min_move_score_bps": health_min_move_score,
                "max_selected_assigned_streams": (
                    max(selected_assignments) if selected_assignments else None
                ),
                "max_selected_health_score_bps": (
                    max(selected_scores) if selected_scores else None
                ),
                "max_selected_health_gap_ms": (
                    max(selected_gaps) if selected_gaps else None
                ),
                "selected_bad_health_rows": selected_bad_health_rows,
                "max_alt_health_score_bps": max(alt_scores) if alt_scores else None,
                "best_alt_health_score_bps": (
                    max(best_alt_scores) if best_alt_scores else None
                ),
                "best_alt_health_gap_ms": (
                    min(best_alt_gaps) if best_alt_gaps else None
                ),
                "first_candidate_context": (
                    first_context.get("summary") if first_context else ""
                ),
                "last_candidate_context": (
                    last_context.get("summary") if last_context else ""
                ),
            }
        )

    return sorted(
        rows,
        key=lambda row: (
            numeric(row.get("queued_1000ms")) or 0,
            numeric(row.get("better_health_alt_rows")) or 0,
            numeric(row.get("lower_assignment_alt_rows")) or 0,
            numeric(row.get("max_fetch_to_request_ms")) or 0,
        ),
        reverse=True,
    )


def browser_resource_queue_choice_class_summary_rows(
    payload: dict[str, object],
    *,
    threshold_ms: float = 100.0,
) -> list[dict[str, object]]:
    grouped: dict[tuple[str, str, str], list[dict[str, object]]] = {}
    for row in browser_resource_queue_selection_context_rows(
        payload, threshold_ms=threshold_ms
    ):
        if (numeric(row.get("queued_1000ms")) or 0) <= 0:
            continue
        choice_class = resource_queue_choice_class(row)
        key = (str(row.get("profile", "")), str(row.get("target", "")), choice_class)
        grouped.setdefault(key, []).append(row)

    rows = []
    for (profile, target, choice_class), group_rows in grouped.items():
        rows.append(
            {
                "profile": profile,
                "target": target,
                "choice_class": choice_class,
                "rows": len(group_rows),
                "queued_1000ms": sum(
                    int(numeric(row.get("queued_1000ms")) or 0)
                    for row in group_rows
                ),
                "max_fetch_to_request_ms": row_max(
                    group_rows, "max_fetch_to_request_ms"
                ),
                "max_selected_assigned_streams": row_max(
                    group_rows, "max_selected_assigned_streams"
                ),
                "below_floor_health_alt_rows": sum(
                    int(numeric(row.get("below_floor_health_alt_rows")) or 0)
                    for row in group_rows
                ),
                "max_alt_health_score_bps": row_max(
                    group_rows, "max_alt_health_score_bps"
                ),
                "health_min_move_score_bps": row_max(
                    group_rows, "health_min_move_score_bps"
                ),
                "top_resources": compact_list(
                    expand_compact_list_field(group_rows, "top_resources"),
                    max_items=3,
                ),
                "next_proof": resource_queue_choice_next_proof(choice_class),
            }
        )
    return sorted(
        rows,
        key=lambda row: (
            numeric(row.get("queued_1000ms")) or 0,
            numeric(row.get("max_fetch_to_request_ms")) or 0,
            str(row.get("profile", "")),
            str(row.get("target", "")),
        ),
        reverse=True,
    )


def resource_queue_choice_class(row: dict[str, object]) -> str:
    if (numeric(row.get("better_health_move_alt_rows")) or 0) > 0:
        return "selector-health move alternative"
    if (numeric(row.get("below_floor_health_alt_rows")) or 0) > 0:
        return "below-floor health alternative"
    if (numeric(row.get("better_health_alt_rows")) or 0) > 0:
        return "better-health alternative"
    if (numeric(row.get("lower_assignment_alt_rows")) or 0) > 0:
        return "lower-assignment alternative"
    if (numeric(row.get("multi_candidate_selected_rows")) or 0) > 0:
        return "multi-candidate no better alt"
    if (numeric(row.get("selected_open_rows")) or 0) > 0:
        return "only selected open"
    return "choice context missing"


def resource_queue_choice_next_proof(choice_class: str) -> str:
    if choice_class == "selector-health move alternative":
        return "selector health proof"
    if choice_class == "below-floor health alternative":
        return "stream gap proof"
    if choice_class == "better-health alternative":
        return "selector rule proof"
    if choice_class == "lower-assignment alternative":
        return "guarded assignment proof"
    if choice_class == "multi-candidate no better alt":
        return "candidate quality proof"
    if choice_class == "only selected open":
        return "same-isolation capacity timing"
    return "choice context proof"


def selection_candidate_context(
    item: dict[str, object],
    *,
    min_move_score_bps: float = SELECTOR_HEALTH_MIN_MOVE_SCORE_BPS,
) -> dict[str, object] | None:
    candidates = parse_torfast_candidate_assignment_summary(
        item.get("candidate_assignment_summary")
    )
    if not candidates:
        return None
    health_rows = parse_torfast_candidate_health_summary(
        item.get("candidate_health_summary")
    )
    selected = find_candidate_by_tunnel_id(candidates, item.get("tunnel_unique_id"))
    if selected is None:
        return None
    selected_index = selected.get("index")
    selected_health = (
        find_candidate_by_index(health_rows, int(selected_index))
        if isinstance(selected_index, int)
        else None
    )
    selected_score = numeric((selected_health or {}).get("health_score_bps")) or 0
    selected_gap = numeric((selected_health or {}).get("max_relay_data_gap_ms"))
    if selected_gap is None:
        selected_gap = numeric(item.get("selected_health_max_gap_ms"))
    selected_age = numeric((selected_health or {}).get("health_age_ms"))
    if selected_age is None:
        selected_age = numeric(item.get("selected_health_age_ms"))
    selected_assigned = numeric(selected.get("assigned_streams"))

    alt_candidates = [
        candidate
        for candidate in candidates
        if candidate.get("index") != selected_index
    ]
    alt_health_rows = [
        health
        for health in health_rows
        if health.get("index") != selected_index
    ]
    alt_assignments = [
        numeric(candidate.get("assigned_streams"))
        for candidate in alt_candidates
        if numeric(candidate.get("assigned_streams")) is not None
    ]
    alt_scores = [
        numeric(health.get("health_score_bps")) or 0 for health in alt_health_rows
    ]
    max_alt_score = max(alt_scores) if alt_scores else 0
    best_alt_health = (
        max(
            alt_health_rows,
            key=lambda health: numeric(health.get("health_score_bps")) or 0,
        )
        if alt_health_rows
        else {}
    )
    best_alt_index = best_alt_health.get("index")
    best_alt_assignment = (
        find_candidate_by_index(alt_candidates, int(best_alt_index))
        if isinstance(best_alt_index, int)
        else None
    )
    has_better_health_alt = bool(alt_scores) and max_alt_score > selected_score
    has_better_health_move_alt = False
    has_below_floor_health_alt = False
    if has_better_health_alt:
        if selected_score <= 0:
            has_better_health_move_alt = max_alt_score >= min_move_score_bps
            has_below_floor_health_alt = 0 < max_alt_score < min_move_score_bps
        else:
            has_better_health_move_alt = (
                max_alt_score * SELECTOR_HEALTH_MIN_IMPROVEMENT_DEN
                >= selected_score * SELECTOR_HEALTH_MIN_IMPROVEMENT_NUM
            )
    return {
        "selected_assigned_streams": selected_assigned,
        "selected_health_score_bps": selected_score,
        "selected_health_max_gap_ms": selected_gap,
        "selected_health_age_ms": selected_age,
        "selected_has_bad_health": item.get("selected_has_bad_health"),
        "max_alt_health_score_bps": max_alt_score,
        "best_alt_health_score_bps": best_alt_health.get("health_score_bps"),
        "best_alt_health_max_gap_ms": best_alt_health.get(
            "max_relay_data_gap_ms"
        ),
        "best_alt_assigned_streams": (
            best_alt_assignment.get("assigned_streams")
            if best_alt_assignment
            else None
        ),
        "has_lower_assignment_alt": (
            selected_assigned is not None
            and any(assignment < selected_assigned for assignment in alt_assignments)
        ),
        "has_better_health_alt": has_better_health_alt,
        "has_better_health_move_alt": has_better_health_move_alt,
        "has_below_floor_health_alt": has_below_floor_health_alt,
        "health_min_move_score_bps": min_move_score_bps,
        "summary": compact_selection_candidate_context(
            candidates, health_rows, selected_index
        ),
    }


def compact_selection_candidate_context(
    candidates: list[dict[str, object]],
    health_rows: list[dict[str, object]],
    selected_index: object,
    max_items: int = 4,
) -> str:
    values = []
    for candidate in candidates[:max_items]:
        idx = candidate.get("index")
        health = (
            find_candidate_by_index(health_rows, int(idx))
            if isinstance(idx, int)
            else None
        )
        label = "*" if idx == selected_index else ""
        score = numeric((health or {}).get("health_score_bps")) or 0
        gap = numeric((health or {}).get("max_relay_data_gap_ms")) or 0
        values.append(
            "{label}{idx}:{circ}:a{assigned}:s{score}:g{gap}".format(
                label=label,
                idx=idx,
                circ=str(candidate.get("tunnel_unique_id", "")).replace("|", "/"),
                assigned=fmt(candidate.get("assigned_streams")),
                score=fmt(score),
                gap=fmt(gap),
            )
        )
    if len(candidates) > max_items:
        values.append(f"+{len(candidates) - max_items}")
    return ", ".join(values)


def torfast_circuit_selection_context_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    rows = []
    for profile_name, profile, target, _summary, run in iter_runs(payload):
        health_min_move_score = (
            numeric((profile or {}).get("arti_exit_select_health_min_move_score_bps"))
            or SELECTOR_HEALTH_MIN_MOVE_SCORE_BPS
        )
        timings = torfast_circuit_selection_timings_for_run(
            payload, str(profile_name), str(target), run.get("run_index")
        )
        open_items = [
            item
            for item in timings
            if item.get("event") == "open"
            and item.get("usage_kind") == "exit"
            and item.get("tunnel_unique_id")
        ]
        by_circuit: dict[str, list[dict[str, object]]] = {}
        for item in open_items:
            by_circuit.setdefault(str(item.get("tunnel_unique_id")), []).append(item)
        build_complete_by_circuit: dict[str, list[dict[str, object]]] = {}
        for item in timings:
            if item.get("event") != "build_complete" or not item.get(
                "tunnel_unique_id"
            ):
                continue
            build_complete_by_circuit.setdefault(
                str(item.get("tunnel_unique_id")), []
            ).append(item)

        for circuit, selected_rows in sorted(by_circuit.items()):
            selected_assignments = []
            selected_scores = []
            selected_gaps = []
            selected_bad_health_rows = 0
            alt_scores = []
            best_alt_scores = []
            best_alt_gaps = []
            lower_assignment_alt_rows = 0
            better_health_alt_rows = 0
            better_health_move_alt_rows = 0
            below_floor_health_alt_rows = 0
            cold_selected_alt_scored_rows = 0
            multi_candidate_rows = 0
            first_context = None
            last_context = None

            for item in selected_rows:
                context = selection_candidate_context(
                    item,
                    min_move_score_bps=health_min_move_score,
                )
                if context is None:
                    continue
                first_context = first_context or context
                last_context = context
                if (numeric(item.get("open_candidates")) or 0) > 1:
                    multi_candidate_rows += 1
                selected_assignment = numeric(context.get("selected_assigned_streams"))
                selected_score = numeric(context.get("selected_health_score_bps")) or 0
                selected_gap = numeric(context.get("selected_health_max_gap_ms"))
                max_alt_score = numeric(context.get("max_alt_health_score_bps")) or 0
                best_alt_score = numeric(context.get("best_alt_health_score_bps"))
                best_alt_gap = numeric(context.get("best_alt_health_max_gap_ms"))
                if selected_assignment is not None:
                    selected_assignments.append(selected_assignment)
                if selected_gap is not None:
                    selected_gaps.append(selected_gap)
                if context.get("selected_has_bad_health") is True:
                    selected_bad_health_rows += 1
                selected_scores.append(selected_score)
                alt_scores.append(max_alt_score)
                if best_alt_score is not None:
                    best_alt_scores.append(best_alt_score)
                if best_alt_gap is not None:
                    best_alt_gaps.append(best_alt_gap)
                if context.get("has_lower_assignment_alt") is True:
                    lower_assignment_alt_rows += 1
                if context.get("has_better_health_alt") is True:
                    better_health_alt_rows += 1
                if context.get("has_better_health_move_alt") is True:
                    better_health_move_alt_rows += 1
                if context.get("has_below_floor_health_alt") is True:
                    below_floor_health_alt_rows += 1
                if selected_score <= 0 and max_alt_score > 0:
                    cold_selected_alt_scored_rows += 1

            rows.append(
                {
                    "profile": profile_name,
                    "target": target,
                    "run_index": run.get("run_index"),
                    "circ_id": circuit,
                    "selected_open_rows": len(selected_rows),
                    "multi_candidate_selected_rows": multi_candidate_rows,
                    "lower_assignment_alt_rows": lower_assignment_alt_rows,
                    "better_health_alt_rows": better_health_alt_rows,
                    "better_health_move_alt_rows": better_health_move_alt_rows,
                    "below_floor_health_alt_rows": below_floor_health_alt_rows,
                    "cold_selected_alt_scored_rows": cold_selected_alt_scored_rows,
                    "health_min_move_score_bps": health_min_move_score,
                    "max_selected_assigned_streams": (
                        max(selected_assignments) if selected_assignments else None
                    ),
                    "max_selected_health_score_bps": (
                        max(selected_scores) if selected_scores else None
                    ),
                    "max_selected_health_gap_ms": (
                        max(selected_gaps) if selected_gaps else None
                    ),
                    "selected_bad_health_rows": selected_bad_health_rows,
                    "max_alt_health_score_bps": (
                        max(alt_scores) if alt_scores else None
                    ),
                    "best_alt_health_score_bps": (
                        max(best_alt_scores) if best_alt_scores else None
                    ),
                    "best_alt_health_gap_ms": (
                        min(best_alt_gaps) if best_alt_gaps else None
                    ),
                    "first_candidate_context": (
                        first_context.get("summary") if first_context else ""
                    ),
                    "last_candidate_context": (
                        last_context.get("summary") if last_context else ""
                    ),
                }
            )
        for circuit, build_rows in sorted(build_complete_by_circuit.items()):
            if circuit in by_circuit:
                continue
            latest_build = max(
                build_rows, key=lambda item: numeric(item.get("timestamp_ms")) or 0
            )
            context = build_complete_context(latest_build)
            rows.append(
                {
                    "profile": profile_name,
                    "target": target,
                    "run_index": run.get("run_index"),
                    "circ_id": circuit,
                    "selected_open_rows": 0,
                    "multi_candidate_selected_rows": 0,
                    "lower_assignment_alt_rows": 0,
                    "better_health_alt_rows": 0,
                    "better_health_move_alt_rows": 0,
                    "below_floor_health_alt_rows": 0,
                    "cold_selected_alt_scored_rows": 0,
                    "health_min_move_score_bps": health_min_move_score,
                    "max_selected_assigned_streams": None,
                    "max_selected_health_score_bps": None,
                    "max_alt_health_score_bps": None,
                    "first_candidate_context": context,
                    "last_candidate_context": context,
                }
            )
    return sorted(
        rows,
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0,
            str(row.get("circ_id", "")),
        ),
    )


def build_complete_context(item: dict[str, object]) -> str:
    parts = ["build complete"]
    age = numeric(item.get("pending_age_ms"))
    if age is not None:
        parts.append(f"age={fmt(age)}ms")
    usage = item.get("usage_kind")
    if usage:
        parts.append(f"usage={usage}")
    build_origin = item.get("build_origin")
    if build_origin:
        parts.append(f"origin={build_origin}")
    waiters = numeric(item.get("pending_request_matches"))
    if waiters is not None:
        parts.append(f"waiters={fmt(waiters)}")
    return " ".join(parts)


def browser_resource_socks_relay_summary_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    grouped: dict[tuple[str, str], list[dict[str, object]]] = {}
    for row in browser_resource_socks_relay_join_rows(payload):
        profile = str(row.get("profile", ""))
        target = str(row.get("target", ""))
        grouped.setdefault((profile, target), []).append(row)

    summary_rows = []
    for (profile, target), rows in grouped.items():
        summary_rows.append(
            {
                "profile": profile,
                "target": target,
                "resources": len(rows),
                "high_confidence": sum(
                    1 for row in rows if row.get("match_confidence") == "high"
                ),
                "slow_resources_2s": row_count_at_least(rows, "duration_ms", 2000),
                "resources_ending_final_1s": sum(
                    1
                    for value in (
                        numeric(row.get("response_end_before_load_ms"))
                        for row in rows
                    )
                    if value is not None and 0 <= value <= 1000
                ),
                "median_duration_ms": row_median(rows, "duration_ms"),
                "median_wait_ms": row_median(rows, "wait_ms"),
                "median_receive_ms": row_median(rows, "receive_ms"),
                "max_response_end_ms": row_max(rows, "response_end_ms"),
                "max_tail_after_dom_ms": row_max(rows, "tail_after_dom_ms"),
                "median_response_end_before_load_ms": row_median(
                    rows, "response_end_before_load_ms"
                ),
                "median_relay_ms": row_median(rows, "relay_ms"),
                "median_last_tor_to_client_ms": row_positive_median(
                    rows, "last_tor_to_client_ms"
                ),
                "median_tor_to_client_idle_after_last_ms": row_positive_median(
                    rows, "tor_to_client_idle_after_last_ms"
                ),
                "median_response_end_after_last_tor_byte_ms": row_median(
                    rows, "response_end_after_last_tor_byte_ms"
                ),
                "median_abs_match_delta_ms": row_median(rows, "abs_match_delta_ms"),
                "max_receive_gap_ms": row_max(rows, "max_gap_ms"),
                "median_body_bytes": row_median(rows, "body_bytes"),
            }
        )
    return sorted(summary_rows, key=lambda row: (row["profile"], row["target"]))


def browser_resource_stream_gap_context_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    resource_rows = browser_resource_socks_relay_join_rows(payload)
    gap_rows = torfast_socks_relay_join_gap_detail_rows(payload)
    run_origins = browser_run_origin_map(payload)
    relay_timings = relay_receive_timings_by_profile(payload)
    rows: list[dict[str, object]] = []

    for gap_row in gap_rows:
        profile = str(gap_row.get("profile", ""))
        target = str(gap_row.get("target", ""))
        run_index = gap_row.get("run_index")
        key = (profile, target, run_index)
        time_origin = run_origins.get(key)
        gap_start_epoch = numeric(gap_row.get("prev_event_epoch_ms"))
        gap_end_epoch = numeric(gap_row.get("next_event_epoch_ms"))
        gap_start_ms = subtract_numeric(gap_start_epoch, time_origin)
        gap_end_ms = subtract_numeric(gap_end_epoch, time_origin)
        timing_id = gap_row.get("timing_id")
        circ_id = gap_row.get("circ_id")
        stream_id = gap_row.get("stream_id")
        same_circuit_activity = same_circuit_activity_during_stream_gap(
            relay_timings.get(profile, []),
            circ_id,
            stream_id,
            gap_start_epoch,
            gap_end_epoch,
        )
        same_stream_resources = [
            row
            for row in resource_rows
            if row.get("profile") == profile
            and row.get("target") == target
            and row.get("run_index") == run_index
            and (
                (
                    timing_id is not None
                    and row.get("timing_id") == timing_id
                )
                or (
                    timing_id is None
                    and row.get("stream_id") == stream_id
                    and torfast_circ_ids_match(circ_id, row.get("circ_id"))
                )
            )
        ]

        overlap_rows = []
        for resource in same_stream_resources:
            fetch_overlap = interval_overlap_ms(
                gap_start_ms,
                gap_end_ms,
                numeric(resource.get("fetch_start_ms")),
                numeric(resource.get("request_start_ms")),
            )
            wait_overlap = interval_overlap_ms(
                gap_start_ms,
                gap_end_ms,
                numeric(resource.get("request_start_ms")),
                numeric(resource.get("response_start_ms")),
            )
            receive_overlap = interval_overlap_ms(
                gap_start_ms,
                gap_end_ms,
                numeric(resource.get("response_start_ms")),
                numeric(resource.get("response_end_ms")),
            )
            active_overlap = interval_overlap_ms(
                gap_start_ms,
                gap_end_ms,
                numeric(resource.get("resource_start_ms")),
                numeric(resource.get("response_end_ms")),
            )
            row = dict(resource)
            row["fetch_to_request_overlap_ms"] = fetch_overlap
            row["request_wait_overlap_ms"] = wait_overlap
            row["response_receive_overlap_ms"] = receive_overlap
            row["active_overlap_ms"] = active_overlap
            phases = [
                ("fetch_to_request", fetch_overlap),
                ("request_wait", wait_overlap),
                ("response_receive", receive_overlap),
            ]
            top_phase, top_phase_overlap = max(
                phases,
                key=lambda item: numeric(item[1]) or 0,
            )
            if (numeric(top_phase_overlap) or 0) > 0:
                row["top_overlap_phase"] = top_phase
                row["top_overlap_ms"] = top_phase_overlap
            elif (active_overlap or 0) > 0:
                row["top_overlap_phase"] = "active_other"
                row["top_overlap_ms"] = active_overlap
            else:
                row["top_overlap_phase"] = ""
                row["top_overlap_ms"] = top_phase_overlap
            overlap_rows.append(row)

        top_overlap = None
        if overlap_rows:
            top_overlap = max(
                overlap_rows,
                key=lambda row: (
                    numeric(row.get("top_overlap_ms")) or 0,
                    numeric(row.get("active_overlap_ms")) or 0,
                    numeric(row.get("duration_ms")) or 0,
                ),
            )

        rows.append(
            {
                "profile": profile,
                "target": target,
                "run_index": run_index,
                "timing_id": timing_id,
                "circ_id": circ_id,
                "stream_id": stream_id,
                "gap_ms": gap_row.get("gap_ms"),
                "gap_start_ms": gap_start_ms,
                "gap_end_ms": gap_end_ms,
                **same_circuit_activity,
                "same_stream_resources": len(same_stream_resources),
                "high_confidence_resources": sum(
                    1
                    for row in same_stream_resources
                    if row.get("match_confidence") == "high"
                ),
                "slow_resources_2s": row_count_at_least(
                    same_stream_resources, "duration_ms", 2000
                ),
                "fetch_to_request_overlap_resources": sum(
                    1
                    for row in overlap_rows
                    if (numeric(row.get("fetch_to_request_overlap_ms")) or 0) > 0
                ),
                "request_wait_overlap_resources": sum(
                    1
                    for row in overlap_rows
                    if (numeric(row.get("request_wait_overlap_ms")) or 0) > 0
                ),
                "response_receive_overlap_resources": sum(
                    1
                    for row in overlap_rows
                    if (numeric(row.get("response_receive_overlap_ms")) or 0) > 0
                ),
                "fetch_to_request_overlap_ms": sum(
                    numeric(row.get("fetch_to_request_overlap_ms")) or 0
                    for row in overlap_rows
                ),
                "request_wait_overlap_ms": sum(
                    numeric(row.get("request_wait_overlap_ms")) or 0
                    for row in overlap_rows
                ),
                "response_receive_overlap_ms": sum(
                    numeric(row.get("response_receive_overlap_ms")) or 0
                    for row in overlap_rows
                ),
                "top_overlap_resource": (top_overlap or {}).get("resource"),
                "top_overlap_resource_type": (top_overlap or {}).get(
                    "resource_type"
                ),
                "top_overlap_duration_ms": (top_overlap or {}).get("duration_ms"),
                "top_overlap_fetch_to_request_ms": (top_overlap or {}).get(
                    "fetch_to_request_ms"
                ),
                "top_overlap_wait_ms": (top_overlap or {}).get("wait_ms"),
                "top_overlap_receive_ms": (top_overlap or {}).get("receive_ms"),
                "top_overlap_ms": (top_overlap or {}).get("top_overlap_ms"),
                "top_overlap_phase": (top_overlap or {}).get("top_overlap_phase"),
            }
        )

    return sorted(
        rows,
        key=lambda row: numeric(row.get("gap_ms")) or 0,
        reverse=True,
    )


def same_circuit_activity_during_stream_gap(
    relay_timings: list[dict[str, object]],
    circ_id: object,
    stream_id: object,
    gap_start_epoch: float | None,
    gap_end_epoch: float | None,
) -> dict[str, object]:
    empty = {
        "same_circuit_other_data_cells": 0,
        "same_circuit_other_data_kib": 0.0,
        "same_circuit_other_streams": 0,
        "same_circuit_top_other_stream_id": None,
        "same_circuit_top_other_stream_data_cells": 0,
        "same_circuit_top_other_stream_data_kib": 0.0,
        "max_circuit_data_gap_during_stream_gap_ms": None,
        "gap_scope_hint": "",
    }
    if (
        gap_start_epoch is None
        or gap_end_epoch is None
        or gap_end_epoch < gap_start_epoch
    ):
        return empty

    same_circuit_data_items = []
    other_data_items = []
    data_timestamps = []
    for item in relay_timings:
        if item.get("event") != "delivered" or item.get("relay_cmd") != "DATA":
            continue
        if not torfast_circ_ids_match(circ_id, item.get("circ_id")):
            continue
        timestamp = numeric(item.get("timestamp_ms"))
        if timestamp is None or timestamp < gap_start_epoch or timestamp > gap_end_epoch:
            continue
        same_circuit_data_items.append(item)
        data_timestamps.append(timestamp)
        if item.get("stream_id") != stream_id and gap_start_epoch < timestamp < gap_end_epoch:
            other_data_items.append(item)

    by_stream: dict[object, dict[str, float]] = {}
    for item in other_data_items:
        other_stream = item.get("stream_id")
        stats = by_stream.setdefault(other_stream, {"cells": 0.0, "bytes": 0.0})
        stats["cells"] += 1.0
        stats["bytes"] += numeric(item.get("data_len")) or 0.0

    top_other_stream_id = None
    top_other_stats = {"cells": 0.0, "bytes": 0.0}
    if by_stream:
        top_other_stream_id, top_other_stats = max(
            by_stream.items(),
            key=lambda item: (item[1].get("cells", 0.0), item[1].get("bytes", 0.0)),
        )

    circuit_points = [gap_start_epoch, *sorted(data_timestamps), gap_end_epoch]
    max_circuit_gap = max(
        max(0.0, right - left)
        for left, right in zip(circuit_points, circuit_points[1:])
    )

    same_circuit_other_data_cells = len(other_data_items)
    return {
        "same_circuit_other_data_cells": same_circuit_other_data_cells,
        "same_circuit_other_data_kib": (
            sum(numeric(item.get("data_len")) or 0.0 for item in other_data_items)
            / 1024.0
        ),
        "same_circuit_other_streams": len(by_stream),
        "same_circuit_top_other_stream_id": top_other_stream_id,
        "same_circuit_top_other_stream_data_cells": top_other_stats.get("cells", 0.0),
        "same_circuit_top_other_stream_data_kib": (
            top_other_stats.get("bytes", 0.0) / 1024.0
        ),
        "max_circuit_data_gap_during_stream_gap_ms": max_circuit_gap,
        "gap_scope_hint": (
            "stream-specific gap; circuit still active"
            if same_circuit_other_data_cells > 0
            else "whole circuit quiet during stream gap"
        ),
    }


def browser_resource_stream_gap_phase_summary_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    load_by_run = {
        (str(profile), str(target), run.get("run_index")): run.get("load_ms")
        for profile, _profile, target, _summary, run in iter_runs(payload)
        if isinstance(run, dict)
    }
    groups: dict[tuple[str, str, object], dict[str, object]] = {}
    top_resources: dict[tuple[str, str, object], list[str]] = {}

    for row in browser_resource_stream_gap_context_rows(payload):
        profile = str(row.get("profile", ""))
        target = str(row.get("target", ""))
        run_index = row.get("run_index")
        key = (profile, target, run_index)
        group = groups.setdefault(
            key,
            {
                "profile": profile,
                "target": target,
                "run_index": run_index,
                "load_ms": load_by_run.get(key),
                "gaps": 0,
                "gaps_1s": 0,
                "matched_gaps": 0,
                "fetch_to_request_overlap_ms": 0.0,
                "request_wait_overlap_ms": 0.0,
                "response_receive_overlap_ms": 0.0,
                "unmatched_gap_ms": 0.0,
                "max_gap_ms": None,
            },
        )

        gap_ms = numeric(row.get("gap_ms"))
        if gap_ms is None:
            continue

        group["gaps"] = int(group["gaps"]) + 1
        if gap_ms >= 1000:
            group["gaps_1s"] = int(group["gaps_1s"]) + 1
        group["max_gap_ms"] = max(
            numeric(group.get("max_gap_ms")) or 0.0,
            gap_ms,
        )

        fetch_overlap = numeric(row.get("fetch_to_request_overlap_ms")) or 0.0
        wait_overlap = numeric(row.get("request_wait_overlap_ms")) or 0.0
        receive_overlap = numeric(row.get("response_receive_overlap_ms")) or 0.0
        matched_overlap = fetch_overlap + wait_overlap + receive_overlap

        group["fetch_to_request_overlap_ms"] = (
            numeric(group.get("fetch_to_request_overlap_ms")) or 0.0
        ) + fetch_overlap
        group["request_wait_overlap_ms"] = (
            numeric(group.get("request_wait_overlap_ms")) or 0.0
        ) + wait_overlap
        group["response_receive_overlap_ms"] = (
            numeric(group.get("response_receive_overlap_ms")) or 0.0
        ) + receive_overlap

        if matched_overlap > 0:
            group["matched_gaps"] = int(group["matched_gaps"]) + 1
        else:
            group["unmatched_gap_ms"] = (
                numeric(group.get("unmatched_gap_ms")) or 0.0
            ) + gap_ms

        resource = row.get("top_overlap_resource")
        if isinstance(resource, str) and resource:
            top_resources.setdefault(key, []).append(compact_url(resource, max_length=42))

    for key, row in groups.items():
        phase_totals = {
            "fetch_to_request": numeric(row.get("fetch_to_request_overlap_ms")) or 0.0,
            "request_wait": numeric(row.get("request_wait_overlap_ms")) or 0.0,
            "response_receive": numeric(row.get("response_receive_overlap_ms")) or 0.0,
            "unmatched": numeric(row.get("unmatched_gap_ms")) or 0.0,
        }
        dominant_phase, dominant_ms = max(
            phase_totals.items(),
            key=lambda item: item[1],
        )
        row["dominant_phase"] = dominant_phase if dominant_ms > 0 else ""
        row["top_overlap_resources"] = compact_list(top_resources.get(key, []))

    return sorted(
        groups.values(),
        key=lambda row: (
            numeric(row.get("max_gap_ms")) or 0.0,
            numeric(row.get("load_ms")) or 0.0,
        ),
        reverse=True,
    )


def browser_resource_stream_gap_byte_context_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    context_rows = browser_resource_stream_gap_context_rows(payload)
    run_origins = browser_run_origin_map(payload)
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return []

    events_by_profile: dict[str, list[dict[str, object]]] = {}
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        events_by_profile[str(profile_name)] = parse_torfast_socks_byte_events(
            [str(line) for line in lines]
        )

    rows: list[dict[str, object]] = []
    for context_row in context_rows:
        profile = str(context_row.get("profile", ""))
        target = str(context_row.get("target", ""))
        run_index = context_row.get("run_index")
        timing_id = context_row.get("timing_id")
        if timing_id is None:
            continue
        time_origin = run_origins.get((profile, target, run_index))
        gap_start_epoch = add_numeric(time_origin, context_row.get("gap_start_ms"))
        gap_end_epoch = add_numeric(time_origin, context_row.get("gap_end_ms"))
        if gap_start_epoch is None or gap_end_epoch is None:
            continue

        events = [
            event
            for event in events_by_profile.get(profile, [])
            if event.get("timing_id") == timing_id
            and numeric(event.get("event_epoch_ms")) is not None
        ]
        client_events = [
            event for event in events if event.get("direction") == "client_to_tor"
        ]
        client_write_events = [
            event for event in events if event.get("direction") == "client_to_tor_write"
        ]
        tor_events = [
            event
            for event in events
            if event.get("direction") in {"tor_to_client", "tor_to_client_write"}
        ]
        client_in_gap = events_in_epoch_window(
            client_events, gap_start_epoch, gap_end_epoch, include_edges=False
        )
        client_on_edges = events_on_epoch_edges(
            client_events, gap_start_epoch, gap_end_epoch
        )
        client_write_in_gap = events_in_epoch_window(
            client_write_events, gap_start_epoch, gap_end_epoch, include_edges=False
        )
        client_write_on_edges = events_on_epoch_edges(
            client_write_events, gap_start_epoch, gap_end_epoch
        )
        tor_in_gap = events_in_epoch_window(
            tor_events, gap_start_epoch, gap_end_epoch, include_edges=False
        )
        client_before_gap_end = [
            event
            for event in client_events
            if (numeric(event.get("event_epoch_ms")) or 0) <= gap_end_epoch
        ]
        last_client = max(
            client_before_gap_end,
            key=lambda event: numeric(event.get("event_epoch_ms")) or 0,
            default=None,
        )
        last_client_epoch = (
            numeric(last_client.get("event_epoch_ms"))
            if isinstance(last_client, dict)
            else None
        )
        client_in_gap_epochs = [
            numeric(event.get("event_epoch_ms"))
            for event in client_in_gap
            if numeric(event.get("event_epoch_ms")) is not None
        ]
        rows.append(
            {
                "profile": profile,
                "target": target,
                "run_index": run_index,
                "timing_id": timing_id,
                "stream_id": context_row.get("stream_id"),
                "gap_ms": context_row.get("gap_ms"),
                "gap_phase": context_row.get("top_overlap_phase"),
                "client_events_in_gap": len(client_in_gap),
                "client_bytes_in_gap": sum(byte_event_size(event) for event in client_in_gap),
                "client_events_on_gap_edges": len(client_on_edges),
                "client_bytes_on_gap_edges": sum(
                    byte_event_size(event) for event in client_on_edges
                ),
                "client_write_events_in_gap": len(client_write_in_gap),
                "client_write_bytes_in_gap": sum(
                    byte_event_size(event) for event in client_write_in_gap
                ),
                "client_write_events_on_gap_edges": len(client_write_on_edges),
                "client_write_bytes_on_gap_edges": sum(
                    byte_event_size(event) for event in client_write_on_edges
                ),
                "first_client_in_gap_ms": subtract_numeric(
                    min(client_in_gap_epochs) if client_in_gap_epochs else None,
                    time_origin,
                ),
                "last_client_in_gap_ms": subtract_numeric(
                    max(client_in_gap_epochs) if client_in_gap_epochs else None,
                    time_origin,
                ),
                "gap_end_after_last_client_ms": subtract_numeric(
                    gap_end_epoch, last_client_epoch
                ),
                "last_client_cumulative_bytes": (
                    numeric(last_client.get("cumulative_bytes"))
                    if isinstance(last_client, dict)
                    else None
                ),
                "tor_events_in_gap": len(tor_in_gap),
                "tor_bytes_in_gap": sum(byte_event_size(event) for event in tor_in_gap),
                "top_overlap_resource": context_row.get("top_overlap_resource"),
            }
        )
    return sorted(
        rows,
        key=lambda row: numeric(row.get("gap_ms")) or 0,
        reverse=True,
    )


def browser_navigation_socks_join_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    rows = []
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return rows
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        socks_rows = list(
            group_torfast_socks_timings(
                parse_torfast_socks_timings([str(line) for line in lines])
            ).values()
        )
        if not socks_rows:
            continue
        relay_rows_by_timing_id = {
            row.get("timing_id"): row
            for row in torfast_socks_relay_join_rows([str(line) for line in lines])
            if row.get("timing_id") is not None
        }
        enriched_rows = []
        for socks_row in socks_rows:
            row = dict(socks_row)
            relay_row = relay_rows_by_timing_id.get(row.get("timing_id"))
            if relay_row:
                for field in (
                    "circ_id",
                    "stream_id",
                    "relay_ms",
                    "data_bytes",
                    "max_gap_ms",
                ):
                    if field in relay_row:
                        row[field] = relay_row[field]
            enriched_rows.append(row)

        records = profile_browser_run_records(profile)
        if not records:
            continue
        bounds = browser_run_epoch_bounds([run for _target, run, _index in records])
        for record_index, (target, run, original_index) in enumerate(records):
            lower, upper = bounds[record_index]
            run_rows = [
                row
                for row in enriched_rows
                if torfast_socks_row_epoch_ms(row) is not None
                and lower <= (torfast_socks_row_epoch_ms(row) or 0) < upper
            ]
            if not run_rows:
                continue
            match_epoch, match_field = browser_navigation_match_epoch_ms(run)
            if match_epoch is None:
                continue
            nearest = min(
                run_rows,
                key=lambda row: abs((torfast_socks_row_epoch_ms(row) or 0) - match_epoch),
            )
            joined_epoch = torfast_socks_row_epoch_ms(nearest)
            response_epoch = browser_response_epoch_ms(run)
            reply_epoch = add_numeric(
                joined_epoch, numeric(nearest.get("reply_elapsed_ms"))
            )
            first_tor_epoch = numeric(nearest.get("first_tor_to_client_epoch_ms"))
            timing = run.get("performance_timing", {})
            nav = {}
            if isinstance(timing, dict) and isinstance(timing.get("navigation"), dict):
                nav = timing.get("navigation") or {}
            rows.append(
                {
                    "profile": profile_name,
                    "target": target,
                    "run_index": run.get("run_index", original_index + 1),
                    "resource": nav.get("name") or target,
                    "resource_type": nav.get("initiatorType") or "navigation",
                    "resource_start_ms": nav.get("startTime"),
                    "fetch_start_ms": nav.get("fetchStart"),
                    "request_start_ms": nav.get("requestStart"),
                    "response_start_ms": nav.get("responseStart"),
                    "response_end_ms": nav.get("responseEnd"),
                    "duration_ms": nav.get("duration"),
                    "fetch_to_request_ms": resource_phase_ms(
                        nav, "fetchToRequest"
                    ),
                    "wait_ms": resource_phase_ms(nav, "requestWait"),
                    "receive_ms": resource_phase_ms(nav, "responseReceive"),
                    "body_bytes": nav.get("encodedBodySize"),
                    "nav_response_ms": nav_value(run, "responseStart"),
                    "load_ms": run.get("load_ms"),
                    "match_field": match_field,
                    "match_delta_ms": subtract_numeric(joined_epoch, match_epoch),
                    "abs_match_delta_ms": abs(joined_epoch - match_epoch)
                    if joined_epoch is not None
                    else None,
                    "match_confidence": match_confidence(
                        abs(joined_epoch - match_epoch)
                        if joined_epoch is not None
                        else None
                    ),
                    "timing_id": nearest.get("timing_id"),
                    "connect_ms": nearest.get("connect_ms"),
                    "reply_elapsed_ms": nearest.get("reply_elapsed_ms"),
                    "first_tor_to_client_ms": nearest.get("first_tor_to_client_ms"),
                    "first_tor_byte_to_response_ms": subtract_numeric(
                        response_epoch, first_tor_epoch
                    ),
                    "response_after_reply_ms": subtract_numeric(
                        response_epoch, reply_epoch
                    ),
                    "circ_id": nearest.get("circ_id"),
                    "stream_id": nearest.get("stream_id"),
                    "relay_ms": nearest.get("relay_ms"),
                    "data_bytes": nearest.get("data_bytes"),
                    "max_gap_ms": nearest.get("max_gap_ms"),
                }
            )
    return sorted(
        rows,
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0,
        ),
    )


def socks_first_byte_after_reply_median(
    timings: list[dict[str, object]],
) -> float | None:
    return first_byte_after_reply_median_for_rows(
        group_torfast_socks_timings(timings).values()
    )


def first_byte_after_reply_median_for_rows(
    rows: object,
) -> float | None:
    deltas = []
    for row in rows:
        if not isinstance(row, dict):
            continue
        first_byte = numeric(row.get("first_tor_to_client_ms"))
        reply = numeric(row.get("reply_elapsed_ms"))
        if first_byte is None or first_byte == 0 or reply is None:
            continue
        deltas.append(first_byte - reply)
    return median(deltas) if deltas else None


def socks_rows_by_target_kind(
    timings: list[dict[str, object]],
) -> dict[str, list[dict[str, object]]]:
    rows_by_kind: dict[str, list[dict[str, object]]] = {}
    for row in group_torfast_socks_timings(timings).values():
        kind = row.get("target_kind")
        if not isinstance(kind, str):
            kind = "unknown"
        rows_by_kind.setdefault(kind, []).append(row)
    return rows_by_kind


def torfast_socks_partial_idle_timeout_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    rows = []
    seen = set()
    for profile_name, _profile, target, _summary, run in iter_runs(payload):
        lines = run_torfast_lines(run)
        if not lines:
            continue
        timings = parse_torfast_socks_timings(lines)
        grouped = group_torfast_socks_timings(timings)
        for item in timings:
            if item.get("event") != "partial_relay_idle_timeout":
                continue
            timing_id = item.get("timing_id")
            key = (
                profile_name,
                target,
                run.get("run_index"),
                timing_id,
                item.get("elapsed_ms"),
                item.get("partial_relay_idle_timeout_ms"),
            )
            if key in seen:
                continue
            seen.add(key)
            socks_row = grouped.get(timing_id, {}) if timing_id is not None else {}
            relay_ms = numeric(socks_row.get("relay_ms"))
            elapsed_ms = numeric(item.get("elapsed_ms"))
            relay_after_timeout_ms = None
            if relay_ms is not None and elapsed_ms is not None:
                relay_after_timeout_ms = max(0.0, relay_ms - elapsed_ms)
            client_abandon_at_timeout = partial_idle_client_abandon_signal(item)
            rows.append(
                {
                    "profile": profile_name,
                    "target": target,
                    "run_index": run.get("run_index"),
                    "load_ms": run.get("load_ms"),
                    "timing_id": timing_id,
                    "conn_started_epoch_ms": item.get("conn_started_epoch_ms"),
                    "target_kind": item.get(
                        "target_kind", socks_row.get("target_kind", "")
                    ),
                    "partial_relay_idle_timeout_ms": item.get(
                        "partial_relay_idle_timeout_ms"
                    ),
                    "elapsed_ms": item.get("elapsed_ms"),
                    "last_tor_to_client_ms": item.get("last_tor_to_client_ms"),
                    "idle_after_last_tor_byte_ms": item.get(
                        "idle_after_last_tor_byte_ms"
                    ),
                    "tor_to_client_bytes": item.get(
                        "tor_to_client_bytes", socks_row.get("tor_to_client_bytes")
                    ),
                    "client_abandon_at_timeout": client_abandon_at_timeout,
                    "client_to_tor_eof_at_timeout_ms": item.get(
                        "client_to_tor_eof_ms"
                    ),
                    "client_to_tor_error_at_timeout_ms": item.get(
                        "client_to_tor_error_ms"
                    ),
                    "tor_to_client_write_error_at_timeout_ms": item.get(
                        "tor_to_client_write_error_ms"
                    ),
                    "tor_to_client_write_close_at_timeout_ms": item.get(
                        "tor_to_client_write_close_ms"
                    ),
                    "tor_to_client_write_close_error_at_timeout_ms": item.get(
                        "tor_to_client_write_close_error_ms"
                    ),
                    "tor_to_client_write_bytes_at_timeout": item.get(
                        "tor_to_client_write_bytes"
                    ),
                    "relay_ms": socks_row.get("relay_ms"),
                    "relay_after_timeout_ms": relay_after_timeout_ms,
                    "client_to_tor_eof_ms": socks_row.get("client_to_tor_eof_ms"),
                    "copy_error_kind": socks_row.get("copy_error_kind", ""),
                }
            )
    return sorted(
        rows,
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0,
            numeric(row.get("elapsed_ms")) or 0,
        ),
    )


def partial_idle_client_abandon_signal(row: dict[str, object]) -> bool | None:
    return timeout_client_abandon_signal(row)


def no_tor_byte_client_abandon_signal(row: dict[str, object]) -> bool | None:
    return timeout_client_abandon_signal(row)


def timeout_client_abandon_signal(row: dict[str, object]) -> bool | None:
    fields = (
        "client_to_tor_eof_ms",
        "client_to_tor_error_ms",
        "tor_to_client_write_error_ms",
        "tor_to_client_write_close_error_ms",
    )
    values = [numeric(row.get(field)) for field in fields if field in row]
    if not values:
        return None
    return any(value is not None and value > 0 for value in values)


