def torfast_socks_partial_idle_resource_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    resource_rows = browser_resource_socks_relay_join_rows(payload)
    rows = []
    for timeout in torfast_socks_partial_idle_timeout_rows(payload):
        profile = str(timeout.get("profile", ""))
        target = str(timeout.get("target", ""))
        run_index = timeout.get("run_index")
        timing_id = timeout.get("timing_id")
        run = browser_run_by_profile_target_index(
            payload, profile=profile, target=target, run_index=run_index
        )
        if run is None:
            continue
        time_origin = browser_time_origin_ms(run)
        timeout_epoch = add_numeric(
            timeout.get("conn_started_epoch_ms"), timeout.get("elapsed_ms")
        )
        timeout_after_start = subtract_numeric(timeout_epoch, time_origin)
        load_after_timeout = subtract_numeric(browser_load_epoch_ms(run), timeout_epoch)
        exact_matches = [
            row
            for row in resource_rows
            if row.get("profile") == profile
            and row.get("target") == target
            and row.get("run_index") == run_index
            and row.get("timing_id") == timing_id
        ]
        active_counts = browser_resource_phase_counts_at_epoch(run, timeout_epoch)
        active_resources = browser_active_resource_rows_at_epoch(run, timeout_epoch)
        active_end_after_timeout_values = [
            numeric(row.get("response_end_after_timeout_ms"))
            for row in active_resources
            if numeric(row.get("response_end_after_timeout_ms")) is not None
        ]

        nearest_resource = nearest_resource_by_response_end(run, timeout_epoch)
        nearest_resource_name = ""
        nearest_resource_type = ""
        nearest_resource_body = None
        nearest_resource_protocol = ""
        nearest_response_end_delta = None
        phase_at_timeout = "no_resource_match"
        if nearest_resource is not None:
            nearest_resource_name = str(nearest_resource.get("name", ""))
            nearest_resource_type = str(nearest_resource.get("initiatorType", ""))
            nearest_resource_body = nearest_resource.get("encodedBodySize")
            nearest_resource_protocol = protocol_label(
                nearest_resource.get("nextHopProtocol")
            )
            nearest_response_end_delta = subtract_numeric(
                add_numeric(
                    browser_time_origin_ms(run),
                    nearest_resource.get("responseEnd"),
                ),
                timeout_epoch,
            )
            phase_at_timeout = browser_resource_phase_at_epoch(
                run, nearest_resource, timeout_epoch
            )

        rows.append(
            {
                "profile": profile,
                "target": target,
                "run_index": run_index,
                "load_ms": timeout.get("load_ms"),
                "timing_id": timing_id,
                "timeout_after_start_ms": timeout_after_start,
                "load_after_timeout_ms": load_after_timeout,
                "active_resources_at_timeout": active_counts.get("active", 0),
                "queued_resources_at_timeout": active_counts.get("queued", 0),
                "waiting_resources_at_timeout": active_counts.get("waiting", 0),
                "receiving_resources_at_timeout": active_counts.get("receiving", 0),
                "max_active_end_after_timeout_ms": (
                    max(active_end_after_timeout_values)
                    if active_end_after_timeout_values
                    else None
                ),
                "active_resource_samples": format_active_resource_samples(
                    active_resources
                ),
                "exact_resource_matches": len(exact_matches),
                "exact_high_confidence_matches": sum(
                    1 for row in exact_matches if row.get("match_confidence") == "high"
                ),
                "nearest_response_end_delta_ms": nearest_response_end_delta,
                "phase_at_timeout": phase_at_timeout,
                "nearest_resource": nearest_resource_name,
                "nearest_resource_type": nearest_resource_type,
                "nearest_resource_protocol": nearest_resource_protocol,
                "nearest_resource_body_bytes": nearest_resource_body,
                "partial_relay_idle_timeout_ms": timeout.get(
                    "partial_relay_idle_timeout_ms"
                ),
                "idle_after_last_tor_byte_ms": timeout.get(
                    "idle_after_last_tor_byte_ms"
                ),
                "tor_to_client_bytes": timeout.get("tor_to_client_bytes"),
            }
        )
    return sorted(
        rows,
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0,
            numeric(row.get("timeout_after_start_ms")) or 0,
        ),
    )


