def arti_profile_queue_loss_capacity_rows(
    payload: dict[str, object], baseline_profile: str = "arti_release_browser"
) -> list[dict[str, object]]:
    rows = []
    for choice_row in arti_profile_queue_loss_choice_rows(payload, baseline_profile):
        profile = str(choice_row.get("candidate_profile", ""))
        target = str(choice_row.get("target", ""))
        run_index = choice_row.get("worst_queue_run")
        circuit = str(choice_row.get("queue_circuit", ""))
        timings = torfast_circuit_selection_timings_for_run(
            payload, profile, target, run_index
        )
        open_items = [item for item in timings if item.get("event") == "open"]
        exit_open_items = [
            item for item in open_items if item.get("usage_kind") == "exit"
        ]
        selected_open_items = [
            item
            for item in exit_open_items
            if torfast_circ_ids_match(circuit, item.get("tunnel_unique_id"))
        ]
        open_candidates = [
            numeric(item.get("open_candidates"))
            for item in selected_open_items
            if numeric(item.get("open_candidates")) is not None
        ]
        selected_assigned = [
            numeric(item.get("selected_assigned_streams"))
            for item in selected_open_items
            if numeric(item.get("selected_assigned_streams")) is not None
        ]
        selected_active = [
            numeric(item.get("selected_active_streams"))
            for item in selected_open_items
            if numeric(item.get("selected_active_streams")) is not None
        ]
        active_caps = [
            numeric(item.get("select_max_active_streams"))
            for item in selected_open_items
            if numeric(item.get("select_max_active_streams")) is not None
        ]
        support_summaries = [
            row
            for item in selected_open_items
            if (
                row := parse_torfast_open_support_summary(
                    item.get("open_support_summary")
                )
            )
        ]
        build_items = [item for item in timings if item.get("event") == "build"]
        build_parallelism = [
            numeric(item.get("launch_parallelism"))
            for item in build_items
            if numeric(item.get("launch_parallelism")) is not None
        ]
        row = {
            **choice_row,
            "selected_open_rows": len(selected_open_items),
            "exit_open_rows": len(exit_open_items),
            "min_open_candidates": min(open_candidates) if open_candidates else None,
            "median_open_candidates": median(open_candidates)
            if open_candidates
            else None,
            "max_open_candidates": max(open_candidates) if open_candidates else None,
            "max_selected_assigned_streams": max(selected_assigned)
            if selected_assigned
            else None,
            "max_selected_active_streams": max(selected_active)
            if selected_active
            else None,
            "max_open_total": max(
                (row.get("total", 0) for row in support_summaries), default=None
            ),
            "max_isolation_rejects": max(
                (row.get("isolation", 0) for row in support_summaries),
                default=None,
            ),
            "max_exit_unisolated": max(
                (row.get("exit_unisolated", 0) for row in support_summaries),
                default=None,
            ),
            "max_exit_compatible_isolated": max(
                (
                    row.get("exit_compatible_isolated", 0)
                    for row in support_summaries
                ),
                default=None,
            ),
            "max_exit_incompatible_isolated": max(
                (
                    row.get("exit_incompatible_isolated", 0)
                    for row in support_summaries
                ),
                default=None,
            ),
            "max_port_rejects": max(
                (row.get("port", 0) for row in support_summaries), default=None
            ),
            "max_unusable": max(
                (row.get("unusable", 0) for row in support_summaries), default=None
            ),
            "max_active_cap": max(active_caps) if active_caps else None,
            "active_cap_moves": sum(
                1
                for item in selected_open_items
                if item.get("active_stream_cap_moved") is True
            ),
            "active_cap_saturated": sum(
                1
                for item in selected_open_items
                if item.get("active_stream_cap_saturated") is True
            ),
            "load_aware_selected_rows": sum(
                1
                for item in selected_open_items
                if item.get("select_load_aware") is True
            ),
            "health_aware_selected_rows": sum(
                1
                for item in selected_open_items
                if item.get("select_health_aware") is True
            ),
            "builds": len(build_items),
            "max_build_parallelism": max(build_parallelism)
            if build_parallelism
            else None,
            "same_isolation_topups": count_events(timings, "same_isolation_topup"),
            "same_isolation_topup_failures": count_events(
                timings, "same_isolation_topup_failed"
            ),
        }
        row["capacity_hint"] = queue_loss_capacity_hint(row)
        rows.append(row)
    return sorted(rows, key=queue_loss_sort_key, reverse=True)


def arti_one_eligible_open_circuit_burst_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    rows = []
    for profile_name, _profile, target, _summary, run in iter_runs(payload):
        if not str(profile_name).startswith("arti_"):
            continue
        run_index = run.get("run_index")
        timings = torfast_circuit_selection_timings_for_run(
            payload, str(profile_name), str(target), run_index
        )
        open_items = [item for item in timings if item.get("event") == "open"]
        exit_open_items = [
            item for item in open_items if item.get("usage_kind") == "exit"
        ]
        one_candidate_items = [
            item
            for item in exit_open_items
            if numeric(item.get("open_candidates")) == 1
        ]
        if not one_candidate_items:
            continue
        support_summaries = [
            row
            for item in one_candidate_items
            if (
                row := parse_torfast_open_support_summary(
                    item.get("open_support_summary")
                )
            )
        ]
        selected_assigned = [
            numeric(item.get("selected_assigned_streams"))
            for item in one_candidate_items
            if numeric(item.get("selected_assigned_streams")) is not None
        ]
        selected_active = [
            numeric(item.get("selected_active_streams"))
            for item in one_candidate_items
            if numeric(item.get("selected_active_streams")) is not None
        ]
        selected_circuits = [
            str(item.get("tunnel_unique_id"))
            for item in one_candidate_items
            if item.get("tunnel_unique_id")
        ]
        rejected_open = [
            row.get("total", 0) - row.get("supported", 0)
            for row in support_summaries
        ]
        row = {
            "profile": profile_name,
            "target": target,
            "run_index": run_index,
            "ok": run.get("ok"),
            "load_ms": run.get("load_ms"),
            "one_candidate_exit_rows": len(one_candidate_items),
            "exit_open_rows": len(exit_open_items),
            "one_candidate_exit_row_share_pct": (
                len(one_candidate_items) * 100.0 / len(exit_open_items)
                if exit_open_items
                else None
            ),
            "max_selected_assigned_streams": max(selected_assigned)
            if selected_assigned
            else None,
            "max_selected_active_streams": max(selected_active)
            if selected_active
            else None,
            "max_open_total": max(
                (row.get("total", 0) for row in support_summaries), default=None
            ),
            "max_rejected_open": max(rejected_open, default=None),
            "max_isolation_rejects": max(
                (row.get("isolation", 0) for row in support_summaries),
                default=None,
            ),
            "max_exit_unisolated": max(
                (row.get("exit_unisolated", 0) for row in support_summaries),
                default=None,
            ),
            "max_exit_compatible_isolated": max(
                (
                    row.get("exit_compatible_isolated", 0)
                    for row in support_summaries
                ),
                default=None,
            ),
            "max_exit_incompatible_isolated": max(
                (
                    row.get("exit_incompatible_isolated", 0)
                    for row in support_summaries
                ),
                default=None,
            ),
            "max_port_rejects": max(
                (row.get("port", 0) for row in support_summaries), default=None
            ),
            "max_unusable": max(
                (row.get("unusable", 0) for row in support_summaries), default=None
            ),
            "pending_waits": count_pending_wait_events(timings),
            "builds": count_events(timings, "build"),
            "selected_circuits": compact_list(selected_circuits),
        }
        row["hint"] = one_eligible_open_circuit_burst_hint(row)
        if one_eligible_open_circuit_burst_is_notable(row):
            rows.append(row)
    return sorted(rows, key=one_eligible_open_circuit_burst_sort_key, reverse=True)[
        :20
    ]


def one_eligible_open_circuit_burst_is_notable(row: dict[str, object]) -> bool:
    return (
        (numeric(row.get("max_selected_assigned_streams")) or 0) >= 4
        or (numeric(row.get("max_selected_active_streams")) or 0) >= 3
        or (numeric(row.get("max_rejected_open")) or 0) >= 2
    )


def one_eligible_open_circuit_burst_sort_key(row: dict[str, object]) -> tuple:
    return (
        numeric(row.get("max_rejected_open")) or 0,
        numeric(row.get("max_selected_assigned_streams")) or 0,
        numeric(row.get("one_candidate_exit_rows")) or 0,
        numeric(row.get("load_ms")) or 0,
    )


def one_eligible_open_circuit_burst_hint(row: dict[str, object]) -> str:
    max_open_total = numeric(row.get("max_open_total")) or 0
    max_rejected = numeric(row.get("max_rejected_open")) or 0
    max_isolation = numeric(row.get("max_isolation_rejects")) or 0
    max_other_iso = numeric(row.get("max_exit_incompatible_isolated")) or 0
    max_port = numeric(row.get("max_port_rejects")) or 0
    max_unusable = numeric(row.get("max_unusable")) or 0
    pending_waits = numeric(row.get("pending_waits")) or 0
    builds = numeric(row.get("builds")) or 0

    if max_open_total <= 1:
        return "needs more open exit circuits"
    if max_other_iso > 0 and max_other_iso >= max_isolation:
        return "other isolation groups own open circuits"
    if max_isolation > 0 and max_isolation >= max_port and max_isolation >= max_unusable:
        return "isolation rejects most open circuits"
    if max_port > 0 and max_port >= max_unusable:
        return "port rejects limit open circuits"
    if max_unusable > 0:
        return "unusable open circuits"
    if max_rejected > 0:
        return "open circuits rejected for mixed reasons"
    if pending_waits > 0 or builds > 0:
        return "pending/builds not ready before burst"
    return "only one eligible open circuit logged"


def torfast_circuit_selection_timings_for_run(
    payload: dict[str, object],
    profile_name: str,
    target: str,
    run_index: object,
) -> list[dict[str, object]]:
    for current_profile, profile, current_target, _summary, run in iter_runs(payload):
        if (
            str(current_profile) != profile_name
            or str(current_target) != target
            or run.get("run_index") != run_index
        ):
            continue
        lines = run_torfast_lines(run)
        if not lines and isinstance(profile, dict):
            lines = proxy_log_lines(profile)
        return parse_torfast_circuit_selection_timings([str(line) for line in lines])
    return []


def queue_loss_capacity_hint(row: dict[str, object]) -> str:
    selected_rows = numeric(row.get("selected_open_rows")) or 0
    max_open = numeric(row.get("max_open_candidates"))
    max_assigned = numeric(row.get("max_selected_assigned_streams")) or 0
    max_active = numeric(row.get("max_selected_active_streams")) or 0
    max_isolation = numeric(row.get("max_isolation_rejects")) or 0
    max_other_iso = numeric(row.get("max_exit_incompatible_isolated")) or 0
    max_active_cap = numeric(row.get("max_active_cap")) or 0
    topups = numeric(row.get("same_isolation_topups")) or 0

    if selected_rows <= 0:
        return "selected circuit proof missing"
    if (
        max_open is not None
        and max_open <= 1
        and max_isolation > 0
        and (max_assigned >= 6 or max_active >= 4)
    ):
        if max_other_iso > 0 and max_other_iso >= max_isolation:
            return "other isolation groups own open circuits"
        if topups <= 0:
            return "eligible same-isolation open capacity missing"
        return "same-isolation capacity still too low"
    if max_active_cap <= 0 and (max_assigned >= 6 or max_active >= 4):
        return "active stream cap not enabled"
    if max_open is not None and max_open <= 1:
        return "only one eligible open circuit"
    return "capacity pressure unclear"


def best_matching_late_phase_queue_row(
    rows: list[dict[str, object]],
    profile: str,
    target: str,
    run_index: object,
    circuit: str,
) -> dict[str, object] | None:
    for row in rows:
        if (
            str(row.get("profile", "")) == profile
            and str(row.get("target", "")) == target
            and row.get("run_index") == run_index
            and torfast_circ_ids_match(circuit, row.get("queue_circ_id"))
        ):
            return row
    return None


def queue_loss_choice_hint(row: dict[str, object]) -> str:
    better_health = numeric(row.get("better_health_alt_rows")) or 0
    lower_assignment = numeric(row.get("lower_assignment_alt_rows")) or 0
    context = str(row.get("candidate_context", "")).strip()
    if not context:
        return "choice context missing"
    if context.startswith("build complete"):
        return "pending build context only"
    if better_health > 0 or lower_assignment > 0:
        return "logged open alternative existed"
    if context.startswith("*") and ", " not in context:
        return "only selected open circuit logged"
    return "no better logged open alternative"


def best_matching_scheduler_late_circuit_row(
    rows: list[dict[str, object]],
    profile: str,
    target: str,
    run_index: object,
    circuit: str,
) -> dict[str, object] | None:
    for row in rows:
        if (
            str(row.get("profile", "")) == profile
            and str(row.get("target", "")) == target
            and row.get("run_index") == run_index
            and torfast_circ_ids_match(circuit, row.get("circuit"))
        ):
            return row
    return None


def circuit_congestion_timings_by_run(
    payload: dict[str, object],
) -> dict[tuple[str, str, object], list[dict[str, object]]]:
    rows: dict[tuple[str, str, object], list[dict[str, object]]] = {}
    for profile_name, profile, target, _summary, run in iter_runs(payload):
        lines = run_torfast_lines(run)
        if not lines and isinstance(profile, dict):
            lines = proxy_log_lines(profile)
        timings = parse_torfast_circuit_congestion_timings(
            [str(line) for line in lines]
        )
        if not timings:
            continue
        key = (str(profile_name), str(target), run.get("run_index"))
        rows.setdefault(key, []).extend(timings)
    return rows


def summarize_circuit_congestion_rows(
    rows: list[dict[str, object]],
) -> dict[str, object]:
    cwnds = [
        numeric(row.get("cwnd"))
        for row in rows
        if row.get("cwnd_present") is True and numeric(row.get("cwnd")) is not None
    ]
    inflights = [
        numeric(row.get("inflight"))
        for row in rows
        if row.get("inflight_present") is True
        and numeric(row.get("inflight")) is not None
    ]
    return {
        "congestion_events": len(rows),
        "congestion_sendme_sent": count_events(rows, "sendme_sent"),
        "congestion_sendme_received": count_events(rows, "sendme_received"),
        "congestion_scheduler_blocks": count_events(rows, "scheduler_hop_blocked"),
        "congestion_can_send_false": sum(
            1 for row in rows if row.get("can_send") is False
        ),
        "congestion_channel_blocked": sum(
            1 for row in rows if row.get("channel_blocked") is True
        ),
        "congestion_algorithms": format_counts(
            value_counts(row.get("algorithm") for row in rows)
        ),
        "congestion_min_cwnd": min(cwnds) if cwnds else None,
        "congestion_max_cwnd": max(cwnds) if cwnds else None,
        "congestion_max_inflight": max(inflights) if inflights else None,
    }


def queue_loss_cause_hint(row: dict[str, object]) -> str:
    scheduler_hint = str(row.get("scheduler_proof_hint", ""))
    congestion_blocks = numeric(row.get("congestion_scheduler_blocks")) or 0
    can_send_false = numeric(row.get("congestion_can_send_false")) or 0
    pending = numeric(row.get("max_terminal_pending_after_bytes"))
    sendmes = numeric(row.get("terminal_sendmes"))
    sendme_ok = numeric(row.get("terminal_sendme_ok"))
    min_window = numeric(row.get("min_terminal_recv_window_after_take"))

    if scheduler_hint in {
        "single stream picked on multi-stream circuit",
        "skewed scheduler picks",
        "repeated same-stream picks",
    }:
        return "scheduler fairness risk"
    if congestion_blocks > 0 or can_send_false > 0:
        return "circuit congestion send block"
    if pending is not None and pending > 0:
        return "local pending bytes"
    if sendmes is not None and sendme_ok is not None and sendme_ok < sendmes:
        return "SENDME gap risk"
    if min_window is not None and min_window <= 0:
        return "receive window risk"
    if scheduler_hint == "no scheduler monopoly seen":
        return "late selected-circuit DATA, not scheduler/congestion"
    return "late selected-circuit cause unclear"


def row_circuit_matches_queue(row: dict[str, object], queue_circuit: str) -> bool:
    if not queue_circuit:
        return True
    circuits = expand_compact_list_field([row], "blocker_circuits")
    return any(torfast_circ_ids_match(queue_circuit, circuit) for circuit in circuits)


def compact_value_counts(
    rows: list[dict[str, object]], field: str
) -> dict[str, int]:
    counts: dict[str, int] = {}
    for row in rows:
        for value in expand_compact_list_field([row], field):
            counts[value] = counts.get(value, 0) + 1
    return counts


def top_count(counts: dict[str, int]) -> tuple[str | None, int]:
    if not counts:
        return None, 0
    return max(counts.items(), key=lambda item: (item[1], item[0]))


def count_share_pct(count: int, total: int) -> float | None:
    if total <= 0:
        return None
    return count * 100.0 / total


def selected_circuit_pattern_hint(row: dict[str, object]) -> str:
    late_resources = numeric(row.get("late_resources")) or 0
    late_stream_count = numeric(row.get("late_stream_count")) or 0
    late_timing_count = numeric(row.get("late_timing_count")) or 0
    terminal_streams = numeric(row.get("terminal_streams")) or 0
    top_stream_share = numeric(row.get("top_stream_share_pct"))

    if late_resources <= 0:
        return "late circuit pattern unclear"
    if (
        late_stream_count <= 1
        and late_timing_count <= 1
        and terminal_streams <= 1
        and (top_stream_share is None or top_stream_share >= 100.0)
    ):
        return "single stream late"
    if late_stream_count >= 2 or terminal_streams >= 2:
        return "multi-stream circuit late"
    return "late circuit pattern unclear"


def best_queue_loss_circuit_row(
    circuit_rows: list[dict[str, object]], loss_row: dict[str, object]
) -> dict[str, object] | None:
    wanted = str(loss_row.get("queue_circ_id", ""))
    for row in circuit_rows:
        circuit = str(row.get("circuit", ""))
        if wanted and (
            circuit == wanted or circuit.startswith(wanted) or wanted.startswith(circuit)
        ):
            return row
    if not circuit_rows:
        return None
    return max(
        circuit_rows,
        key=lambda row: (
            numeric(row.get("late_resources")) or 0,
            numeric(row.get("max_terminal_last_data_after_queue_ms")) or 0,
        ),
    )


def queue_loss_mechanism_circuit(
    loss_row: dict[str, object],
    write_row: dict[str, object],
    circuit_row: dict[str, object] | None,
) -> str:
    if circuit_row and circuit_row.get("circuit"):
        return str(circuit_row.get("circuit", ""))
    if loss_row.get("queue_circ_id"):
        return str(loss_row.get("queue_circ_id", ""))
    return str(write_row.get("blocker_circuits", ""))


def queue_loss_mechanism_hint(row: dict[str, object]) -> str:
    pending = numeric(row.get("max_terminal_pending_after_bytes"))
    sendmes = numeric(row.get("terminal_sendmes"))
    sendme_ok = numeric(row.get("terminal_sendme_ok"))
    min_window = numeric(row.get("min_terminal_recv_window_after_take"))
    write_after_terminal = numeric(row.get("max_write_after_terminal_last_data_ms"))
    terminal_after_queue = numeric(row.get("max_terminal_last_data_after_queue_ms"))

    if pending is not None and pending > 0:
        return "local pending bytes"
    if sendmes is not None and sendme_ok is not None and sendme_ok < sendmes:
        return "SENDME gap risk"
    if min_window is not None and min_window <= 0:
        return "receive window risk"
    if write_after_terminal is not None and write_after_terminal > 500:
        return "browser write lag after Tor data"
    if (
        terminal_after_queue is not None
        and terminal_after_queue >= 1000
        and (pending is None or pending == 0)
        and (sendmes is None or sendme_ok == sendmes)
        and (min_window is None or min_window > 0)
        and (write_after_terminal is None or write_after_terminal <= 0)
    ):
        return "late Tor data, no local pending/window block"
    return "late queue mechanism unclear"


def queue_loss_sort_key(row: dict[str, object]) -> tuple[float, float, float, float]:
    return (
        numeric(row.get("median_load_delta_ms")) or 0,
        numeric(row.get("worst_run_queued_1000_delta")) or 0,
        numeric(row.get("worst_run_max_queue_delta_ms")) or 0,
        numeric(row.get("median_max_queue_delta_ms")) or 0,
    )


def queue_loss_reason_hint(row: dict[str, object]) -> str:
    if (numeric(row.get("lower_assignment_alt_rows")) or 0) > 0:
        return "lower-assignment alternative existed"
    if (numeric(row.get("better_health_alt_rows")) or 0) > 0:
        return "better-health alternative existed"
    if row.get("queue_circ_id"):
        return "single selected circuit queue"
    return "browser resource queue"


def queue_metric(row: dict[str, object], field: str) -> float:
    value = numeric(row.get(field))
    return value if value is not None else 0.0


def arti_profile_promotion_risk_rows(
    payload: dict[str, object], baseline_profile: str = "arti_release_browser"
) -> list[dict[str, object]]:
    partial_idle_risks_by_profile_target: dict[
        tuple[str, str], list[dict[str, object]]
    ] = {}
    for risk_row in partial_idle_active_resource_risk_rows(payload):
        key = (str(risk_row.get("profile", "")), str(risk_row.get("target", "")))
        partial_idle_risks_by_profile_target.setdefault(key, []).append(risk_row)

    partial_idle_no_client_by_profile_target: dict[
        tuple[str, str], list[dict[str, object]]
    ] = {}
    for risk_row in partial_idle_no_client_abandon_risk_rows(payload):
        key = (str(risk_row.get("profile", "")), str(risk_row.get("target", "")))
        partial_idle_no_client_by_profile_target.setdefault(key, []).append(risk_row)

    no_byte_risks_by_profile_target: dict[
        tuple[str, str], list[dict[str, object]]
    ] = {}
    for risk_row in no_tor_byte_active_resource_risk_rows(payload):
        key = (str(risk_row.get("profile", "")), str(risk_row.get("target", "")))
        no_byte_risks_by_profile_target.setdefault(key, []).append(risk_row)

    no_byte_no_client_by_profile_target: dict[
        tuple[str, str], list[dict[str, object]]
    ] = {}
    for risk_row in no_tor_byte_no_client_abandon_risk_rows(payload):
        key = (str(risk_row.get("profile", "")), str(risk_row.get("target", "")))
        no_byte_no_client_by_profile_target.setdefault(key, []).append(risk_row)

    rows: list[dict[str, object]] = []
    for row in arti_profile_ab_rows(payload, baseline_profile):
        risks = []
        candidate_profile = str(row.get("candidate_profile", ""))
        target = str(row.get("target", ""))
        paired_delta = numeric(row.get("median_load_delta_ms"))
        summary_delta = numeric(row.get("summary_median_load_delta_ms"))
        max_delta = numeric(row.get("max_load_delta_ms"))
        paired_runs = numeric(row.get("paired_runs"))
        wins = numeric(row.get("candidate_load_wins"))
        if paired_delta is not None and paired_delta > 0:
            risks.append("paired median slower")
        if summary_delta is not None and summary_delta > 0:
            risks.append("summary median slower")
        if max_delta is not None and max_delta > 0:
            risks.append("max tail worse")
        if (
            paired_runs is not None
            and wins is not None
            and paired_runs > 0
            and wins <= paired_runs / 2
        ):
            risks.append("low paired wins")
        if partial_idle_risks_by_profile_target.get((candidate_profile, target)):
            risks.append("partial idle active resources")
        if partial_idle_no_client_by_profile_target.get((candidate_profile, target)):
            risks.append("partial idle no client abandon")
        if no_byte_risks_by_profile_target.get((candidate_profile, target)):
            risks.append("no-byte active resources")
        if no_byte_no_client_by_profile_target.get((candidate_profile, target)):
            risks.append("no-byte no client abandon")
        if not risks:
            continue
        rows.append(
            {
                **row,
                "risk": ", ".join(risks),
                "paired_load_wins": f"{fmt(row.get('candidate_load_wins'))}/{fmt(row.get('paired_runs'))}",
            }
        )
    return rows


def arti_profile_promotion_risk_detail_rows(
    payload: dict[str, object], baseline_profile: str = "arti_release_browser"
) -> list[dict[str, object]]:
    rows: list[dict[str, object]] = []
    for risk_row in arti_profile_promotion_risk_rows(payload, baseline_profile):
        target = str(risk_row.get("target", ""))
        candidate_profile = str(risk_row.get("candidate_profile", ""))
        baseline = str(risk_row.get("baseline_profile", baseline_profile))
        candidate_runs = runs_by_index(payload, candidate_profile, target)
        baseline_runs = runs_by_index(payload, baseline, target)
        candidate_items = [
            (index, numeric(run.get("load_ms")), run)
            for index, run in candidate_runs.items()
            if run.get("ok") and numeric(run.get("load_ms")) is not None
        ]
        baseline_items = [
            (index, numeric(run.get("load_ms")), run)
            for index, run in baseline_runs.items()
            if run.get("ok") and numeric(run.get("load_ms")) is not None
        ]
        if not candidate_items:
            continue
        candidate_index, candidate_load, candidate_run = max(
            candidate_items, key=lambda item: item[1] or 0
        )
        _baseline_index, baseline_load, _baseline_run = max(
            baseline_items, key=lambda item: item[1] or 0
        ) if baseline_items else (None, None, {})
        slowest_resource = run_slowest_resource(candidate_run)
        slowest_ms = (
            numeric(slowest_resource.get("duration"))
            if isinstance(slowest_resource, dict)
            else None
        )
        rows.append(
            {
                "target": target,
                "candidate_profile": candidate_profile,
                "baseline_profile": baseline,
                "candidate_max_run": candidate_index,
                "candidate_max_load_ms": candidate_load,
                "baseline_max_load_ms": baseline_load,
                "phase_hint": max_run_phase_hint(candidate_run),
                "nav_connect_ms": nav_phase(candidate_run, "connectStart", "connectEnd"),
                "response_to_dom_ms": nav_phase(
                    candidate_run, "responseStart", "domContentLoadedEventEnd"
                ),
                "dom_to_load_ms": nav_phase(
                    candidate_run, "domContentLoadedEventEnd", "loadEventEnd"
                ),
                "slowest_resource_ms": slowest_ms,
                "slowest_resource": compact_url(
                    str(slowest_resource.get("name", "")), max_length=72
                )
                if isinstance(slowest_resource, dict)
                else "",
            }
        )
    return rows


def arti_profile_promotion_risk_socks_context_rows(
    payload: dict[str, object], baseline_profile: str = "arti_release_browser"
) -> list[dict[str, object]]:
    joins_by_run = {
        promotion_risk_socks_context_key(row, "profile", "run_index"): row
        for row in browser_navigation_socks_join_rows(payload)
        if promotion_risk_socks_context_key(row, "profile", "run_index") is not None
    }
    rows: list[dict[str, object]] = []
    for detail_row in arti_profile_promotion_risk_detail_rows(payload, baseline_profile):
        key = promotion_risk_socks_context_key(
            detail_row, "candidate_profile", "candidate_max_run"
        )
        if key is None:
            continue
        join_row = joins_by_run.get(key)
        if not join_row:
            continue
        rows.append(
            {
                "target": detail_row.get("target"),
                "candidate_profile": detail_row.get("candidate_profile"),
                "baseline_profile": detail_row.get("baseline_profile"),
                "candidate_max_run": detail_row.get("candidate_max_run"),
                "candidate_max_load_ms": detail_row.get("candidate_max_load_ms"),
                "phase_hint": detail_row.get("phase_hint"),
                "match_confidence": join_row.get("match_confidence"),
                "match_field": join_row.get("match_field"),
                "timing_id": join_row.get("timing_id"),
                "connect_ms": join_row.get("connect_ms"),
                "reply_elapsed_ms": join_row.get("reply_elapsed_ms"),
                "first_tor_to_client_ms": join_row.get("first_tor_to_client_ms"),
                "first_tor_byte_to_response_ms": join_row.get(
                    "first_tor_byte_to_response_ms"
                ),
                "response_after_reply_ms": join_row.get("response_after_reply_ms"),
                "circ_id": join_row.get("circ_id"),
                "stream_id": join_row.get("stream_id"),
                "relay_ms": join_row.get("relay_ms"),
                "data_bytes": join_row.get("data_bytes"),
                "max_gap_ms": join_row.get("max_gap_ms"),
            }
        )
    return rows


def arti_profile_promotion_risk_stream_receiver_rows(
    payload: dict[str, object], baseline_profile: str = "arti_release_browser"
) -> list[dict[str, object]]:
    receiver_by_run: dict[tuple[str, str, int], list[dict[str, object]]] = {}
    for row in torfast_stream_receiver_terminal_top_rows(payload):
        key = promotion_risk_socks_context_key(row, "profile", "run_index")
        if key is None:
            continue
        receiver_by_run.setdefault(key, []).append(row)

    rows: list[dict[str, object]] = []
