def arti_profile_top_resource_relay_ab_rows(
    payload: dict[str, object], baseline_profile: str = "arti_release_browser"
) -> list[dict[str, object]]:
    join_groups = browser_resource_join_groups(payload)
    rows = []
    for ab_row in arti_profile_ab_rows(payload, baseline_profile):
        target = str(ab_row.get("target", ""))
        candidate_profile = str(ab_row.get("candidate_profile", ""))
        profile_baseline = str(ab_row.get("baseline_profile", baseline_profile))
        for row in top_resource_delta_rows(
            payload,
            candidate_profile=candidate_profile,
            baseline_profile=profile_baseline,
        ):
            if row.get("target") != target:
                continue
            resource = str(row.get("resource", ""))
            candidate_rows = join_groups.get((candidate_profile, target, resource), [])
            baseline_rows = join_groups.get((profile_baseline, target, resource), [])
            if not candidate_rows and not baseline_rows:
                continue
            candidate_slowest = slowest_row(candidate_rows, "duration_ms")
            baseline_slowest = slowest_row(baseline_rows, "duration_ms")
            candidate_relay = row_median(candidate_rows, "relay_ms")
            baseline_relay = row_median(baseline_rows, "relay_ms")
            candidate_gap = row_max(candidate_rows, "max_gap_ms")
            baseline_gap = row_max(baseline_rows, "max_gap_ms")
            rows.append(
                {
                    **row,
                    "candidate_profile": candidate_profile,
                    "baseline_profile": profile_baseline,
                    "candidate_join_rows": len(candidate_rows),
                    "baseline_join_rows": len(baseline_rows),
                    "candidate_high_confidence": high_confidence_count(
                        candidate_rows
                    ),
                    "baseline_high_confidence": high_confidence_count(baseline_rows),
                    "candidate_tail_after_dom_ms": row_median(
                        candidate_rows, "tail_after_dom_ms"
                    ),
                    "baseline_tail_after_dom_ms": row_median(
                        baseline_rows, "tail_after_dom_ms"
                    ),
                    "tail_after_dom_delta_ms": subtract_numeric(
                        row_median(candidate_rows, "tail_after_dom_ms"),
                        row_median(baseline_rows, "tail_after_dom_ms"),
                    ),
                    "candidate_relay_ms": candidate_relay,
                    "baseline_relay_ms": baseline_relay,
                    "relay_delta_ms": subtract_numeric(candidate_relay, baseline_relay),
                    "candidate_max_gap_ms": candidate_gap,
                    "baseline_max_gap_ms": baseline_gap,
                    "max_gap_delta_ms": subtract_numeric(candidate_gap, baseline_gap),
                    "candidate_timing_id": candidate_slowest.get("timing_id"),
                    "baseline_timing_id": baseline_slowest.get("timing_id"),
                    "candidate_circ_id": candidate_slowest.get("circ_id"),
                    "baseline_circ_id": baseline_slowest.get("circ_id"),
                }
            )
    return sorted(
        rows,
        key=lambda row: numeric(row.get("duration_delta_ms")) or 0,
        reverse=True,
    )


def arti_profile_resource_http_phase_ab_rows(
    payload: dict[str, object], baseline_profile: str = "arti_release_browser"
) -> list[dict[str, object]]:
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return []
    rows = []
    for ab_row in arti_profile_ab_rows(payload, baseline_profile):
        target = str(ab_row.get("target", ""))
        candidate_profile = str(ab_row.get("candidate_profile", ""))
        profile_baseline = str(ab_row.get("baseline_profile", baseline_profile))
        candidate = profiles.get(candidate_profile, {})
        baseline = profiles.get(profile_baseline, {})
        if not isinstance(candidate, dict) or not isinstance(baseline, dict):
            continue
        candidate_groups = group_resources_by_name(
            resource_rows_for_profile_target(candidate, target)
        )
        baseline_groups = group_resources_by_name(
            resource_rows_for_profile_target(baseline, target)
        )
        for resource_name in sorted(set(candidate_groups) & set(baseline_groups)):
            candidate_resources = candidate_groups[resource_name]
            baseline_resources = baseline_groups[resource_name]
            duration_delta = subtract_numeric(
                resource_metric_median(candidate_resources, "duration"),
                resource_metric_median(baseline_resources, "duration"),
            )
            if duration_delta is None:
                continue
            rows.append(
                {
                    "target": target,
                    "candidate_profile": candidate_profile,
                    "baseline_profile": profile_baseline,
                    "resource": resource_name,
                    "resource_type": resource_type_label(candidate_resources),
                    "candidate_count": len(candidate_resources),
                    "baseline_count": len(baseline_resources),
                    "duration_delta_ms": duration_delta,
                    "fetch_to_request_delta_ms": subtract_numeric(
                        resource_phase_median(candidate_resources, "fetchToRequest"),
                        resource_phase_median(baseline_resources, "fetchToRequest"),
                    ),
                    "request_wait_delta_ms": subtract_numeric(
                        resource_phase_median(candidate_resources, "requestWait"),
                        resource_phase_median(baseline_resources, "requestWait"),
                    ),
                    "receive_delta_ms": subtract_numeric(
                        resource_phase_median(candidate_resources, "responseReceive"),
                        resource_phase_median(baseline_resources, "responseReceive"),
                    ),
                    "fetch_to_response_delta_ms": subtract_numeric(
                        resource_phase_median(candidate_resources, "fetchToResponse"),
                        resource_phase_median(baseline_resources, "fetchToResponse"),
                    ),
                    "candidate_zero_connect_setup": zero_connect_setup_count(
                        candidate_resources
                    ),
                    "baseline_zero_connect_setup": zero_connect_setup_count(
                        baseline_resources
                    ),
                    "candidate_protocol_summary": compact_counts(
                        count_labels(
                            protocol_label(resource.get("nextHopProtocol"))
                            for resource in candidate_resources
                        )
                    ),
                    "baseline_protocol_summary": compact_counts(
                        count_labels(
                            protocol_label(resource.get("nextHopProtocol"))
                            for resource in baseline_resources
                        )
                    ),
                }
            )
    return sorted(
        rows,
        key=lambda row: numeric(row.get("duration_delta_ms")) or 0,
        reverse=True,
    )


