def browser_resource_join_groups(
    payload: dict[str, object],
) -> dict[tuple[str, str, str], list[dict[str, object]]]:
    groups: dict[tuple[str, str, str], list[dict[str, object]]] = {}
    for row in browser_resource_socks_relay_join_rows(payload):
        profile = str(row.get("profile", ""))
        target = str(row.get("target", ""))
        resource = str(row.get("resource", ""))
        groups.setdefault((profile, target, resource), []).append(row)
    return groups


def high_confidence_count(rows: list[dict[str, object]]) -> int:
    return sum(1 for row in rows if row.get("match_confidence") == "high")


def slowest_row(rows: list[dict[str, object]], field: str) -> dict[str, object]:
    if not rows:
        return {}
    return max(rows, key=lambda row: numeric(row.get(field)) or 0)


def runs_by_index(
    payload: dict[str, object], profile_name: str, target: str
) -> dict[int, dict[str, object]]:
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return {}
    profile = profiles.get(profile_name, {})
    if not isinstance(profile, dict):
        return {}
    benchmarks = profile.get("benchmarks", {})
    if not isinstance(benchmarks, dict):
        return {}
    bench = benchmarks.get(target, {})
    if not isinstance(bench, dict):
        return {}
    runs = bench.get("runs", [])
    if not isinstance(runs, list):
        return {}
    indexed = {}
    for fallback_index, run in enumerate(runs, start=1):
        if not isinstance(run, dict):
            continue
        run_index = run.get("run_index", fallback_index)
        if isinstance(run_index, bool) or not isinstance(run_index, int):
            run_index = fallback_index
        indexed[run_index] = run
    return indexed


def profile_boot_ms(payload: dict[str, object], profile_name: str) -> float | None:
    seconds = profile_boot_seconds(payload, profile_name)
    return seconds * 1000 if seconds is not None else None


def profile_boot_seconds(payload: dict[str, object], profile_name: str) -> float | None:
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return None
    profile = profiles.get(profile_name, {})
    if not isinstance(profile, dict) or profile.get("skipped"):
        return None
    return boot_seconds_for_profile(profile)


def boot_seconds_for_profile(profile: dict[str, object]) -> float | None:
    boot = profile.get("boot", {})
    if not isinstance(boot, dict):
        return None
    seconds_from_launch = numeric(boot.get("seconds_from_launch"))
    if seconds_from_launch is not None:
        return seconds_from_launch
    interleaved_launch = profile.get("interleaved_launch", {})
    if isinstance(interleaved_launch, dict):
        started_epoch_ms = numeric(interleaved_launch.get("started_epoch_ms"))
        ready_epoch_ms = numeric(boot.get("ready_epoch_ms"))
        if started_epoch_ms is not None and ready_epoch_ms is not None:
            return round(max(0.0, ready_epoch_ms - started_epoch_ms) / 1000.0, 3)
    return numeric(boot.get("seconds"))


def nav_value(run: dict[str, object], field: str) -> float | None:
    timing = run.get("performance_timing", {})
    if not isinstance(timing, dict):
        return None
    nav = timing.get("navigation")
    if not isinstance(nav, dict):
        return None
    return numeric(nav.get(field))


def nav_phase(run: dict[str, object], start_field: str, end_field: str) -> float | None:
    start = nav_value(run, start_field)
    end = nav_value(run, end_field)
    if start is None or end is None:
        return None
    return end - start


def run_slowest_resource_ms(run: dict[str, object]) -> float | None:
    resource = run_slowest_resource(run)
    return numeric(resource.get("duration")) if resource else None


def run_slowest_resource(run: dict[str, object]) -> dict[str, object]:
    timing = run.get("performance_timing", {})
    if not isinstance(timing, dict):
        return {}
    resources = timing.get("resources")
    if not isinstance(resources, list):
        resources = timing.get("slowest_resources", [])
    if not isinstance(resources, list):
        return {}
    candidates = [
        resource
        for resource in resources
        if isinstance(resource, dict) and numeric(resource.get("duration")) is not None
    ]
    if not candidates:
        return {}
    return max(candidates, key=lambda resource: numeric(resource.get("duration")) or 0)


def get_metric(
    payload: dict[str, object], profile_name: str, target: str, metric: str
) -> object:
    summary = get_summary(payload, profile_name, target)
    profiles = payload.get("profiles", {})
    profile = profiles.get(profile_name, {}) if isinstance(profiles, dict) else {}
    if metric.startswith("boot_plus_"):
        inner_metric = metric.removeprefix("boot_plus_")
        boot = boot_seconds_for_profile(profile) if isinstance(profile, dict) else None
        return add_boot_ms(boot, summary.get(inner_metric))
    return summary.get(metric)


def get_summary(
    payload: dict[str, object], profile_name: str, target: str
) -> dict[str, object]:
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return {}
    profile = profiles.get(profile_name, {})
    if not isinstance(profile, dict):
        return {}
    benchmarks = profile.get("benchmarks", {})
    if not isinstance(benchmarks, dict):
        return {}
    bench = benchmarks.get(target, {})
    if not isinstance(bench, dict):
        return {}
    summary = bench.get("summary", {})
    if not isinstance(summary, dict):
        return {}
    return summary


def resource_rows_for_profile_target(
    profile: dict[str, object], target: str
) -> list[dict[str, object]]:
    benchmarks = profile.get("benchmarks", {})
    if not isinstance(benchmarks, dict):
        return []
    bench = benchmarks.get(target, {})
    if not isinstance(bench, dict):
        return []
    rows: list[dict[str, object]] = []
    runs = bench.get("runs", [])
    if not isinstance(runs, list):
        return rows
    for run in runs:
        if not isinstance(run, dict) or not run.get("ok"):
            continue
        timing = run.get("performance_timing", {})
        if not isinstance(timing, dict):
            continue
        resources = timing.get("resources")
        if not isinstance(resources, list):
            resources = timing.get("slowest_resources", [])
        if not isinstance(resources, list):
            continue
        rows.extend(resource for resource in resources if isinstance(resource, dict))
    return rows


def browser_run_late_phase_queue_context_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    cluster_by_run: dict[tuple[str, str, object], dict[str, object]] = {}
    for cluster in browser_resource_queue_socks_relay_cluster_rows(payload):
        key = (
            str(cluster.get("profile", "")),
            str(cluster.get("target", "")),
            cluster.get("run_index"),
        )
        existing = cluster_by_run.get(key)
        if existing is None or queue_cluster_sort_key(cluster) > queue_cluster_sort_key(
            existing
        ):
            cluster_by_run[key] = cluster

    selection_by_cluster: dict[tuple[str, str, object, object, object], dict[str, object]] = {}
    for selection in browser_resource_queue_selection_context_rows(payload):
        key = (
            str(selection.get("profile", "")),
            str(selection.get("target", "")),
            selection.get("run_index"),
            selection.get("timing_id"),
            selection.get("circ_id"),
        )
        existing = selection_by_cluster.get(key)
        if existing is None or queue_cluster_sort_key(selection) > queue_cluster_sort_key(
            existing
        ):
            selection_by_cluster[key] = selection

    rows = []
    for profile_name, _profile, target, _summary, run in iter_runs(payload):
        resources = browser_resource_rows_for_run(run)
        if not resources:
            continue
        response_start = nav_value(run, "responseStart")
        dom_loaded = nav_value(run, "domContentLoadedEventEnd")
        load_end = nav_value(run, "loadEventEnd")
        if response_start is None and dom_loaded is None and load_end is None:
            continue

        queued_resources = []
        slot_depth_6_queued_1000 = 0
        for resource in resources:
            fetch_to_request = resource_phase_ms(resource, "fetchToRequest")
            if fetch_to_request is None:
                continue
            slot_depth = same_origin_protocol_slot_depth_at_request(
                resource, resources
            )
            if fetch_to_request >= 500:
                queued_resources.append(
                    {
                        "resource": resource.get("name"),
                        "fetch_to_request_ms": fetch_to_request,
                        "slot_depth_at_request": slot_depth,
                    }
                )
            if fetch_to_request >= 1000 and slot_depth >= 6:
                slot_depth_6_queued_1000 += 1

        top_queued = (
            max(
                queued_resources,
                key=lambda row: numeric(row.get("fetch_to_request_ms")) or 0,
            )
            if queued_resources
            else {}
        )
        key = (str(profile_name), str(target), run.get("run_index"))
        cluster = cluster_by_run.get(key, {})
        selection = selection_by_cluster.get(
            (
                str(profile_name),
                str(target),
                run.get("run_index"),
                cluster.get("timing_id"),
                cluster.get("circ_id"),
            ),
            {},
        )
        rows.append(
            {
                "profile": profile_name,
                "target": target,
                "run_index": run.get("run_index"),
                "ok": run.get("ok"),
                "response_start_ms": response_start,
                "response_to_dom_ms": subtract_numeric(dom_loaded, response_start),
                "dom_to_load_ms": subtract_numeric(load_end, dom_loaded),
                "load_event_ms": load_end,
                "resource_count": len(resources),
                "queued_500ms": len(queued_resources),
                "queued_1000ms": row_count_at_least(
                    queued_resources, "fetch_to_request_ms", 1000
                ),
                "slot_depth_6_queued_1000ms": slot_depth_6_queued_1000,
                "max_fetch_to_request_ms": row_max(
                    queued_resources, "fetch_to_request_ms"
                ),
                "top_queued_resource": top_queued.get("resource"),
                "queue_timing_id": cluster.get("timing_id"),
                "queue_circ_id": cluster.get("circ_id"),
                "cluster_queued_1000ms": cluster.get("queued_1000ms"),
                "cluster_relay_ms": cluster.get("relay_ms"),
                "cluster_max_receive_gap_ms": cluster.get("max_receive_gap_ms"),
                "better_health_alt_rows": selection.get("better_health_alt_rows"),
                "lower_assignment_alt_rows": selection.get(
                    "lower_assignment_alt_rows"
                ),
                "candidate_context": selection.get("first_candidate_context", ""),
            }
        )

    return sorted(
        rows,
        key=lambda row: (
            numeric(row.get("response_to_dom_ms")) or 0,
            numeric(row.get("dom_to_load_ms")) or 0,
            numeric(row.get("queued_1000ms")) or 0,
            numeric(row.get("max_fetch_to_request_ms")) or 0,
        ),
        reverse=True,
    )


def queue_cluster_sort_key(row: dict[str, object]) -> tuple[float, float, float]:
    return (
        numeric(row.get("queued_1000ms")) or 0,
        numeric(row.get("max_fetch_to_request_ms")) or 0,
        numeric(row.get("queued_resources")) or 0,
    )


def resource_type_delta_rows(
    payload: dict[str, object],
    *,
    candidate_profile: str,
    baseline_profile: str,
) -> list[dict[str, object]]:
    rows = []
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return rows
    candidate = profiles.get(candidate_profile, {})
    baseline = profiles.get(baseline_profile, {})
    if not isinstance(candidate, dict) or not isinstance(baseline, dict):
        return rows
    targets = payload.get("targets", [])
    if not isinstance(targets, list):
        return rows
    for target in targets:
        candidate_groups = group_resources_by_type(
            resource_rows_for_profile_target(candidate, str(target))
        )
        baseline_groups = group_resources_by_type(
            resource_rows_for_profile_target(baseline, str(target))
        )
        for resource_type in sorted(set(candidate_groups) | set(baseline_groups)):
            candidate_resources = candidate_groups.get(resource_type, [])
            baseline_resources = baseline_groups.get(resource_type, [])
            rows.append(
                {
                    "target": str(target),
                    "resource_type": resource_type,
                    "candidate_count": len(candidate_resources),
                    "baseline_count": len(baseline_resources),
                    "duration_delta_ms": subtract_numeric(
                        resource_metric_median(candidate_resources, "duration"),
                        resource_metric_median(baseline_resources, "duration"),
                    ),
                    "wait_delta_ms": subtract_numeric(
                        resource_phase_median(candidate_resources, "requestWait"),
                        resource_phase_median(baseline_resources, "requestWait"),
                    ),
                    "receive_delta_ms": subtract_numeric(
                        resource_phase_median(candidate_resources, "responseReceive"),
                        resource_phase_median(baseline_resources, "responseReceive"),
                    ),
                    "body_delta_bytes": subtract_numeric(
                        resource_metric_median(candidate_resources, "encodedBodySize"),
                        resource_metric_median(baseline_resources, "encodedBodySize"),
                    ),
                }
            )
    return rows


def resource_queue_delta_rows(
    payload: dict[str, object],
    *,
    candidate_profile: str,
    baseline_profile: str,
) -> list[dict[str, object]]:
    rows = []
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return rows
    candidate = profiles.get(candidate_profile, {})
    baseline = profiles.get(baseline_profile, {})
    if not isinstance(candidate, dict) or not isinstance(baseline, dict):
        return rows
    targets = payload.get("targets", [])
    if not isinstance(targets, list):
        return rows
    for target in targets:
        candidate_resources = resource_rows_for_profile_target(candidate, str(target))
        baseline_resources = resource_rows_for_profile_target(baseline, str(target))
        groups: list[tuple[str, list[dict[str, object]], list[dict[str, object]]]] = [
            ("all", candidate_resources, baseline_resources)
        ]
        candidate_by_protocol = group_resources_by_protocol(candidate_resources)
        baseline_by_protocol = group_resources_by_protocol(baseline_resources)
        for protocol in sorted(set(candidate_by_protocol) | set(baseline_by_protocol)):
            groups.append(
                (
                    f"protocol:{protocol}",
                    candidate_by_protocol.get(protocol, []),
                    baseline_by_protocol.get(protocol, []),
                )
            )
        for group, candidate_group, baseline_group in groups:
            if not candidate_group and not baseline_group:
                continue
            rows.append(
                {
                    "target": str(target),
                    "group": group,
                    "candidate_count": len(candidate_group),
                    "baseline_count": len(baseline_group),
                    "fetch_to_request_100_delta": subtract_numeric(
                        resource_phase_count_at_least(
                            candidate_group, "fetchToRequest", 100
                        ),
                        resource_phase_count_at_least(
                            baseline_group, "fetchToRequest", 100
                        ),
                    ),
                    "fetch_to_request_500_delta": subtract_numeric(
                        resource_phase_count_at_least(
                            candidate_group, "fetchToRequest", 500
                        ),
                        resource_phase_count_at_least(
                            baseline_group, "fetchToRequest", 500
                        ),
                    ),
                    "fetch_to_request_1000_delta": subtract_numeric(
                        resource_phase_count_at_least(
                            candidate_group, "fetchToRequest", 1000
                        ),
                        resource_phase_count_at_least(
                            baseline_group, "fetchToRequest", 1000
                        ),
                    ),
                    "median_fetch_to_request_delta_ms": subtract_numeric(
                        resource_phase_median(candidate_group, "fetchToRequest"),
                        resource_phase_median(baseline_group, "fetchToRequest"),
                    ),
                    "max_fetch_to_request_delta_ms": subtract_numeric(
                        resource_phase_max(candidate_group, "fetchToRequest"),
                        resource_phase_max(baseline_group, "fetchToRequest"),
                    ),
                    "median_request_wait_delta_ms": subtract_numeric(
                        resource_phase_median(candidate_group, "requestWait"),
                        resource_phase_median(baseline_group, "requestWait"),
                    ),
                    "median_duration_delta_ms": subtract_numeric(
                        resource_metric_median(candidate_group, "duration"),
                        resource_metric_median(baseline_group, "duration"),
                    ),
                }
            )
    return sorted(
        rows,
        key=lambda row: (
            str(row.get("target", "")),
            0 if row.get("group") == "all" else 1,
            str(row.get("group", "")),
        ),
    )


def top_resource_delta_rows(
    payload: dict[str, object],
    *,
    candidate_profile: str,
    baseline_profile: str,
) -> list[dict[str, object]]:
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return []
    candidate = profiles.get(candidate_profile, {})
    baseline = profiles.get(baseline_profile, {})
    if not isinstance(candidate, dict) or not isinstance(baseline, dict):
        return []
    targets = payload.get("targets", [])
    if not isinstance(targets, list):
        return []

    rows = []
    for target in targets:
        candidate_groups = group_resources_by_name(
            resource_rows_for_profile_target(candidate, str(target))
        )
        baseline_groups = group_resources_by_name(
            resource_rows_for_profile_target(baseline, str(target))
        )
        for resource_name in sorted(set(candidate_groups) & set(baseline_groups)):
            candidate_resources = candidate_groups[resource_name]
            baseline_resources = baseline_groups[resource_name]
            duration_delta = subtract_numeric(
                resource_metric_median(candidate_resources, "duration"),
                resource_metric_median(baseline_resources, "duration"),
            )
            if duration_delta is None:
                continue
            rows.append(
                {
                    "target": str(target),
                    "resource": resource_name,
                    "resource_type": resource_type_label(candidate_resources),
                    "samples": min(len(candidate_resources), len(baseline_resources)),
                    "duration_delta_ms": duration_delta,
                    "wait_delta_ms": subtract_numeric(
                        resource_phase_median(candidate_resources, "requestWait"),
                        resource_phase_median(baseline_resources, "requestWait"),
                    ),
                    "receive_delta_ms": subtract_numeric(
                        resource_phase_median(candidate_resources, "responseReceive"),
                        resource_phase_median(baseline_resources, "responseReceive"),
                    ),
                    "candidate_duration_ms": resource_metric_median(
                        candidate_resources, "duration"
                    ),
                    "baseline_duration_ms": resource_metric_median(
                        baseline_resources, "duration"
                    ),
                }
            )
    return sorted(
        rows,
        key=lambda row: numeric(row.get("duration_delta_ms")) or 0,
        reverse=True,
    )


def load_tail_resource_delta_rows(
    payload: dict[str, object],
    *,
    candidate_profile: str,
    baseline_profile: str,
) -> list[dict[str, object]]:
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return []
    candidate = profiles.get(candidate_profile, {})
    baseline = profiles.get(baseline_profile, {})
    if not isinstance(candidate, dict) or not isinstance(baseline, dict):
        return []
    targets = payload.get("targets", [])
    if not isinstance(targets, list):
        return []

    rows = []
    for target in targets:
        candidate_groups = group_resources_by_name(
            resource_tail_rows_for_profile_target(candidate, str(target))
        )
        baseline_groups = group_resources_by_name(
            resource_tail_rows_for_profile_target(baseline, str(target))
        )
        for resource_name in sorted(set(candidate_groups) & set(baseline_groups)):
            candidate_resources = candidate_groups[resource_name]
            baseline_resources = baseline_groups[resource_name]
            tail_delta = subtract_numeric(
                resource_metric_median(candidate_resources, "tail_after_dom_ms"),
                resource_metric_median(baseline_resources, "tail_after_dom_ms"),
            )
            response_end_delta = subtract_numeric(
                resource_metric_median(candidate_resources, "responseEnd"),
                resource_metric_median(baseline_resources, "responseEnd"),
            )
            if tail_delta is None and response_end_delta is None:
                continue
            rows.append(
                {
                    "target": str(target),
                    "resource": resource_name,
                    "resource_type": resource_type_label(candidate_resources),
                    "samples": min(len(candidate_resources), len(baseline_resources)),
                    "response_end_delta_ms": response_end_delta,
                    "tail_after_dom_delta_ms": tail_delta,
                    "candidate_tail_after_dom_ms": resource_metric_median(
                        candidate_resources, "tail_after_dom_ms"
                    ),
                    "baseline_tail_after_dom_ms": resource_metric_median(
                        baseline_resources, "tail_after_dom_ms"
                    ),
                    "candidate_load_gap_ms": resource_metric_median(
                        candidate_resources, "load_gap_ms"
                    ),
                    "baseline_load_gap_ms": resource_metric_median(
                        baseline_resources, "load_gap_ms"
                    ),
                }
            )
    return sorted(
        rows,
        key=lambda row: numeric(row.get("tail_after_dom_delta_ms"))
        if numeric(row.get("tail_after_dom_delta_ms")) is not None
        else numeric(row.get("response_end_delta_ms")) or 0,
        reverse=True,
    )


def resource_tail_rows_for_profile_target(
    profile: dict[str, object], target: str
) -> list[dict[str, object]]:
    benchmarks = profile.get("benchmarks", {})
    if not isinstance(benchmarks, dict):
        return []
    bench = benchmarks.get(target, {})
    if not isinstance(bench, dict):
        return []
    runs = bench.get("runs", [])
    if not isinstance(runs, list):
        return []
    rows = []
    for fallback_index, run in enumerate(runs, start=1):
        if not isinstance(run, dict) or not run.get("ok"):
            continue
        run_index = run.get("run_index", fallback_index)
        dom_end = nav_value(run, "domContentLoadedEventEnd")
        load_end = nav_value(run, "loadEventEnd")
        timing = run.get("performance_timing", {})
        if not isinstance(timing, dict):
            continue
        resources = timing.get("resources")
        if not isinstance(resources, list):
            resources = timing.get("slowest_resources", [])
        if not isinstance(resources, list):
            continue
        for resource in resources:
            if not isinstance(resource, dict):
                continue
            response_end = numeric(resource.get("responseEnd"))
            if response_end is None:
                continue
            row = dict(resource)
            row["run_index"] = run_index
            row["tail_after_dom_ms"] = (
                response_end - dom_end if dom_end is not None else None
            )
            row["load_gap_ms"] = load_end - response_end if load_end is not None else None
            rows.append(row)
    return rows


def group_resources_by_type(
    resources: list[dict[str, object]],
) -> dict[str, list[dict[str, object]]]:
    grouped: dict[str, list[dict[str, object]]] = {}
    for resource in resources:
        grouped.setdefault(resource_type_label([resource]), []).append(resource)
    return grouped


def group_resources_by_name(
    resources: list[dict[str, object]],
) -> dict[str, list[dict[str, object]]]:
    grouped: dict[str, list[dict[str, object]]] = {}
    for resource in resources:
        name = resource.get("name")
        if not isinstance(name, str) or not name:
            continue
        grouped.setdefault(name, []).append(resource)
    return grouped


def group_resources_by_protocol(
    resources: list[dict[str, object]],
) -> dict[str, list[dict[str, object]]]:
    grouped: dict[str, list[dict[str, object]]] = {}
    for resource in resources:
        protocol = protocol_label(resource.get("nextHopProtocol"))
        grouped.setdefault(protocol, []).append(resource)
    return grouped


def resource_type_label(resources: list[dict[str, object]]) -> str:
    for resource in resources:
        value = resource.get("initiatorType")
        if isinstance(value, str) and value:
            return value
    return "unknown"


def resource_metric_median(
    resources: list[dict[str, object]], field: str
) -> float | None:
    values = []
    for resource in resources:
        value = numeric(resource.get(field))
        if value is not None:
            values.append(value)
    return median(values) if values else None


def resource_phase_median(
    resources: list[dict[str, object]], field: str
) -> float | None:
    values = []
    for resource in resources:
        value = resource_phase_ms(resource, field)
        if value is not None:
            values.append(value)
    return median(values) if values else None


def resource_phase_max(resources: list[dict[str, object]], field: str) -> float | None:
    values = []
    for resource in resources:
        value = resource_phase_ms(resource, field)
        if value is not None:
            values.append(value)
    return max(values) if values else None


def resource_phase_count_at_least(
    resources: list[dict[str, object]], field: str, threshold: float
) -> int:
    return sum(
        1
        for resource in resources
        if (value := resource_phase_ms(resource, field)) is not None
        and value >= threshold
    )


def count_at_least(values: list[float], threshold: float) -> int:
    return sum(1 for value in values if value >= threshold)


def same_origin_protocol_slot_depth_at_request(
    resource: dict[str, object], resources: list[dict[str, object]]
) -> int | None:
    request_start = numeric(resource.get("requestStart"))
    if request_start is None:
        return None
    origin = origin_label(resource.get("name"))
    protocol = protocol_label(resource.get("nextHopProtocol"))
    active = 1
    for other in resources:
        if other is resource:
            continue
        if origin_label(other.get("name")) != origin:
            continue
        if protocol_label(other.get("nextHopProtocol")) != protocol:
            continue
        other_request_start = numeric(other.get("requestStart"))
        other_response_end = numeric(other.get("responseEnd"))
        if other_request_start is None or other_response_end is None:
            continue
        if other_request_start <= request_start < other_response_end:
            active += 1
    return active


def same_origin_protocol_active_resources_at_request(
    resource: dict[str, object], resources: list[dict[str, object]]
) -> list[dict[str, object]]:
    request_start = numeric(resource.get("requestStart"))
    if request_start is None:
        return []
    origin = origin_label(resource.get("name"))
    protocol = protocol_label(resource.get("nextHopProtocol"))
    active = []
    for other in resources:
        if other is resource:
            continue
        if origin_label(other.get("name")) != origin:
            continue
        if protocol_label(other.get("nextHopProtocol")) != protocol:
            continue
        other_request_start = numeric(other.get("requestStart"))
        other_response_end = numeric(other.get("responseEnd"))
        if other_request_start is None or other_response_end is None:
            continue
        if other_request_start <= request_start < other_response_end:
            active.append(other)
    return sorted(
        active,
        key=lambda row: subtract_numeric(row.get("responseEnd"), request_start) or 0,
        reverse=True,
    )


def resource_connection_shape_rows(payload: dict[str, object]) -> list[dict[str, object]]:
    rows = []
    for profile_name, profile, url, _summary in iter_summaries(payload):
        resources = resource_rows_for_profile_target(profile, str(url))
        if not resources:
            continue
        origins = count_labels(
            origin_label(resource.get("name")) for resource in resources
        )
        protocols = count_labels(
            protocol_label(resource.get("nextHopProtocol")) for resource in resources
        )
        fetch_buckets = count_labels(
            timing_bucket(resource.get("fetchStart")) for resource in resources
        )
        request_starts = [
            value
            for value in (numeric(resource.get("requestStart")) for resource in resources)
            if value is not None
        ]
        fetch_to_request = [
            value
            for value in (
                subtract_fields(resource, "fetchStart", "requestStart")
                for resource in resources
            )
            if value is not None
        ]
        waits = [
            value
            for value in (
                resource_phase_ms(resource, "requestWait") for resource in resources
            )
            if value is not None
        ]
        rows.append(
            {
                "profile": profile_name,
                "target": str(url),
                "resource_count": len(resources),
                "origin_count": len(origins),
                "top_origin_share_pct": top_share_pct(origins),
                "protocol_summary": compact_counts(protocols),
                "fetch_start_bucket_count": len(fetch_buckets),
                "top_fetch_start_bucket_share_pct": top_share_pct(fetch_buckets),
                "request_start_span_ms": (
                    max(request_starts) - min(request_starts)
                    if len(request_starts) >= 2
                    else None
                ),
                "median_fetch_to_request_ms": (
                    median(fetch_to_request) if fetch_to_request else None
                ),
                "max_fetch_to_request_ms": (
                    max(fetch_to_request) if fetch_to_request else None
                ),
                "fetch_to_request_100ms": count_at_least(fetch_to_request, 100),
                "fetch_to_request_500ms": count_at_least(fetch_to_request, 500),
                "fetch_to_request_1000ms": count_at_least(fetch_to_request, 1000),
                "median_request_wait_ms": median(waits) if waits else None,
            }
        )
    return rows


def resource_queue_saturation_rows(
    payload: dict[str, object], threshold_ms: float = 500.0
) -> list[dict[str, object]]:
    grouped: dict[tuple[str, str, str], list[dict[str, object]]] = {}
    for profile_name, _profile, target, _summary, run in iter_runs(payload):
        resources = browser_resource_rows_for_run(run)
        for resource in resources:
            fetch_to_request = resource_phase_ms(resource, "fetchToRequest")
            if fetch_to_request is None or fetch_to_request < threshold_ms:
                continue
            slot_depth = same_origin_protocol_slot_depth_at_request(
                resource, resources
            )
            row = {
                "resource": resource.get("name"),
                "fetch_to_request_ms": fetch_to_request,
                "slot_depth_at_request": slot_depth,
            }
            protocol = protocol_label(resource.get("nextHopProtocol"))
            for group in ("all", f"protocol:{protocol}"):
                grouped.setdefault((str(profile_name), str(target), group), []).append(
                    row
                )

    rows = []
    for (profile, target, group), group_rows in grouped.items():
        slot_depths = [
            value
            for value in (
                numeric(row.get("slot_depth_at_request")) for row in group_rows
            )
            if value is not None
        ]
        sorted_resources = sorted(
            group_rows,
            key=lambda row: numeric(row.get("fetch_to_request_ms")) or 0,
            reverse=True,
        )
        rows.append(
            {
                "profile": profile,
                "target": target,
                "group": group,
                "queued_500ms": len(group_rows),
                "queued_1000ms": row_count_at_least(
                    group_rows, "fetch_to_request_ms", 1000
                ),
                "slot_depth_6": row_count_at_least(
                    group_rows, "slot_depth_at_request", 6
                ),
                "slot_depth_6_queued_1000ms": sum(
                    1
                    for row in group_rows
                    if (numeric(row.get("slot_depth_at_request")) or 0) >= 6
                    and (numeric(row.get("fetch_to_request_ms")) or 0) >= 1000
                ),
                "median_slot_depth_at_request": (
                    median(slot_depths) if slot_depths else None
                ),
                "max_slot_depth_at_request": max(slot_depths)
                if slot_depths
                else None,
                "median_fetch_to_request_ms": row_median(
                    group_rows, "fetch_to_request_ms"
                ),
                "max_fetch_to_request_ms": row_max(
                    group_rows, "fetch_to_request_ms"
                ),
                "top_resources": compact_list(
                    [
                        compact_url(str(row.get("resource", "")), max_length=42)
                        for row in sorted_resources
                    ],
                    max_items=3,
                ),
            }
        )
    return sorted(
        rows,
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            0 if row.get("group") == "all" else 1,
            str(row.get("group", "")),
        ),
    )


def resource_queue_slot_blocker_rows(
    payload: dict[str, object], threshold_ms: float = 1000.0
) -> list[dict[str, object]]:
    join_index = browser_resource_join_index(payload)
    relay_timings_by_profile = relay_receive_timings_by_profile(payload)
    receiver_timings_by_profile = stream_receiver_timings_by_profile(payload)
    rows: list[dict[str, object]] = []
    for profile_name, _profile, target, _summary, run in iter_runs(payload):
        resources = browser_resource_rows_for_run(run)
        if not resources:
            continue
        run_index = run.get("run_index")
        for resource in resources:
            fetch_to_request = resource_phase_ms(resource, "fetchToRequest")
            if fetch_to_request is None or fetch_to_request < threshold_ms:
                continue
            queued_request_start = numeric(resource.get("requestStart"))
            queued_request_epoch = add_numeric(
                browser_time_origin_ms(run), queued_request_start
            )
            blockers = same_origin_protocol_active_resources_at_request(
                resource, resources
            )
            blocker_rows = []
            for blocker in blockers:
                joined = join_index.get(
                    browser_resource_join_key(
                        str(profile_name), str(target), run_index, blocker
                    )
                )
                row = {
                    "resource": blocker.get("name"),
                    "remaining_ms": subtract_numeric(
                        blocker.get("responseEnd"), queued_request_start
                    ),
                    "wait_remaining_ms": blocker_wait_remaining_at_request(
                        blocker, queued_request_start
                    ),
                    "receive_remaining_ms": blocker_receive_remaining_at_request(
                        blocker, queued_request_start
                    ),
                    "joined": joined,
                }
                if joined is not None:
                    relay_context = relay_receive_context_for_joined(
                        joined,
                        relay_timings_by_profile.get(str(profile_name), []),
                        queued_request_epoch,
                    )
                    receiver_context = stream_receiver_context_for_joined(
                        joined, receiver_timings_by_profile.get(str(profile_name), [])
                    )
                    receiver_terminal_context = (
                        stream_receiver_terminal_context_for_joined(
                            joined,
                            receiver_timings_by_profile.get(str(profile_name), []),
                            queued_request_epoch,
                        )
                    )
                    row.update(
                        {
                            "timing_id": joined.get("timing_id"),
                            "circ_id": joined.get("circ_id"),
                            "stream_id": joined.get("stream_id"),
                            "match_confidence": joined.get("match_confidence"),
                            "relay_ms": joined.get("relay_ms"),
                            "last_tor_to_client_ms": joined.get(
                                "last_tor_to_client_ms"
                            ),
                            "tor_to_client_idle_after_last_ms": joined.get(
                                "tor_to_client_idle_after_last_ms"
                            ),
                            "max_gap_ms": joined.get("max_gap_ms"),
                            "last_tor_to_client_write_epoch_ms": joined.get(
                                "last_tor_to_client_write_epoch_ms"
                            ),
                            "last_receive_epoch_ms": joined.get(
                                "last_receive_epoch_ms"
                            ),
                            "first_relay_after_queued_request_ms": (
                                relay_context.get(
                                    "first_relay_after_queued_request_ms"
                                )
                            ),
                            "last_relay_after_queued_request_ms": (
                                relay_context.get(
                                    "last_relay_after_queued_request_ms"
                                )
                            ),
                            "relay_cells_after_queued_request": relay_context.get(
                                "relay_cells_after_queued_request"
                            ),
                            "relay_data_after_queued_request_bytes": (
                                relay_context.get(
                                    "relay_data_after_queued_request_bytes"
                                )
                            ),
                            "max_relay_gap_after_queued_request_ms": (
                                relay_context.get(
                                    "max_relay_gap_after_queued_request_ms"
                                )
                            ),
                            "last_stream_receiver_read_epoch_ms": (
                                receiver_context.get(
                                    "last_stream_receiver_read_epoch_ms"
                                )
                            ),
                            "last_write_after_queued_request_ms": subtract_numeric(
                                joined.get("last_tor_to_client_write_epoch_ms"),
                                queued_request_epoch,
                            ),
                            "last_write_after_last_relay_receive_ms": subtract_numeric(
                                joined.get("last_tor_to_client_write_epoch_ms"),
                                joined.get("last_receive_epoch_ms"),
                            ),
                            "last_write_after_last_stream_receiver_read_ms": subtract_numeric(
                                joined.get("last_tor_to_client_write_epoch_ms"),
                                receiver_context.get(
                                    "last_stream_receiver_read_epoch_ms"
                                ),
                            ),
                            "stream_receiver_read_after_last_relay_receive_ms": subtract_numeric(
                                receiver_context.get(
                                    "last_stream_receiver_read_epoch_ms"
                                ),
                                joined.get("last_receive_epoch_ms"),
                            ),
                            "stream_receiver_max_queued_after_bytes": (
                                receiver_context.get("max_queued_after_bytes")
                            ),
                            "stream_receiver_min_recv_window_after": (
                                receiver_context.get("min_recv_window_after")
                            ),
                            "terminal_last_data_after_queued_request_ms": (
                                receiver_terminal_context.get(
                                    "last_data_after_queued_request_ms"
                                )
                            ),
                            "last_write_after_terminal_last_data_ms": subtract_numeric(
                                joined.get("last_tor_to_client_write_epoch_ms"),
                                receiver_terminal_context.get("last_data_epoch_ms"),
                            ),
                            "terminal_transfer_ms": receiver_terminal_context.get(
                                "transfer_ms"
                            ),
                            "terminal_idle_after_last_data_ms": (
                                receiver_terminal_context.get(
                                    "idle_after_last_data_ms"
                                )
                            ),
                            "terminal_max_data_gap_ms": (
                                receiver_terminal_context.get("max_data_gap_ms")
                            ),
                            "terminal_relay_data_bytes": (
                                receiver_terminal_context.get("relay_data_bytes")
                            ),
                            "terminal_pending_after_bytes": (
                                receiver_terminal_context.get("pending_after_bytes")
                            ),
                            "terminal_read_events": receiver_terminal_context.get(
                                "read_events"
                            ),
                            "terminal_sendmes": receiver_terminal_context.get("sendmes"),
                            "terminal_sendme_ok": receiver_terminal_context.get(
                                "sendme_ok"
                            ),
                            "terminal_min_recv_window_after_take": (
                                receiver_terminal_context.get(
                                    "min_recv_window_after_take"
                                )
                            ),
                            "terminal_max_queued_after_bytes": (
                                receiver_terminal_context.get("max_queued_after_bytes")
                            ),
                            "response_end_after_last_write_ms": joined.get(
                                "response_end_after_last_tor_write_ms"
                            ),
                        }
                    )
                blocker_rows.append(row)

            high_conf_blocker_rows = [
                row
                for row in blocker_rows
                if row.get("match_confidence") == "high"
            ]
            rows.append(
                {
                    "profile": profile_name,
                    "target": str(target),
                    "run_index": run_index,
                    "queued_resource": resource.get("name"),
                    "fetch_to_request_ms": fetch_to_request,
                    "slot_depth_at_request": same_origin_protocol_slot_depth_at_request(
                        resource, resources
                    ),
                    "active_blockers": len(blocker_rows),
                    "max_blocker_remaining_ms": row_max(
                        blocker_rows, "remaining_ms"
                    ),
                    "blockers_waiting_for_first_byte": row_count_at_least(
                        blocker_rows, "wait_remaining_ms", 0.001
                    ),
                    "blockers_receiving_body": row_count_at_least(
                        blocker_rows, "receive_remaining_ms", 0.001
                    ),
                    "max_blocker_wait_remaining_ms": row_max(
                        blocker_rows, "wait_remaining_ms"
                    ),
                    "max_blocker_receive_remaining_ms": row_max(
                        blocker_rows, "receive_remaining_ms"
                    ),
                    "max_blocker_last_write_after_queued_request_ms": row_max(
                        blocker_rows, "last_write_after_queued_request_ms"
                    ),
                    "median_blocker_response_end_after_last_write_ms": row_median(
                        blocker_rows, "response_end_after_last_write_ms"
                    ),
                    "high_conf_max_blocker_last_write_after_queued_request_ms": row_max(
                        high_conf_blocker_rows, "last_write_after_queued_request_ms"
                    ),
                    "high_conf_median_blocker_response_end_after_last_write_ms": row_median(
                        high_conf_blocker_rows,
                        "response_end_after_last_write_ms",
                    ),
                    "high_conf_min_first_relay_after_queued_request_ms": row_min(
                        high_conf_blocker_rows,
                        "first_relay_after_queued_request_ms",
                    ),
                    "high_conf_max_last_relay_after_queued_request_ms": row_max(
                        high_conf_blocker_rows,
                        "last_relay_after_queued_request_ms",
                    ),
                    "high_conf_relay_data_after_queued_request_bytes": sum(
                        int(numeric(row.get("relay_data_after_queued_request_bytes")) or 0)
                        for row in high_conf_blocker_rows
                    )
                    if high_conf_blocker_rows
                    else None,
                    "high_conf_max_relay_gap_after_queued_request_ms": row_max(
                        high_conf_blocker_rows,
                        "max_relay_gap_after_queued_request_ms",
                    ),
                    "high_conf_max_blocker_last_write_after_last_relay_receive_ms": row_max(
                        high_conf_blocker_rows,
                        "last_write_after_last_relay_receive_ms",
                    ),
                    "high_conf_max_blocker_last_write_after_last_stream_receiver_read_ms": row_max(
                        high_conf_blocker_rows,
                        "last_write_after_last_stream_receiver_read_ms",
                    ),
                    "high_conf_max_stream_receiver_queued_after_bytes": row_max(
                        high_conf_blocker_rows,
                        "stream_receiver_max_queued_after_bytes",
                    ),
                    "high_conf_min_stream_receiver_recv_window_after": row_min(
                        high_conf_blocker_rows,
                        "stream_receiver_min_recv_window_after",
                    ),
                    "high_conf_terminal_coverage": row_count_at_least(
                        high_conf_blocker_rows,
                        "terminal_transfer_ms",
                        0,
                    ),
                    "high_conf_max_terminal_last_data_after_queued_request_ms": row_max(
                        high_conf_blocker_rows,
                        "terminal_last_data_after_queued_request_ms",
                    ),
                    "high_conf_median_last_write_after_terminal_last_data_ms": row_median(
                        high_conf_blocker_rows,
                        "last_write_after_terminal_last_data_ms",
                    ),
                    "high_conf_max_last_write_after_terminal_last_data_ms": row_max(
                        high_conf_blocker_rows,
                        "last_write_after_terminal_last_data_ms",
                    ),
                    "high_conf_max_terminal_data_gap_ms": row_max(
                        high_conf_blocker_rows,
                        "terminal_max_data_gap_ms",
                    ),
                    "high_conf_max_terminal_idle_after_last_data_ms": row_max(
                        high_conf_blocker_rows,
                        "terminal_idle_after_last_data_ms",
                    ),
                    "high_conf_max_terminal_pending_after_bytes": row_max(
                        high_conf_blocker_rows,
                        "terminal_pending_after_bytes",
                    ),
                    "high_conf_terminal_sendmes": row_sum(
                        high_conf_blocker_rows,
                        "terminal_sendmes",
                    ),
                    "high_conf_terminal_sendme_ok": row_sum(
                        high_conf_blocker_rows,
                        "terminal_sendme_ok",
                    ),
                    "high_conf_min_terminal_recv_window_after_take": row_min(
                        high_conf_blocker_rows,
                        "terminal_min_recv_window_after_take",
                    ),
                    "high_conf_max_terminal_queued_after_bytes": row_max(
                        high_conf_blocker_rows,
                        "terminal_max_queued_after_bytes",
                    ),
                    "blocker_high_confidence": sum(
                        1
                        for row in blocker_rows
                        if row.get("match_confidence") == "high"
                    ),
                    "blocker_timing_ids": compact_list(
                        [
                            row.get("timing_id")
                            for row in blocker_rows
                            if row.get("timing_id") is not None
                        ],
                        max_items=4,
                    ),
                    "high_conf_blocker_timing_ids": compact_list(
                        [
                            row.get("timing_id")
                            for row in high_conf_blocker_rows
                            if row.get("timing_id") is not None
                        ],
                        max_items=4,
                    ),
                    "blocker_stream_ids": compact_list(
                        [
                            row.get("stream_id")
                            for row in blocker_rows
                            if row.get("stream_id") is not None
                        ],
                        max_items=4,
                    ),
                    "high_conf_blocker_stream_ids": compact_list(
                        [
                            row.get("stream_id")
                            for row in high_conf_blocker_rows
                            if row.get("stream_id") is not None
                        ],
                        max_items=4,
                    ),
                    "blocker_circuits": compact_list(
                        [
                            row.get("circ_id")
                            for row in blocker_rows
                            if row.get("circ_id")
                        ],
                        max_items=3,
                    ),
                    "high_conf_blocker_circuits": compact_list(
                        [
                            row.get("circ_id")
                            for row in high_conf_blocker_rows
                            if row.get("circ_id")
                        ],
                        max_items=3,
                    ),
                    "blocker_max_relay_ms": row_max(blocker_rows, "relay_ms"),
                    "blocker_max_last_tor_to_client_ms": row_max(
                        blocker_rows, "last_tor_to_client_ms"
                    ),
                    "blocker_max_idle_after_last_ms": row_max(
                        blocker_rows, "tor_to_client_idle_after_last_ms"
                    ),
                    "blocker_max_receive_gap_ms": row_max(blocker_rows, "max_gap_ms"),
                    "top_blockers": compact_list(
                        [
                            format_slot_blocker(row)
                            for row in sorted(
                                blocker_rows,
                                key=lambda row: numeric(row.get("remaining_ms")) or 0,
                                reverse=True,
                            )
                        ],
                        max_items=3,
                    ),
                }
            )
    return sorted(
        rows,
        key=lambda row: (
            numeric(row.get("fetch_to_request_ms")) or 0,
            numeric(row.get("max_blocker_remaining_ms")) or 0,
            numeric(row.get("active_blockers")) or 0,
        ),
        reverse=True,
    )


def resource_queue_slot_blocker_summary_rows(
    payload: dict[str, object], threshold_ms: float = 1000.0
) -> list[dict[str, object]]:
    grouped: dict[tuple[str, str, object], list[dict[str, object]]] = {}
    for row in resource_queue_slot_blocker_rows(payload, threshold_ms=threshold_ms):
        key = (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            row.get("run_index"),
        )
        grouped.setdefault(key, []).append(row)

    rows = []
    for (profile, target, run_index), group_rows in grouped.items():
        sorted_rows = sorted(
            group_rows,
            key=lambda row: numeric(row.get("fetch_to_request_ms")) or 0,
            reverse=True,
        )
        queue_minus_remaining_rows = [
            {
                "queue_minus_max_blocker_left_ms": subtract_numeric(
                    row.get("fetch_to_request_ms"), row.get("max_blocker_remaining_ms")
                )
            }
            for row in group_rows
        ]
        rows.append(
            {
                "profile": profile,
                "target": target,
                "run_index": run_index,
                "queued_resources": len(group_rows),
                "slot_depth_6": row_count_at_least(
                    group_rows, "slot_depth_at_request", 6
                ),
                "rows_with_active_blockers": row_count_at_least(
                    group_rows, "active_blockers", 1
                ),
                "receive_dominant_rows": sum(
                    1
                    for row in group_rows
                    if (numeric(row.get("max_blocker_receive_remaining_ms")) or 0)
                    >= (numeric(row.get("max_blocker_wait_remaining_ms")) or 0)
                    and (numeric(row.get("max_blocker_receive_remaining_ms")) or 0)
                    > 0
                ),
                "wait_dominant_rows": sum(
                    1
                    for row in group_rows
                    if (numeric(row.get("max_blocker_wait_remaining_ms")) or 0)
                    > (numeric(row.get("max_blocker_receive_remaining_ms")) or 0)
                ),
                "high_conf_write_after_queue_500ms": row_count_at_least(
                    group_rows,
                    "high_conf_max_blocker_last_write_after_queued_request_ms",
                    500,
                ),
                "high_conf_write_after_queue_1000ms": row_count_at_least(
                    group_rows,
                    "high_conf_max_blocker_last_write_after_queued_request_ms",
                    1000,
                ),
                "blockers_left_500ms": sum(
                    1
                    for row in group_rows
                    if (value := numeric(row.get("max_blocker_remaining_ms")))
                    is not None
                    and value <= 500
                ),
                "rows_with_joined_blockers": sum(
                    1 for row in group_rows if row.get("blocker_timing_ids")
                ),
                "rows_with_high_conf_blockers": sum(
                    1
                    for row in group_rows
                    if (numeric(row.get("blocker_high_confidence")) or 0) > 0
                ),
                "median_fetch_to_request_ms": row_median(
                    group_rows, "fetch_to_request_ms"
                ),
                "max_fetch_to_request_ms": row_max(
                    group_rows, "fetch_to_request_ms"
                ),
                "median_max_blocker_remaining_ms": row_median(
                    group_rows, "max_blocker_remaining_ms"
                ),
                "max_blocker_remaining_ms": row_max(
                    group_rows, "max_blocker_remaining_ms"
                ),
                "median_queue_minus_max_blocker_left_ms": row_median(
                    queue_minus_remaining_rows,
                    "queue_minus_max_blocker_left_ms",
                ),
                "median_max_blocker_wait_left_ms": row_median(
                    group_rows, "max_blocker_wait_remaining_ms"
                ),
                "median_max_blocker_receive_left_ms": row_median(
                    group_rows, "max_blocker_receive_remaining_ms"
                ),
                "median_high_conf_max_blocker_last_write_after_queued_request_ms": row_median(
                    group_rows,
                    "high_conf_max_blocker_last_write_after_queued_request_ms",
                ),
                "max_blocker_relay_ms": row_max(group_rows, "blocker_max_relay_ms"),
                "top_queued_resource": compact_url(
                    str(sorted_rows[0].get("queued_resource", "")), max_length=42
                )
                if sorted_rows
                else "",
                "blocker_timing_ids": compact_list(
                    expand_compact_list_field(group_rows, "blocker_timing_ids"),
                    max_items=6,
                ),
                "blocker_circuits": compact_list(
                    expand_compact_list_field(group_rows, "blocker_circuits"),
                    max_items=4,
                ),
            }
        )
    return sorted(
        rows,
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0,
        ),
    )


def resource_queue_late_write_summary_rows(
    payload: dict[str, object], threshold_ms: float = 1000.0
) -> list[dict[str, object]]:
    grouped: dict[tuple[str, str, object], list[dict[str, object]]] = {}
    for row in resource_queue_slot_blocker_rows(payload, threshold_ms=threshold_ms):
        if (
            row.get("high_conf_max_blocker_last_write_after_queued_request_ms")
            is None
        ):
            continue
        key = (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            row.get("run_index"),
        )
        grouped.setdefault(key, []).append(row)

    rows = []
    for (profile, target, run_index), group_rows in grouped.items():
        sorted_rows = sorted(
            group_rows,
            key=lambda row: numeric(
                row.get("high_conf_max_blocker_last_write_after_queued_request_ms")
            )
            or 0,
            reverse=True,
        )
        response_after_write_rows = [
            {
                "response_after_write_ms": row.get(
                    "high_conf_median_blocker_response_end_after_last_write_ms"
                )
            }
            for row in group_rows
        ]
        positive_release_rows = [
            row
            for row in response_after_write_rows
            if (numeric(row.get("response_after_write_ms")) or 0) > 0
        ]
        rows.append(
            {
                "profile": profile,
                "target": target,
                "run_index": run_index,
                "high_conf_queued_rows": len(group_rows),
                "high_conf_write_after_queue_500ms": row_count_at_least(
                    group_rows,
                    "high_conf_max_blocker_last_write_after_queued_request_ms",
                    500,
                ),
                "high_conf_write_after_queue_1000ms": row_count_at_least(
                    group_rows,
                    "high_conf_max_blocker_last_write_after_queued_request_ms",
                    1000,
                ),
                "median_high_conf_write_after_queue_ms": row_median(
                    group_rows,
                    "high_conf_max_blocker_last_write_after_queued_request_ms",
                ),
                "max_high_conf_write_after_queue_ms": row_max(
                    group_rows,
                    "high_conf_max_blocker_last_write_after_queued_request_ms",
                ),
                "terminal_coverage_rows": row_count_at_least(
                    group_rows,
                    "high_conf_terminal_coverage",
                    1,
                ),
                "terminal_last_data_after_queue_1000ms": row_count_at_least(
                    group_rows,
                    "high_conf_max_terminal_last_data_after_queued_request_ms",
                    1000,
                ),
                "median_terminal_last_data_after_queue_ms": row_median(
                    group_rows,
                    "high_conf_max_terminal_last_data_after_queued_request_ms",
                ),
                "max_terminal_last_data_after_queue_ms": row_max(
                    group_rows,
                    "high_conf_max_terminal_last_data_after_queued_request_ms",
                ),
                "median_write_after_terminal_last_data_ms": row_median(
                    group_rows,
                    "high_conf_median_last_write_after_terminal_last_data_ms",
                ),
                "max_write_after_terminal_last_data_ms": row_max(
                    group_rows,
                    "high_conf_max_last_write_after_terminal_last_data_ms",
                ),
                "max_terminal_data_gap_ms": row_max(
                    group_rows,
                    "high_conf_max_terminal_data_gap_ms",
                ),
                "max_terminal_idle_after_last_data_ms": row_max(
                    group_rows,
                    "high_conf_max_terminal_idle_after_last_data_ms",
                ),
                "max_terminal_pending_after_bytes": row_max(
                    group_rows,
                    "high_conf_max_terminal_pending_after_bytes",
                ),
                "terminal_sendmes": row_sum(
                    group_rows,
                    "high_conf_terminal_sendmes",
                ),
                "terminal_sendme_ok": row_sum(
                    group_rows,
                    "high_conf_terminal_sendme_ok",
                ),
                "min_terminal_recv_window_after_take": row_min(
                    group_rows,
                    "high_conf_min_terminal_recv_window_after_take",
                ),
                "max_terminal_queued_after_bytes": row_max(
                    group_rows,
                    "high_conf_max_terminal_queued_after_bytes",
                ),
                "browser_release_after_write_rows": len(positive_release_rows),
                "browser_release_after_write_500ms": row_count_at_least(
                    response_after_write_rows,
                    "response_after_write_ms",
                    500,
                ),
                "response_before_last_write_rows": sum(
                    1
                    for row in response_after_write_rows
                    if (value := numeric(row.get("response_after_write_ms")))
                    is not None
                    and value < 0
                ),
                "median_positive_browser_release_after_write_ms": row_median(
                    positive_release_rows,
                    "response_after_write_ms",
                ),
                "top_late_queued_resource": compact_url(
                    str(sorted_rows[0].get("queued_resource", "")), max_length=42
                )
                if sorted_rows
                else "",
                "blocker_timing_ids": compact_list(
                    expand_compact_list_field(group_rows, "blocker_timing_ids"),
                    max_items=6,
                ),
                "blocker_circuits": compact_list(
                    expand_compact_list_field(group_rows, "blocker_circuits"),
                    max_items=4,
                ),
            }
        )
    return sorted(
        rows,
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0,
        ),
    )


def resource_queue_late_stream_detail_rows(
    payload: dict[str, object], threshold_ms: float = 1000.0
) -> list[dict[str, object]]:
    rows = [
        row
        for row in resource_queue_slot_blocker_rows(payload, threshold_ms=threshold_ms)
        if row.get("high_conf_max_terminal_last_data_after_queued_request_ms")
        is not None
    ]
    return sorted(
        rows,
        key=lambda row: (
            numeric(
                row.get("high_conf_max_terminal_last_data_after_queued_request_ms")
            )
            or 0,
            numeric(row.get("high_conf_max_terminal_data_gap_ms")) or 0,
            numeric(row.get("fetch_to_request_ms")) or 0,
        ),
        reverse=True,
    )


def resource_queue_lifecycle_evidence_rows(
    payload: dict[str, object], threshold_ms: float = 1000.0
) -> list[dict[str, object]]:
    runs = {
        (str(profile_name), str(target), run.get("run_index")): run
        for profile_name, _profile, target, _summary, run in iter_runs(payload)
    }
    parsed: dict[
        tuple[str, str, object],
        tuple[list[str], list[dict[str, object]], list[dict[str, object]]],
    ] = {}
    rows: list[dict[str, object]] = []
    seen: set[tuple[str, str, object, object, object, object]] = set()
    for queue_row in resource_queue_late_stream_detail_rows(
        payload, threshold_ms=threshold_ms
    ):
        key = (
            str(queue_row.get("profile", "")),
            str(queue_row.get("target", "")),
            queue_row.get("run_index"),
        )
        run = runs.get(key)
        if not run:
            continue
        if key not in parsed:
            lines = dedupe_lines(run_torfast_lines(run))
            parsed[key] = (
                lines,
                list(
                    group_torfast_socks_timings(
                        parse_torfast_socks_timings(lines)
                    ).values()
                ),
                parse_torfast_stream_lifecycle_timings(lines),
            )
        lines, socks_rows, lifecycle_rows = parsed[key]
        if not lines:
            continue
        timing_ids = set(
            expand_compact_list_field([queue_row], "high_conf_blocker_timing_ids")
            or expand_compact_list_field([queue_row], "blocker_timing_ids")
        )
        stream_ids = set(
            expand_compact_list_field([queue_row], "high_conf_blocker_stream_ids")
            or expand_compact_list_field([queue_row], "blocker_stream_ids")
        )
        circuits = (
            expand_compact_list_field([queue_row], "high_conf_blocker_circuits")
            or expand_compact_list_field([queue_row], "blocker_circuits")
        )
        for socks_row in socks_rows:
            timing_match = str(socks_row.get("timing_id")) in timing_ids
            stream_match = str(socks_row.get("stream_id")) in stream_ids
            circuit_match = not circuits or any(
                torfast_circ_ids_match(socks_row.get("circ_id"), circuit)
                for circuit in circuits
            )
            if not timing_match and not (stream_match and circuit_match):
                continue
            seen_key = (
                key[0],
                key[1],
                key[2],
                socks_row.get("timing_id"),
                socks_row.get("stream_id"),
                queue_row.get("queued_resource"),
            )
            if seen_key in seen:
                continue
            seen.add(seen_key)
            lifecycle = lifecycle_rows_for_socks(socks_row, lifecycle_rows)
            terminal = latest_stream_receiver_terminal(socks_row, lines)
            detail = stream_lifecycle_detail_row(
                profile_name=key[0],
                target=key[1],
                run=run,
                socks_row=socks_row,
                lifecycle=lifecycle,
                terminal=terminal,
            )
            detail.update(
                {
                    "queued_resource": queue_row.get("queued_resource"),
                    "fetch_to_request_ms": queue_row.get("fetch_to_request_ms"),
                    "slot_depth_at_request": queue_row.get("slot_depth_at_request"),
                    "terminal_last_data_after_queued_request_ms": queue_row.get(
                        "high_conf_max_terminal_last_data_after_queued_request_ms"
                    ),
                }
            )
            rows.append(detail)
    return sorted(
        rows,
        key=lambda row: (
            numeric(row.get("terminal_last_data_after_queued_request_ms")) or 0,
            numeric(row.get("fetch_to_request_ms")) or 0,
            numeric(row.get("terminal_idle_after_last_data_ms")) or 0,
            numeric(row.get("data_to_data_ms")) or 0,
        ),
        reverse=True,
    )


def resource_queue_late_circuit_summary_rows(
    payload: dict[str, object], threshold_ms: float = 1000.0
) -> list[dict[str, object]]:
    grouped: dict[tuple[str, str, object, str], list[dict[str, object]]] = {}
    for row in resource_queue_late_stream_detail_rows(
        payload, threshold_ms=threshold_ms
    ):
        circuits = expand_compact_list_field([row], "blocker_circuits")
        for circuit in circuits:
            key = (
                str(row.get("profile", "")),
                str(row.get("target", "")),
                row.get("run_index"),
                circuit,
            )
            grouped.setdefault(key, []).append(row)

    terminal_rows = torfast_stream_receiver_terminal_top_rows(payload)
    rows = []
    for (profile, target, run_index, circuit), group_rows in grouped.items():
        sorted_late = sorted(
            group_rows,
            key=lambda row: numeric(
                row.get("high_conf_max_terminal_last_data_after_queued_request_ms")
            )
            or 0,
            reverse=True,
        )
        matching_terminals = [
            row
            for row in terminal_rows
            if str(row.get("profile", "")) == profile
            and torfast_circ_ids_match(circuit, str(row.get("circ_id", "")))
            and (not row.get("target") or str(row.get("target", "")) == target)
            and (row.get("run_index") is None or row.get("run_index") == run_index)
        ]
        terminal_stream_ids = [
            row.get("stream_id")
            for row in matching_terminals
            if row.get("stream_id") is not None
        ]
        rows.append(
            {
                "profile": profile,
                "target": target,
                "run_index": run_index,
                "circuit": circuit,
                "late_resources": len(group_rows),
                "max_terminal_last_data_after_queue_ms": row_max(
                    group_rows,
                    "high_conf_max_terminal_last_data_after_queued_request_ms",
                ),
                "max_late_terminal_data_gap_ms": row_max(
                    group_rows, "high_conf_max_terminal_data_gap_ms"
                ),
                "top_late_resource": compact_url(
                    str(sorted_late[0].get("queued_resource", "")), max_length=42
                )
                if sorted_late
                else "",
                "late_timing_ids": compact_list(
                    expand_compact_list_field(group_rows, "blocker_timing_ids"),
                    max_items=6,
                ),
                "terminal_streams": len(set(terminal_stream_ids)),
                "terminal_timing_ids": compact_list(
                    [
                        row.get("timing_id")
                        for row in matching_terminals
                        if row.get("timing_id") is not None
                    ],
                    max_items=8,
                ),
                "terminal_stream_ids": compact_list(
                    terminal_stream_ids,
                    max_items=8,
                ),
                "terminal_relay_kib": sum(
                    numeric(row.get("relay_kib")) or 0 for row in matching_terminals
                ),
                "max_terminal_transfer_ms": row_max(
                    matching_terminals, "transfer_ms"
                ),
                "max_terminal_data_gap_ms": row_max(
                    matching_terminals, "max_data_gap_ms"
                ),
                "max_terminal_idle_after_last_data_ms": row_max(
                    matching_terminals, "idle_after_last_data_ms"
                ),
                "terminal_data_cells": sum(
                    numeric(row.get("data_cells")) or 0 for row in matching_terminals
                ),
            }
        )
    return sorted(
        rows,
        key=lambda row: (
            numeric(row.get("late_resources")) or 0,
            numeric(row.get("max_terminal_last_data_after_queue_ms")) or 0,
        ),
        reverse=True,
    )


def torfast_stream_scheduler_late_circuit_fairness_rows(
    payload: dict[str, object], threshold_ms: float = 1000.0
) -> list[dict[str, object]]:
    picks_by_run: dict[tuple[str, str, object], list[dict[str, object]]] = {}
    for profile_name, profile, target, _summary, run in iter_runs(payload):
        lines = run_torfast_lines(run)
        if not lines and isinstance(profile, dict):
            lines = proxy_log_lines(profile)
        if not lines:
            continue
        timings = parse_torfast_stream_scheduler_timings([str(line) for line in lines])
        picks = [item for item in timings if item.get("event") == "picked"]
        if not picks:
            continue
        key = (str(profile_name), str(target), run.get("run_index"))
        picks_by_run.setdefault(key, []).extend(picks)

    rows = []
    for late_row in resource_queue_late_circuit_summary_rows(
        payload, threshold_ms=threshold_ms
    ):
        profile = str(late_row.get("profile", ""))
        target = str(late_row.get("target", ""))
        run_index = late_row.get("run_index")
        circuit = str(late_row.get("circuit", ""))
        picks = [
            item
            for item in picks_by_run.get((profile, target, run_index), [])
            if torfast_circ_ids_match(circuit, item.get("circ_id"))
        ]
        stream_counts: dict[object, int] = {}
        for item in picks:
            stream_id = item.get("stream_id")
            if stream_id is None:
                continue
            stream_counts[stream_id] = stream_counts.get(stream_id, 0) + 1
        top_stream_id: object | None = None
        top_stream_picks = 0
        if stream_counts:
            top_stream_id, top_stream_picks = max(
                stream_counts.items(), key=lambda item: (item[1], str(item[0]))
            )
        scheduler_picks = len(picks)
        top_share = (
            top_stream_picks * 100.0 / scheduler_picks if scheduler_picks else None
        )
        row = {
            **late_row,
            "scheduler_picks": scheduler_picks,
            "data_picks": sum(1 for item in picks if item.get("relay_cmd") == "DATA"),
            "picked_streams": len(stream_counts),
            "top_picked_stream_id": top_stream_id,
            "top_picked_stream_picks": top_stream_picks if stream_counts else None,
            "top_picked_stream_share_pct": top_share,
            "max_consecutive_same_stream_picks": max_consecutive_same_stream_picks(
                picks
            ),
            "top_picked_streams": compact_scheduler_stream_counts(stream_counts),
        }
        row["proof_hint"] = torfast_stream_scheduler_fairness_hint(row)
        rows.append(row)
    return sorted(
        rows,
        key=lambda row: (
            numeric(row.get("late_resources")) or 0,
            numeric(row.get("scheduler_picks")) or 0,
            numeric(row.get("top_picked_stream_share_pct")) or 0,
        ),
        reverse=True,
    )


def max_consecutive_same_stream_picks(picks: list[dict[str, object]]) -> int:
    longest = 0
    current = 0
    previous: object | None = None
    for item in picks:
        stream_id = item.get("stream_id")
        if stream_id is None:
            continue
        if stream_id == previous:
            current += 1
        else:
            previous = stream_id
            current = 1
        longest = max(longest, current)
    return longest


def compact_scheduler_stream_counts(counts: dict[object, int], max_items: int = 6) -> str:
    pairs = sorted(counts.items(), key=lambda item: (-item[1], str(item[0])))
    shown = [f"{stream_id}:{count}" for stream_id, count in pairs[:max_items]]
    suffix = "" if len(pairs) <= max_items else f", +{len(pairs) - max_items}"
    return ", ".join(shown) + suffix


def torfast_stream_scheduler_fairness_hint(row: dict[str, object]) -> str:
    picks = numeric(row.get("scheduler_picks")) or 0
    if picks == 0:
        return "no matching scheduler picks"
    picked_streams = numeric(row.get("picked_streams")) or 0
    terminal_streams = numeric(row.get("terminal_streams")) or 0
    top_share = numeric(row.get("top_picked_stream_share_pct")) or 0
    streak = numeric(row.get("max_consecutive_same_stream_picks")) or 0
    if picked_streams <= 1 and terminal_streams > 1:
        return "single stream picked on multi-stream circuit"
    if picked_streams > 1 and top_share >= 80:
        return "skewed scheduler picks"
    if picked_streams > 1 and streak >= 5:
        return "repeated same-stream picks"
    return "no scheduler monopoly seen"


def arti_selected_circuit_network_evidence_rows(
    payload: dict[str, object],
    *,
    late_threshold_ms: float = 1000.0,
    relay_threshold_ms: float = 5000.0,
) -> list[dict[str, object]]:
    rows_by_key: dict[tuple[str, str, object, str], dict[str, object]] = {}

    def ensure_row(
        profile: object, target: object, run_index: object, circuit: object
    ) -> dict[str, object] | None:
        profile_text = str(profile or "")
        circuit_text = str(circuit or "")
        if not profile_text.startswith("arti_") or not circuit_text:
            return None
        key = (profile_text, str(target or ""), run_index, circuit_text)
        row = rows_by_key.get(key)
        if row is None:
            row = {
                "profile": key[0],
                "target": key[1],
                "run_index": key[2],
                "circuit": key[3],
                "late_resources": 0,
                "relay_tail_streams": 0,
                "not_connected_streams": 0,
                "no_end_close_events": 0,
            }
            rows_by_key[key] = row
        return row

    detail_rows = resource_queue_late_stream_detail_rows(
        payload, threshold_ms=late_threshold_ms
    )
    details_by_key: dict[tuple[str, str, object, str], list[dict[str, object]]] = {}
    for detail in detail_rows:
        for circuit in expand_compact_list_field([detail], "blocker_circuits"):
            key = (
                str(detail.get("profile", "")),
                str(detail.get("target", "")),
                detail.get("run_index"),
                circuit,
            )
            details_by_key.setdefault(key, []).append(detail)

    for late_row in resource_queue_late_circuit_summary_rows(
        payload, threshold_ms=late_threshold_ms
    ):
        row = ensure_row(
            late_row.get("profile"),
            late_row.get("target"),
            late_row.get("run_index"),
            late_row.get("circuit"),
        )
        if row is None:
            continue
        row["late_resources"] = late_row.get("late_resources")
        row["terminal_streams"] = late_row.get("terminal_streams")
        row["max_terminal_last_data_after_queue_ms"] = late_row.get(
            "max_terminal_last_data_after_queue_ms"
        )
        row["max_data_gap_ms"] = late_row.get("max_terminal_data_gap_ms")
        row["max_idle_after_last_data_ms"] = late_row.get(
            "max_terminal_idle_after_last_data_ms"
        )
        row["terminal_data_cells"] = late_row.get("terminal_data_cells")

    for tail_row in failed_run_relay_tail_circuit_concentration_rows(
        payload, relay_threshold_ms=relay_threshold_ms
    ):
        row = ensure_row(
            tail_row.get("profile"),
            tail_row.get("target"),
            tail_row.get("run_index"),
            tail_row.get("circ_id"),
        )
        if row is None:
            continue
        row["relay_tail_streams"] = tail_row.get("relay_tail_streams")
        row["relay_tail_with_tor_bytes"] = tail_row.get("with_tor_bytes")
        row["relay_tail_no_tor_bytes"] = tail_row.get("no_tor_bytes")
        row["reader_not_connected_streams"] = tail_row.get(
            "reader_not_connected_streams"
        )
        row["max_relay_ms"] = row_max([row, tail_row], "max_relay_ms")
        row["max_idle_after_last_data_ms"] = row_max(
            [
                row,
                {
                    "max_idle_after_last_data_ms": tail_row.get(
                        "max_idle_after_last_tor_byte_ms"
                    )
                },
            ],
            "max_idle_after_last_data_ms",
        )

    terminal_groups: dict[tuple[str, str, object, str], list[dict[str, object]]] = {}
    for terminal in torfast_stream_receiver_terminal_top_rows(payload):
        profile = str(terminal.get("profile", ""))
        circuit = str(terminal.get("circ_id", ""))
        if not profile.startswith("arti_") or not circuit:
            continue
        key = (
            profile,
            str(terminal.get("target") or ""),
            terminal.get("run_index"),
            circuit,
        )
        terminal_groups.setdefault(key, []).append(terminal)

    for key, terminals in terminal_groups.items():
        not_connected = [
            row for row in terminals if stream_receiver_row_is_not_connected(row)
        ]
        has_notable_terminal = (
            row_max(not_connected, "socks_relay_ms") or 0
        ) >= relay_threshold_ms or (
            row_max(not_connected, "idle_after_last_data_ms") or 0
        ) >= late_threshold_ms
        if key not in rows_by_key and not has_notable_terminal:
            continue
        row = ensure_row(*key)
        if row is None:
            continue
        row["terminal_streams"] = max(
            numeric(row.get("terminal_streams")) or 0,
            len({item.get("stream_id") for item in terminals}),
        )
        row["not_connected_streams"] = len(not_connected)
        row["not_connected_sources"] = compact_counts(
            count_labels(
                item.get("not_connected_source")
                for item in not_connected
                if item.get("not_connected_source")
            )
        )
        row["stream_close_causes"] = compact_counts(
            count_labels(
                item.get("stream_close_cause")
                for item in not_connected
                if item.get("stream_close_cause")
            )
        )
        row["no_end_close_events"] = row_sum(terminals, "no_end_close_events") or 0
        row["no_end_close_queued_after_bytes"] = row_max(
            terminals, "no_end_close_queued_after_bytes"
        )
        row["close_decision_events"] = row_sum(terminals, "close_decision_events") or 0
        close_reason_values = [
            value
            for terminal in terminals
            for value in terminal.get("_close_reason_values", [])
        ]
        close_should_send_end_values = [
            value
            for terminal in terminals
            for value in terminal.get("_close_should_send_end_values", [])
        ]
        row["close_reasons"] = compact_counts(count_labels(close_reason_values))
        row["close_should_send_end"] = compact_counts(
            count_labels(close_should_send_end_values)
        )
        row["max_relay_ms"] = row_max(
            [row, {"max_relay_ms": row_max(terminals, "socks_relay_ms")}],
            "max_relay_ms",
        )
        row["max_idle_after_last_data_ms"] = row_max(
            [
                row,
                {
                    "max_idle_after_last_data_ms": row_max(
                        terminals, "idle_after_last_data_ms"
                    )
                },
            ],
            "max_idle_after_last_data_ms",
        )
        row["max_data_gap_ms"] = row_max(
            [row, {"max_data_gap_ms": row_max(terminals, "max_data_gap_ms")}],
            "max_data_gap_ms",
        )
        row["terminal_data_cells"] = row_max(
            [row, {"terminal_data_cells": row_sum(terminals, "data_cells")}],
            "terminal_data_cells",
        )
        row["sendmes"] = row_sum(terminals, "sendmes")
        row["sendme_ok"] = row_sum(terminals, "sendme_ok")
        row["min_recv_window_after_take"] = row_min(
            terminals, "min_recv_window_after_take"
        )
        row["max_queued_after_bytes"] = row_max(terminals, "max_queued_after_bytes")

    scheduler_rows = torfast_stream_scheduler_late_circuit_fairness_rows(
        payload, threshold_ms=late_threshold_ms
    )
    circuit_gap_rows = torfast_relay_receive_circuit_gap_summary_rows(payload)
    resource_stream_gap_by_key: dict[
        tuple[str, str, object, str], dict[str, object]
    ] = {}
    for gap_row in browser_resource_stream_gap_context_rows(payload):
        circuit = str(gap_row.get("circ_id") or "")
        profile = str(gap_row.get("profile") or "")
        if not circuit or not profile.startswith("arti_"):
            continue
        key = (
            profile,
            str(gap_row.get("target") or ""),
            gap_row.get("run_index"),
            circuit,
        )
        old = resource_stream_gap_by_key.get(key)
        if old is None or (numeric(gap_row.get("gap_ms")) or 0) > (
            numeric(old.get("gap_ms")) or 0
        ):
            resource_stream_gap_by_key[key] = gap_row
    selection_rows = browser_resource_queue_selection_context_rows(payload)
    direct_selection_rows = torfast_circuit_selection_context_rows(payload)
    late_phase_rows = browser_run_late_phase_queue_context_rows(payload)
    congestion_by_run = circuit_congestion_timings_by_run(payload)

    rows = []
    for key, row in rows_by_key.items():
        profile, target, run_index, circuit = key
        scheduler = best_matching_scheduler_late_circuit_row(
            scheduler_rows, profile, target, run_index, circuit
        )
        if scheduler:
            row["scheduler_proof_hint"] = scheduler.get("proof_hint", "")
            row["scheduler_picks"] = scheduler.get("scheduler_picks")
            row["picked_streams"] = scheduler.get("picked_streams")
            row["top_picked_stream_share_pct"] = scheduler.get(
                "top_picked_stream_share_pct"
            )
        else:
            row["scheduler_proof_hint"] = ""

        selection = best_matching_selection_context_row(
            selection_rows, profile, target, run_index, circuit
        )
        if not selection:
            selection = best_matching_selection_context_row(
                direct_selection_rows, profile, target, run_index, circuit
            )
        if selection:
            row["better_health_alt_rows"] = selection.get("better_health_alt_rows")
            row["lower_assignment_alt_rows"] = selection.get(
                "lower_assignment_alt_rows"
            )
            row["candidate_context"] = selection.get("last_candidate_context") or (
                selection.get("first_candidate_context") or ""
            )
            row["choice_hint"] = queue_loss_choice_hint(row)
        else:
            late_phase = best_matching_late_phase_queue_row(
                late_phase_rows, profile, target, run_index, circuit
            )
            if late_phase:
                row["better_health_alt_rows"] = late_phase.get(
                    "better_health_alt_rows"
                )
                row["lower_assignment_alt_rows"] = late_phase.get(
                    "lower_assignment_alt_rows"
                )
                row["candidate_context"] = late_phase.get("candidate_context", "")
                row["choice_hint"] = queue_loss_choice_hint(row)
            else:
                row["choice_hint"] = "choice context missing"

        matching_details = details_by_key.get(key, [])
        row["terminal_pending_bytes"] = row_max(
            matching_details, "high_conf_max_terminal_pending_after_bytes"
        )
        row["sendmes"] = row_max(
            [row, {"sendmes": row_max(matching_details, "high_conf_terminal_sendmes")}],
            "sendmes",
        )
        row["sendme_ok"] = row_max(
            [
                row,
                {
                    "sendme_ok": row_max(
                        matching_details, "high_conf_terminal_sendme_ok"
                    )
                },
            ],
            "sendme_ok",
        )
        row["min_recv_window_after_take"] = row_min(
            [
                row,
                {
                    "min_recv_window_after_take": row_min(
                        matching_details,
                        "high_conf_min_terminal_recv_window_after_take",
                    )
                },
            ],
            "min_recv_window_after_take",
        )
        row["max_queued_after_bytes"] = row_max(
            [
                row,
                {
                    "max_queued_after_bytes": row_max(
                        matching_details, "high_conf_max_terminal_queued_after_bytes"
                    )
                },
            ],
            "max_queued_after_bytes",
        )

        congestion_rows = [
            item
            for item in congestion_by_run.get((profile, target, run_index), [])
            if torfast_circ_ids_match(circuit, item.get("circ_id"))
        ]
        row.update(summarize_circuit_congestion_rows(congestion_rows))
        circuit_gap = best_matching_scheduler_late_circuit_row(
            circuit_gap_rows, profile, target, run_index, circuit
        )
        if circuit_gap:
            row["max_circuit_data_gap_ms"] = circuit_gap.get(
                "max_circuit_data_gap_ms"
            )
            row["median_circuit_data_gap_ms"] = circuit_gap.get(
                "median_circuit_data_gap_ms"
            )
            row["circuit_data_cells"] = circuit_gap.get("data_cells")
            row["circuit_data_streams"] = circuit_gap.get("circuit_streams")
            row["circuit_data_gap_cross_stream_rows"] = circuit_gap.get(
                "cross_stream_gap_rows"
            )
            row["circuit_data_gap_same_stream_rows"] = circuit_gap.get(
                "same_stream_gap_rows"
            )
        resource_gap = resource_stream_gap_by_key.get(key)
        if resource_gap:
            row["max_resource_stream_gap_ms"] = resource_gap.get("gap_ms")
        row["max_observed_stream_gap_ms"] = row_max(
            [
                row,
                {"max_observed_stream_gap_ms": row.get("max_data_gap_ms")},
                {
                    "max_observed_stream_gap_ms": row.get(
                        "max_resource_stream_gap_ms"
                    )
                },
            ],
            "max_observed_stream_gap_ms",
        )
        row["data_gap_scope_hint"] = selected_circuit_data_gap_scope_hint(
            row, gap_threshold_ms=late_threshold_ms
        )
        row["local_block_summary"] = selected_circuit_local_block_summary(row)
        row["evidence_hint"] = selected_circuit_network_evidence_hint(row)
        rows.append(row)

    return sorted(
        rows,
        key=lambda row: (
            numeric(row.get("not_connected_streams")) or 0,
            numeric(row.get("relay_tail_streams")) or 0,
            numeric(row.get("late_resources")) or 0,
            numeric(row.get("max_idle_after_last_data_ms")) or 0,
            numeric(row.get("max_relay_ms")) or 0,
        ),
        reverse=True,
    )


def arti_selected_circuit_gap_predictability_rows(
    payload: dict[str, object],
    *,
    gap_threshold_ms: float = SELECTOR_BAD_HEALTH_GAP_MS,
) -> list[dict[str, object]]:
    selection_rows = torfast_circuit_selection_context_rows(payload)
    network_rows = arti_selected_circuit_network_evidence_rows(payload)
    rows = []
    gap_sources = []

    for gap_row in torfast_socks_relay_join_gap_detail_rows(payload):
        gap_sources.append(
            {
                "profile": gap_row.get("profile"),
                "target": gap_row.get("target"),
                "run_index": gap_row.get("run_index"),
                "circ_id": gap_row.get("circ_id"),
                "stream_id": gap_row.get("stream_id"),
                "actual_gap_ms": gap_row.get("gap_ms"),
                "gap_end_before_load_ms": gap_row.get("gap_end_before_load_ms"),
            }
        )
    for terminal in torfast_stream_receiver_terminal_top_rows(payload):
        if not terminal.get("target") or terminal.get("run_index") is None:
            continue
        gap_sources.append(
            {
                "profile": terminal.get("profile"),
                "target": terminal.get("target"),
                "run_index": terminal.get("run_index"),
                "circ_id": terminal.get("circ_id"),
                "stream_id": terminal.get("stream_id"),
                "actual_gap_ms": terminal.get("max_data_gap_ms"),
                "gap_end_before_load_ms": None,
            }
        )

    best_gap_sources: dict[tuple[object, ...], dict[str, object]] = {}
    for gap_row in gap_sources:
        circuit_key = str(gap_row.get("circ_id", "")).split(" (", 1)[0]
        key = (
            str(gap_row.get("profile", "")),
            str(gap_row.get("target", "")),
            gap_row.get("run_index"),
            circuit_key,
            gap_row.get("stream_id"),
        )
        existing = best_gap_sources.get(key)
        if existing is None or (numeric(gap_row.get("actual_gap_ms")) or 0) > (
            numeric(existing.get("actual_gap_ms")) or 0
        ):
            best_gap_sources[key] = gap_row

    for gap_row in best_gap_sources.values():
        profile = str(gap_row.get("profile", ""))
        if not profile.startswith("arti_"):
            continue
        actual_gap = numeric(gap_row.get("actual_gap_ms"))
        if actual_gap is None or actual_gap < gap_threshold_ms:
            continue
        target = str(gap_row.get("target", ""))
        run_index = gap_row.get("run_index")
        circuit = str(gap_row.get("circ_id", ""))
        selection = best_matching_selection_context_row(
            selection_rows, profile, target, run_index, circuit
        )
        network = best_matching_scheduler_late_circuit_row(
            network_rows, profile, target, run_index, circuit
        )
        row = {
            "profile": profile,
            "target": target,
            "run_index": run_index,
            "circuit": circuit,
            "stream_id": gap_row.get("stream_id"),
            "actual_gap_ms": actual_gap,
            "gap_end_before_load_ms": gap_row.get("gap_end_before_load_ms"),
            "selected_open_rows": None,
            "selected_health_gap_ms": None,
            "selected_health_score_bps": None,
            "selected_bad_health_rows": None,
            "best_alt_health_score_bps": None,
            "best_alt_health_gap_ms": None,
            "better_health_alt_rows": None,
            "lower_assignment_alt_rows": None,
            "candidate_context": "",
            "choice_hint": "",
        }
        if selection:
            candidate_context = (
                selection.get("last_candidate_context")
                or selection.get("first_candidate_context")
                or ""
            )
            row.update(
                {
                    "selected_open_rows": selection.get("selected_open_rows"),
                    "selected_health_gap_ms": selection.get(
                        "max_selected_health_gap_ms"
                    ),
                    "selected_health_score_bps": selection.get(
                        "max_selected_health_score_bps"
                    ),
                    "selected_bad_health_rows": selection.get(
                        "selected_bad_health_rows"
                    ),
                    "best_alt_health_score_bps": selection.get(
                        "best_alt_health_score_bps"
                    ),
                    "best_alt_health_gap_ms": selection.get(
                        "best_alt_health_gap_ms"
                    ),
                    "better_health_alt_rows": selection.get(
                        "better_health_alt_rows"
                    ),
                    "lower_assignment_alt_rows": selection.get(
                        "lower_assignment_alt_rows"
                    ),
                    "candidate_context": candidate_context,
                }
            )
            row["choice_hint"] = queue_loss_choice_hint(row)
        if network:
            row["choice_hint"] = network.get("choice_hint") or row.get(
                "choice_hint", ""
            )
            row["local_block_summary"] = network.get("local_block_summary")
            row["evidence_hint"] = network.get("evidence_hint")
        row["predictability_hint"] = selected_circuit_gap_predictability_hint(
            row, gap_threshold_ms=gap_threshold_ms
        )
        rows.append(row)

    return sorted(
        rows,
        key=lambda row: (
            numeric(row.get("actual_gap_ms")) or 0,
            numeric(row.get("gap_end_before_load_ms")) or 0,
        ),
        reverse=True,
    )


def relay_receive_run_contexts(
    payload: dict[str, object],
) -> dict[tuple[str, str, object], dict[str, object]]:
    contexts: dict[tuple[str, str, object], dict[str, object]] = {}
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return contexts

    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        profile_timings = parse_torfast_relay_receive_timings(
            dedupe_lines(proxy_log_lines(profile))
        )
        benchmarks = profile.get("benchmarks", {})
        if not isinstance(benchmarks, dict):
            continue
        for target, bench in sorted(benchmarks.items()):
            if not isinstance(bench, dict):
                continue
            runs = [
                run for run in bench.get("runs", []) if isinstance(run, dict)
            ]
            timed_runs = [
                run for run in runs if browser_time_origin_ms(run) is not None
            ]
            bounds_by_run_id = {
                id(run): bounds
                for run, bounds in zip(timed_runs, browser_run_epoch_bounds(timed_runs))
            }
            for run in runs:
                run_timings = parse_torfast_relay_receive_timings(
                    dedupe_lines(run_torfast_lines(run))
                )
                bound = bounds_by_run_id.get(id(run))
                bounded_profile_timings = []
                if bound is not None:
                    lower, upper = bound
                    bounded_profile_timings = [
                        item
                        for item in profile_timings
                        if (
                            (timestamp := numeric(item.get("timestamp_ms")))
                            is not None
                            and lower <= timestamp <= upper
                        )
                    ]

                merged = []
                seen = set()
                for item in run_timings + bounded_profile_timings:
                    key = (
                        item.get("timestamp_ms"),
                        item.get("circ_id"),
                        item.get("stream_id"),
                        item.get("event"),
                        item.get("relay_cmd"),
                        item.get("data_len"),
                        item.get("queued_before_bytes"),
                        item.get("queued_after_bytes"),
                    )
                    if key in seen:
                        continue
                    seen.add(key)
                    merged.append(item)

                contexts[
                    (str(profile_name), str(target), run.get("run_index"))
                ] = {
                    "relay_timings": merged,
                    "time_origin_ms": browser_time_origin_ms(run),
                }
    return contexts


def selected_stream_gap_cross_activity_hint(row: dict[str, object]) -> str:
    other_cells = numeric(row.get("same_circuit_other_data_cells")) or 0
    if other_cells <= 0:
        return "whole circuit quiet during stream gap"
    if str(row.get("local_block_summary", "")) == "no local block seen":
        return "other streams active; no local block seen"
    return "other streams active on same circuit"


def arti_selected_stream_gap_cross_activity_rows(
    payload: dict[str, object],
    *,
    gap_threshold_ms: float = SELECTOR_BAD_HEALTH_GAP_MS,
) -> list[dict[str, object]]:
    run_contexts = relay_receive_run_contexts(payload)
    network_rows = arti_selected_circuit_network_evidence_rows(payload)
    rows = []

    for gap_row in arti_selected_circuit_gap_predictability_rows(
        payload, gap_threshold_ms=gap_threshold_ms
    ):
        profile = str(gap_row.get("profile", ""))
        target = str(gap_row.get("target", ""))
        run_index = gap_row.get("run_index")
        circuit = str(gap_row.get("circuit", ""))
        stream_id = gap_row.get("stream_id")
        if not profile or not circuit or stream_id is None:
            continue
        context = run_contexts.get((profile, target, run_index), {})
        timings = context.get("relay_timings", [])
        if not isinstance(timings, list) or not timings:
            continue

        target_data_items = [
            item
            for item in timings
            if item.get("event") == "delivered"
            and item.get("relay_cmd") == "DATA"
            and item.get("stream_id") == stream_id
            and torfast_circ_ids_match(circuit, item.get("circ_id"))
        ]
        gap_bounds = event_timestamp_gap_bounds_ms(target_data_items)
        if not gap_bounds:
            continue
        max_gap = max(gap_bounds, key=lambda item: numeric(item.get("gap_ms")) or 0)
        actual_gap = numeric(max_gap.get("gap_ms"))
        if actual_gap is None or actual_gap < gap_threshold_ms:
            continue
        gap_start = numeric(max_gap.get("start_timestamp_ms"))
        gap_end = numeric(max_gap.get("end_timestamp_ms"))
        if gap_start is None or gap_end is None:
            continue

        other_data_items = [
            item
            for item in timings
            if item.get("event") == "delivered"
            and item.get("relay_cmd") == "DATA"
            and item.get("stream_id") != stream_id
            and torfast_circ_ids_match(circuit, item.get("circ_id"))
            and (timestamp := numeric(item.get("timestamp_ms"))) is not None
            and gap_start < timestamp < gap_end
        ]
        by_stream: dict[object, dict[str, float]] = {}
        for item in other_data_items:
            other_stream = item.get("stream_id")
            stats = by_stream.setdefault(other_stream, {"cells": 0.0, "bytes": 0.0})
            stats["cells"] += 1.0
            stats["bytes"] += numeric(item.get("data_len")) or 0

        top_other_stream_id = None
        top_other_stats = {"cells": 0.0, "bytes": 0.0}
        if by_stream:
            top_other_stream_id, top_other_stats = max(
                by_stream.items(),
                key=lambda item: (item[1].get("cells", 0), item[1].get("bytes", 0)),
            )

        network = best_matching_scheduler_late_circuit_row(
            network_rows, profile, target, run_index, circuit
        )
        origin = numeric(context.get("time_origin_ms"))
        row = {
            "profile": profile,
            "target": target,
            "run_index": run_index,
            "circuit": circuit,
            "stream_id": stream_id,
            "actual_gap_ms": actual_gap,
            "gap_start_timestamp_ms": gap_start,
            "gap_end_timestamp_ms": gap_end,
            "gap_start_after_origin_ms": (
                gap_start - origin if origin is not None else None
            ),
            "gap_end_after_origin_ms": gap_end - origin if origin is not None else None,
            "same_circuit_other_data_cells": len(other_data_items),
            "same_circuit_other_data_kib": (
                sum(numeric(item.get("data_len")) or 0 for item in other_data_items)
                / 1024.0
            ),
            "same_circuit_other_streams": len(by_stream),
            "top_other_stream_id": top_other_stream_id,
            "top_other_stream_data_cells": top_other_stats.get("cells"),
            "top_other_stream_data_kib": top_other_stats.get("bytes", 0) / 1024.0,
            "choice_hint": gap_row.get("choice_hint", ""),
            "predictability_hint": gap_row.get("predictability_hint", ""),
            "local_block_summary": gap_row.get("local_block_summary")
            or (network.get("local_block_summary") if network else ""),
            "source_evidence_hint": gap_row.get("evidence_hint")
            or (network.get("evidence_hint") if network else ""),
        }
        row["cross_stream_evidence_hint"] = selected_stream_gap_cross_activity_hint(
            row
        )
        rows.append(row)

    return sorted(
        rows,
        key=lambda row: (
            numeric(row.get("actual_gap_ms")) or 0,
            numeric(row.get("same_circuit_other_data_cells")) or 0,
        ),
        reverse=True,
    )


def selected_stream_gap_resource_overlap_hint(row: dict[str, object]) -> str:
    if (numeric(row.get("same_stream_resources")) or 0) <= 0:
        return "no browser resource match"
    phase_totals = {
        "browser queue": numeric(row.get("fetch_to_request_overlap_ms")) or 0.0,
        "server wait": numeric(row.get("request_wait_overlap_ms")) or 0.0,
        "response receive": numeric(row.get("response_receive_overlap_ms")) or 0.0,
    }
    phase, phase_ms = max(phase_totals.items(), key=lambda item: item[1])
    if phase_ms > 0:
        return f"gap overlaps {phase}"
    if (numeric(row.get("active_overlap_ms")) or 0) > 0:
        return "resource active, phase unclear"
    return "matched resource not active during gap"


def arti_selected_stream_gap_resource_overlap_rows(
    payload: dict[str, object],
    *,
    gap_threshold_ms: float = SELECTOR_BAD_HEALTH_GAP_MS,
) -> list[dict[str, object]]:
    resource_rows = (
        browser_resource_socks_relay_join_rows(payload)
        + browser_navigation_socks_join_rows(payload)
    )
    rows = []

    for gap_row in arti_selected_stream_gap_cross_activity_rows(
        payload, gap_threshold_ms=gap_threshold_ms
    ):
        profile = str(gap_row.get("profile", ""))
        target = str(gap_row.get("target", ""))
        run_index = gap_row.get("run_index")
        circuit = str(gap_row.get("circuit", ""))
        stream_id = gap_row.get("stream_id")
        gap_start = numeric(gap_row.get("gap_start_after_origin_ms"))
        gap_end = numeric(gap_row.get("gap_end_after_origin_ms"))
        if gap_start is None or gap_end is None:
            continue

        same_stream_resources = [
            row
            for row in resource_rows
            if row.get("profile") == profile
            and row.get("target") == target
            and row.get("run_index") == run_index
            and row.get("stream_id") == stream_id
            and torfast_circ_ids_match(circuit, row.get("circ_id"))
        ]

        overlap_rows = []
        for resource in same_stream_resources:
            fetch_overlap = interval_overlap_ms(
                gap_start,
                gap_end,
                numeric(resource.get("fetch_start_ms")),
                numeric(resource.get("request_start_ms")),
            )
            wait_overlap = interval_overlap_ms(
                gap_start,
                gap_end,
                numeric(resource.get("request_start_ms")),
                numeric(resource.get("response_start_ms")),
            )
            receive_overlap = interval_overlap_ms(
                gap_start,
                gap_end,
                numeric(resource.get("response_start_ms")),
                numeric(resource.get("response_end_ms")),
            )
            active_overlap = interval_overlap_ms(
                gap_start,
                gap_end,
                numeric(resource.get("resource_start_ms")),
                numeric(resource.get("response_end_ms")),
            )
            row = dict(resource)
            row["fetch_to_request_overlap_ms"] = fetch_overlap
            row["request_wait_overlap_ms"] = wait_overlap
            row["response_receive_overlap_ms"] = receive_overlap
            row["active_overlap_ms"] = active_overlap
            phases = [
                ("fetch_to_request", fetch_overlap),
                ("request_wait", wait_overlap),
                ("response_receive", receive_overlap),
            ]
            top_phase, top_phase_overlap = max(
                phases,
                key=lambda item: numeric(item[1]) or 0,
            )
            if (numeric(top_phase_overlap) or 0) > 0:
                row["top_overlap_phase"] = top_phase
                row["top_overlap_ms"] = top_phase_overlap
            elif (active_overlap or 0) > 0:
                row["top_overlap_phase"] = "active_other"
                row["top_overlap_ms"] = active_overlap
            else:
                row["top_overlap_phase"] = ""
                row["top_overlap_ms"] = top_phase_overlap
            overlap_rows.append(row)

        top_overlap = None
        if overlap_rows:
            top_overlap = max(
                overlap_rows,
                key=lambda row: (
                    numeric(row.get("top_overlap_ms")) or 0,
                    numeric(row.get("active_overlap_ms")) or 0,
                    numeric(row.get("duration_ms")) or 0,
                ),
            )

        row = {
            "profile": profile,
            "target": target,
            "run_index": run_index,
            "circuit": circuit,
            "stream_id": stream_id,
            "actual_gap_ms": gap_row.get("actual_gap_ms"),
            "gap_start_after_origin_ms": gap_start,
            "gap_end_after_origin_ms": gap_end,
            "same_circuit_other_data_cells": gap_row.get(
                "same_circuit_other_data_cells"
            ),
            "local_block_summary": gap_row.get("local_block_summary"),
            "same_stream_resources": len(same_stream_resources),
            "high_confidence_resources": sum(
                1
                for item in same_stream_resources
                if item.get("match_confidence") == "high"
            ),
            "active_overlap_resources": sum(
                1
                for item in overlap_rows
                if (numeric(item.get("active_overlap_ms")) or 0) > 0
            ),
            "fetch_to_request_overlap_ms": sum(
                numeric(item.get("fetch_to_request_overlap_ms")) or 0
                for item in overlap_rows
            ),
            "request_wait_overlap_ms": sum(
                numeric(item.get("request_wait_overlap_ms")) or 0
                for item in overlap_rows
            ),
            "response_receive_overlap_ms": sum(
                numeric(item.get("response_receive_overlap_ms")) or 0
                for item in overlap_rows
            ),
            "active_overlap_ms": sum(
                numeric(item.get("active_overlap_ms")) or 0 for item in overlap_rows
            ),
            "top_overlap_resource": (top_overlap or {}).get("resource"),
            "top_overlap_resource_type": (top_overlap or {}).get("resource_type"),
            "top_overlap_duration_ms": (top_overlap or {}).get("duration_ms"),
            "top_overlap_fetch_to_request_ms": (top_overlap or {}).get(
                "fetch_to_request_ms"
            ),
            "top_overlap_wait_ms": (top_overlap or {}).get("wait_ms"),
            "top_overlap_receive_ms": (top_overlap or {}).get("receive_ms"),
            "top_overlap_ms": (top_overlap or {}).get("top_overlap_ms"),
            "top_overlap_phase": (top_overlap or {}).get("top_overlap_phase"),
        }
        row["resource_overlap_hint"] = selected_stream_gap_resource_overlap_hint(row)
        rows.append(row)

    return sorted(
        rows,
        key=lambda row: (
            numeric(row.get("actual_gap_ms")) or 0,
            numeric(row.get("active_overlap_ms")) or 0,
        ),
        reverse=True,
    )


def browser_navigation_resource_row(
    run: dict[str, object], target: str
) -> dict[str, object] | None:
    timing = run.get("performance_timing", {})
    if not isinstance(timing, dict):
        return None
    navigation = timing.get("navigation")
    if not isinstance(navigation, dict):
        return None
    row = dict(navigation)
    row["name"] = row.get("name") or target
    row["initiatorType"] = row.get("initiatorType") or "navigation"
    return row


def browser_resource_rows_for_run_with_navigation(
    run: dict[str, object], target: str
) -> list[dict[str, object]]:
    rows = []
    navigation = browser_navigation_resource_row(run, target)
    if navigation is not None:
        rows.append(navigation)
    rows.extend(browser_resource_rows_for_run(run))
    return rows


def matching_browser_resource_row(
    resources: list[dict[str, object]],
    resource_name: object,
    resource_type: object,
) -> dict[str, object] | None:
    name = str(resource_name or "")
    rtype = str(resource_type or "")
    if not name:
        return None
    exact_name = [resource for resource in resources if resource.get("name") == name]
    if not exact_name:
        return None
    typed = [
        resource
        for resource in exact_name
        if not rtype or str(resource.get("initiatorType") or "") == rtype
    ]
    return (typed or exact_name)[0]


def resource_active_interval(resource: dict[str, object]) -> tuple[float | None, float | None]:
    start = numeric(resource.get("requestStart"))
    if start is None:
        start = numeric(resource.get("startTime"))
    end = numeric(resource.get("responseEnd"))
    return start, end


def resource_queued_interval(resource: dict[str, object]) -> tuple[float | None, float | None]:
    start = numeric(resource.get("fetchStart"))
    if start is None:
        start = numeric(resource.get("startTime"))
    end = numeric(resource.get("requestStart"))
    return start, end


def resource_phase_overlap_row(
    resource: dict[str, object], gap_start: object, gap_end: object
) -> dict[str, object]:
    queued_start, queued_end = resource_queued_interval(resource)
    active_start, active_end = resource_active_interval(resource)
    fetch_overlap = interval_overlap_ms(gap_start, gap_end, queued_start, queued_end)
    wait_overlap = interval_overlap_ms(
        gap_start,
        gap_end,
        numeric(resource.get("requestStart")),
        numeric(resource.get("responseStart")),
    )
    receive_overlap = interval_overlap_ms(
        gap_start,
        gap_end,
        numeric(resource.get("responseStart")),
        numeric(resource.get("responseEnd")),
    )
    active_overlap = interval_overlap_ms(gap_start, gap_end, active_start, active_end)
    phase_pairs = [
        ("fetch_to_request", fetch_overlap),
        ("request_wait", wait_overlap),
        ("response_receive", receive_overlap),
    ]
    top_phase, top_overlap = max(phase_pairs, key=lambda item: numeric(item[1]) or 0)
    if (numeric(top_overlap) or 0) <= 0 and (numeric(active_overlap) or 0) > 0:
        top_phase = "active_other"
        top_overlap = active_overlap
    return {
        "resource": resource,
        "fetch_to_request_overlap_ms": fetch_overlap,
        "request_wait_overlap_ms": wait_overlap,
        "response_receive_overlap_ms": receive_overlap,
        "active_overlap_ms": active_overlap,
        "top_phase": top_phase if (numeric(top_overlap) or 0) > 0 else "",
        "top_overlap_ms": top_overlap,
    }


def same_origin_protocol_resource_rows(
    reference: dict[str, object], resources: list[dict[str, object]]
) -> list[dict[str, object]]:
    origin = origin_label(reference.get("name"))
    protocol = protocol_label(reference.get("nextHopProtocol"))
    return [
        resource
        for resource in resources
        if origin_label(resource.get("name")) == origin
        and protocol_label(resource.get("nextHopProtocol")) == protocol
    ]


def resource_socket_active_at_ms(resource: dict[str, object], point_ms: object) -> bool:
    point = numeric(point_ms)
    start, end = resource_active_interval(resource)
    if point is None or start is None or end is None:
        return False
    return start <= point < end


def resource_queued_at_ms(resource: dict[str, object], point_ms: object) -> bool:
    point = numeric(point_ms)
    start, end = resource_queued_interval(resource)
    if point is None or start is None or end is None:
        return False
    return start <= point < end


def max_same_origin_protocol_active_count_in_gap(
    resources: list[dict[str, object]], gap_start: float, gap_end: float
) -> int:
    points = {gap_start, gap_end, gap_start + ((gap_end - gap_start) / 2.0)}
    for resource in resources:
        for field in ("requestStart", "responseStart", "responseEnd"):
            value = numeric(resource.get(field))
            if value is not None and gap_start <= value <= gap_end:
                points.add(value)
    return max(
        (
            sum(1 for resource in resources if resource_socket_active_at_ms(resource, point))
            for point in points
        ),
        default=0,
    )


def selected_gap_joined_active_resource_rows(
    profile: str,
    target: str,
    run_index: object,
    resources: list[dict[str, object]],
    join_index: dict[tuple[object, ...], dict[str, object]],
    relay_timings: list[dict[str, object]],
    gap_start_epoch: object,
) -> list[dict[str, object]]:
    rows = []
    for resource in resources:
        joined = join_index.get(
            browser_resource_join_key(profile, target, run_index, resource)
        )
        row = {
            "resource": resource.get("name"),
            "joined": joined,
        }
        if joined is not None:
            relay_context = relay_receive_context_for_joined(
                joined, relay_timings, gap_start_epoch
            )
            row.update(
                {
                    "timing_id": joined.get("timing_id"),
                    "circ_id": joined.get("circ_id"),
                    "stream_id": joined.get("stream_id"),
                    "match_confidence": joined.get("match_confidence"),
                    "stream_set_match_confidence": joined.get(
                        "stream_set_match_confidence"
                    ),
                    "host_lifetime_candidates": joined.get(
                        "host_lifetime_candidates"
                    ),
                    "host_lifetime_candidate_stream_ids": joined.get(
                        "host_lifetime_candidate_stream_ids"
                    ),
                    "relay_ms": joined.get("relay_ms"),
                    "last_tor_to_client_ms": joined.get("last_tor_to_client_ms"),
                    "max_gap_ms": joined.get("max_gap_ms"),
                    "last_write_after_gap_start_ms": subtract_numeric(
                        joined.get("last_tor_to_client_write_epoch_ms"),
                        gap_start_epoch,
                    ),
                    "relay_cells_after_gap_start": relay_context.get(
                        "relay_cells_after_queued_request"
                    ),
                    "relay_data_after_gap_start_bytes": relay_context.get(
                        "relay_data_after_queued_request_bytes"
                    ),
                    "first_relay_after_gap_start_ms": relay_context.get(
                        "first_relay_after_queued_request_ms"
                    ),
                    "last_relay_after_gap_start_ms": relay_context.get(
                        "last_relay_after_queued_request_ms"
                    ),
                    "max_relay_gap_after_gap_start_ms": relay_context.get(
                        "max_relay_gap_after_queued_request_ms"
                    ),
                }
            )
        rows.append(row)
    return rows


def selected_stream_gap_slot_pressure_hint(row: dict[str, object]) -> str:
    if not row.get("matched_resource"):
        return "no browser resource match"
    matched_active = numeric(row.get("matched_active_overlap_ms")) or 0
    max_active = numeric(row.get("max_same_origin_active_in_gap")) or 0
    if matched_active <= 0:
        if max_active >= 6:
            return "same-origin slots busy; matched resource inactive"
        return "matched resource not active during gap"
    if (numeric(row.get("same_origin_active_resources_in_gap")) or 0) <= 0:
        return "matched resource active, neighbors missing"
    protocol = str(row.get("protocol", ""))
    queued_1000 = numeric(row.get("same_origin_queued_1000_resources_in_gap")) or 0
    fetch_overlap = numeric(row.get("matched_fetch_to_request_overlap_ms")) or 0
    if protocol == "http/1.1" and max_active >= 6 and fetch_overlap > 0:
        return "queued behind HTTP/1.1 slots"
    if protocol == "http/1.1" and max_active >= 6 and queued_1000 > 0:
        return "HTTP/1.1 slot pressure during selected gap"
    if protocol == "http/1.1" and max_active >= 6:
        return "HTTP/1.1 saturated while stream gap ran"
    if fetch_overlap > 0:
        return "browser queue during selected gap"
    return "resource active without slot pressure"


def run_rows_by_profile_target_index(
    payload: dict[str, object],
) -> dict[tuple[str, str, object], dict[str, object]]:
    rows = {}
    for profile_name, _profile, target, _summary, run in iter_runs(payload):
        rows[(str(profile_name), str(target), run.get("run_index"))] = run
    return rows


def arti_selected_stream_gap_slot_pressure_rows(
    payload: dict[str, object],
    *,
    gap_threshold_ms: float = SELECTOR_BAD_HEALTH_GAP_MS,
) -> list[dict[str, object]]:
    runs = run_rows_by_profile_target_index(payload)
    join_index = browser_resource_join_index(payload)
    relay_timings_by_profile = relay_receive_timings_by_profile(payload)
    rows = []
    for overlap_row in arti_selected_stream_gap_resource_overlap_rows(
        payload, gap_threshold_ms=gap_threshold_ms
    ):
        profile = str(overlap_row.get("profile", ""))
        target = str(overlap_row.get("target", ""))
        run_index = overlap_row.get("run_index")
        run = runs.get((profile, target, run_index))
        if run is None:
            continue
        gap_start = numeric(overlap_row.get("gap_start_after_origin_ms"))
        gap_end = numeric(overlap_row.get("gap_end_after_origin_ms"))
        if gap_start is None or gap_end is None:
            continue
        resources = browser_resource_rows_for_run_with_navigation(run, target)
        matched_resource = matching_browser_resource_row(
            resources,
            overlap_row.get("top_overlap_resource"),
            overlap_row.get("top_overlap_resource_type"),
        )
        if matched_resource is None:
            row = dict(overlap_row)
            row.update(
                {
                    "matched_resource": None,
                    "protocol": "",
                    "same_origin_active_at_gap_start": None,
                    "max_same_origin_active_in_gap": None,
                    "same_origin_active_resources_in_gap": 0,
                    "same_origin_queued_1000_resources_in_gap": 0,
                    "same_origin_request_wait_overlap_ms": None,
                    "same_origin_response_receive_overlap_ms": None,
                    "top_active_resource": None,
                    "top_active_phase": "",
                    "top_active_overlap_ms": None,
                    "matched_fetch_to_request_overlap_ms": None,
                    "matched_active_overlap_ms": None,
                    "matched_top_phase": "",
                    "joined_active_resources": 0,
                    "joined_match_confidences": "",
                    "joined_timing_confidences": "",
                    "exact_joined_active_resources": 0,
                    "ambiguous_joined_active_resources": 0,
                    "joined_active_stream_ids": "",
                    "joined_active_circuits": "",
                    "high_conf_joined_active_resources": 0,
                    "high_conf_active_stream_ids": "",
                    "high_conf_active_circuits": "",
                    "high_conf_relay_cells_after_gap_start": None,
                    "high_conf_relay_data_after_gap_start_bytes": None,
                    "high_conf_first_relay_after_gap_start_ms": None,
                    "high_conf_last_relay_after_gap_start_ms": None,
                    "high_conf_max_relay_gap_after_gap_start_ms": None,
                    "high_conf_max_last_write_after_gap_start_ms": None,
                }
            )
            row["slot_pressure_hint"] = selected_stream_gap_slot_pressure_hint(row)
            rows.append(row)
            continue

        same_origin_resources = same_origin_protocol_resource_rows(
            matched_resource, resources
        )
        phase_rows = [
            phase_row
            for resource in same_origin_resources
            if (numeric((phase_row := resource_phase_overlap_row(resource, gap_start, gap_end)).get("active_overlap_ms")) or 0) > 0
        ]
        queued_1000 = sum(
            1
            for resource in same_origin_resources
            if resource_phase_ms(resource, "fetchToRequest") is not None
            and (numeric(resource_phase_ms(resource, "fetchToRequest")) or 0) >= 1000
            and (interval_overlap_ms(gap_start, gap_end, *resource_queued_interval(resource)) or 0)
            > 0
        )
        top_active = None
        if phase_rows:
            top_active = max(
                phase_rows,
                key=lambda row: (
                    numeric(row.get("top_overlap_ms")) or 0,
                    numeric(row.get("active_overlap_ms")) or 0,
                ),
            )
        active_resources = [
            row.get("resource")
            for row in phase_rows
            if isinstance(row.get("resource"), dict)
        ]
        gap_start_epoch = add_numeric(browser_time_origin_ms(run), gap_start)
        joined_rows = selected_gap_joined_active_resource_rows(
            profile,
            target,
            run_index,
            active_resources,
            join_index,
            relay_timings_by_profile.get(profile, []),
            gap_start_epoch,
        )
        joined_active_rows = [
            row for row in joined_rows if row.get("joined") is not None
        ]
        high_conf_joined_rows = [
            row
            for row in joined_active_rows
            if row.get("match_confidence") == "high"
        ]
        matched_phase = resource_phase_overlap_row(matched_resource, gap_start, gap_end)
        row = dict(overlap_row)
        row.update(
            {
                "matched_resource": matched_resource.get("name"),
                "protocol": protocol_label(matched_resource.get("nextHopProtocol")),
                "same_origin_active_at_gap_start": sum(
                    1
                    for resource in same_origin_resources
                    if resource_socket_active_at_ms(resource, gap_start)
                ),
                "max_same_origin_active_in_gap": max_same_origin_protocol_active_count_in_gap(
                    same_origin_resources, gap_start, gap_end
                ),
                "same_origin_active_resources_in_gap": len(phase_rows),
                "same_origin_queued_1000_resources_in_gap": queued_1000,
                "same_origin_request_wait_overlap_ms": sum(
                    numeric(row.get("request_wait_overlap_ms")) or 0
                    for row in phase_rows
                ),
                "same_origin_response_receive_overlap_ms": sum(
                    numeric(row.get("response_receive_overlap_ms")) or 0
                    for row in phase_rows
                ),
                "top_active_resource": ((top_active or {}).get("resource") or {}).get(
                    "name"
                ),
                "top_active_phase": (top_active or {}).get("top_phase"),
                "top_active_overlap_ms": (top_active or {}).get("top_overlap_ms"),
                "matched_fetch_to_request_overlap_ms": matched_phase.get(
                    "fetch_to_request_overlap_ms"
                ),
                "matched_active_overlap_ms": matched_phase.get("active_overlap_ms"),
                "matched_top_phase": matched_phase.get("top_phase"),
                "joined_active_resources": len(joined_active_rows),
                "joined_match_confidences": format_counts(
                    count_labels(
                        row.get("stream_set_match_confidence")
                        for row in joined_active_rows
                    )
                ),
                "joined_timing_confidences": format_counts(
                    count_labels(
                        row.get("match_confidence")
                        for row in joined_active_rows
                    )
                ),
                "exact_joined_active_resources": sum(
                    1
                    for row in joined_active_rows
                    if row.get("stream_set_match_confidence") == "exact"
                ),
                "ambiguous_joined_active_resources": sum(
                    1
                    for row in joined_active_rows
                    if row.get("stream_set_match_confidence") == "ambiguous"
                ),
                "joined_active_stream_ids": compact_list(
                    [
                        joined.get("stream_id")
                        for joined in joined_active_rows
                        if joined.get("stream_id") is not None
                    ],
                    max_items=4,
                ),
                "joined_active_circuits": compact_list(
                    [
                        joined.get("circ_id")
                        for joined in joined_active_rows
                        if joined.get("circ_id")
                    ],
                    max_items=3,
                ),
                "high_conf_joined_active_resources": len(high_conf_joined_rows),
                "high_conf_active_stream_ids": compact_list(
                    [
                        joined.get("stream_id")
                        for joined in high_conf_joined_rows
                        if joined.get("stream_id") is not None
                    ],
                    max_items=4,
                ),
                "high_conf_active_circuits": compact_list(
                    [
                        joined.get("circ_id")
                        for joined in high_conf_joined_rows
                        if joined.get("circ_id")
                    ],
                    max_items=3,
                ),
                "high_conf_relay_cells_after_gap_start": row_sum(
                    high_conf_joined_rows, "relay_cells_after_gap_start"
                ),
                "high_conf_relay_data_after_gap_start_bytes": row_sum(
                    high_conf_joined_rows, "relay_data_after_gap_start_bytes"
                ),
                "high_conf_first_relay_after_gap_start_ms": row_min(
                    high_conf_joined_rows, "first_relay_after_gap_start_ms"
                ),
                "high_conf_last_relay_after_gap_start_ms": row_max(
                    high_conf_joined_rows, "last_relay_after_gap_start_ms"
                ),
                "high_conf_max_relay_gap_after_gap_start_ms": row_max(
                    high_conf_joined_rows, "max_relay_gap_after_gap_start_ms"
                ),
                "high_conf_max_last_write_after_gap_start_ms": row_max(
                    high_conf_joined_rows, "last_write_after_gap_start_ms"
                ),
            }
        )
        row["slot_pressure_hint"] = selected_stream_gap_slot_pressure_hint(row)
        rows.append(row)

    return sorted(
        rows,
        key=lambda row: (
            numeric(row.get("actual_gap_ms")) or 0,
            numeric(row.get("max_same_origin_active_in_gap")) or 0,
            numeric(row.get("same_origin_active_resources_in_gap")) or 0,
        ),
        reverse=True,
    )


def selected_circuit_gap_predictability_hint(
    row: dict[str, object], *, gap_threshold_ms: float = SELECTOR_BAD_HEALTH_GAP_MS
) -> str:
    if not row.get("candidate_context"):
        return "choice context missing"
    if (numeric(row.get("selected_bad_health_rows")) or 0) > 0:
        return "selected already marked bad"
    selected_gap = numeric(row.get("selected_health_gap_ms"))
    if selected_gap is not None and selected_gap >= gap_threshold_ms:
        return "selected had prior bad gap"
    selected_score = numeric(row.get("selected_health_score_bps"))
    alt_score = numeric(row.get("best_alt_health_score_bps"))
    if (selected_score or 0) <= 0 and (alt_score or 0) > 0:
        return "cold selected, scored alt existed"
    if (numeric(row.get("better_health_alt_rows")) or 0) > 0:
        return "better-health alt existed"
    if (numeric(row.get("lower_assignment_alt_rows")) or 0) > 0:
        return "lower-assignment alt existed"
    if (numeric(row.get("selected_open_rows")) or 0) <= 1:
        return "only selected open; later gap not predictable"
    return "later gap not predictable from logged health"


def best_matching_selection_context_row(
    rows: list[dict[str, object]],
    profile: str,
    target: str,
    run_index: object,
    circuit: str,
) -> dict[str, object] | None:
    for row in rows:
        if (
            str(row.get("profile", "")) == profile
            and str(row.get("target", "")) == target
            and row.get("run_index") == run_index
            and torfast_circ_ids_match(circuit, row.get("circ_id"))
        ):
            return row
    return None


def selected_circuit_local_block_summary(row: dict[str, object]) -> str:
    risks = []
    scheduler_hint = str(row.get("scheduler_proof_hint", ""))
    if scheduler_hint in {
        "single stream picked on multi-stream circuit",
        "skewed scheduler picks",
        "repeated same-stream picks",
    }:
        risks.append("scheduler")
    if (numeric(row.get("congestion_scheduler_blocks")) or 0) > 0:
        risks.append("scheduler-blocked")
    if (numeric(row.get("congestion_can_send_false")) or 0) > 0:
        risks.append("can-send-false")
    if (numeric(row.get("congestion_channel_blocked")) or 0) > 0:
        risks.append("channel-blocked")
    if (numeric(row.get("terminal_pending_bytes")) or 0) > 0:
        risks.append("pending-bytes")
    sendmes = numeric(row.get("sendmes"))
    sendme_ok = numeric(row.get("sendme_ok"))
    if sendmes is not None and sendme_ok is not None and sendme_ok < sendmes:
        risks.append("sendme-gap")
    min_window = numeric(row.get("min_recv_window_after_take"))
    if min_window is not None and min_window <= 0 and (
        numeric(row.get("read_events")) or 0
    ) > 0:
        risks.append("recv-window")
    if risks:
        return compact_list(risks, max_items=4)
    if scheduler_hint == "no scheduler monopoly seen":
        return "no local block seen"
    return "local block not proved"


def selected_circuit_network_evidence_hint(row: dict[str, object]) -> str:
    local_summary = str(row.get("local_block_summary", ""))
    if local_summary not in {"no local block seen", "local block not proved"}:
        return "local block still possible"
    stream_close_causes = str(row.get("stream_close_causes", ""))
    local_close_sent_end = (
        (numeric(row.get("close_decision_events")) or 0) > 0
        and "StreamTargetClosed" in str(row.get("close_reasons", ""))
        and "Send" in str(row.get("close_should_send_end", ""))
    )
    if local_close_sent_end and (numeric(row.get("no_end_close_events")) or 0) > 0:
        if (numeric(row.get("relay_tail_with_tor_bytes")) or 0) > 0:
            return "local close after partial DATA; END selected"
        if (numeric(row.get("max_idle_after_last_data_ms")) or 0) >= 1000:
            return "local close sent END after DATA idle"
        return "local close sent END"
    if "stream_target_closed" in stream_close_causes:
        if (numeric(row.get("relay_tail_with_tor_bytes")) or 0) > 0:
            return "local stream target closed after partial DATA"
        if (numeric(row.get("max_idle_after_last_data_ms")) or 0) >= 1000:
            return "local stream target closed after DATA idle"
        return "local stream target closed"
    if (numeric(row.get("relay_tail_streams")) or 0) > 0 and (
        numeric(row.get("relay_tail_with_tor_bytes")) or 0
    ) > 0:
        if (numeric(row.get("no_end_close_events")) or 0) > 0:
            return "failed partial DATA then no-END close"
        return "failed run partial DATA then idle"
    if (numeric(row.get("no_end_close_events")) or 0) > 0 and (
        numeric(row.get("max_idle_after_last_data_ms")) or 0
    ) >= 1000:
        return "receiver closed without END after DATA idle"
    if (numeric(row.get("not_connected_streams")) or 0) > 0 and (
        numeric(row.get("max_idle_after_last_data_ms")) or 0
    ) >= 1000:
        return "connected stream later not_connected after idle"
    if str(row.get("choice_hint", "")) == "logged open alternative existed":
        return "circuit choice alternative logged"
    if (numeric(row.get("late_resources")) or 0) > 0 and local_summary == (
        "no local block seen"
    ):
        gap_scope = str(row.get("data_gap_scope_hint", ""))
        if gap_scope == "whole circuit quiet":
            return "whole-circuit DATA gap on selected circuit"
        if gap_scope == "stream-specific gap; circuit still active":
            return "stream-specific DATA gap on selected circuit"
        if gap_scope == "mixed circuit and stream gap":
            return "mixed DATA gap on selected circuit"
        return "late DATA on selected circuit"
    return "network-side evidence unclear"


def selected_circuit_data_gap_scope_hint(
    row: dict[str, object], *, gap_threshold_ms: float = 1000.0
) -> str:
    stream_gap = numeric(row.get("max_observed_stream_gap_ms"))
    if stream_gap is None:
        stream_gap = numeric(row.get("max_data_gap_ms"))
    circuit_gap = numeric(row.get("max_circuit_data_gap_ms"))
    if circuit_gap is None:
        return ""
    if circuit_gap < gap_threshold_ms and (stream_gap is None or stream_gap < gap_threshold_ms):
        return "no large DATA gap seen"
    if stream_gap is None or stream_gap < gap_threshold_ms:
        return "circuit DATA gap"
    if circuit_gap >= stream_gap * 0.8:
        return "whole circuit quiet"
    if circuit_gap <= stream_gap * 0.7:
        return "stream-specific gap; circuit still active"
    return "mixed circuit and stream gap"


def blocker_wait_remaining_at_request(
    resource: dict[str, object], request_start: object
) -> float | None:
    queue_start = numeric(request_start)
    response_start = numeric(resource.get("responseStart"))
    response_end = numeric(resource.get("responseEnd"))
    if queue_start is None or response_start is None or response_end is None:
        return None
    if queue_start >= response_end:
        return 0.0
    return max(0.0, response_start - queue_start)


def blocker_receive_remaining_at_request(
    resource: dict[str, object], request_start: object
) -> float | None:
    queue_start = numeric(request_start)
    response_start = numeric(resource.get("responseStart"))
    response_end = numeric(resource.get("responseEnd"))
    if queue_start is None or response_start is None or response_end is None:
        return None
    if queue_start >= response_end:
        return 0.0
    return max(0.0, response_end - max(queue_start, response_start))


def relay_receive_timings_by_profile(
    payload: dict[str, object]
) -> dict[str, list[dict[str, object]]]:
    timings_by_profile: dict[str, list[dict[str, object]]] = {}
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return timings_by_profile
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        timings_by_profile[str(profile_name)] = parse_torfast_relay_receive_timings(
            [str(line) for line in lines]
        )
    return timings_by_profile


def relay_receive_context_for_joined(
    joined: dict[str, object],
    relay_timings: list[dict[str, object]],
    queued_request_epoch: object,
) -> dict[str, object]:
    stream_id = joined.get("stream_id")
    circ_id = joined.get("circ_id")
    queued_epoch = numeric(queued_request_epoch)
    if stream_id is None or circ_id is None or queued_epoch is None:
        return {}
    conn_start = numeric(joined.get("conn_started_epoch_ms"))
    conn_end = add_numeric(conn_start, joined.get("total_elapsed_ms"))
    if conn_end is None:
        conn_end = add_numeric(conn_start, joined.get("relay_ms"))
    delivered = []
    for item in relay_timings:
        if item.get("event") != "delivered":
            continue
        if item.get("stream_id") != stream_id:
            continue
        if not torfast_circ_ids_match(circ_id, item.get("circ_id")):
            continue
        timestamp = numeric(item.get("timestamp_ms"))
        if timestamp is None or timestamp < queued_epoch:
            continue
        if conn_start is not None and timestamp < conn_start - 1000:
            continue
        if conn_end is not None and timestamp > conn_end + 1000:
            continue
        delivered.append(item)
    if not delivered:
        return {}
    delivered.sort(key=lambda item: numeric(item.get("timestamp_ms")) or 0)
    timestamps = [
        numeric(item.get("timestamp_ms"))
        for item in delivered
        if numeric(item.get("timestamp_ms")) is not None
    ]
    gaps = event_timestamp_gaps_ms(delivered)
    data_bytes = sum(int(numeric(item.get("data_len")) or 0) for item in delivered)
    queued_after = [
        numeric(item.get("queued_after_bytes"))
        for item in delivered
        if numeric(item.get("queued_after_bytes")) is not None
    ]
    first = min(timestamps) if timestamps else None
    last = max(timestamps) if timestamps else None
    return {
        "relay_cells_after_queued_request": len(delivered),
        "relay_data_after_queued_request_bytes": data_bytes,
        "first_relay_after_queued_request_ms": subtract_numeric(
            first, queued_epoch
        ),
        "last_relay_after_queued_request_ms": subtract_numeric(last, queued_epoch),
        "max_relay_gap_after_queued_request_ms": max(gaps) if gaps else None,
        "max_relay_queued_after_bytes": max(queued_after) if queued_after else None,
    }


def stream_receiver_timings_by_profile(
    payload: dict[str, object]
) -> dict[str, list[dict[str, object]]]:
    timings_by_profile: dict[str, list[dict[str, object]]] = {}
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return timings_by_profile
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        lines = proxy_log_lines(profile)
        if not isinstance(lines, list):
            continue
        timings_by_profile[str(profile_name)] = parse_torfast_stream_receiver_timings(
            [str(line) for line in lines]
        )
    return timings_by_profile


def stream_receiver_context_for_joined(
    joined: dict[str, object], receiver_timings: list[dict[str, object]]
) -> dict[str, object]:
    stream_id = joined.get("stream_id")
    if stream_id is None:
        return {}
    conn_start = numeric(joined.get("conn_started_epoch_ms"))
    conn_end = add_numeric(conn_start, joined.get("total_elapsed_ms"))
    if conn_end is None:
        conn_end = add_numeric(conn_start, joined.get("relay_ms"))
    read_rows = []
    for item in receiver_timings:
        if item.get("event") != "read" or item.get("stream_id") != stream_id:
            continue
        timestamp = numeric(item.get("timestamp_ms"))
        if timestamp is None:
            continue
        if conn_start is not None and timestamp < conn_start - 1000:
            continue
        if conn_end is not None and timestamp > conn_end + 1000:
            continue
        read_rows.append(item)
    if not read_rows:
        return {}
    timestamps = [
        numeric(item.get("timestamp_ms"))
        for item in read_rows
        if numeric(item.get("timestamp_ms")) is not None
    ]
    queued_after = [
        numeric(item.get("queued_after_bytes"))
        for item in read_rows
        if numeric(item.get("queued_after_bytes")) is not None
    ]
    recv_windows = [
        numeric(item.get("recv_window_after"))
        for item in read_rows
        if numeric(item.get("recv_window_after")) is not None
    ]
    return {
        "stream_receiver_reads": len(read_rows),
        "first_stream_receiver_read_epoch_ms": min(timestamps)
        if timestamps
        else None,
        "last_stream_receiver_read_epoch_ms": max(timestamps)
        if timestamps
        else None,
        "max_queued_after_bytes": max(queued_after) if queued_after else None,
        "min_recv_window_after": min(recv_windows) if recv_windows else None,
    }


def stream_receiver_terminal_context_for_joined(
    joined: dict[str, object],
    receiver_timings: list[dict[str, object]],
    queued_request_epoch: object,
) -> dict[str, object]:
    stream_id = joined.get("stream_id")
    circ_id = joined.get("circ_id")
    queued_epoch = numeric(queued_request_epoch)
    if stream_id is None or queued_epoch is None:
        return {}
    conn_start = numeric(joined.get("conn_started_epoch_ms"))
    conn_end = add_numeric(conn_start, joined.get("total_elapsed_ms"))
    if conn_end is None:
        conn_end = add_numeric(conn_start, joined.get("relay_ms"))
    terminals = []
    for item in receiver_timings:
        if item.get("event") != "terminal" or item.get("stream_id") != stream_id:
            continue
        if circ_id is not None and not torfast_circ_ids_match(
            circ_id, item.get("circ_id")
        ):
            continue
        timestamp = numeric(item.get("timestamp_ms"))
        if timestamp is None:
            continue
        if conn_start is not None and timestamp < conn_start - 1000:
            continue
        if conn_end is not None and timestamp > conn_end + 1000:
            continue
        terminals.append(item)
    if not terminals:
        return {}
    terminal = max(terminals, key=lambda item: numeric(item.get("timestamp_ms")) or 0)
    timestamp = numeric(terminal.get("timestamp_ms"))
    idle_after_last = numeric(terminal.get("idle_after_last_data_ms"))
    last_data_epoch = subtract_numeric(timestamp, idle_after_last)
    return {
        "event_epoch_ms": timestamp,
        "last_data_epoch_ms": last_data_epoch,
        "last_data_after_queued_request_ms": subtract_numeric(
            last_data_epoch, queued_epoch
        ),
        "transfer_ms": terminal.get("transfer_ms"),
        "idle_after_last_data_ms": terminal.get("idle_after_last_data_ms"),
        "max_data_gap_ms": terminal.get("max_data_gap_ms"),
        "relay_data_bytes": terminal.get("relay_data_bytes"),
        "pending_after_bytes": terminal.get("pending_after_bytes"),
        "user_read_bytes": terminal.get("user_read_bytes"),
        "data_cells": terminal.get("data_cells"),
        "read_events": terminal.get("read_events"),
        "sendmes": terminal.get("sendmes"),
        "sendme_ok": terminal.get("sendme_ok"),
        "min_recv_window_after_take": terminal.get("min_recv_window_after_take"),
        "max_queued_after_bytes": terminal.get("max_queued_after_bytes"),
    }


def browser_resource_join_index(
    payload: dict[str, object]
) -> dict[tuple[object, ...], dict[str, object]]:
    index: dict[tuple[object, ...], dict[str, object]] = {}
    for row in browser_resource_socks_relay_join_rows(payload):
        key = (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            row.get("run_index"),
            str(row.get("resource", "")),
            numeric(row.get("request_start_ms")),
            numeric(row.get("response_end_ms")),
        )
        index.setdefault(key, row)
    return index


def browser_resource_join_key(
    profile: str,
    target: str,
    run_index: object,
    resource: dict[str, object],
) -> tuple[object, ...]:
    return (
        profile,
        target,
        run_index,
        str(resource.get("name", "")),
        numeric(resource.get("requestStart")),
        numeric(resource.get("responseEnd")),
    )


def format_slot_blocker(row: dict[str, object]) -> str:
    text = compact_url(str(row.get("resource", "")), max_length=36)
    details = []
    if row.get("remaining_ms") is not None:
        details.append(f"{fmt(row.get('remaining_ms'))}ms left")
    if (numeric(row.get("wait_remaining_ms")) or 0) > 0:
        details.append(f"{fmt(row.get('wait_remaining_ms'))}ms wait")
    if (numeric(row.get("receive_remaining_ms")) or 0) > 0:
        details.append(f"{fmt(row.get('receive_remaining_ms'))}ms recv")
    if row.get("last_write_after_queued_request_ms") is not None:
        details.append(
            f"{fmt(row.get('last_write_after_queued_request_ms'))}ms write-after-queue"
        )
    if row.get("response_end_after_last_write_ms") is not None:
        details.append(
            f"{fmt(row.get('response_end_after_last_write_ms'))}ms resp-after-write"
        )
    if row.get("last_write_after_last_relay_receive_ms") is not None:
        details.append(
            f"{fmt(row.get('last_write_after_last_relay_receive_ms'))}ms write-after-relay"
        )
    if row.get("last_write_after_last_stream_receiver_read_ms") is not None:
        details.append(
            f"{fmt(row.get('last_write_after_last_stream_receiver_read_ms'))}ms write-after-read"
        )
    if row.get("timing_id") is not None:
        details.append(f"tid {fmt(row.get('timing_id'))}")
    if row.get("circ_id"):
        details.append(str(row.get("circ_id")))
    if row.get("match_confidence"):
        details.append(str(row.get("match_confidence")))
    if details:
        text = f"{text} ({', '.join(details)})"
    return format_table_text(text, max_len=140)


def count_labels(labels: object) -> dict[str, int]:
    counts: dict[str, int] = {}
    for label in labels:
        if not isinstance(label, str) or not label:
            label = "unknown"
        counts[label] = counts.get(label, 0) + 1
    return counts


def origin_label(value: object) -> str:
    if not isinstance(value, str) or not value:
        return "unknown"
    parsed = urlparse(value)
    if not parsed.scheme or not parsed.netloc:
        return "unknown"
    return f"{parsed.scheme}://{parsed.netloc}"


def protocol_label(value: object) -> str:
    if not isinstance(value, str) or not value.strip():
        return "unknown"
    return value.strip()


def timing_bucket(value: object, bucket_ms: float = RESOURCE_TIMING_BUCKET_MS) -> str:
    number = numeric(value)
    if number is None:
        return "unknown"
    bucket = int(number // bucket_ms)
    return str(bucket)


def top_share_pct(counts: dict[str, int]) -> float | None:
    total = sum(counts.values())
    if total <= 0:
        return None
    return max(counts.values()) * 100.0 / total


def compact_counts(counts: dict[str, int], limit: int = 3) -> str:
    if not counts:
        return ""
    items = sorted(counts.items(), key=lambda item: (-item[1], item[0]))
    shown = [f"{name}:{count}" for name, count in items[:limit]]
    if len(items) > limit:
        shown.append(f"other:{sum(count for _name, count in items[limit:])}")
    return ", ".join(shown)


def load_tail_rows(payload: dict[str, object]) -> list[dict[str, object]]:
    rows: list[dict[str, object]] = []
    for profile_name, profile, url, summary in iter_summaries(payload):
        benchmarks = profile.get("benchmarks", {})
        if not isinstance(benchmarks, dict):
            continue
        bench = benchmarks.get(url, {})
        if not isinstance(bench, dict):
            continue
        runs = [run for run in bench.get("runs", []) if isinstance(run, dict)]
        load_items: list[tuple[int, float, dict[str, object]]] = []
        for index, run in enumerate(runs, start=1):
            load_ms = numeric(run.get("load_ms"))
            if load_ms is not None:
                load_items.append((index, load_ms, run))
        if not load_items:
            continue
        max_run_index, max_load_ms, max_run = max(load_items, key=lambda item: item[1])
        median_load_ms = numeric(summary.get("median_load_ms"))
        ratio = (
            max_load_ms / median_load_ms
            if median_load_ms is not None and median_load_ms > 0
            else None
        )
        rows.append(
            {
                "profile": profile_name,
                "target": url,
                "runs": len(runs),
                "ok_runs": sum(1 for run in runs if run.get("ok")),
                "median_load_ms": median_load_ms,
                "max_load_ms": max_load_ms,
                "max_to_median_load": ratio,
                "max_load_run": max_run_index,
                "max_elapsed_ms": numeric(max_run.get("elapsed_ms")),
            }
        )
    return rows


def promotion_blocker_summary_rows(
    payload: dict[str, object],
    *,
    baseline_profile: str = "local_c_tor_browser",
) -> list[dict[str, object]]:
    candidates = promotion_candidate_profile_names(payload, baseline_profile)
    if not candidates:
        return []
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        profiles = {}
    baseline_failure_signals = profile_browser_failure_signals(
        payload, baseline_profile
    )
    baseline_boot_seconds = promotion_profile_boot_seconds(payload, baseline_profile)
    queue_rows_by_profile: dict[str, list[dict[str, object]]] = {}
    for row in browser_run_late_phase_queue_context_rows(payload):
        profile = str(row.get("profile", ""))
        if profile in candidates and (numeric(row.get("queued_1000ms")) or 0) > 0:
            queue_rows_by_profile.setdefault(profile, []).append(row)

    data_gap_rows_by_profile: dict[str, list[dict[str, object]]] = {}
    for row in resource_queue_late_write_summary_rows(payload):
        profile = str(row.get("profile", ""))
        if profile in candidates:
            data_gap_rows_by_profile.setdefault(profile, []).append(row)

    partial_idle_rows_by_profile: dict[str, list[dict[str, object]]] = {}
    for row in partial_idle_active_resource_risk_rows(payload):
        profile = str(row.get("profile", ""))
        if profile in candidates:
            partial_idle_rows_by_profile.setdefault(profile, []).append(row)

    partial_idle_no_client_rows_by_profile: dict[str, list[dict[str, object]]] = {}
    for row in partial_idle_no_client_abandon_risk_rows(payload):
        profile = str(row.get("profile", ""))
        if profile in candidates:
            partial_idle_no_client_rows_by_profile.setdefault(profile, []).append(row)

    no_byte_rows_by_profile: dict[str, list[dict[str, object]]] = {}
    for row in no_tor_byte_active_resource_risk_rows(payload):
        profile = str(row.get("profile", ""))
        if profile in candidates:
            no_byte_rows_by_profile.setdefault(profile, []).append(row)

    no_byte_no_client_rows_by_profile: dict[str, list[dict[str, object]]] = {}
    for row in no_tor_byte_no_client_abandon_risk_rows(payload):
        profile = str(row.get("profile", ""))
        if profile in candidates:
            no_byte_no_client_rows_by_profile.setdefault(profile, []).append(row)

    rows = []
    for profile in candidates:
        paired_rows = (
            paired_run_delta_rows(
                payload,
                candidate_profile=profile,
                baseline_profile=baseline_profile,
            )
            if baseline_profile
            else []
        )
        slow_target_rows = [
            row
            for row in paired_rows
            if (numeric(row.get("median_load_delta_ms")) or 0) > 0
        ]
        worst_delta = row_max(paired_rows, "median_load_delta_ms")
        profile_data = profiles.get(profile, {})
        boot_seconds = promotion_profile_boot_seconds(payload, profile)
        boot_delta_seconds = subtract_numeric(boot_seconds, baseline_boot_seconds)
        boot_delta_ms = (
            boot_delta_seconds * 1000.0 if boot_delta_seconds is not None else None
        )
        boot_regression_ms = (
            boot_delta_ms
            if boot_delta_ms is not None and boot_delta_ms > 0
            else None
        )
        directory_failure_signals = 0
        if isinstance(profile_data, dict):
            boot = profile_data.get("boot", {})
            if isinstance(boot, dict):
                directory_failure_signals += boot_failure_signal_count(boot)
            warmup_boot = profile_data.get("warmup_boot")
            if isinstance(warmup_boot, dict):
                directory_failure_signals += boot_failure_signal_count(warmup_boot)

        slow_streams = promotion_slow_stream_counts(payload, profile)
        queue_rows = queue_rows_by_profile.get(profile, [])
        queue_regression_rows = promotion_resource_queue_regression_rows(
            payload,
            candidate_profile=profile,
            baseline_profile=baseline_profile,
        )
        data_gap_rows = data_gap_rows_by_profile.get(profile, [])
        max_data_gap = row_max(data_gap_rows, "max_terminal_data_gap_ms")
        partial_idle_rows = partial_idle_rows_by_profile.get(profile, [])
        partial_idle_active_closes = len(partial_idle_rows)
        max_partial_idle_active_resources = row_max(
            partial_idle_rows, "active_resources_at_timeout"
        )
        partial_idle_no_client_abandon_closes = len(
            partial_idle_no_client_rows_by_profile.get(profile, [])
        )
        no_byte_rows = no_byte_rows_by_profile.get(profile, [])
        no_tor_byte_active_closes = len(no_byte_rows)
        max_no_tor_byte_active_resources = row_max(
            no_byte_rows, "active_resources_at_timeout"
        )
        no_tor_byte_no_client_abandon_closes = len(
            no_byte_no_client_rows_by_profile.get(profile, [])
        )
        blockers = promotion_blocker_labels(
            baseline_failure_signals=baseline_failure_signals,
            boot_regression_ms=boot_regression_ms,
            slow_targets=len(slow_target_rows),
            directory_failure_signals=directory_failure_signals,
            queue_regression_targets=len(queue_regression_rows),
            slow_unresolved_streams=slow_streams["slow_unresolved_streams"],
            slow_unresolved_onion_streams=(
                slow_streams["slow_unresolved_onion_streams"]
            ),
            slow_unresolved_hostname_streams=(
                slow_streams["slow_unresolved_hostname_streams"]
            ),
            max_data_gap_ms=max_data_gap,
            partial_idle_active_closes=partial_idle_active_closes,
            partial_idle_no_client_abandon_closes=(
                partial_idle_no_client_abandon_closes
            ),
            no_tor_byte_active_closes=no_tor_byte_active_closes,
            no_tor_byte_no_client_abandon_closes=(
                no_tor_byte_no_client_abandon_closes
            ),
        )
        rows.append(
            {
                "profile": profile,
                "blockers": ", ".join(blockers) if blockers else "none seen",
                "slow_targets": len(slow_target_rows),
                "worst_load_delta_ms": worst_delta,
                "boot_seconds": boot_seconds,
                "boot_delta_ms": boot_delta_ms,
                "baseline_failure_signals": baseline_failure_signals,
                "directory_failure_signals": directory_failure_signals,
                "queued_runs": len(queue_rows),
                "queue_regression_targets": len(queue_regression_rows),
                "max_fetch_to_request_ms": row_max(
                    queue_rows, "max_fetch_to_request_ms"
                ),
                "max_queue_delta_ms": row_max(
                    queue_regression_rows, "max_fetch_to_request_delta_ms"
                ),
                "slow_onion_streams": slow_streams["slow_onion_streams"],
                "slow_hostname_streams": slow_streams["slow_hostname_streams"],
                "slow_same_close_not_connected_streams": (
                    slow_streams["slow_same_close_not_connected_streams"]
                ),
                "slow_client_reset_close_streams": (
                    slow_streams["slow_client_reset_close_streams"]
                ),
                "slow_remote_end_close_streams": (
                    slow_streams["slow_remote_end_close_streams"]
                ),
                "slow_unresolved_streams": slow_streams["slow_unresolved_streams"],
                "slow_unresolved_onion_streams": (
                    slow_streams["slow_unresolved_onion_streams"]
                ),
                "slow_unresolved_hostname_streams": (
                    slow_streams["slow_unresolved_hostname_streams"]
                ),
                "max_slow_last_tor_byte_to_client_eof_ms": (
                    slow_streams["max_slow_last_tor_byte_to_client_eof_ms"]
                ),
                "max_relay_ms": slow_streams["max_relay_ms"],
                "max_data_gap_ms": max_data_gap,
                "partial_idle_active_closes": partial_idle_active_closes,
                "partial_idle_no_client_abandon_closes": (
                    partial_idle_no_client_abandon_closes
                ),
                "max_partial_idle_active_resources": (
                    max_partial_idle_active_resources
                ),
                "no_tor_byte_active_closes": no_tor_byte_active_closes,
                "no_tor_byte_no_client_abandon_closes": (
                    no_tor_byte_no_client_abandon_closes
                ),
                "max_no_tor_byte_active_resources": max_no_tor_byte_active_resources,
                "next_proof": promotion_next_proof(
                    baseline_failure_signals=baseline_failure_signals,
                    boot_regression_ms=boot_regression_ms,
                    directory_failure_signals=directory_failure_signals,
                    slow_targets=len(slow_target_rows),
                    queue_regression_targets=len(queue_regression_rows),
                    slow_unresolved_streams=slow_streams[
                        "slow_unresolved_streams"
                    ],
                    max_data_gap_ms=max_data_gap,
                    partial_idle_active_closes=partial_idle_active_closes,
                    partial_idle_no_client_abandon_closes=(
                        partial_idle_no_client_abandon_closes
                    ),
                    no_tor_byte_active_closes=no_tor_byte_active_closes,
                    no_tor_byte_no_client_abandon_closes=(
                        no_tor_byte_no_client_abandon_closes
                    ),
                ),
            }
        )
    return sorted(
        rows,
        key=lambda row: (
            -len(str(row.get("blockers", "")).split(",")),
            -(numeric(row.get("worst_load_delta_ms")) or 0),
            str(row.get("profile", "")),
        ),
    )


def promotion_slow_target_proof_rows(
    payload: dict[str, object],
    *,
    baseline_profile: str = "local_c_tor_browser",
) -> list[dict[str, object]]:
    candidates = promotion_candidate_profile_names(payload, baseline_profile)
    if not candidates:
        return []

    navigation_by_run = {
        promotion_risk_socks_context_key(row, "profile", "run_index"): row
        for row in browser_navigation_socks_join_rows(payload)
        if promotion_risk_socks_context_key(row, "profile", "run_index") is not None
    }
    receiver_by_run: dict[tuple[str, str, int], list[dict[str, object]]] = {}
    for row in torfast_stream_receiver_terminal_top_rows(payload):
        key = promotion_risk_socks_context_key(row, "profile", "run_index")
        if key is None:
            continue
        receiver_by_run.setdefault(key, []).append(row)

    lifecycle_by_run: dict[tuple[str, str, int], list[dict[str, object]]] = {}
    for row in notable_torfast_socks_stream_lifecycle_rows(payload):
        key = promotion_risk_socks_context_key(row, "profile", "run_index")
        if key is None:
            continue
        lifecycle_by_run.setdefault(key, []).append(row)

    rows: list[dict[str, object]] = []
    for profile in candidates:
        paired_rows = paired_run_delta_rows(
            payload,
            candidate_profile=profile,
            baseline_profile=baseline_profile,
        )
        for paired_row in paired_rows:
            median_load_delta = numeric(paired_row.get("median_load_delta_ms"))
            if median_load_delta is None or median_load_delta <= 0:
                continue
            target = str(paired_row.get("target", ""))
            candidate_runs = runs_by_index(payload, profile, target)
            baseline_runs = runs_by_index(payload, baseline_profile, target)
            candidate_items = [
                (index, numeric(run.get("load_ms")), run)
                for index, run in candidate_runs.items()
                if run.get("ok") and numeric(run.get("load_ms")) is not None
            ]
            baseline_loads = [
                numeric(run.get("load_ms"))
                for run in baseline_runs.values()
                if run.get("ok") and numeric(run.get("load_ms")) is not None
            ]
            if not candidate_items:
                continue
            candidate_index, candidate_load, candidate_run = max(
                candidate_items, key=lambda item: item[1] or 0
            )
            run_key = (profile, target, int(candidate_index))
            nav_join = navigation_by_run.get(run_key, {})
            receivers = receiver_by_run.get(run_key, [])
            lifecycle_rows = lifecycle_by_run.get(run_key, [])
            worst_receiver = promotion_slow_target_worst_receiver(receivers)
            worst_lifecycle = promotion_slow_target_lifecycle(
                lifecycle_rows,
                worst_receiver.get("timing_id") if worst_receiver else None,
            )
            slowest_resource = run_slowest_resource(candidate_run)
            slowest_resource_ms = (
                numeric(slowest_resource.get("duration"))
                if isinstance(slowest_resource, dict)
                else None
            )
            rows.append(
                {
                    "profile": profile,
                    "target": target,
                    "candidate_run": candidate_index,
                    "candidate_load_ms": candidate_load,
                    "baseline_max_load_ms": max(baseline_loads)
                    if baseline_loads
                    else None,
                    "median_load_delta_ms": median_load_delta,
                    "nav_response_ms": nav_value(candidate_run, "responseStart"),
                    "nav_wait_ms": nav_phase(
                        candidate_run, "requestStart", "responseStart"
                    ),
                    "nav_receive_ms": nav_phase(
                        candidate_run, "responseStart", "responseEnd"
                    ),
                    "response_to_dom_ms": nav_phase(
                        candidate_run, "responseStart", "domContentLoadedEventEnd"
                    ),
                    "dom_to_load_ms": nav_phase(
                        candidate_run, "domContentLoadedEventEnd", "loadEventEnd"
                    ),
                    "resource_count": len(browser_resource_rows_for_run(candidate_run)),
                    "slowest_resource_ms": slowest_resource_ms,
                    "nav_timing_id": nav_join.get("timing_id"),
                    "nav_first_tor_byte_to_response_ms": nav_join.get(
                        "first_tor_byte_to_response_ms"
                    ),
                    "nav_relay_ms": nav_join.get("relay_ms"),
                    "worst_timing_id": (
                        worst_receiver.get("timing_id")
                        if worst_receiver
                        else worst_lifecycle.get("timing_id")
                    ),
                    "worst_lifecycle_state": worst_lifecycle.get(
                        "lifecycle_state", ""
                    ),
                    "worst_relay_ms": (
                        worst_receiver.get("socks_relay_ms")
                        if worst_receiver
                        else worst_lifecycle.get("relay_ms")
                    ),
                    "worst_transfer_ms": (
                        worst_receiver.get("transfer_ms")
                        if worst_receiver
                        else None
                    ),
                    "worst_data_gap_ms": (
                        worst_receiver.get("max_data_gap_ms")
                        if worst_receiver
                        else None
                    ),
                    "worst_idle_after_last_data_ms": (
                        worst_receiver.get("idle_after_last_data_ms")
                        if worst_receiver
                        else worst_lifecycle.get("idle_after_last_tor_byte_ms")
                    ),
                    "worst_relay_kib": (
                        worst_receiver.get("relay_kib")
                        if worst_receiver
                        else None
                    ),
                }
            )
    return sorted(
        rows,
        key=lambda row: (
            -(numeric(row.get("median_load_delta_ms")) or 0),
            -(numeric(row.get("candidate_load_ms")) or 0),
            str(row.get("profile", "")),
            str(row.get("target", "")),
        ),
    )


def promotion_slow_target_worst_receiver(
    rows: list[dict[str, object]],
) -> dict[str, object]:
    if not rows:
        return {}
    return max(rows, key=promotion_risk_receiver_sort_key)


def promotion_slow_target_lifecycle(
    rows: list[dict[str, object]], timing_id: object
) -> dict[str, object]:
    if not rows:
        return {}
    timing = numeric(timing_id)
    if timing is not None:
        for row in rows:
            if numeric(row.get("timing_id")) == timing:
                return row
    return max(rows, key=slow_sock_sort_value)


def promotion_candidate_profile_names(
    payload: dict[str, object], baseline_profile: str
) -> list[str]:
    names = arti_profile_names(payload, baseline_profile)
    if names:
        return names
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return []
    skipped = {baseline_profile, "local_c_tor_browser", "bundled_c_tor_browser"}
    return sorted(
        name
        for name, profile in profiles.items()
        if isinstance(profile, dict)
        and not profile.get("skipped")
        and name not in skipped
        and name.startswith("arti")
    )


def promotion_slow_stream_counts(
    payload: dict[str, object], profile_name: str
) -> dict[str, object]:
    slow_onion_streams = 0
    slow_hostname_streams = 0
    slow_same_close_not_connected_streams = 0
    slow_client_reset_close_streams = 0
    slow_remote_end_close_streams = 0
    slow_unresolved_streams = 0
    slow_unresolved_onion_streams = 0
    slow_unresolved_hostname_streams = 0
    slow_rows: list[dict[str, object]] = []
    slow_same_close_rows: list[dict[str, object]] = []
    slow_unresolved_rows: list[dict[str, object]] = []
    for current_profile, _profile, _target, _summary, run in iter_runs(payload):
        if current_profile != profile_name:
            continue
        lines = dedupe_lines(run_torfast_lines(run))
        timings = parse_torfast_socks_timings(lines)
        lifecycle_rows = parse_torfast_stream_lifecycle_timings(lines)
        for item in torfast_slow_socks_rows(timings):
            row = dict(item)
            terminal = latest_stream_receiver_terminal(row, lines)
            copy_if_present(row, terminal, "stream_close_cause")
            slow_rows.append(row)
            same_close = socks_row_is_same_close_not_connected(row)
            client_reset_close = socks_row_is_client_reset_end_close(
                row, lifecycle_rows
            )
            remote_end_close = socks_row_is_remote_end_client_close(
                row, lifecycle_rows
            )
            if same_close:
                slow_same_close_not_connected_streams += 1
                slow_same_close_rows.append(row)
            if client_reset_close:
                slow_client_reset_close_streams += 1
            if remote_end_close:
                slow_remote_end_close_streams += 1
            resolved_close = same_close or client_reset_close or remote_end_close
            if not resolved_close:
                slow_unresolved_streams += 1
                slow_unresolved_rows.append(row)
            target_kind = row.get("target_kind")
            if target_kind == "onion":
                slow_onion_streams += 1
                if not resolved_close:
                    slow_unresolved_onion_streams += 1
            elif target_kind == "hostname":
                slow_hostname_streams += 1
                if not resolved_close:
                    slow_unresolved_hostname_streams += 1
    return {
        "slow_onion_streams": slow_onion_streams,
        "slow_hostname_streams": slow_hostname_streams,
        "slow_same_close_not_connected_streams": slow_same_close_not_connected_streams,
        "slow_client_reset_close_streams": slow_client_reset_close_streams,
        "slow_remote_end_close_streams": slow_remote_end_close_streams,
        "slow_unresolved_streams": slow_unresolved_streams,
        "slow_unresolved_onion_streams": slow_unresolved_onion_streams,
        "slow_unresolved_hostname_streams": slow_unresolved_hostname_streams,
        "max_slow_last_tor_byte_to_client_eof_ms": row_max(
            slow_same_close_rows, "last_tor_byte_to_client_eof_ms"
        ),
        "max_unresolved_relay_ms": row_max(slow_unresolved_rows, "relay_ms"),
        "max_relay_ms": row_max(slow_rows, "relay_ms"),
    }


def promotion_unresolved_slow_stream_rows(
    payload: dict[str, object],
    *,
    baseline_profile: str = "local_c_tor_browser",
) -> list[dict[str, object]]:
    candidates = set(promotion_candidate_profile_names(payload, baseline_profile))
    rows: list[dict[str, object]] = []
    for profile_name, _profile, target, _summary, run in iter_runs(payload):
        if profile_name not in candidates:
            continue
        lines = dedupe_lines(run_torfast_lines(run))
        timings = parse_torfast_socks_timings(lines)
        lifecycle_rows = parse_torfast_stream_lifecycle_timings(lines)
        for item in torfast_slow_socks_rows(timings):
            row = dict(item)
            terminal = latest_stream_receiver_terminal(row, lines)
            copy_if_present(row, terminal, "stream_close_cause")
            if socks_row_is_resolved_client_close(row, lifecycle_rows):
                continue
            rows.append(
                {
                    "profile": profile_name,
                    "target": target,
                    "run_index": run.get("run_index"),
                    "timing_id": row.get("timing_id"),
                    "reason": torfast_slow_reason(row),
                    "target_kind": row.get("target_kind"),
                    "connect_ms": row.get("connect_ms"),
                    "relay_ms": row.get("relay_ms"),
                    "last_tor_to_client_ms": row.get("last_tor_to_client_ms"),
                    "client_to_tor_eof_ms": row.get("client_to_tor_eof_ms"),
                    "tor_to_client_bytes": row.get("tor_to_client_bytes"),
                    "copy_error_kind": row.get("copy_error_kind", ""),
                    "circ_id": row.get("circ_id", ""),
                    "stream_id": row.get("stream_id"),
                    "_sort_ms": slow_sock_sort_value(row),
                }
            )
    return sorted(
        rows,
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0,
            -(numeric(row.get("_sort_ms")) or 0),
        ),
    )


def promotion_resource_queue_regression_rows(
    payload: dict[str, object],
    *,
    candidate_profile: str,
    baseline_profile: str,
) -> list[dict[str, object]]:
    rows = []
    for row in resource_queue_delta_rows(
        payload,
        candidate_profile=candidate_profile,
        baseline_profile=baseline_profile,
    ):
        if row.get("group") != "all":
            continue
        queued_1000_delta = numeric(row.get("fetch_to_request_1000_delta")) or 0
        median_delta = numeric(row.get("median_fetch_to_request_delta_ms")) or 0
        max_delta = numeric(row.get("max_fetch_to_request_delta_ms")) or 0
        if (
            queued_1000_delta > 0
            or median_delta > PROMOTION_QUEUE_MEDIAN_REGRESSION_MS
            or max_delta > PROMOTION_QUEUE_MAX_REGRESSION_MS
        ):
            rows.append(row)
    return rows


def promotion_profile_boot_seconds(
    payload: dict[str, object], profile_name: str
) -> float | None:
    return profile_boot_seconds(payload, profile_name)


def profile_browser_failure_signals(
    payload: dict[str, object], profile_name: str
) -> int:
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return 0
    profile = profiles.get(profile_name)
    if not isinstance(profile, dict) or profile.get("skipped"):
        return 0
    failures = 0
    benchmarks = profile.get("benchmarks", {})
    if not isinstance(benchmarks, dict):
        return 0
    for bench in benchmarks.values():
        if not isinstance(bench, dict):
            continue
        summary = bench.get("summary", {})
        if isinstance(summary, dict) and summary.get("ok") is not True:
            failures += 1
        runs = bench.get("runs", [])
        if not isinstance(runs, list):
            continue
        failures += sum(
            1 for run in runs if isinstance(run, dict) and run.get("ok") is not True
        )
    return failures


def promotion_blocker_labels(
    *,
    baseline_failure_signals: int,
    boot_regression_ms: object,
    slow_targets: int,
    directory_failure_signals: int,
    queue_regression_targets: int,
    slow_unresolved_streams: int,
    slow_unresolved_onion_streams: int,
    slow_unresolved_hostname_streams: int,
    max_data_gap_ms: object,
    partial_idle_active_closes: int,
    partial_idle_no_client_abandon_closes: int,
    no_tor_byte_active_closes: int,
    no_tor_byte_no_client_abandon_closes: int,
) -> list[str]:
    labels = []
    if baseline_failure_signals:
        labels.append("baseline failed")
    if (numeric(boot_regression_ms) or 0) > 0:
        labels.append("boot slower")
    if directory_failure_signals:
        labels.append("boot directory")
    if slow_targets:
        labels.append("slower than C Tor")
    if partial_idle_no_client_abandon_closes:
        labels.append("partial idle no client abandon")
    if partial_idle_active_closes:
        labels.append("partial idle active resources")
    if no_tor_byte_no_client_abandon_closes:
        labels.append("no-byte no client abandon")
    if no_tor_byte_active_closes:
        labels.append("no-byte active resources")
    if queue_regression_targets:
        labels.append("resource queue")
    if slow_unresolved_onion_streams or (numeric(max_data_gap_ms) or 0) >= 5000:
        labels.append("slow onion/data gap")
    if slow_unresolved_hostname_streams:
        labels.append("slow hostname stream")
    return labels


def promotion_next_proof(
    *,
    baseline_failure_signals: int,
    boot_regression_ms: object,
    directory_failure_signals: int,
    slow_targets: int,
    queue_regression_targets: int,
    slow_unresolved_streams: int,
    max_data_gap_ms: object,
    partial_idle_active_closes: int,
    partial_idle_no_client_abandon_closes: int,
    no_tor_byte_active_closes: int,
    no_tor_byte_no_client_abandon_closes: int,
) -> str:
    if baseline_failure_signals:
        return "clean baseline proof"
    if partial_idle_no_client_abandon_closes or no_tor_byte_no_client_abandon_closes:
        return "client-abandon proof"
    if partial_idle_active_closes or no_tor_byte_active_closes:
        return "client-abandon proof"
    if slow_unresolved_streams or (numeric(max_data_gap_ms) or 0) >= 5000:
        return "stream gap proof"
    if slow_targets:
        return "slow target proof"
    if queue_regression_targets:
        return "resource queue proof"
    if (numeric(boot_regression_ms) or 0) > 0:
        return "boot proof"
    if directory_failure_signals:
        return "directory boot proof"
    return "broader A/B"


def boot_failure_signal_stats(boot: dict[str, object]) -> dict[str, object]:
    lines = boot.get("signal_lines")
    if not isinstance(lines, list):
        lines = boot.get("lines", [])
    if not isinstance(lines, list):
        lines = []
    text_lines = [str(line) for line in lines]
    directory_failures = 0
    directory_timeouts = 0
    notdirectory = 0
    partial_response = 0
    terminal_summaries = 0
    warnings = 0
    last_signal = ""
    for line in text_lines:
        lower = line.lower()
        failure_signal = False
        if "directory failure" in lower:
            directory_failures += 1
            failure_signal = True
        if "directory timed out" in lower:
            directory_timeouts += 1
            failure_signal = True
        if "notdirectory" in lower:
            notdirectory += 1
            failure_signal = True
        if "partial response" in lower:
            partial_response += 1
            failure_signal = True
        if "terminal summary" in lower:
            terminal_summaries += 1
        if "warn" in lower:
            warnings += 1
        if failure_signal:
            last_signal = line
    has_boot_failure_signal = (
        boot.get("ok") is not True
        or directory_failures
        or directory_timeouts
        or notdirectory
        or partial_response
    )
    return {
        "boot_ok": boot.get("ok") is True,
        "boot_lines": len(text_lines),
        "directory_failures": directory_failures,
        "directory_timeouts": directory_timeouts,
        "notdirectory": notdirectory,
        "partial_response": partial_response,
        "terminal_summaries": terminal_summaries,
        "warnings": warnings,
        "last_boot_signal": last_signal or (text_lines[-1] if text_lines else ""),
        "has_boot_failure_signal": has_boot_failure_signal,
    }


def boot_failure_signal_count(boot: dict[str, object]) -> int:
    stats = boot_failure_signal_stats(boot)
    count = sum(
        int(numeric(stats.get(field)) or 0)
        for field in (
            "directory_failures",
            "directory_timeouts",
            "notdirectory",
            "partial_response",
        )
    )
    if boot.get("ok") is not True:
        count += 1
    return count


def boot_directory_failure_rows(payload: dict[str, object]) -> list[dict[str, object]]:
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return []
    rows: list[dict[str, object]] = []
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        boot = profile.get("boot", {})
        if not isinstance(boot, dict):
            continue
        stats = boot_failure_signal_stats(boot)
        if not stats["has_boot_failure_signal"]:
            continue
        rows.append(
            {
                "profile": profile_name,
                "boot_seconds": boot_seconds_for_profile(profile),
                "boot_ok": stats["boot_ok"],
                "boot_lines": stats["boot_lines"],
                "directory_failures": stats["directory_failures"],
                "directory_timeouts": stats["directory_timeouts"],
                "notdirectory": stats["notdirectory"],
                "partial_response": stats["partial_response"],
                "terminal_summaries": stats["terminal_summaries"],
                "warnings": stats["warnings"],
                "last_boot_signal": stats["last_boot_signal"],
            }
        )
    return rows


def boot_directory_timeline_rows(payload: dict[str, object]) -> list[dict[str, object]]:
    profiles = payload.get("profiles", {})
    if not isinstance(profiles, dict):
        return []
    rows: list[dict[str, object]] = []
    for profile_name, profile in sorted(profiles.items()):
        if not isinstance(profile, dict) or profile.get("skipped"):
            continue
        boot = profile.get("boot", {})
        if not isinstance(boot, dict):
            continue
        timeline = boot_timeline(boot)
        if not timeline:
            continue
        row = {
            "profile": profile_name,
            "boot_seconds": boot_seconds_for_profile(profile),
            **timeline,
        }
        relay_bytes = timeline.get("terminal_summary_total_relay_bytes")
        if isinstance(relay_bytes, int):
            row["terminal_summary_relay_mib"] = round(relay_bytes / 1_048_576, 3)
        rows.append(row)
    return rows


def navigation_phase_summary(
    profile: dict[str, object], target: str, summary: dict[str, object]
) -> dict[str, object]:
    if summary.get("median_nav_response_to_dom_ms") is not None:
        return {
            "median_nav_response_start_ms": summary.get("median_nav_response_start_ms"),
            "median_nav_response_to_dom_ms": summary.get("median_nav_response_to_dom_ms"),
            "median_nav_dom_to_load_ms": summary.get("median_nav_dom_to_load_ms"),
        }

    benchmarks = profile.get("benchmarks", {})
    if not isinstance(benchmarks, dict):
        return {}
    bench = benchmarks.get(target, {})
    if not isinstance(bench, dict):
        return {}
    runs = bench.get("runs", [])
    if not isinstance(runs, list):
        return {}

    response_values = []
    response_to_dom_values = []
    dom_to_load_values = []
    for run in runs:
        if not isinstance(run, dict):
            continue
        timing = run.get("performance_timing", {})
        if not isinstance(timing, dict):
            continue
        nav = timing.get("navigation")
        if not isinstance(nav, dict):
            continue
        response = nav.get("responseStart")
        dom = nav.get("domContentLoadedEventEnd")
        load = nav.get("loadEventEnd")
        if isinstance(response, (int, float)):
            response_values.append(response)
        if isinstance(response, (int, float)) and isinstance(dom, (int, float)):
            response_to_dom_values.append(dom - response)
        if isinstance(dom, (int, float)) and isinstance(load, (int, float)):
            dom_to_load_values.append(load - dom)

    return {
        "median_nav_response_start_ms": median(response_values)
        if response_values
        else None,
        "median_nav_response_to_dom_ms": median(response_to_dom_values)
        if response_to_dom_values
        else None,
        "median_nav_dom_to_load_ms": median(dom_to_load_values)
        if dom_to_load_values
        else None,
    }


def resource_family(resource_name: str, resource_type: str) -> str:
    parsed = urlsplit(resource_name)
    path = parsed.path.lower()
    if "/static/fonts/fontawesome/png/" in path:
        return "fontawesome png"
    if "/static/fonts/fontawesome/webfonts/" in path:
        return "fontawesome webfont"
    if "/static/fonts/fontawesome/css/" in path:
        return "fontawesome css"
    if "/static/fonts/sourcesanspro/" in path:
        return "source sans font"
    if "/static/fonts/sourcecodepro/" in path:
        return "source code font"
    if "/static/images/download/png/" in path:
        return "download png"
    if "/static/images/download/svg/" in path:
        return "download svg"
    if "/static/images/tor-browser-mobile-window/png/" in path:
        return "product window png"
    if "/static/images/tb85/" in path:
        return "tb85 image"
    if "/static/images/favicon/" in path:
        return "favicon"
    if "/static/images/" in path:
        return "site image"
    if "/static/css/" in path:
        return "site css"
    if "/static/js/" in path:
        return "site js"
    suffix = Path(path).suffix.lower()
    if suffix == ".css":
        return "css"
    if suffix == ".js":
        return "js"
    if suffix in {".png", ".jpg", ".jpeg", ".gif", ".webp", ".svg"}:
        return "image"
    return resource_type or "other"


def compact_resource(value: str, max_length: int = 42) -> str:
    if len(value) <= max_length:
        return value
    parsed = urlsplit(value)
    if parsed.scheme and parsed.netloc:
        parts = [part for part in parsed.path.split("/") if part]
        query = f"?{parsed.query}" if parsed.query else ""
        candidates = []
        if parts:
            for keep in (3, 2, 1):
                tail = "/".join(parts[-keep:])
                candidates.append(tail + query)
        candidates.append(parsed.netloc + "/" + (parts[-1] if parts else "") + query)
        for candidate in candidates:
            if len(candidate) <= max_length:
                return candidate
        if candidates:
            candidate = candidates[0]
            return "…" + candidate[-(max_length - 1) :]
    return "…" + value[-(max_length - 1) :]


def browser_resource_metric_row(
    resource: dict[str, object],
) -> dict[str, object] | None:
    duration_ms = numeric(resource.get("duration"))
    if duration_ms is None:
        return None
    resource_name = str(resource.get("name") or "")
    resource_type = str(resource.get("initiatorType") or "unknown")
    return {
        "resource": resource_name,
        "family": resource_family(resource_name, resource_type),
        "request_start_ms": numeric(resource.get("requestStart")),
        "duration_ms": duration_ms,
        "transfer_size_bytes": numeric(resource.get("transferSize")),
        "encoded_body_size_bytes": numeric(resource.get("encodedBodySize")),
    }


def resource_variant_swap_rows(payload: dict[str, object]) -> list[dict[str, object]]:
    grouped: dict[tuple[str, str, str, str], list[dict[str, object]]] = defaultdict(list)
    for profile_name, _profile, target, _summary, run in iter_runs(payload):
        if not run.get("ok"):
            continue
        metric_by_resource: dict[str, dict[str, object]] = {}
        discovery_by_variant: dict[str, list[dict[str, object]]] = defaultdict(list)
        discovery_by_match_key: dict[str, list[dict[str, object]]] = defaultdict(list)
        for resource in browser_resource_rows_for_run(run):
            row = browser_resource_metric_row(resource)
            if row is None:
                continue
            metric_by_resource[str(row.get("resource", ""))] = row
        for row in browser_page_resource_discovery_rows_for_run(run):
            url = str(row.get("url", ""))
            if not url:
                continue
            for key in resource_url_match_keys(url):
                discovery_by_match_key[key].append(row)
            variant = resource_variant_key(url)
            if variant:
                discovery_by_variant[variant].append(row)
        for resource_url, metric in metric_by_resource.items():
            if any(
                discovery_by_match_key.get(key)
                for key in resource_url_match_keys(resource_url)
            ):
                continue
            variant = resource_variant_key(resource_url)
            if not variant:
                continue
            matches = discovery_by_variant.get(variant, [])
            if not matches:
                continue
            loaded_family = str(metric.get("family", ""))
            current_families = sorted(
                {
                    resource_family(str(match.get("url", "")), "")
                    for match in matches
                    if str(match.get("url", ""))
                }
            )
            current_family = (
                current_families[0]
                if len(current_families) == 1
                else ", ".join(current_families[:3])
            )
            grouped[(profile_name, target, loaded_family, current_family)].append(
                {
                    "resource": resource_url,
                    "request_start_ms": metric.get("request_start_ms"),
                    "current_urls": [
                        str(match.get("url", ""))
                        for match in matches
                        if str(match.get("url", ""))
                    ],
                }
            )

    output = []
    for (profile_name, target, loaded_family, current_family), rows in sorted(
        grouped.items()
    ):
        request_starts = [
            value
            for row in rows
            if (value := numeric(row.get("request_start_ms"))) is not None
        ]
        loaded_freq: dict[str, int] = defaultdict(int)
        current_freq: dict[str, int] = defaultdict(int)
        for row in rows:
            resource = str(row.get("resource", ""))
            if resource:
                loaded_freq[resource] += 1
            for current_url in row.get("current_urls", []):
                current_freq[str(current_url)] += 1
        top_loaded = sorted(
            loaded_freq.items(),
            key=lambda item: (item[1], item[0]),
            reverse=True,
        )
        top_current = sorted(
            current_freq.items(),
            key=lambda item: (item[1], item[0]),
            reverse=True,
        )
        output.append(
            {
                "profile": profile_name,
                "target": target,
                "loaded_family": loaded_family,
                "current_family": current_family,
                "resources": len(rows),
                "median_request_start_ms": (
                    median(request_starts) if request_starts else None
                ),
                "top_loaded_resources": ", ".join(
                    compact_resource(name, 32) for name, _count in top_loaded[:3]
                ),
                "top_current_resources": ", ".join(
                    compact_resource(name, 32) for name, _count in top_current[:3]
                ),
            }
        )
    output.sort(
        key=lambda row: (
            numeric(row.get("resources")) or 0.0,
            numeric(row.get("median_request_start_ms")) or 0.0,
        ),
        reverse=True,
    )
    return output


def resource_basename(resource_name: object) -> str:
    if not isinstance(resource_name, str) or not resource_name:
        return ""
    return Path(urlsplit(resource_name).path).name


def first_resource_row_by_basename(
    run: dict[str, object], basename: str
) -> dict[str, object] | None:
    matches = [
        resource
        for resource in browser_resource_rows_for_run(run)
        if resource_basename(resource.get("name")) == basename
    ]
    if not matches:
        return None
    matches.sort(
        key=lambda resource: (
            numeric(resource.get("requestStart")) or 0.0,
            numeric(resource.get("responseEnd")) or 0.0,
            str(resource.get("name") or ""),
        )
    )
    return matches[0]


def activity_observed_relative_ms(
    run: dict[str, object], row: dict[str, object]
) -> float | None:
    observed_epoch_ms = numeric(row.get("observed_epoch_ms"))
    time_origin_ms = browser_time_origin_ms(run)
    if observed_epoch_ms is None or time_origin_ms is None:
        return None
    return observed_epoch_ms - time_origin_ms


def stop_request_observed_relative_ms_for_uri(
    run: dict[str, object], uri: str
) -> list[float]:
    values = []
    for row in browser_activity_probe_rows_for_run(run):
        if str(row.get("uri", "")) != uri:
            continue
        if str(row.get("topic", "")) != "http-on-stop-request":
            continue
        value = activity_observed_relative_ms(run, row)
        if value is not None:
            values.append(value)
    return values


def variant_swap_window_rows(payload: dict[str, object]) -> list[dict[str, object]]:
    rows = []
    for profile_name, _profile, target, _summary, run in iter_runs(payload):
        if not run.get("ok"):
            continue
        metric_by_resource: dict[str, dict[str, object]] = {}
        discovery_by_variant: dict[str, list[dict[str, object]]] = defaultdict(list)
        discovery_by_match_key: dict[str, list[dict[str, object]]] = defaultdict(list)
        activity_by_uri = browser_activity_summary_by_uri_for_run(run)
        for resource in browser_resource_rows_for_run(run):
            row = browser_resource_metric_row(resource)
            if row is None:
                continue
            metric_by_resource[str(row.get("resource", ""))] = row
        for discovery_row in browser_page_resource_discovery_rows_for_run(run):
            url = str(discovery_row.get("url", ""))
            if not url:
                continue
            for key in resource_url_match_keys(url):
                discovery_by_match_key[key].append(discovery_row)
            variant = resource_variant_key(url)
            if variant:
                discovery_by_variant[variant].append(discovery_row)

        run_groups: dict[tuple[str, str], list[dict[str, object]]] = defaultdict(list)
        for resource_url, metric in metric_by_resource.items():
            if any(
                discovery_by_match_key.get(key)
                for key in resource_url_match_keys(resource_url)
            ):
                continue
            variant = resource_variant_key(resource_url)
            if not variant:
                continue
            matches = discovery_by_variant.get(variant, [])
            if not matches:
                continue
            loaded_family = str(metric.get("family", ""))
            current_families = sorted(
                {
                    resource_family(str(match.get("url", "")), "")
                    for match in matches
                    if str(match.get("url", ""))
                }
            )
            current_family = (
                current_families[0]
                if len(current_families) == 1
                else ", ".join(current_families[:3])
            )
            run_groups[(loaded_family, current_family)].append(
                {
                    "resource": resource_url,
                    "request_start_ms": metric.get("request_start_ms"),
                    "current_urls": [
                        str(match.get("url", ""))
                        for match in matches
                        if str(match.get("url", ""))
                    ],
                }
            )

        bootstrap_css = first_resource_row_by_basename(run, "bootstrap.css")
        fallback_js = first_resource_row_by_basename(run, "fallback.js")
        bootstrap_css_response_end_ms = (
            numeric(bootstrap_css.get("responseEnd"))
            if bootstrap_css is not None
            else None
        )
        fallback_js_request_start_ms = (
            numeric(fallback_js.get("requestStart")) if fallback_js is not None else None
        )
        fallback_js_response_end_ms = (
            numeric(fallback_js.get("responseEnd")) if fallback_js is not None else None
        )

        for (loaded_family, current_family), group_rows in sorted(run_groups.items()):
            loaded_request_starts = [
                value
                for row in group_rows
                if (value := numeric(row.get("request_start_ms"))) is not None
            ]
            current_request_starts = []
            pre_network_cancel_resources = 0
            pre_network_cancel_stop_values = []
            for group_row in group_rows:
                resource_url = str(group_row.get("resource", ""))
                metric = metric_by_resource.get(resource_url)
                if metric is None:
                    continue
                activity = activity_by_uri.get(resource_url)
                if activity is not None:
                    duration_ms = numeric(metric.get("duration_ms")) or 0.0
                    transfer_size_bytes = (
                        numeric(metric.get("transfer_size_bytes")) or 0.0
                    )
                    encoded_body_size_bytes = (
                        numeric(metric.get("encoded_body_size_bytes")) or 0.0
                    )
                    stop_request_rows = int(activity.get("stop_request_rows") or 0)
                    examine_response_rows = int(
                        activity.get("examine_response_rows") or 0
                    )
                    if (
                        duration_ms == 0.0
                        and transfer_size_bytes == 0.0
                        and encoded_body_size_bytes == 0.0
                        and stop_request_rows > 0
                        and examine_response_rows <= 0
                        and activity.get("any_socket_ports") is not True
                    ):
                        pre_network_cancel_resources += 1
                        pre_network_cancel_stop_values.extend(
                            stop_request_observed_relative_ms_for_uri(run, resource_url)
                        )
                for current_url in group_row.get("current_urls", []):
                    current_metric = metric_by_resource.get(str(current_url))
                    if current_metric is None:
                        continue
                    request_start_ms = numeric(current_metric.get("request_start_ms"))
                    if request_start_ms is not None:
                        current_request_starts.append(request_start_ms)

            pre_network_cancel_first_stop_request_ms = (
                min(pre_network_cancel_stop_values)
                if pre_network_cancel_stop_values
                else None
            )
            loaded_first_request_start_ms = (
                min(loaded_request_starts) if loaded_request_starts else None
            )
            current_first_request_start_ms = (
                min(current_request_starts) if current_request_starts else None
            )
            rows.append(
                {
                    "profile": profile_name,
                    "target": target,
                    "run_index": run.get("run_index"),
                    "loaded_family": loaded_family,
                    "current_family": current_family,
                    "resources": len(group_rows),
                    "bootstrap_css_response_end_ms": bootstrap_css_response_end_ms,
                    "fallback_js_request_start_ms": fallback_js_request_start_ms,
                    "fallback_js_response_end_ms": fallback_js_response_end_ms,
                    "loaded_first_request_start_ms": loaded_first_request_start_ms,
                    "pre_network_cancel_resources": pre_network_cancel_resources,
                    "pre_network_cancel_first_stop_request_ms": (
                        pre_network_cancel_first_stop_request_ms
                    ),
                    "current_first_request_start_ms": current_first_request_start_ms,
                    "bootstrap_css_end_to_fallback_js_request_ms": subtract_numeric(
                        fallback_js_request_start_ms, bootstrap_css_response_end_ms
                    ),
                    "fallback_js_end_to_cancel_stop_request_ms": subtract_numeric(
                        pre_network_cancel_first_stop_request_ms,
                        fallback_js_response_end_ms,
                    ),
                    "fallback_js_end_to_current_request_ms": subtract_numeric(
                        current_first_request_start_ms, fallback_js_response_end_ms
                    ),
                }
            )

    rows.sort(
        key=lambda row: (
            str(row.get("profile", "")),
            str(row.get("target", "")),
            numeric(row.get("run_index")) or 0.0,
            str(row.get("loaded_family", "")),
            str(row.get("current_family", "")),
        )
    )
    return rows


def pre_network_cancel_summary_rows(
    payload: dict[str, object],
) -> list[dict[str, object]]:
    grouped: dict[tuple[str, str, str, str, bool], list[dict[str, object]]] = defaultdict(list)
    for profile_name, _profile, target, _summary, run in iter_runs(payload):
        if not run.get("ok"):
            continue
        activity_by_uri = browser_activity_summary_by_uri_for_run(run)
        blocked_uri_counts = browser_request_blocked_uri_counter_for_run(run)
        discovery_by_variant: dict[str, list[dict[str, object]]] = defaultdict(list)
        discovery_by_match_key: dict[str, list[dict[str, object]]] = defaultdict(list)
        for row in browser_page_resource_discovery_rows_for_run(run):
            url = str(row.get("url", ""))
            if not url:
                continue
            for key in resource_url_match_keys(url):
                discovery_by_match_key[key].append(row)
            variant = resource_variant_key(url)
            if variant:
                discovery_by_variant[variant].append(row)

        for resource in browser_resource_rows_for_run(run):
            metric = browser_resource_metric_row(resource)
            if metric is None:
                continue
            resource_url = str(metric.get("resource", ""))
            if not resource_url:
                continue
            activity = activity_by_uri.get(resource_url)
            if not activity:
                continue
            duration_ms = numeric(metric.get("duration_ms")) or 0.0
            transfer_size_bytes = numeric(metric.get("transfer_size_bytes")) or 0.0
            encoded_body_size_bytes = (
                numeric(metric.get("encoded_body_size_bytes")) or 0.0
            )
            if (
                duration_ms != 0.0
                or transfer_size_bytes != 0.0
                or encoded_body_size_bytes != 0.0
            ):
                continue
            stop_request_rows = int(activity.get("stop_request_rows") or 0)
            examine_response_rows = int(activity.get("examine_response_rows") or 0)
            if stop_request_rows <= 0:
                continue
            if examine_response_rows > 0 or activity.get("any_socket_ports") is True:
                continue
            request_blocked = blocked_uri_counts.get(resource_url, 0) > 0
            current_matches: list[dict[str, object]] = []
            if not any(
                discovery_by_match_key.get(key)
                for key in resource_url_match_keys(resource_url)
            ):
                variant = resource_variant_key(resource_url)
                if variant:
                    current_matches = [
                        row
                        for row in discovery_by_variant.get(variant, [])
                        if str(row.get("url", "")) and str(row.get("url", "")) != resource_url
                    ]
            current_families = sorted(
                {
                    resource_family(str(match.get("url", "")), "")
                    for match in current_matches
                    if str(match.get("url", ""))
                }
            )
            current_family = (
                current_families[0]
                if len(current_families) == 1
                else (
                    ", ".join(current_families[:3])
                    if current_families
                    else str(metric.get("family", ""))
                )
            )
            grouped[
                (
                    profile_name,
                    target,
                    str(metric.get("family", "")),
                    current_family,
                    request_blocked,
                )
            ].append(
                {
                    "resource": resource_url,
                    "request_start_ms": metric.get("request_start_ms"),
                    "stop_request_rows": stop_request_rows,
                    "channel_count": len(activity.get("channel_ids", set())),
                    "current_urls": [
                        str(match.get("url", ""))
                        for match in current_matches
                        if str(match.get("url", ""))
                    ],
                }
            )

    output = []
    for (
        profile_name,
        target,
        loaded_family,
        current_family,
        request_blocked,
    ), rows in sorted(grouped.items()):
        request_starts = [
            value
            for row in rows
            if (value := numeric(row.get("request_start_ms"))) is not None
        ]
        loaded_freq: dict[str, int] = defaultdict(int)
        current_freq: dict[str, int] = defaultdict(int)
        stop_request_rows = 0
        channel_count = 0
        for row in rows:
            resource = str(row.get("resource", ""))
            if resource:
                loaded_freq[resource] += 1
            stop_request_rows += int(row.get("stop_request_rows") or 0)
            channel_count += int(row.get("channel_count") or 0)
            for current_url in row.get("current_urls", []):
                text = str(current_url or "")
                if text:
                    current_freq[text] += 1
        top_loaded = sorted(
            loaded_freq.items(),
            key=lambda item: (item[1], item[0]),
            reverse=True,
        )
        top_current = sorted(
            current_freq.items(),
            key=lambda item: (item[1], item[0]),
            reverse=True,
        )
        output.append(
            {
                "profile": profile_name,
                "target": target,
                "loaded_family": loaded_family,
                "current_family": current_family,
                "request_blocked": request_blocked,
                "resources": len(rows),
                "unique_resources": len(loaded_freq),
                "median_request_start_ms": (
                    median(request_starts) if request_starts else None
                ),
                "stop_request_rows": stop_request_rows,
                "channel_count": channel_count,
                "top_loaded_resources": ", ".join(
                    compact_resource(name, 32) for name, _count in top_loaded[:3]
                ),
                "top_current_resources": ", ".join(
                    compact_resource(name, 32) for name, _count in top_current[:3]
                ),
            }
        )
    output.sort(
        key=lambda row: (
            1 if row.get("request_blocked") else 0,
            numeric(row.get("resources")) or 0.0,
            numeric(row.get("median_request_start_ms")) or 0.0,
        ),
        reverse=True,
    )
    return output


def resource_phase_ms(resource: dict[str, object], field: str) -> float | None:
    value = numeric(resource.get(field))
    if value is not None:
        return value

    if field == "fetchToRequest":
        return subtract_fields(resource, "fetchStart", "requestStart")
    if field == "requestWait":
        return subtract_fields(resource, "requestStart", "responseStart")
    if field == "responseReceive":
        return subtract_fields(resource, "responseStart", "responseEnd")
    if field == "fetchToResponse":
        return subtract_fields(resource, "fetchStart", "responseStart")
    if field == "connectSetup":
        return subtract_fields(resource, "connectStart", "connectEnd")
    return None


def zero_connect_setup_count(resources: list[dict[str, object]]) -> int:
    count = 0
    for resource in resources:
        setup = resource_phase_ms(resource, "connectSetup")
        if setup is not None and abs(setup) <= 1.0:
            count += 1
    return count


def subtract_fields(
    values: dict[str, object], start_field: str, end_field: str
) -> float | None:
    start = numeric(values.get(start_field))
    end = numeric(values.get(end_field))
    if start is None or end is None:
        return None
    return end - start


def subtract_numeric(candidate: object, baseline: object) -> float | None:
    candidate_value = numeric(candidate)
    baseline_value = numeric(baseline)
    if candidate_value is None or baseline_value is None:
        return None
    return candidate_value - baseline_value


def add_numeric(left: object, right: object) -> float | None:
    left_value = numeric(left)
    right_value = numeric(right)
    if left_value is None or right_value is None:
        return None
    return left_value + right_value


def interval_overlap_ms(
    left_start: object,
    left_end: object,
    right_start: object,
    right_end: object,
) -> float | None:
    left_start_value = numeric(left_start)
    left_end_value = numeric(left_end)
    right_start_value = numeric(right_start)
    right_end_value = numeric(right_end)
    if (
        left_start_value is None
        or left_end_value is None
        or right_start_value is None
        or right_end_value is None
    ):
        return None
    return max(
        0.0,
        min(left_end_value, right_end_value)
        - max(left_start_value, right_start_value),
    )


def add_boot_ms(boot_seconds: object, metric_ms: object) -> float | None:
    if not isinstance(boot_seconds, (int, float)):
        return None
    if not isinstance(metric_ms, (int, float)):
        return None
    return boot_seconds * 1000 + metric_ms


def delta(candidate: object, baseline: object) -> str:
    if not isinstance(candidate, (int, float)) or not isinstance(baseline, (int, float)):
        return ""
    if baseline == 0:
        return ""
    pct = ((candidate - baseline) / baseline) * 100
    direction = "faster" if pct < 0 else "slower"
    return f"{abs(pct):.1f}% {direction}"


def median(values: list[float]) -> float:
    return float(statistics.median(values))


def compact_url(value: str, max_length: int = 80) -> str:
    parsed = urlparse(value)
    if parsed.netloc:
        value = parsed.netloc + parsed.path
    if len(value) <= max_length:
        return value
    return "..." + value[-(max_length - 3):]


def compact_list(values: object, max_items: int = 4) -> str:
    unique = []
    for value in values:
        text = str(value)
        if text in unique:
            continue
        unique.append(text)
    shown = unique[:max_items]
    suffix = "" if len(unique) <= max_items else f", +{len(unique) - max_items}"
    return ", ".join(shown) + suffix


def expand_compact_list_field(rows: list[dict[str, object]], field: str) -> list[str]:
    values = []
    for row in rows:
        text = str(row.get(field, "")).strip()
        if not text:
            continue
        for part in text.split(", "):
            part = part.strip()
            if not part or part.startswith("+"):
                continue
            values.append(part)
    return values


def fmt(value: object) -> str:
    if value is None:
        return ""
    if isinstance(value, float):
        return f"{value:.3f}"
    return str(value)


def fmt_diff(value: object) -> str:
    number = numeric(value)
    if number is None:
        return ""
    return f"{number:+.3f}"


def yes_no_unknown(value: object) -> str:
    if value is True:
        return "yes"
    if value is False:
        return "no"
    return "unknown"


def format_table_text(value: object, max_len: int = 180) -> str:
    if value is None:
        return ""
    text = re.sub(r"\s+", " ", str(value)).strip().replace("|", "/")
    if len(text) <= max_len:
        return text
    return text[: max_len - 3] + "..."


if __name__ == "__main__":
    raise SystemExit(main())
